#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        int min_idx = 0;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < a[min_idx]) {
                min_idx = i;
            }
        }

        long long min_val = a[min_idx];
        long long total_spells = 0;

        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue;
            }
            // For each other pile a[i], we can add min_val to it
            // until a[i] + X * min_val > k
            // So, a[i] + X * min_val <= k
            // X * min_val <= k - a[i]
            // X <= (k - a[i]) / min_val
            // Since X must be an integer, X = floor((k - a[i]) / min_val)
            if (min_val > 0) { // Should always be true as a_i >= 1
                total_spells += (k - a[i]) / min_val;
            }
        }
        std::cout << total_spells << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k coal and k sticks.
        // To get k coal, we need k * y sticks.
        // So, total sticks required for coal and torches = k * y + k = k * (y + 1).
        long long total_sticks_needed = k * (y + 1);

        // We start with 1 stick.
        // We need to acquire (total_sticks_needed - 1) more sticks using the first trade.
        // Each trade of type 1 (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        long long sticks_to_gain = total_sticks_needed - 1;
        long long trades_for_sticks = (sticks_to_gain + (x - 2)) / (x - 1); // Equivalent to ceil(sticks_to_gain / (x - 1))

        // Total trades = trades for sticks + trades for coal
        // Trades for coal = k (since 1 trade gives 1 coal)
        long long total_trades = trades_for_sticks + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

