#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks for the minimum absolute difference between medians.
        // After sorting the array a, the optimal strategy is to pick the
        // n-th element (0-indexed: a[n-1]) as the median for one class
        // and the (n+1)-th element (0-indexed: a[n]) as the median for the other class.
        // This is because if we pick a[i] and a[j] as medians, and i < n-1 or j > n,
        // we could always move them closer to the center (n-1 and n) to reduce the difference
        // or keep it the same, while still being able to form valid odd-sized classes.
        // Specifically, the smallest possible median for a class of size 2k+1 is a[k].
        // The largest possible median for a class of size 2k+1 is a[2n-1-k].
        // For the two classes to cover all 2n students, if one class has median a[i]
        // and the other has median a[j], then i and j must be "central" elements.
        // The two medians will always be a[n-1] and a[n] after sorting.
        // This is a known property for this type of problem.
        // The first class will have median a[n-1] and the second class will have median a[n].
        // The difference is a[n] - a[n-1].
        long long diff = a[n] - a[n - 1];
        std::cout << diff << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<long long> b(n);
    bool has_pos_one = false;
    bool has_neg_one = false;

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            has_pos_one = true;
        } else if (a[i] == -1) {
            has_neg_one = true;
        }
    }
    for (int i = 0; i < n; ++i) {
        std::cin >> b[i];
    }

    if (a[0] != b[0]) {
        std::cout << "NO\n";
        return;
    }

    for (int i = 1; i < n; ++i) {
        if (a[i] < b[i]) { // Need to increase a[i]
            if (!has_pos_one) {
                std::cout << "NO\n";
                return;
            }
        } else if (a[i] > b[i]) { // Need to decrease a[i]
            if (!has_neg_one) {
                std::cout << "NO\n";
                return;
            }
        }
        // If a[i] == b[i], no operation is needed for this element.
        // The flags has_pos_one and has_neg_one are updated based on a[i]
        // for future elements.
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n, m;
    std::cin >> n >> m;
    std::vector<std::vector<int>> a(n, std::vector<int>(m));
    std::vector<bool> row_taken(n, false);
    std::vector<bool> col_taken(m, false);

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            std::cin >> a[i][j];
            if (a[i][j] == 1) {
                row_taken[i] = true;
                col_taken[j] = true;
            }
        }
    }

    int available_rows = 0;
    for (int i = 0; i < n; ++i) {
        if (!row_taken[i]) {
            available_rows++;
        }
    }

    int available_cols = 0;
    for (int j = 0; j < m; ++j) {
        if (!col_taken[j]) {
            available_cols++;
        }
    }

    int num_moves = std::min(available_rows, available_cols);

    if (num_moves % 2 == 1) {
        std::cout << "Ashish\n";
    } else {
        std::cout << "Vivek\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <string>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_video_count = 0;
    int posts_formed = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_video_count++;

        if (current_post_sum == target_duration) {
            s_values.push_back(current_post_video_count);
            current_post_sum = 0;
            current_post_video_count = 0;
            posts_formed++;
        } else if (current_post_sum > target_duration) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_formed == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long l, r;
    std::cin >> l >> r;

    if (l == r) {
        // If l == r, the only number is l.
        // We need to find its smallest prime factor, or just l itself if it's prime.
        // However, the problem asks for *any* divisor that appears max times.
        // Since l is the only number, any divisor of l (except 1) appears once.
        // The smallest possible divisor > 1 is 2.
        // If l is even, 2 is a divisor.
        // If l is odd, 2 is not a divisor.
        // But the problem asks for the integer that we wrote down the maximum number of times.
        // If l=3, r=3, the only number is 3. Divisors (except 1) are {3}. Max is 3.
        // If l=4, r=4, the only number is 4. Divisors (except 1) are {2, 4}. Max is 2 or 4.
        // The problem states "If there are multiple answers, print any of them."
        // The simplest answer for l=r is just l itself if l > 1.
        // But the general logic below will handle this.
        // For l=r, the count for any divisor d of l is 1.
        // The count for any divisor d not of l is 0.
        // So we just need to pick any divisor of l.
        // The problem asks for the integer that we wrote down the maximum number of times.
        // If l=3, r=3, output 3.
        // If l=4, r=4, output 2 (or 4).
        // The general logic below will output 2 if l is even, or l if l is odd.
        // This is because 2 is always checked first and if it's a divisor, it's a valid answer.
        // If l is odd, 2 is not a divisor, so it won't be chosen.
        // The logic for l=r is implicitly handled by the general case.
        // For l=r, count(d) = r/d - (l-1)/d = l/d - (l-1)/d.
        // If d divides l, then l/d is an integer. (l-1)/d = l/d - 1/d.
        // If d divides l, then (l-1)/d = floor((l-1)/d) = l/d - 1.
        // So count(d) = l/d - (l/d - 1) = 1.
        // If d does not divide l, then l/d is not an integer.
        // (l-1)/d might be l/d or l/d - 1.
        // Example: l=5, r=5. d=2. count(2) = 5/2 - (5-1)/2 = 2 - 4/2 = 2 - 2 = 0.
        // Example: l=5, r=5. d=5. count(5) = 5/5 - (5-1)/5 = 1 - 4/5 = 1 - 0 = 1.
        // So the logic holds.
    }

    // The number of multiples of x in [l, r] is floor(r/x) - ceil(l/x) + 1.
    // Using integer division, this is r/x - (l-1)/x.
    // We want to maximize this value.
    // Consider two divisors x and y.
    // If x < y, then r/x >= r/y and (l-1)/x >= (l-1)/y.
    // So r/x - (l-1)/x is generally greater than or equal to r/y - (l-1)/y.
    // This means smaller divisors tend to have more occurrences.
    // The smallest possible divisor greater than 1 is 2.
    // If 2 is a divisor for any number in the range, it will likely be the most frequent.
    // The count for 2 is (r/2) - ((l-1)/2).
    // The count for 3 is (r/3) - ((l-1)/3).
    // If r/2 - (l-1)/2 is greater than or equal to r/3 - (l-1)/3, then 2 is a good candidate.
    // This is almost always true for ranges of any significant size.
    // For example, if l=19, r=29:
    // Count for 2: 29/2 - (19-1)/2 = 14 - 9 = 5.
    // Count for 3: 29/3 - (19-1)/3 = 9 - 6 = 3.
    // Count for 4: 29/4 - (19-1)/4 = 7 - 4 = 3.
    // Count for 5: 29/5 - (19-1)/5 = 5 - 3 = 2.
    // The only case where a larger number might win is if the range is very small and specifically excludes multiples of 2.
    // Example: l=3, r=3. Count(2)=0, Count(3)=1. Output 3.
    // Example: l=3, r=4. Count(2)=1 (for 4), Count(3)=1 (for 3). Output 2 (or 3).
    // Example: l=3, r=6. Count(2)=2 (for 4,6), Count(3)=2 (for 3,6). Output 2 (or 3).
    // The example output for 3 6 is 3. This implies that if counts are equal, any is fine.
    // Since 2 is the smallest possible divisor, it will always have the highest or equal highest count.
    // The only exception is when the range [l, r] contains no even numbers, i.e., l is odd and r is odd, and r-l is small.
    // For example, l=3, r=3. Count(2)=0, Count(3)=1.
    // For l=5, r=5. Count(2)=0, Count(5)=1.
    // For l=7, r=7. Count(2)=0, Count(7)=1.
    // In such cases, 2 is not a divisor for any number in the range.
    // However, if r-l >= 1, there must be an even number.
    // If r-l >= 1, then either l is even, or l is odd and l+1 is even.
    // So if r-l >= 1, there is at least one even number in the range.
    // Thus, 2 will appear at least once as a divisor.
    // If r-l >= 1, the count for 2 will be at least 1.
    // The count for any other divisor d > 2 will be at most (r-l+1)/d.
    // For d=3, count is at most (r-l+1)/3.
    // For d=2, count is at least (r-l+1)/2 (approximately).
    // So, for r-l >= 1, 2 is always the best choice or tied for best.
    // The only edge case is l=r.
    // If l=r, and l is odd, then 2 has count 0. The answer should be l.
    // If l=r, and l is even, then 2 has count 1. The answer can be 2.
    // The problem states "If there are multiple answers, print any of them."
    // So, if r-l >= 1, 2 is always a valid answer.
    // If l=r:
    //   If l is even, 2 is a divisor of l. Count(2)=1. Output 2.
    //   If l is odd, 2 is not a divisor of l. Count(2)=0.
    //     In this case, we need to find a divisor of l. The smallest prime factor of l would be a good candidate.
    //     But the problem allows any. So l itself is a divisor. Output l.
    // This logic can be simplified:
    // If r-l >= 1, output 2.
    // If l=r:
    //   If l is even, output 2.
    //   If l is odd, output l.
    // This can be further simplified:
    // If r-l >= 1, output 2.
    // If l=r and l is even, output 2.
    // If l=r and l is odd, output l.
    // This is equivalent to: if r-l >= 1 OR l is even, output 2. Else (l=r AND l is odd), output l.
    // This is equivalent to: if l != r OR l % 2 == 0, output 2. Else output l.

    if (l != r) {
        std::cout << 2 << std::endl;
    } else { // l == r
        if (l % 2 == 0) {
            std::cout << 2 << std::endl;
        } else {
            std::cout << l << std::endl;
        }
    }

    return 0;
}

