    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;

        // The maximum number of teams 'k' is limited by three factors:
        // 1. The number of coders available (k <= c)
        // 2. The number of mathematicians available (k <= m)
        // 3. The total number of students available divided by 3 (k <= (c + m + x) / 3)
        // So, k <= min(c, m, (c + m + x) / 3)

        // Let's find the maximum possible value for k.
        // The minimum of c and m gives an upper bound on k, because each team needs at least one coder and one mathematician.
        // The total number of students (c + m + x) divided by 3 also gives an upper bound on k, because each team needs 3 students.

        // The actual number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // k <= (c + m + x) / 3

        // So, the maximum k is the minimum of these three values.
        long long max_teams = std::min({c, m, (c + m + x) / 3});

