int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int max_dist = 0;
        int last_R_pos = -1; // Represents the last 'R' cell's 0-indexed position, or -1 for cell 0.
                             // The distance from last_R_pos to the current 'R' cell is what matters.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed).
                // Distance from previous 'R' cell (or 0) to current 'R' cell.
                // If last_R_pos is -1, it means we are coming from cell 0.
                // The current 'R' cell is at index i.
                // The distance is (i + 1) - (last_R_pos + 1) = i - last_R_pos.
                // Example: last_R_pos = -1 (cell 0), current 'R' at index 0 (cell 1). Distance = 0 - (-1) = 1.
                // Example: last_R_pos = 0 (cell 1), current 'R' at index 2 (cell 3). Distance = 2 - 0 = 2.
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, we need to consider the jump from the last 'R' cell
        // to the target cell n+1.
        // The last 'R' cell is at index last_R_pos. Its 1-indexed position is last_R_pos + 1.
        // The target is n+1.
        // The distance is (n + 1) - (last_R_pos + 1) = n - last_R_pos.
        max_dist = std::max(max_dist, n - last_R_pos);

        std::cout << max_dist << "\n";
    }
    return 0;
}

