#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    std::vector<int> p(n);
    int left = 1;
    int right = k + 1; // The largest number we will use for the first k differences

    // Generate k distinct differences using numbers from 1 to k+1
    // This will generate differences: k, k-1, ..., 1
    // Example: k=2, right=3. Sequence: 1 3 2
    // Differences: |1-3|=2, |3-2|=1. Two distinct differences.
    // Example: k=3, right=4. Sequence: 1 4 2 3
    // Differences: |1-4|=3, |4-2|=2, |2-3|=1. Three distinct differences.
    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index, take from left (smaller)
            p[i] = left++;
        } else { // Odd index, take from right (larger)
            p[i] = right--;
        }
    }

    // Fill the remaining n - (k+1) elements in increasing order
    // These elements will be k+2, k+3, ..., n
    // The differences generated by these elements will all be 1,
    // which is already covered by the first k differences (since k >= 1).
    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be left, which is k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

