void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::string ans1 = "Tidak", ans2 = "Tidak", ans3 = "Tidak", ans4 = "Tidak";

    if (total_toys == 0) { // Should not happen based on constraints A+B+C+D > 0
        std::cout << "Tidak Tidak Tidak Tidak\n";
        return;
    }

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (a == 1) ans1 = "Ya";
        if (b == 1) ans2 = "Ya";
        if (c == 1) ans3 = "Ya";
        if (d == 1) ans4 = "Ya";
        std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
        return;
    }

    // Box 1: (-inf, -1]
    // Final toy must be negative and magnitude >= 1
    // This requires an odd number of negative factors.
    // And at least one factor with magnitude >= 1, or multiple factors with magnitude > 1/sqrt(X) etc.
    // It's always possible to make magnitude >= 1 if there's at least one toy in Box 1 or Box 4.
    // If there are no toys in Box 1 or Box 4, then all initial toys have magnitude < 1.
    // In this case, the final product will always have magnitude < 1.
    // So, if a+d == 0, Box 1 is impossible.
    // Otherwise, if a+d > 0, we can achieve magnitude >= 1.
    // We need an odd number of negative factors.
    // The number of negative factors is a + b.
    // If (a + b) is odd, it's possible.
    // If (a + b) is even, we need to change the parity. This can be done if we have at least one toy in Box 2 or Box 3.
    // If (a+b) is even and (b+c) > 0, we can pick a toy from B or C, multiply it by something, and change its sign.
    // For example, if we have a toy in B (negative, <1) and a toy in C (positive, <1), we can multiply them to get a negative toy (<1).
    // This doesn't change the parity of negative toys.
    // The parity of negative toys (a+b) is fixed.
    // So, if (a+b) is odd AND (a+d > 0), then Box 1 is possible.
    // What if (a+b) is even? Can we make it odd? No, the parity of negative toys is invariant.
    // So, for Box 1: (a + b) % 2 == 1 AND (a + d > 0)
    if ((a + b) % 2 == 1 && (a + d > 0)) {
        ans1 = "Ya";
    }

    // Box 2: (-1, 0)
    // Final toy must be negative and magnitude < 1
    // This requires an odd number of negative factors.
    // And all factors must be able to result in magnitude < 1.
    // If a+d == 0, all initial toys have magnitude < 1. The product will always have magnitude < 1.
    // So if a+d == 0, and (a+b) is odd, Box 2 is possible.
    // If a+d > 0, we need to be careful. We need to ensure the final product has magnitude < 1.
    // This is always possible if we have at least one toy in Box 2 or Box 3 (b+c > 0).
    // We can pick a toy from Box 2 or Box 3 (e.g., 0.5 or -0.5) and multiply it by the current product.
    // If the current product is large (e.g., 100), multiplying by 0.5 makes it 50.
    // We can keep multiplying by small numbers until it's < 1.
    // So, if (a+b) is odd, and (b+c > 0 OR a+d == 0), then Box 2 is possible.
    // The condition (b+c > 0 OR a+d == 0) simplifies to (b+c > 0 OR (a==0 AND d==0)).
    // If a+d == 0, then all toys are in B or C. Their product will always be < 1.
    // If a+d > 0, we need to "shrink" the product. This requires at least one toy in B or C.
    // So, if (a+b) is odd AND (b + c > 0 || (a == 0 && d == 0))
    if ((a + b) % 2 == 1 && (b + c > 0 || (a == 0 && d == 0))) {
        ans2 = "Ya";
    }

    // Box 3: (0, 1)
    // Final toy must be positive and magnitude < 1
    // This requires an even number of negative factors.
    // Similar to Box 2, if a+d == 0, all initial toys have magnitude < 1. The product will always have magnitude < 1.
    // So if a+d == 0, and (a+b) is even, Box 3 is possible.
    // If a+d > 0, we need to ensure magnitude < 1. This requires at least one toy in Box 2 or Box 3 (b+c > 0).
    // So, if (a+b) is even AND (b + c > 0 || (a == 0 && d == 0))
    if ((a + b) % 2 == 0 && (b + c > 0 || (a == 0 && d == 0))) {
        ans3 = "Ya";
    }

    // Box 4: [1, inf)
    // Final toy must be positive and magnitude >= 1
    // This requires an even number of negative factors.
    // Similar to Box 1, if a+d == 0, all initial toys have magnitude < 1. The product will always have magnitude < 1.
    // So if a+d == 0, Box 4 is impossible.
    // Otherwise, if a+d > 0, we can achieve magnitude >= 1.
    // So, if (a+b) is even AND (a + d > 0)
    if ((a + b) % 2 == 0 && (a + d > 0)) {
        ans4 = "Ya";
    }

    std::cout << ans1 << " " << ans2 << " " << ans3 << " " << ans4 << "\n";
}

