int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count01 = 0; // a[i] = '0', b[i] = '1'
    int count10 = 0; // a[i] = '1', b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (count10 > 0) { // Found a '10' mismatch to pair with
                    cost += 1; // Cost of swapping adjacent '01' and '10' is 1
                    count10--; // Both are resolved
                } else {
                    count01++; // No '10' to pair with, add to '01' count
                }
            } else { // a[i] = '1', b[i] = '0'
                if (count01 > 0) { // Found a '01' mismatch to pair with
                    cost += 1; // Cost of swapping adjacent '10' and '01' is 1
                    count01--; // Both are resolved
                } else {
                    count10++; // No '01' to pair with, add to '10' count
                }
            }
        }
    }

    // After iterating, any remaining count01 or count10 must be resolved by flipping.
    // Each flip costs 1.
    cost += (long long)count01 + count10;

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i from 1 to n-1 (corresponding to q_2 to q_n)
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, p_i must be q_i
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i must be unique if it's a new max
                // and q_i is guaranteed to be <= n.
                // However, if q_i was already used as p_j for j < i, it's an issue.
                // But p_j = q_j if q_j > q_{j-1}. So q_i would be equal to some q_j.
                // This implies q_i was not a new maximum, contradiction.
                // So this check is mostly for robustness, but shouldn't trigger with valid q.
                possible = false;
                break;
            }
            p[i] = q[i];
            used_numbers.insert(q[i]);
        } else { // q[i] == q[i-1]
            // p_i must be some unused number less than q[i]
            // To maximize chances, pick the smallest available number
            int current_val = 1;
            while (used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val >= q[i]) {
                // No unused number less than q[i] is available
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_stair_n = 1;
        long long current_cost = 1; // Cost for n=1 staircase
        while (x >= current_cost) {
            x -= current_cost;
            count++;
            current_stair_n = current_stair_n * 2 + 1;
            // Calculate cost for the next nice staircase (with current_stair_n stairs)
            // Cost = current_stair_n * (current_stair_n + 1) / 2
            // This can be derived from the previous cost:
            // Let N_prev be the number of stairs for the previous nice staircase.
            // N_curr = 2 * N_prev + 1.
            // Cost_curr = N_curr * (N_curr + 1) / 2
            // Cost_curr = (2 * N_prev + 1) * (2 * N_prev + 2) / 2
            // Cost_curr = (2 * N_prev + 1) * (N_prev + 1)
            // Cost_curr = 2 * N_prev * (N_prev + 1) + (N_prev + 1)
            // Cost_curr = 4 * (N_prev * (N_prev + 1) / 2) + (N_prev + 1)
            // Cost_curr = 4 * Cost_prev + (N_prev + 1)
            // Using this recurrence relation to avoid large intermediate products for current_stair_n * (current_stair_n + 1)
            // N_prev is the value of current_stair_n from the previous iteration.
            // So, current_cost (new) = 4 * current_cost (old) + (current_stair_n (old) + 1)
            // The current_stair_n variable has already been updated to the new value (2*N_prev+1).
            // So, N_prev = (current_stair_n - 1) / 2.
            // current_cost (new) = 4 * current_cost (old) + ((current_stair_n (new) - 1) / 2 + 1)
            // current_cost (new) = 4 * current_cost (old) + (current_stair_n (new) + 1) / 2
            current_cost = 4 * current_cost + (current_stair_n + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[left_ptr] <= d

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Advance right_ptr until x[right_ptr] - x[left_ptr] > d
        // or until right_ptr reaches the end of the array.
        // The condition x[right_ptr] <= x[left_ptr] + d is equivalent to x[right_ptr] - x[left_ptr] <= d.
        while (right_ptr < n && x[right_ptr] <= x[left_ptr] + d) {
            right_ptr++;
        }
        // At this point, all points from x[left_ptr] to x[right_ptr - 1] satisfy the condition
        // with x[left_ptr] as the leftmost point.
        // We need to choose two more points from the range (left_ptr, right_ptr - 1].
        // The number of available points in this range is (right_ptr - 1) - (left_ptr + 1) + 1
        // which simplifies to right_ptr - 1 - left_ptr.
        // Let k = right_ptr - 1 - left_ptr.
        // If k >= 2, we can choose 2 points from these k points.
        // The number of ways to choose 2 points from k points is k * (k - 1) / 2.

        long long k = static_cast<long long>(right_ptr) - 1 - left_ptr;
        if (k >= 2) {
            count += k * (k - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    // Sort A in ascending order
    std::sort(A.begin(), A.end(), compareElementA);

    // Sort B in ascending order
    std::sort(B.begin(), B.end(), compareElementB);

    // Create the result array A_prime
    // A_prime[B[i].original_index] will store the A value that corresponds to B[i]
    std::vector<long long> A_prime(m);

    // The optimal strategy is to pair the smallest A with the largest B,
    // the second smallest A with the second largest B, and so on.
    // This means A[i] (sorted A) should be paired with B[m-1-i] (sorted B).
    // The value A[i].value should be placed at the original index of B[m-1-i].
    for (int i = 0; i < m; ++i) {
        A_prime[B[i].original_index] = A[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << A_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // 1. Make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // 2. Ensure elements to the left of median are <= s
    // These elements are a[0]...a[median_idx-1]
    // If a[i] > s, we must decrease it to s.
    // Since a is sorted, if a[i] > s, then a[i+1]...a[median_idx-1] are also > s.
    // We only need to consider elements that are currently greater than s.
    // Elements that are already <= s don't need to be changed to satisfy the median property for the left side.
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // 3. Ensure elements to the right of median are >= s
    // These elements are a[median_idx+1]...a[n-1]
    // If a[i] < s, we must increase it to s.
    // Since a is sorted, if a[i] < s, then a[i-1]...a[median_idx+1] are also < s.
    // We only need to consider elements that are currently smaller than s.
    // Elements that are already >= s don't need to be changed to satisfy the median property for the right side.
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

