void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of the suffix that is non-decreasing
    // This is the end of the "decreasing part" of the suffix
    int i = n - 1;
    while (i > 0 && a[i-1] >= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // Find the rightmost peak of the suffix that is non-increasing
    // This is the end of the "increasing part" of the suffix
    int j = i; // Start from where the non-decreasing part ended
    while (j > 0 && a[j-1] <= a[j]) {
        j--;
    }
    // Now a[j...n-1] is a "good" suffix (first non-increasing, then non-decreasing)

    std::cout << j << std::endl;
}

