#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation_prefix(const std::vector<int>& a, int len) {
    if (len == 0) return false;
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[i] <= 0 || a[i] > len) {
            return false;
        }
        if (seen[a[i]]) {
            return false;
        }
        seen[a[i]] = true;
        if (a[i] > max_val) {
            max_val = a[i];
        }
    }
    return max_val == len;
}

bool is_permutation_suffix(const std::vector<int>& a, int start_idx, int len) {
    if (len == 0) return false;
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (a[start_idx + i] <= 0 || a[start_idx + i] > len) {
            return false;
        }
        if (seen[a[start_idx + i]]) {
            return false;
        }
        seen[a[start_idx + i]] = true;
        if (a[start_idx + i] > max_val) {
            max_val = a[start_idx + i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int current_max = 0;
    bool current_prefix_valid = true;
    for (int i = 0; i < n; ++i) {
        if (current_prefix_valid) {
            if (a[i] <= 0 || a[i] > i + 1 || seen_prefix[a[i]]) {
                current_prefix_valid = false;
            } else {
                seen_prefix[a[i]] = true;
                if (a[i] > current_max) {
                    current_max = a[i];
                }
                if (current_max == i + 1) {
                    prefix_is_perm[i + 1] = true;
                }
            }
        }
    }

    std::vector<bool> suffix_is_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    current_max = 0;
    bool current_suffix_valid = true;
    for (int i = n - 1; i >= 0; --i) {
        int len = n - i;
        if (current_suffix_valid) {
            if (a[i] <= 0 || a[i] > len || seen_suffix[a[i]]) {
                current_suffix_valid = false;
            } else {
                seen_suffix[a[i]] = true;
                if (a[i] > current_max) {
                    current_max = a[i];
                }
                if (current_max == len) {
                    suffix_is_perm[len] = true;
                }
            }
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

