#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[val] stores the 0-indexed position of val

    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    result.reserve(n);

    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1] at pos[1].
        // min_idx and max_idx are both pos[1].
        // min_val is 1, max_val is 1. Length is 1.
        // This is always beautiful.

        // For m > 1, we need to expand the current segment [current_min_idx, current_max_idx]
        // to include 'm'.
        // The number 'm' is at pos[m].
        // We need to update current_min_idx and current_max_idx to cover the range
        // from 1 to m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // Now, the segment p[current_min_idx ... current_max_idx] contains all numbers
        // from 1 to m (and possibly some other numbers > m).
        // The minimum value in this segment is 1.
        // The maximum value in this segment is m.
        // For m to be beautiful, the length of this segment must be exactly m.
        // Length = current_max_idx - current_min_idx + 1.
        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;
    int a_ptr_left = 0;
    int a_ptr_right = n - 1;

    // Friends who get w_i = 1 integers
    // These friends should get the largest available integers,
    // as their happiness is 2 * integer.
    // Since w is sorted, these are the first elements in w.
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_right];
            a_ptr_right--;
        } else {
            // All remaining w_i will be > 1
            // Break and handle them in the next loop
            // This relies on w being sorted.
            break;
        }
    }

    // Friends who get w_i > 1 integers
    // These friends should get one largest available integer (for max_val)
    // and one smallest available integer (for min_val).
    // The remaining w_i - 2 integers don't affect max/min, so they can be
    // any other available integers. To maximize sum of min_val, we should
    // give the smallest available integers to these friends.
    // We iterate w in reverse order for w_i > 1 to assign largest max_val first.
    // The largest w_i values will consume more elements from the left.
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_right]; // Max value for this friend
            a_ptr_right--;

            total_happiness += a[a_ptr_left]; // Min value for this friend
            a_ptr_left += (w[i] - 1); // Consume w_i - 1 smallest elements
        }
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl;
        std::cout << std::endl;
    } else {
        // We need to append elements b1, b2, ... such that
        // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

        // Let's try to append two elements.
        // Let b1 = current_xor_sum
        // Let b2 = current_sum + current_xor_sum
        // New XOR sum: X' = current_xor_sum ^ b1 ^ b2
        // X' = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // X' = 0 ^ (current_sum + current_xor_sum)
        // X' = current_sum + current_xor_sum
        //
        // New SUM: S' = current_sum + b1 + b2
        // S' = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // S' = 2 * (current_sum + current_xor_sum)
        //
        // We need S' = 2 * X'
        // 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum)
        // This identity holds.
        // So, we can always append b1 = current_xor_sum and b2 = current_sum + current_xor_sum.
        // These values are non-negative since current_sum and current_xor_sum are non-negative.
        // The maximum value for current_sum is 10^5 * 10^9 = 10^14.
        // The maximum value for current_xor_sum is 2^30 - 1 (approx 10^9).
        // So b2 can be up to 10^14 + 10^9, which fits in long long.

        std::cout << 2 << std::endl;
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << std::endl;
    }
}

