    long long total_steps = 0;
    long long count_a = 0;
    long long MOD = 1e9 + 7;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a' to its left
            // will eventually have to jump over this 'b'.
            // Each 'a' that jumps over this 'b' will contribute
            // 'count_a' steps (for the current 'b' and all 'b's it created).
            // The 'count_a' itself doubles for the next 'b' to its left.
            total_steps = (total_steps + count_a) % MOD;
            count_a = (count_a * 2) % MOD;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to jump over all 'b's to its right.
            // The number of 'b's it needs to jump over is 'count_a'.
            // So, we add 1 to 'count_a' for this 'a' itself, as it
            // represents a potential 'a' that needs to jump.
            count_a = (count_a + 1) % MOD;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
