void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // First pass: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Second pass: Verify if the constructed w can produce s
    std::string s_prime(n, '0'); // This will be the s generated by our candidate w
    for (int i = 0; i < n; ++i) {
        bool is_one = false;
        if (i - x >= 0 && w[i - x] == '1') {
            is_one = true;
        }
        if (i + x < n && w[i + x] == '1') {
            is_one = true;
        }
        if (is_one) {
            s_prime[i] = '1';
        } else {
            s_prime[i] = '0';
        }
    }

    if (s == s_prime) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

