#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_score = 0;
    long long turn = 0; // 0 for Chanek, 1 for Opponent

    while (n > 0) {
        if (turn == 0) { // Chanek's turn
            if (n % 2 == 1) { // N is odd
                chanek_score += 1;
                n -= 1;
            } else { // N is even
                // Option 1: Take 1 coin
                // Remaining N-1. Opponent gets optimal from N-1.
                // Chanek gets 1 + (N-1 - Opponent's optimal from N-1)

                // Option 2: Take N/2 coins
                // Remaining N/2. Opponent gets optimal from N/2.
                // Chanek gets N/2 + (N/2 - Opponent's optimal from N/2)

                // Let's analyze the opponent's optimal play.
                // If N is even, and Chanek takes N/2:
                //   Chanek gets N/2. Remaining N/2.
                //   Opponent faces N/2.
                //   If N/2 is odd, opponent takes 1. Remaining N/2-1.
                //   If N/2 is even, opponent can take N/4 or 1.
                //   This is a recursive structure.

                // Consider the case where N is a power of 2, say N = 2^k.
                // If Chanek takes N/2, remaining N/2 = 2^(k-1).
                // Opponent takes N/4, remaining N/4 = 2^(k-2).
                // ...
                // This continues until 2 coins remain.
                // Chanek takes 1. Opponent takes 1.
                // In this scenario, Chanek gets N/2 + N/8 + N/32 + ...
                // Opponent gets N/4 + N/16 + N/64 + ...
                // Total coins taken by Chanek = N/2 * (1 + 1/4 + 1/16 + ...) = N/2 * (1 / (1 - 1/4)) = N/2 * (4/3) = 2N/3.
                // Total coins taken by Opponent = N/4 * (1 + 1/4 + 1/16 + ...) = N/4 * (4/3) = N/3.
                // This strategy (always taking N/2) seems good for Chanek if N is a power of 2.

                // What if N is even but not a power of 2?
                // N = 6.
                // Chanek's turn.
                //   Option 1: Take 1. Chanek = 1. N = 5.
                //     Opponent's turn. N = 5 (odd). Opponent takes 1. Opponent = 1. N = 4.
                //     Chanek's turn. N = 4 (even).
                //       Chanek can take 1. Chanek = 1+1=2. N = 3.
                //         Opponent's turn. N = 3 (odd). Opponent takes 1. Opponent = 1+1=2. N = 2.
                //         Chanek's turn. N = 2 (even). Chanek can take 1 or 1. Chanek takes 1. Chanek = 2+1=3. N = 1.
                //           Opponent's turn. N = 1 (odd). Opponent takes 1. Opponent = 2+1=3. N = 0.
                //           Result: Chanek = 3, Opponent = 3.
                //       Chanek can take 4/2=2. Chanek = 1+2=3. N = 2.
                //         Opponent's turn. N = 2 (even). Opponent can take 1 or 1. Opponent takes 1. Opponent = 1+1=2. N = 1.
                //         Chanek's turn. N = 1 (odd). Chanek takes 1. Chanek = 3+1=4. N = 0.
                //         Result: Chanek = 4, Opponent = 2.
                //     Chanek chooses to take 2 from N=4. So Chanek gets 1+2=3. Opponent gets 1.
                //     Then Chanek gets 1 from N=2. Total Chanek = 4. Total Opponent = 2.
                //     So if Chanek takes 1 from N=6, Chanek gets 4.

                //   Option 2: Take N/2 = 3. Chanek = 3. N = 3.
                //     Opponent's turn. N = 3 (odd). Opponent takes 1. Opponent = 1. N = 2.
                //     Chanek's turn. N = 2 (even). Chanek can take 1 or 1. Chanek takes 1. Chanek = 3+1=4. N = 1.
                //     Opponent's turn. N = 1 (odd). Opponent takes 1. Opponent = 1+1=2. N = 0.
                //     Result: Chanek = 4, Opponent = 2.

                // In both cases for N=6, Chanek gets 4.

                // The key insight for even N:
                // If N is even, Chanek can choose to take 1 or N/2.
                // If Chanek takes 1, N becomes N-1 (odd). Opponent faces an odd number.
                // If Chanek takes N/2, N becomes N/2. Opponent faces N/2.

                // If N is even, and N is not a power of 2:
                // N = 2^k * M, where M is odd and M > 1.
                // Example: N = 12 = 2^2 * 3.
                // Chanek's turn, N=12.
                //   Option 1: Take 1. Chanek = 1. N = 11.
                //     Opponent faces 11 (odd). Opponent takes 1. Opponent = 1. N = 10.
                //     Chanek faces 10 (even).
                //       Chanek takes 1. Chanek = 1+1=2. N = 9.
                //         Opponent faces 9 (odd). Opponent takes 1. Opponent = 1+1=2. N = 8.
                //         Chanek faces 8 (power of 2). Chanek takes 8/2=4. Chanek = 2+4=6. N = 4.
                //           Opponent faces 4. Opponent takes 4/2=2. Opponent = 2+2=4. N = 2.
                //           Chanek faces 2. Chanek takes 2/2=1. Chanek = 6+1=7. N = 1.
                //             Opponent faces 1. Opponent takes 1. Opponent = 4+1=5. N = 0.
                //             Result: Chanek = 7, Opponent = 5.
                //       Chanek takes 10/2=5. Chanek = 1+5=6. N = 5.
                //         Opponent faces 5 (odd). Opponent takes 1. Opponent = 1+1=2. N = 4.
                //         Chanek faces 4 (power of 2). Chanek takes 4/2=2. Chanek = 6+2=8. N = 2.
                //           Opponent faces 2. Opponent takes 2/2=1. Opponent = 2+1=3. N = 1.
                //           Chanek faces 1. Chanek takes 1. Chanek = 8+1=9. N = 0.
                //           Result: Chanek = 9, Opponent = 3.
                //     Chanek chooses to take 5 from N=10. So Chanek gets 1+5=6. Opponent gets 1.
                //     Then Chanek gets 2 from N=4. Total Chanek = 8. Total Opponent = 3.
                //     Then Chanek gets 1 from N=1. Total Chanek = 9. Total Opponent = 3.
                //     So if Chanek takes 1 from N=12, Chanek gets 9.

                //   Option 2: Take N/2 = 6. Chanek = 6. N = 6.
                //     Opponent faces 6 (even).
                //       Opponent takes 1. Opponent = 1. N = 5.
                //         Chanek faces 5 (odd). Chanek takes 1. Chanek = 6+1=7. N = 4.
                //         Opponent faces 4. Opponent takes 4/2=2. Opponent = 1+2=3. N = 2.
                //           Chanek faces 2. Chanek takes 2/2=1. Chanek = 7+1=8. N = 1.
                //             Opponent faces 1. Opponent takes 1. Opponent = 3+1=4. N = 0.
                //             Result: Chanek = 8, Opponent = 4.
                //       Opponent takes 6/2=3. Opponent = 3. N = 3.
                //         Chanek faces 3 (odd). Chanek takes 1. Chanek = 6+1=7. N = 2.
                //         Opponent faces 2. Opponent takes 2/2=1. Opponent = 3+1=4. N = 1.
                //           Chanek faces 1. Chanek takes 1. Chanek = 7+1=8. N = 0.
                //           Result: Chanek = 8, Opponent = 4.
                //     Opponent chooses to take 1 or 3, both lead to Opponent getting 4.
                //     So if Chanek takes 6 from N=12, Chanek gets 8.

                // Comparing 9 (take 1) vs 8 (take N/2). Chanek chooses 9.

                // It seems if N is even and not a power of 2, taking 1 is better.
                // If N is a power of 2, taking N/2 is better.
                // How to check if N is a power of 2? (N > 0) && ((N & (N - 1)) == 0).

                if ((n & (n - 1)) == 0) { // N is a power of 2
                    chanek_score += n / 2;
                    n /= 2;
                } else { // N is even but not a power of 2
                    chanek_score += 1;
                    n -= 1;
                }
            }
        } else { // Opponent's turn
            if (n % 2 == 1) { // N is odd
                n -= 1; // Opponent takes 1
            } else { // N is even
                if ((n & (n - 1)) == 0) { // N is a power of 2
                    n /= 2; // Opponent takes N/2
                } else { // N is even but not a power of 2
                    n -= 1; // Opponent takes 1
                }
            }
        }
        turn = 1 - turn; // Switch turn
    }
    return chanek_score;
}

