int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int max_count = std::max({count_x, count_y, count_z});
        int min_count = std::min({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequences = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // If the first matryoshka in a chain is 1, it's a potential start of the main sequence.
        // We need to count how many consecutive correct nestings (j -> j+1) exist starting from 1.
        if (chain[0] == 1) {
            int current_expected = 1;
            for (int j = 0; j < m; ++j) {
                if (chain[j] == current_expected) {
                    correct_sequences++;
                    current_expected++;
                } else {
                    // The sequence 1 -> 2 -> ... -> current_expected-1 is correct.
                    // Any further elements in this chain are not part of the initial correct prefix.
                    break; 
                }
            }
        }
    }

    // Total operations needed:
    // 1. Disassemble all incorrect nestings.
    //    Each chain of length `m` has `m-1` nestings.
    //    Total initial nestings = n - k (since sum of m_i = n, and each chain has m_i-1 nestings)
    //    Number of correct nestings (1->2, 2->3, ...) is `correct_sequences - 1`.
    //    So, `(n - k) - (correct_sequences - 1)` nestings need to be undone.
    //    Each undo operation costs 1 second.
    //    This simplifies to `n - k - correct_sequences + 1` operations.
    // 2. Reassemble the final chain.
    //    The final chain `1 -> 2 -> ... -> n` requires `n-1` nestings.
    //    We already have `correct_sequences - 1` of these.
    //    So, `(n-1) - (correct_sequences - 1)` new nestings need to be performed.
    //    Each new nesting operation costs 1 second.
    //    This simplifies to `n - correct_sequences` operations.

    // Total operations = (disassemble incorrect) + (assemble missing correct)
    // Total operations = ( (n - k) - (correct_sequences - 1) ) + ( (n - 1) - (correct_sequences - 1) )
    // Total operations = (n - k - correct_sequences + 1) + (n - correct_sequences)
    // Total operations = n - k - correct_sequences + 1 + n - correct_sequences
    // Total operations = 2*n - k - 2*correct_sequences + 1

    // Let's re-evaluate.
    // We need to form n-1 connections (1->2, 2->3, ..., (n-1)->n).
    // `correct_sequences - 1` of these connections are already present and correct.
    // So, `(n-1) - (correct_sequences - 1)` connections need to be *made*. This is `n - correct_sequences` 'put' operations.

    // For the 'get out' operations:
    // Each chain has `m_i` dolls. If `m_i > 1`, it has `m_i - 1` internal nestings.
    // The total number of initial nestings across all chains is `(m_1-1) + (m_2-1) + ... + (m_k-1) = (m_1+...+m_k) - k = n - k`.
    // Out of these `n-k` initial nestings, `correct_sequences - 1` are part of the final `1->2->...->n` sequence.
    // The remaining `(n-k) - (correct_sequences - 1)` nestings must be undone. These are 'get out' operations.
    // This simplifies to `n - k - correct_sequences + 1` 'get out' operations.

    total_operations = (long long)(n - correct_sequences) + (long long)(n - k - correct_sequences + 1);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>
#include <numeric>

long long solve() {
    long long p, q;
    std::cin >> p >> q;

    if (p % q != 0) {
        return p;
    }

    long long max_x = 1;
    long long temp_q = q;

    // Find prime factors of q
    // Store them as pairs (prime_factor, count)
    std::vector<std::pair<long long, int>> prime_factors_q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            int count = 0;
            while (temp_q % i == 0) {
                temp_q /= i;
                count++;
            }
            prime_factors_q.push_back({i, count});
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back({temp_q, 1});
    }

    for (const auto& factor_pair : prime_factors_q) {
        long long prime_factor = factor_pair.first;
        int count_in_q = factor_pair.second;

        long long current_p = p;
        // Divide p by prime_factor until it's no longer divisible by q
        // This means we need to remove at least one 'prime_factor' from p
        // such that the resulting number is not divisible by q.
        // The smallest number of 'prime_factor's to remove is count_in_q.
        // So, we divide p by prime_factor until its exponent of prime_factor
        // is less than count_in_q.

        // Calculate p' = p / (prime_factor ^ k) such that p' is not divisible by q
        // and p' is maximized.
        // This means we want to remove just enough prime_factor's from p
        // to break its divisibility by q.
        // The number of prime_factor's in p must be reduced below count_in_q.
        // So, we need to divide p by prime_factor at least (exponent_of_prime_factor_in_p - count_in_q + 1) times.

        long long temp_p = p;
        while (temp_p % q == 0) { // While current_p is still divisible by q
            temp_p /= prime_factor;
        }
        max_x = std::max(max_x, temp_p);
    }

    return max_x;
}

