}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (int pivot_digit = 0; pivot_digit <= 9; ++pivot_digit) {
        std::string current_coloring(n, ' ');
        char last_digit_color1 = '0'; // Represents the last digit assigned to color 1
        char first_digit_color2 = '9' + 1; // Represents the first digit assigned to color 2

        bool possible_for_pivot = true;
        for (int i = 0; i < n; ++i) {
            char d = s[i];
            if (d < (pivot_digit + '0')) {
                current_coloring[i] = '1';
                if (d < last_digit_color1) {
                    possible_for_pivot = false;
                    break;
                }
                last_digit_color1 = d;
            } else if (d > (pivot_digit + '0')) {
                current_coloring[i] = '2';
                if (d < first_digit_color2) { // This check is for S2 being non-decreasing
                    first_digit_color2 = d;
                }
            } else { // d == pivot_digit
                // Try to assign to color 2 first, if it maintains non-decreasing S2
                if (d < first_digit_color2) {
                    current_coloring[i] = '2';
                    first_digit_color2 = d;
                } else { // Assign to color 1
                    current_coloring[i] = '1';
                    if (d < last_digit_color1) {
                        possible_for_pivot = false;
                        break;
                    }
                    last_digit_color1 = d;
                }
            }
        }

        if (possible_for_pivot) {
            // Final check: last_digit_color1 <= first_digit_color2
            // If S1 is empty, last_digit_color1 is '0'. If S2 is empty, first_digit_color2 is '9'+1.
            // In these cases, the condition holds.
            if (last_digit_color1 <= first_digit_color2) {
                // One more check: S2 must be non-decreasing.
                // The logic above ensures that digits assigned to color 2 are non-decreasing
                // if they are greater than pivot_digit.
                // For digits equal to pivot_digit, we assign them to color 2 only if they are <= current first_digit_color2.
                // This means first_digit_color2 will be the smallest digit assigned to color 2.
                // We need to verify that all digits assigned to color 2 are non-decreasing.
                // Let's reconstruct S2 and check.
                char prev_s2_digit = '0';
                bool s2_ok = true;
                for(int i=0; i<n; ++i) {
                    if (current_coloring[i] == '2') {
                        if (s[i] < prev_s2_digit) {
                            s2_ok = false;
                            break;
                        }
                        prev_s2_digit = s[i];
                    }
                }

                if (s2_ok) {
                    result = current_coloring;
                    found_solution = true;
                    break; // Found a solution, no need to check other pivots
                }
            }
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Calculate sum_r = sum_{r=1 to b-1} r
    // sum_r = (b-1) * b / 2
    // Since b can be up to 10^7, (b-1)*b can be up to 10^14, which fits in long long.
    // We need to perform division by 2.
    // If b is even, b/2 is integer.
    // If b is odd, (b-1)/2 is integer.
    // (b-1) * b is always even, so (b-1)*b/2 is always an integer.
    // We need to compute this modulo MOD.
    // (X * Y / 2) % MOD = (X % MOD * Y % MOD * inv(2) % MOD) % MOD
    // inv(2) modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004;

    long long sum_r_term1 = (b - 1) % MOD;
    long long sum_r_term2 = b % MOD;
    long long sum_r = (sum_r_term1 * sum_r_term2) % MOD;
    sum_r = (sum_r * inv2) % MOD;

    // Calculate sum_k_b_plus_1 = sum_{k=1 to a} (k * b + 1)
    // sum_k_b_plus_1 = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_{k=1 to a} k = a * (a + 1) / 2
    // sum_{k=1 to a} 1 = a
    // So, sum_k_b_plus_1 = b * a * (a + 1) / 2 + a

    long long sum_k_term1 = a % MOD;
    long long sum_k_term2 = (a + 1) % MOD;
    long long sum_k = (sum_k_term1 * sum_k_term2) % MOD;
    sum_k = (sum_k * inv2) % MOD;

    long long sum_k_b_plus_1_part1 = (b % MOD * sum_k) % MOD;
    long long sum_k_b_plus_1_part2 = a % MOD;
    long long sum_k_b_plus_1 = (sum_k_b_plus_1_part1 + sum_k_b_plus_1_part2) % MOD;

    // Total sum S = sum_r * sum_k_b_plus_1
    long long total_sum = (sum_r * sum_k_b_plus_1) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

