void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_diff = 0; // S - B
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_diff++;
        } else {
            initial_diff--;
        }
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (S - B) for jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (S - B) for jars 2n-k+1 to 2n
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars eaten from the right to achieve a certain diff_R value
    // map: diff_R_value -> count_R_jars_eaten
    std::map<int, int> right_diff_to_count;
    for (int j = 0; j <= n; ++j) {
        int current_diff_R = diff_R[j];
        if (right_diff_to_count.find(current_diff_R) == right_diff_to_count.end()) {
            right_diff_to_count[current_diff_R] = j;
        }
    }

    int min_jars_eaten = 2 * n; // Initialize with max possible

    // Iterate through all possible numbers of jars eaten from the left (i)
    for (int i = 0; i <= n; ++i) {
        int current_diff_L = diff_L[i];
        // The remaining jars (after eating i from left) have a difference of initial_diff - current_diff_L.
        // We need to eat j jars from the right such that the remaining jars have a total difference of 0.
        // This means the difference from the right jars eaten (diff_R[j]) must cancel out the remaining difference.
        // So, initial_diff - current_diff_L - diff_R[j] = 0
        // We need diff_R[j] = initial_diff - current_diff_L
        int target_diff_R = initial_diff - current_diff_L;

        if (right_diff_to_count.count(target_diff_R)) {
            int j = right_diff_to_count[target_diff_R];
            min_jars_eaten = std::min(min_jars_eaten, i + j);
        }
    }

    std::cout << min_jars_eaten << std::endl;
}

