int calculate_score(int n, const std::string& s) {
    if (n == 0) return 0;
    int score = 0;
    bool prev_won = false;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (prev_won) {
                score += 2;
            } else {
                score += 1;
            }
            prev_won = true;
        } else {
            prev_won = false;
        }
    }
    return score;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            if (n == 0) { // Edge case for n=0, though constraints say n>=1
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + 2 * (n - 1) << "\n";
            }
            continue;
        }

        if (initial_wins == 0 && k == 0) { // All L's, no changes
            std::cout << 0 << "\n";
            continue;
        }

        // Find the first and last 'W'
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) first_w = i;
                last_w = i;
            }
        }

        if (first_w == -1) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else { // Change k 'L's to 'W's. Best to make them consecutive.
                std::cout << 1 + 2 * (k - 1) << "\n";
            }
            continue;
        }

        // Calculate initial score
        int current_score = calculate_score(n, s);

        // Gaps between W's
        std::vector<int> gaps;
        int current_gap = 0;
        bool in_gap = false;
        for (int i = first_w + 1; i < last_w; ++i) {
            if (s[i] == 'L') {
                current_gap++;
                in_gap = true;
            } else { // s[i] == 'W'
                if (in_gap) {
                    gaps.push_back(current_gap);
                    current_gap = 0;
                    in_gap = false;
                }
            }
        }
        std::sort(gaps.begin(), gaps.end());

        // Fill gaps
        for (int gap_len : gaps) {
            if (k >= gap_len) {
                k -= gap_len;
                current_score += 2 * gap_len + 1; // Each L becomes W (+1), and it connects two Ws (+1 for each end)
            } else {
                current_score += 2 * k; // Can only fill k L's, each adds 2 points (1 for itself, 1 for connecting)
                k = 0;
                break;
            }
        }

        // Use remaining k to convert L's at ends
        if (k > 0) {
            // Left side
            current_score += std::min(k, first_w) * 2;
            k -= std::min(k, first_w);

            // Right side
            if (k > 0) {
                current_score += std::min(k, n - 1 - last_w) * 2;
            }
        }

        std::cout << current_score << "\n";
    }
    return 0;
}

