    std::vector<bool> active_nodes(n, false);

    // Iterate through the removal sequence in reverse
    // This means we are effectively adding nodes back to the graph
    // and calculating APSP for the graph with these nodes.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
