        active_nodes[k] = true; // Mark node k as active

        // Floyd-Warshall update step:
        // Consider node k as an intermediate node for all pairs of currently active nodes.
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;

                // Path i -> k -> j
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // Also, consider newly active node k as a source/destination
        // for paths through other active nodes.
        // This is crucial for correctness: when k becomes active, it can be an endpoint
        // or an intermediate node. The previous loop handles k as an intermediate.
        // The following loops ensure that paths involving k as an endpoint are also updated
        // using other active nodes as intermediates.
        // This is essentially running Floyd-Warshall on the subgraph of active_nodes,
        // with k being the latest node added.
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;

                // Path i -> (any active node) -> j
                // This is already covered by the triple loop above if we consider
                // the order of k, i, j.
                // The standard Floyd-Warshall structure is:
                // for k_prime (intermediate)
                //   for i_prime (source)
                //     for j_prime (dest)
                //       dist[i_prime][j_prime] = min(dist[i_prime][j_prime], dist[i_prime][k_prime] + dist[k_prime][j_prime])
                // Here, k is the *newest* intermediate node. So we need to update all pairs (i,j)
                // using k as an intermediate.
                // And then, for any pair (i,j) where i or j is k, we need to update paths
                // using other active nodes as intermediates.
                // The triple loop above (i, j, k) effectively does this for the current set of active nodes.
                // The order of loops (k, i, j) is important.
                // The current implementation is:
                // for each new active node `k`:
                //   for each active node `i`:
                //     for each active node `j`:
                //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
                // This correctly updates all paths using `k` as an intermediate.
                // It also implicitly updates paths where `i` or `j` is `k` because `k` is in the set of active nodes.
                // For example, if `i=k`, then `dist[k][j] = min(dist[k][j], dist[k][k] + dist[k][j])` which is `dist[k][j]`.
                // If `i=k`, then `dist[k][j] = min(dist[k][j], dist[k][p] + dist[p][j])` for any other active `p`.
                // This is what the standard Floyd-Warshall does.
                // So, the triple loop above is sufficient.
            }
        }

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ...)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

