#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> b_prime(n, std::numeric_limits<long long>::max()); // b_prime[j] = m_i - delta[j]
    std::vector<long long> current_delta(n, 0);

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b_prime[j] = std::min(b_prime[j], ops[i].val - current_delta[j]);
            }
        }
    }

    std::vector<long long> a_initial(n);
    for (int i = 0; i < n; ++i) {
        if (b_prime[i] == std::numeric_limits<long long>::max()) {
            a_initial[i] = 0; // If no upper bound, set to 0 (or any value within range)
        } else {
            a_initial[i] = b_prime[i];
        }
    }

    // Verify the solution
    std::vector<long long> a_current = a_initial;
    current_delta.assign(n, 0); // Reset current_delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a_current[j] += ops[i].val;
                current_delta[j] += ops[i].val; // Keep track of delta for type 2 checks
            }
        } else { // type 2
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, a_initial[j] + current_delta[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_initial[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

