        // f1 = 1: can move left (x-1). If f1=0, cannot move left, so target X must be >= current x.
        if (f1 == 0) {
            min_x = std::max(min_x, x);
        }
        // f3 = 1: can move right (x+1). If f3=0, cannot move right, so target X must be <= current x.
        if (f3 == 0) {
            max_x = std::min(max_x, x);
        }
        // f4 = 1: can move down (y-1). If f4=0, cannot move down, so target Y must be >= current y.
        if (f4 == 0) {
            min_y = std::max(min_y, y);
        }
        // f2 = 1: can move up (y+1). If f2=0, cannot move up, so target Y must be <= current y.
        if (f2 == 0) {
            max_y = std::min(max_y, y);
        }
    }

    if (min_x <= max_x && min_y <= max_y) {
        // A valid point exists. We can pick any point within the valid range.
        // The problem guarantees that if a point exists, one with coords <= 10^5 abs value exists.
        // Our min_x, min_y could be outside this range if all robots allow movement in one direction.
        // However, the problem statement implies that if a solution exists, we can find one within the given bounds.
        // The bounds for X, Y are -10^5 to 10^5.
        // Let's pick min_x and min_y as the target.
        // We need to ensure the output X, Y are within the guaranteed range.
        // The problem states "Both X and Y should not exceed 10^5 by absolute value; it is guaranteed that if there exists at least one point reachable by all robots, then at least one of such points has both coordinates not exceeding 10^5 by absolute value."
        // This means if min_x > 10^5 or min_x < -10^5, there must be another valid X in [-10^5, 10^5].
        // However, the simplest approach is to just output min_x, min_y.
        // The constraints on x_i, y_i are -10^5 to 10^5.
        // If f1=0 for a robot at x=10^5, then min_x becomes 10^5.
        // If f3=0 for a robot at x=-10^5, then max_x becomes -10^5.
        // So min_x and max_x will naturally be within the range of initial robot coordinates,
        // which is within the [-10^5, 10^5] range.
        // Thus, min_x and min_y will always be within the required output range if a solution exists.
        std::cout << 1 << " " << min_x << " " << min_y << "\n";
    } else {
        std::cout << 0 << "\n";
    }
}

