int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that [l, r] contains a bad triplet.
                                                // Using 1-based indexing for l and r here.
                                                // Initialize with n+1, meaning no such r found yet.

    // Iterate through all possible x and k to find bad triplets (x, x+k, x+2k)
    // x is 0-indexed, k is 1-indexed.
    // The problem uses 1-based indexing for s_x, s_{x+k}, s_{x+2k}.
    // If s_x = s_{x+k} = s_{x+2k} (0-indexed), then the corresponding 1-based indices are x+1, x+k+1, x+2k+1.
    // For a given bad triplet, any range [l, r] such that l <= x+1 and x+2k+1 <= r will satisfy the condition.
    // We are interested in the smallest possible r for a given l.
    // So, for a bad triplet (x, x+k, x+2k), it implies that for any l' from 1 to x+1,
    // the range [l', x+2k+1] is a valid range.
    // This means min_r_for_l[l'] can be at most x+2k+1.

    for (int x = 0; x < n; ++x) {
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k) (0-indexed)
                // The corresponding 1-based indices are x_1 = x+1 and r_1 = x+2k+1.
                // This triplet makes any range [l_val, r_val] valid if l_val <= x_1 and r_1 <= r_val.
                // We want to update min_r_for_l[l_val] with r_1.
                // Since we are iterating x from left to right, and k from small to large,
                // x+2k+1 will be increasing.
                // For a fixed x, as k increases, x+2k+1 increases.
                // For a fixed k, as x increases, x+2k+1 increases.
                // So, the first time we find a bad triplet for a given x, it gives the smallest r_1 for that x.
                // However, we need to update for all l_val <= x+1.
                // The smallest r_1 for a given l_val is what we need.
                // So, for each l_val from 1 to x+1, we can potentially update min_r_for_l[l_val].
                // We take the minimum of current min_r_for_l[l_val] and x+2k+1.

                // The maximum possible value for x+1 is n.
                // The maximum possible value for x+2k+1 is n.

                // The loop for l_val can be optimized.
                // We only need to update min_r_for_l[x+1] with x+2k+1.
                // The propagation for smaller l_val will be handled in the next step.
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], x + 2 * k + 1);
            }
        }
    }

    // Propagate minimum r values:
    // If min_r_for_l[l] is R, then for any l' < l, min_r_for_l[l'] must be <= R.
    // This is because if [l, R] contains a bad triplet, then [l', R] also contains it.
    // So, min_r_for_l[l] = min(min_r_for_l[l], min_r_for_l[l+1]).
    // We iterate from n-1 down to 1.
    for (int l = n - 1; l >= 1; --l) {
        min_r_for_l[l] = std::min(min_r_for_l[l], min_r_for_l[l + 1]);
    }

    long long total_count = 0;
    for (int l = 1; l <= n; ++l) {
        if (min_r_for_l[l] <= n) { // If there is at least one valid r for this l
            // All r from min_r_for_l[l] to n are valid for this l.
            // Number of such r values is n - min_r_for_l[l] + 1.
            total_count += (n - min_r_for_l[l] + 1);
        }
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <list>

struct Child {
    long long v, d, p;
    int original_idx;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::list<Child> children_list;
    for (int i = 0; i < n; ++i) {
        long long v_val, d_val, p_val;
        std::cin >> v_val >> d_val >> p_val;
        children_list.push_back({v_val, d_val, p_val, i + 1});
    }

    std::vector<int> cured_children_indices;

    while (!children_list.empty()) {
        Child current_child = children_list.front();
        children_list.pop_front();
        cured_children_indices.push_back(current_child.original_idx);

        long long current_v = current_child.v;
        long long total_d_from_runaways = 0;

        auto it = children_list.begin();
        while (it != children_list.end()) {
            // Apply current_v effect
            if (current_v > 0) {
                it->p -= current_v;
                current_v--;
            }

            // Apply total_d_from_runaways effect
            it->p -= total_d_from_runaways;

            if (it->p < 0) {
                total_d_from_runaways += it->d;
                it = children_list.erase(it); // Child runs away
            } else {
                ++it;
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

