int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0;
    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        }
    }

    // To form 'one', we need one 'o', one 'n', one 'e'.
    // The number of '1's we can form is limited by the minimum of these counts.
    // However, 'o' and 'e' are also used by 'zero'.
    // To maximize the number, we want to prioritize '1's.
    // The unique character for 'one' is 'n'.
    // The unique character for 'zero' is 'z'.

    // Count of '1's is limited by 'n'.
    int num_ones = count_n;

    // After forming 'num_ones' 'one's, we use up 'num_ones' 'o's and 'num_ones' 'e's.
    // The remaining 'o's and 'e's, along with 'z' and 'r', can form 'zero's.
    // Count of '0's is limited by 'z'.
    int num_zeros = count_z;

    // Print all '1's first
    bool first_digit = true;
    for (int i = 0; i < num_ones; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 1;
        first_digit = false;
    }

    // Then print all '0's
    for (int i = 0; i < num_zeros; ++i) {
        if (!first_digit) {
            std::cout << " ";
        }
        std::cout << 0;
        first_digit = false;
    }
    std::cout << std::endl;

    return 0;
}

