            }
        } else { // If 360 is not divisible by n, then 360/n is not an integer.
                 // We need to check if 90 is a multiple of (360/n) * some_integer_k.
                 // This simplifies to checking if n is a multiple of 4.
                 // The condition is that there exists an integer k such that
                 // k * (360/n) is a multiple of 90.
                 // k * 360 / n = 90 * m
                 // k * 4 / n = m
                 // This means n must divide 4k.
                 // For this to be possible, n must be a divisor of 4 * LCM(1, 2, ..., n-1)
                 // More simply, if n is a multiple of 4, say n = 4j, then
                 // k * 4 / (4j) = k / j = m. We can choose k=j, then m=1.
                 // This means the angle k * 360/n = j * 360 / (4j) = 360/4 = 90 degrees.
                 // So, if n is a multiple of 4, it's always possible.
            if (n % 4 == 0) {
                std::cout << "YES\n";
            } else {
                std::cout << "NO\n";
            }
        }
    }
    return 0;
}

#include <iostream>
