#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        long long min_val = k + 1; // Initialize with a value larger than any possible a_i
        int min_idx = -1;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] < min_val) {
                min_val = a[i];
                min_idx = i;
            }
        }

        long long operations = 0;
        for (int i = 0; i < n; ++i) {
            if (i == min_idx) {
                continue; // Cannot copy a pile into itself
            }
            // For each other pile a[i], we can add min_val to it as many times as possible
            // without exceeding k.
            // The number of times is floor((k - a[i]) / min_val)
            if (a[i] < k) { // Only if a[i] itself is not already k or more
                operations += (k - a[i]) / min_val;
            }
        }
        std::cout << operations << "\n";
    }
    return 0;
}

