#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<std::vector<int>> a(n, std::vector<int>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> a[i][j];
        }
    }

    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        int max_val_in_row = 0;
        for (int j = 0; j < n; ++j) {
            if (i == j) continue;
            if (a[i][j] > max_val_in_row) {
                max_val_in_row = a[i][j];
            }
        }
        // If max_val_in_row is n-1, it means p[i] must be n.
        // Otherwise, p[i] is max_val_in_row.
        // This logic is based on the observation that if p[i] is not n,
        // then there exists some p[k]=n, and a[i][k] = min(p[i], p[k]) = p[i].
        // This p[i] would be the maximum value in row i if p[i] < n.
        // If p[i] = n, then all a[i][j] (j!=i) are p[j], and the max of these is n-1.
        if (max_val_in_row == n - 1) {
            p[i] = n;
        } else {
            p[i] = max_val_in_row;
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());

        // The problem asks for the minimum absolute difference between medians.
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the partition where one class takes the first n elements
        // and the other class takes the last n elements.
        //
        // Class 1: a_0, a_1, ..., a_{n-1}
        // Class 2: a_n, a_{n+1}, ..., a_{2n-1}
        //
        // Both classes have size n.
        // If n is odd, then both classes have odd sizes.
        // The median of Class 1 would be a_{(n-1)/2}.
        // The median of Class 2 would be a_{n + (n-1)/2}.
        //
        // If n is even, this partition is not valid because class sizes are even.
        //
        // However, the problem statement implies that we can always find a partition
        // where both classes have odd sizes.
        //
        // Let's re-read the median definition: for an array of 2k+1 elements,
        // the median is b_{k+1} (1-indexed) after sorting.
        // This means it's the element at index k (0-indexed).
        // For a class of size S, the median is at index (S-1)/2.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        //
        // If we split the array into two halves:
        // Class 1: a_0, ..., a_{n-1}
        // Class 2: a_n, ..., a_{2n-1}
        //
        // Each class has n elements.
        // If n is odd, then the median of Class 1 is a_{(n-1)/2}.
        // The median of Class 2 is a_{n + (n-1)/2}.
        // The difference would be a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // If n is even, this split is not valid because class sizes are even.
        //
        // The key insight is that to minimize the difference between medians,
        // the medians themselves should be as close as possible in the sorted full array.
        //
        // Let the two classes be $C_1$ and $C_2$.
        // Let $|C_1| = S_1$ and $|C_2| = S_2$.
        // $S_1, S_2$ must be odd. $S_1 + S_2 = 2n$.
        //
        // The smallest possible median for any class is $a_0$ (if $S_1=1$, median is $a_0$).
        // The largest possible median for any class is $a_{2n-1}$ (if $S_1=1$, median is $a_{2n-1}$).
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // Can we always make $a_{n-1}$ the median of one class and $a_n$ the median of another class?
        //
        // If we pick $a_{n-1}$ as the median of $C_1$, then $C_1$ must contain $a_{n-1}$
        // and have $(S_1-1)/2$ elements smaller than or equal to $a_{n-1}$
        // and $(S_1-1)/2$ elements greater than or equal to $a_{n-1}$.
        //
        // If we pick $a_n$ as the median of $C_2$, then $C_2$ must contain $a_n$
        // and have $(S_2-1)/2$ elements smaller than or equal to $a_n$
        // and $(S_2-1)/2$ elements greater than or equal to $a_n$.
        //
        // The minimum possible difference is achieved when the two medians are $a_{n-1}$ and $a_n$.
        //
        // Let's try to construct such a partition.
        // We need to form two classes $C_1$ and $C_2$ with odd sizes $S_1, S_2$ such that $S_1+S_2=2n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // If we make $a_{n-1}$ the median of $C_1$ and $a_n$ the median of $C_2$.
        //
        // For $C_1$ to have $a_{n-1}$ as its median, it must have $(S_1-1)/2$ elements from $a_0, \dots, a_{n-2}$
        // and $(S_1-1)/2$ elements from $a_n, \dots, a_{2n-1}$ (or $a_n, \dots, a_{2n-1}$ if $a_{n-1}$ is not unique).
        //
        // The simplest partition that guarantees odd sizes and uses elements around the middle:
        // Class 1: $a_0, a_1, \dots, a_{n-1}$
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$
        //
        // Each class has $n$ students.
        // If $n$ is odd, this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        //
        // Example 1: n=1, 2n=2. a = [1, 1].
        // n is odd.
        // Class 1: [a_0] = [1]. Median = a_0 = 1.
        // Class 2: [a_1] = [1]. Median = a_1 = 1.
        // Difference = |1-1| = 0.
        // Formula: a_{1 + (1-1)/2} - a_{(1-1)/2} = a_1 - a_0 = 1 - 1 = 0. Correct.
        //
        // Example 2: n=3, 2n=6. a = [1, 2, 3, 4, 5, 6].
        // n is odd.
        // Class 1: [a_0, a_1, a_2] = [1, 2, 3]. Median = a_{(3-1)/2} = a_1 = 2.
        // Class 2: [a_3, a_4, a_5] = [4, 5, 6]. Median = a_{3 + (3-1)/2} = a_{3+1} = a_4 = 5.
        // Difference = |5-2| = 3.
        // The example output is 1. This means my simple partition is not optimal.
        //
        // The example output for n=3, a=[1,2,3,4,5,6] is 1.
        // One possible partition: C1=[6,4,2], median=4. C2=[5,1,3], median=3. Diff=|4-3|=1.
        // Sorted: C1_sorted=[2,4,6], median=4. C2_sorted=[1,3,5], median=3.
        //
        // This means the medians are not necessarily $a_{(n-1)/2}$ and $a_{n+(n-1)/2}$.
        //
        // The crucial observation is that to minimize the difference between medians,
        // the medians themselves must be adjacent in the sorted full array.
        //
        // Consider the elements $a_{n-1}$ and $a_n$.
        // If we can make $a_{n-1}$ the median of one class and $a_n$ the median of the other class,
        // then the difference would be $a_n - a_{n-1}$.
        //
        // Let's try to prove that $a_n - a_{n-1}$ is the minimum possible difference.
        //
        // Let $m_1$ be the median of $C_1$ and $m_2$ be the median of $C_2$.
        // Assume $m_1 \le m_2$. We want to minimize $m_2 - m_1$.
        //
        // $m_1$ is an element from $a$. $m_2$ is an element from $a$.
        //
        // For $m_1$ to be the median of $C_1$ (size $S_1$), there must be $(S_1-1)/2$ elements in $C_1$
        // that are less than or equal to $m_1$, and $(S_1-1)/2$ elements greater than or equal to $m_1$.
        //
        // For $m_2$ to be the median of $C_2$ (size $S_2$), there must be $(S_2-1)/2$ elements in $C_2$
        // that are less than or equal to $m_2$, and $(S_2-1)/2$ elements greater than or equal to $m_2$.
        //
        // Total elements less than or equal to $m_1$ in $C_1$ is $(S_1-1)/2 + 1 = (S_1+1)/2$.
        // Total elements greater than or equal to $m_2$ in $C_2$ is $(S_2-1)/2 + 1 = (S_2+1)/2$.
        //
        // The total number of elements in $a$ that are less than or equal to $m_1$ is at least $(S_1+1)/2$.
        // The total number of elements in $a$ that are greater than or equal to $m_2$ is at least $(S_2+1)/2$.
        //
        // Since $C_1$ and $C_2$ are disjoint, the elements counted for $m_1$ and $m_2$ must be distinct.
        //
        // The number of elements in $a$ that are $\le m_1$ is at least $(S_1+1)/2$.
        // The number of elements in $a$ that are $\ge m_2$ is at least $(S_2+1)/2$.
        //
        // The total number of elements in $a$ is $2n$.
        // The number of elements in $a$ that are $\le m_1$ is $idx(m_1)+1$ (if $m_1$ is $a_{idx(m_1)}$).
        // The number of elements in $a$ that are $\ge m_2$ is $2n - idx(m_2)$.
        //
        // So, $idx(m_1)+1 \ge (S_1+1)/2$.
        // And $2n - idx(m_2) \ge (S_2+1)/2$.
        //
        // Summing these:
        // $idx(m_1)+1 + 2n - idx(m_2) \ge (S_1+1)/2 + (S_2+1)/2 = (S_1+S_2+2)/2 = (2n+2)/2 = n+1$.
        // $idx(m_1) - idx(m_2) + 2n + 1 \ge n+1$.
        // $idx(m_1) - idx(m_2) \ge -n$.
        // $idx(m_2) - idx(m_1) \le n$.
        //
        // This doesn't directly lead to $a_n - a_{n-1}$.
        //
        // Let's consider the indices.
        // $m_1$ is the median of $C_1$. $m_2$ is the median of $C_2$.
        // Let $m_1 = a_i$ and $m_2 = a_j$. We want to minimize $a_j - a_i$.
        //
        // For $a_i$ to be a median of a class of size $S_1$, there must be at least $(S_1-1)/2$ elements
        // with index less than $i$ and at least $(S_1-1)/2$ elements with index greater than $i$
        // (considering distinct values, or just counts of elements).
        //
        // The elements $a_0, \dots, a_{i-1}$ are available for the "left" part of $C_1$.
        // The elements $a_{i+1}, \dots, a_{2n-1}$ are available for the "right" part of $C_1$.
        //
        // The total number of elements available for the left part of $C_1$ is $i$.
        // The total number of elements available for the right part of $C_1$ is $2n-1-i$.
        //
        // So, $i \ge (S_1-1)/2$ and $2n-1-i \ge (S_1-1)/2$.
        // This implies $S_1-1 \le 2i$ and $S_1-1 \le 2(2n-1-i)$.
        // $S_1 \le 2i+1$ and $S_1 \le 2(2n-1-i)+1$.
        //
        // Similarly for $a_j$ as median of $C_2$ (size $S_2$):
        // $j \ge (S_2-1)/2$ and $2n-1-j \ge (S_2-1)/2$.
        // $S_2 \le 2j+1$ and $S_2 \le 2(2n-1-j)+1$.
        //
        // Summing the minimum number of elements required for the left parts of $C_1$ and $C_2$:
        // $(S_1-1)/2 + (S_2-1)/2 = (S_1+S_2-2)/2 = (2n-2)/2 = n-1$.
        // These $n-1$ elements must come from $a_0, \dots, a_{j-1}$ (assuming $i < j$).
        // So, $j \ge n-1$.
        //
        // Summing the minimum number of elements required for the right parts of $C_1$ and $C_2$:
        // $(S_1-1)/2 + (S_2-1)/2 = n-1$.
        // These $n-1$ elements must come from $a_{i+1}, \dots, a_{2n-1}$.
        // So, $2n-1-i \ge n-1 \implies 2n-i \ge n \implies n \ge i$.
        //
        // So we have $i \le n$ and $j \ge n-1$.
        // Since $i < j$ (assuming $m_1 < m_2$), the smallest possible $j$ is $n-1$ and largest possible $i$ is $n$.
        // This means $i$ can be at most $n-1$ and $j$ can be at least $n$.
        //
        // The smallest possible difference $a_j - a_i$ occurs when $j$ is minimized and $i$ is maximized.
        // This implies $i = n-1$ and $j = n$.
        //
        // So the minimum difference is $a_n - a_{n-1}$.
        //
        // Let's verify if we can always construct a partition where $a_{n-1}$ and $a_n$ are medians.
        //
        // We need to form two classes $C_1$ and $C_2$ with odd sizes $S_1, S_2$ such that $S_1+S_2=2n$.
        // Let $a_{n-1}$ be the median of $C_1$ and $a_n$ be the median of $C_2$.
        //
        // Consider $C_1 = \{a_0, a_1, \dots, a_{n-1}\}$ and $C_2 = \{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // Each class has $n$ elements.
        // If $n$ is odd, this is a valid partition.
        // Median of $C_1$ is $a_{(n-1)/2}$. Median of $C_2$ is $a_{n+(n-1)/2}$.
        // This is not $a_{n-1}$ and $a_n$.
        //
        // The problem is simpler than that.
        // The minimum difference between medians will always be $a_n - a_{n-1}$.
        //
        // Let's try to construct a partition for $a_{n-1}$ and $a_n$ to be medians.
        //
        // Class 1: $a_{n-1}$ is the median.
        // Class 2: $a_n$ is the median.
        //
        // We need to pick $(S_1-1)/2$ elements smaller than $a_{n-1}$ for $C_1$.
        // We need to pick $(S_1-1)/2$ elements larger than $a_{n-1}$ for $C_1$.
        // We need to pick $(S_2-1)/2$ elements smaller than $a_n$ for $C_2$.
        // We need to pick $(S_2-1)/2$ elements larger than $a_n$ for $C_2$.
        //
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        // $2k_1+1 + 2k_2+1 = 2n \implies 2k_1+2k_2+2 = 2n \implies k_1+k_2+1 = n$.
        //
        // For $C_1$: $a_{n-1}$ is median. We need $k_1$ elements from $a_0, \dots, a_{n-2}$
        // and $k_1$ elements from $a_n, \dots, a_{2n-1}$.
        // For $C_2$: $a_n$ is median. We need $k_2$ elements from $a_0, \dots, a_{n-1}$
        // and $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // This is a bit complex.
        //
        // The simplest way to ensure $a_{n-1}$ and $a_n$ are medians is to make $C_1$ and $C_2$
        // as small as possible, i.e., size 1.
        // If $n=1$, $2n=2$. $a_0, a_1$. $a_{n-1}=a_0$, $a_n=a_1$.
        // $C_1=\{a_0\}$, $C_2=\{a_1\}$. Both size 1 (odd). Medians are $a_0, a_1$. Diff $a_1-a_0$.
        // This works for $n=1$.
        //
        // For $n > 1$, we need $S_1, S_2$ to be odd and sum to $2n$.
        //
        // Consider the elements $a_0, \dots, a_{n-1}$ and $a_n, \dots, a_{2n-1}$.
        //
        // The minimum possible median for any class is $a_0$.
        // The maximum possible median for any class is $a_{2n-1}$.
        //
        // The key is that the $n$-th element ($a_{n-1}$ in 0-indexed) and the $(n+1)$-th element ($a_n$ in 0-indexed)
        // are the "middle" two elements of the entire sorted array.
        //
        // If we pick $a_{n-1}$ as the median of one class ($C_1$) and $a_n$ as the median of the other class ($C_2$),
        // we need to show that this is always possible.
        //
        // Let $C_1$ consist of $a_{n-1}$ and $k_1$ elements from $a_0, \dots, a_{n-2}$
        // and $k_1$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        // Let $C_2$ consist of $a_n$ and $k_2$ elements from $a_0, \dots, a_{n-2}$
        // and $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // This is not quite right. The elements must be partitioned.
        //
        // Let's try to construct a partition for $a_n - a_{n-1}$.
        //
        // Class 1: $a_0, a_1, \dots, a_{n-1}$. This class has $n$ elements.
        // Class 2: $a_n, a_{n+1}, \dots, a_{2n-1}$. This class has $n$ elements.
        //
        // If $n$ is odd, then this is a valid partition.
        // Median of Class 1 is $a_{(n-1)/2}$.
        // Median of Class 2 is $a_{n + (n-1)/2}$.
        // The difference is $a_{n + (n-1)/2} - a_{(n-1)/2}$.
        //
        // If $n$ is even, this partition is not valid.
        //
        // The problem statement implies that the minimum difference is always $a_n - a_{n-1}$.
        // This is a common pattern in competitive programming problems involving medians and partitions.
        //
        // Let's assume $a_{n-1}$ is the median of $C_1$ and $a_n$ is the median of $C_2$.
        //
        // We need to assign $n-1$ elements to the left of $a_{n-1}$ in $C_1$ and $C_2$ combined.
        // We need to assign $n-1$ elements to the right of $a_n$ in $C_1$ and $C_2$ combined.
        //
        // Let $S_1 = 2k_1+1$ and $S_2 = 2k_2+1$.
        // $k_1+k_2 = n-1$.
        //
        // We can assign $a_{n-1}$ to $C_1$ and $a_n$ to $C_2$.
        //
        // For $C_1$: take $a_{n-1}$. Take $k_1$ elements from $a_0, \dots, a_{n-2}$.
        // Take $k_1$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // For $C_2$: take $a_n$. Take $k_2$ elements from $a_0, \dots, a_{n-2}$.
        // Take $k_2$ elements from $a_{n+1}, \dots, a_{2n-1}$.
        //
        // This is not a partition. Elements must be unique.
        //
        // The actual construction is:
        // Let $C_1$ take $a_{n-1}$ as its median.
        // Let $C_2$ take $a_n$ as its median.
        //
        // We need to select $k_1$ elements smaller than $a_{n-1}$ for $C_1$.
        // We need to select $k_1$ elements larger than $a_{n-1}$ for $C_1$.
        // We need to select $k_2$ elements smaller than $a_n$ for $C_2$.
        // We need to select $k_2$ elements larger than $a_n$ for $C_2$.
        //
        // The elements $a_0, \dots, a_{n-2}$ are $n-1$ elements smaller than $a_{n-1}$.
        // The elements $a_{n+1}, \dots, a_{2n-1}$ are $n-1$ elements larger than $a_n$.
        //
        // We can form $C_1$ with $a_{n-1}$ as median and $C_2$ with $a_n$ as median.
        //
        // Let $C_1$ be $\{a_0, a_1, \dots, a_{n-1}\}$ and $C_2$ be $\{a_n, a_{n+1}, \dots, a_{2n-1}\}$.
        // This is the partition that gives $a_{n + (n-1)/2} - a_{(n-1)/2}$ if $n$ is odd.
        //
        // The problem is simpler: the minimum difference is always $a_n - a_{n-1}$.
        // This is because any class of odd size $S$ must have its median $m$ such that there are $(S-1)/2$ elements
        // smaller than or equal to $m$ and $(S-1)/2$ elements greater than or equal to $m$.
        //
        // If we have two classes $C_1$ and $C_2$ with medians $m_1$ and $m_2$ respectively.
        // Let $m_1 = a_i$ and $m_2 = a_j$ with $i < j$.
        //
        // For $a_i$ to be a median of $C_1$, $C_1$ must contain $a_i$.
        // It must also contain $k_1$ elements $\le a_i$ and $k_1$ elements $\ge a_i$.
        // The elements $a_0, \dots, a_{i-1}$ are available for the "left" part of $C_1$.
        // The elements $a_{i+1}, \dots, a_{2n-1}$ are available for the "right" part of $C_1$.
        //
        // For $a_j$ to be a median of $C_2$, $C_2$ must contain $a_j$.
        // It must also contain $k_2$ elements $\le a_j$ and $k_2$ elements $\ge a_j$.
        // The elements $a_0, \dots, a_{j-1}$ are available for the "left" part of $C_2$.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are available for the "right" part of $C_2$.
        //
        // The total number of elements $a_0, \dots, a_{i-1}$ is $i$.
        // The total number of elements $a_{j+1}, \dots, a_{2n-1}$ is $2n-1-j$.
        //
        // The total number of elements that must be $\le m_1$ or $\le m_2$ is $k_1+k_2$.
        // The total number of elements that must be $\ge m_1$ or $\ge m_2$ is $k_1+k_2$.
        //
        // $k_1+k_2 = n-1$.
        //
        // The elements $a_0, \dots, a_{i-1}$ must provide some of the $k_1$ elements for $C_1$ and some of the $k_2$ elements for $C_2$.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ must provide some of the $k_1$ elements for $C_1$ and some of the $k_2$ elements for $C_2$.
        //
        // The elements $a_0, \dots, a_{i-1}$ are $i$ elements.
        // The elements $a_{i+1}, \dots, a_{j-1}$ are $j-1-i$ elements.
        // The elements $a_{j+1}, \dots, a_{2n-1}$ are $2n-1-j$ elements.
        //
        // $C_1$ needs $k_1$ elements from $a_0, \dots, a_{i-1}$ and $k_1$ elements from $a_{i+1}, \dots, a_{2n-1}$.
        // $C_2$ needs $k_2$ elements from $a_0, \dots, a_{j-1}$ and $k_2$ elements from $a_{j+1}, \dots, a_{2n-1}$.
        //
        // The total number of elements strictly less than $a_i$ is $i$.
        // The total number of elements strictly greater than $a_j$ is $2n-1-j$.
        //
        // For $C_1$, we need $k_1$ elements from $a_0, \dots, a_{i-1}$ and $k_1$ elements from $a_{i+1}, \dots, a_{2n-1}$.
        // For $C_2$, we need $k_2$ elements from $a_0, \dots, a_{j-1}$ and $k_2$ elements from $a_{j+1}, \dots, a_{2n-1}$.
        //
        // The total number of elements to the left of $a_i$ and $a_j$ (excluding $a_i, a_j$) is $i + (j-1-i) = j-1$.
        // These must supply $k_1$ elements for $C_1$ and $k_2$ elements for $C_2$.
        // So $j-1 \ge k_1+k_2 = n-1$. This implies $j \ge n$.
        //
        // The total number of elements to the right of $a_i$ and $a_j$ (excluding $a_i, a_j$) is $(j-1-i) + (2n-1-j) = 2n-2-i$.
        // These must supply $k_1$ elements for $C_1$ and $k_2$ elements for $C_2$.
        // So $2n-2-i \ge k_1+k_2 = n-1$. This implies $2n-2-i \ge n-1 \implies n-1 \ge i$.
        //
        // So we have $i \le n-1$ and $j \ge n$.
        // To minimize $a_j - a_i$, we should choose the smallest possible $j$ and largest possible $i$.
        // This means $i = n-1$ and $j = n$.
        //
        // Thus, the minimum difference is $a_n - a_{n-1}$.
        //
        // This logic holds regardless of the specific odd sizes $S_1, S_2$ as long as $S_1+S_2=2n$.
        // The existence of such a partition is guaranteed by the problem statement (it asks for the minimum possible difference, implying it's always possible).
        //
        // The answer is $a[n] - a[n-1]$ (using 0-indexed array `a`).

        std::cout << a[n] - a[n-1] << "\n";
    }
    return 0;
}

#include <iostream>
