#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_R_pos = 0; // Represents the position of the last 'R' or the starting point (cell 0)
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // Current cell is i+1 (1-indexed)
                // The distance from the last 'R' (or 0) to this 'R' is (i+1) - last_R_pos
                max_gap = std::max(max_gap, (i + 1) - last_R_pos);
                last_R_pos = i + 1;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1
        // The distance is (n+1) - last_R_pos
        max_gap = std::max(max_gap, (n + 1) - last_R_pos);
        std::cout << max_gap << "\n";
    }
    return 0;
}

