int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // Total sticks needed: k for torches + k*y for k coal
        // We start with 1 stick, so we need to acquire (k*y + k - 1) additional sticks.
        // Each trade of type 1 (1 stick -> x sticks) gives a net gain of (x - 1) sticks.
        // Number of type 1 trades = ceil((k*y + k - 1) / (x - 1))
        // Using integer division: ((k*y + k - 1) + (x - 1) - 1) / (x - 1)
        // Or, more simply, (k*y + k - 1) / (x - 1) + 1 if (k*y + k - 1) is not 0.
        // Let's calculate total sticks required for crafting and buying coal.
        long long total_sticks_for_coal = k * y;
        long long total_sticks_needed = total_sticks_for_coal + k; // k for coal + k for torches

        // We start with 1 stick. So we need to acquire (total_sticks_needed - 1) more sticks.
        long long sticks_to_gain = total_sticks_needed - 1;

        // Each trade of type 1 (1 stick for x sticks) gives a net gain of (x - 1) sticks.
        // Number of trades to get these sticks:
        long long num_stick_gain_trades = (sticks_to_gain + (x - 1) - 1) / (x - 1);

        // Total trades = trades to gain sticks + trades to buy coal
        // Trades to buy coal = k (since 1 coal per trade)
        long long total_trades = num_stick_gain_trades + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(p[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is strictly greater than q_{i-1}, then p_i must be q_i.
            // Otherwise, max(q_{i-1}, p_i) would not be q_i.
            p[i] = q[i];
            if (used_numbers.count(p[i])) {
                // q_i is already used, which means it appeared as some p_j where j < i.
                // This is impossible because q_i must be distinct from previous p_j values
                // if it's a new maximum.
                possible = false;
                break;
            }
            used_numbers.insert(p[i]);
        } else {
            // If q_i == q_{i-1}, then p_i must be <= q_{i-1}.
            // We need to pick the smallest available number that is not yet used
            // and is less than or equal to q_i (which is q_{i-1}).
            // To maximize chances of finding a solution, we should pick the smallest
            // available number that satisfies the condition.
            p[i] = -1; // Placeholder for now
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Collect all numbers from 1 to n that have not been used yet
    std::vector<int> available_numbers;
    for (int i = 1; i <= n; ++i) {
        if (!used_numbers.count(i)) {
            available_numbers.push_back(i);
        }
    }
    std::sort(available_numbers.rbegin(), available_numbers.rend()); // Sort in descending order for easy pop_back

    // Fill in the p_i values where q_i == q_{i-1}
    for (int i = 1; i < n; ++i) {
        if (q[i] == q[i-1]) {
            if (available_numbers.empty()) {
                possible = false; // No available numbers left
                break;
            }
            int val_to_assign = available_numbers.back();
            available_numbers.pop_back();

            if (val_to_assign > q[i]) {
                // The smallest available number is greater than q_i.
                // This means p_i would be greater than q_i, which contradicts q_i = max(..., p_i).
                possible = false;
                break;
            }
            p[i] = val_to_assign;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

