    int low = 1;
    int high = k + 1; // The largest number used to generate the first k distinct differences

    for (int i = 0; i <= k; ++i) {
        if (i % 2 == 0) { // Even index (0-based) means we print from low
            std::cout << low++;
        } else { // Odd index means we print from high
            std::cout << high--;
        }
        if (i < n - 1) {
            std::cout << " ";
        }
    }

    // After generating k+1 numbers, we have used numbers from 1 to k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // We can append them in increasing order to ensure the new differences are 1.
    // The differences generated so far are k, k-1, ..., 1.
    // Appending k+2, k+3, ... n will create differences of 1.
    // Since 1 is already in our set of k distinct differences, no new distinct differences are added.
    for (int i = k + 2; i <= n; ++i) {
        std::cout << " " << i;
    }
    std::cout << std::endl;

    return 0;
}

