    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of a non-decreasing suffix
    // This is the first element from the right that breaks the non-decreasing order
    // i.e., a[i] > a[i+1]
    int i = n - 1;
    while (i > 0 && a[i-1] <= a[i]) {
        i--;
    }
    // Now a[i...n-1] is non-decreasing.
    // If i is 0, the whole array is non-decreasing.

    // From this point i, we need to find the rightmost valley of a non-increasing suffix
    // This is the first element from the right that breaks the non-increasing order
    // i.e., a[j] < a[j+1]
    int j = i;
    while (j > 0 && a[j-1] >= a[j]) {
        j--;
    }
    // Now a[j...i-1] is non-increasing (if i > j).
    // The suffix a[j...n-1] is of the form non-increasing then non-decreasing.

    std::cout << j << std::endl;
}

