#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int min_idx = pos[1];
    int max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, min_idx and max_idx are already set to pos[1].
        // The segment is [p[pos[1]]], which is [1]. Length is 1. Min is 1, Max is 1.
        // So m=1 is always beautiful.

        // For m > 1, we need to expand the current segment [min_idx, max_idx]
        // to include 'm'.
        // The number 'm' is at pos[m].
        // To include 'm', the new segment must span from min(current_min_idx, pos[m])
        // to max(current_max_idx, pos[m]).
        min_idx = std::min(min_idx, pos[m]);
        max_idx = std::max(max_idx, pos[m]);

        // The length of the current segment is max_idx - min_idx + 1.
        // The minimum value in this segment is 1 (because we started with 1 and expanded).
        // The maximum value in this segment is m (because we expanded to include m,
        // and all numbers 1 to m-1 were already included).
        // For this segment to be a permutation of 1...m, its length must be m.
        if (max_idx - min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << std::endl;
}

