    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will find the maximum k for a given i

    for (int i = 0; i < n; ++i) {
        // For a fixed x[i], we need to find all x[k] such that x[k] - x[i] <= d.
        // Since x is sorted, we can advance right_ptr.
        // right_ptr will always be >= i.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, x[right_ptr-1] is the largest x_k that satisfies the condition.
        // All points from x[i+1] to x[right_ptr-1] can be x_j or x_k.

        // The number of points available to choose from for x_j and x_k
        // (excluding x[i] itself) is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 distinct points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        // Ensure m is non-negative.
        long long m = right_ptr - 1 - i;
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

