int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_stair_cost = 1; // Cost for n=1 staircase
        long long current_stair_n = 1;
        while (x >= current_stair_cost) {
            count++;
            x -= current_stair_cost;

            // Calculate cost for the next staircase in the sequence:
            // If current_stair_n is k, the next one is 2k+1.
            // The cost for a staircase with m stairs is m*(m+1)/2.
            // The cost for a nice staircase with m stairs is 2*m*(m+1)/2 - m = m*(m+1) - m = m^2.
            // No, this is wrong. The problem states the cost is sum of 1..n.
            // The nice staircase sequence is 1, 3, 7, 15, ... which is 2^k - 1.
            // Let's re-evaluate the cost for these specific nice staircases.
            // n=1: cost = 1*(1+1)/2 = 1.
            // n=3: cost = 3*(3+1)/2 = 6.
            // n=7: cost = 7*(7+1)/2 = 28.
            // n=15: cost = 15*(15+1)/2 = 120.
            // The sequence of costs is 1, 6, 28, 120, ...
            // This is (2^k - 1) * (2^k) / 2.
            // Let m = 2^k - 1. Then the cost is m * (m+1) / 2.
            // The next m is 2*current_stair_n + 1.

            current_stair_n = 2 * current_stair_n + 1;
            current_stair_cost = current_stair_n * (current_stair_n + 1) / 2;
        }
        std::cout << count << "\n";
    }
    return 0;
}

