#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

// Function to check if a box can be the special box
// Parameters:
// initial_A, initial_B, initial_C, initial_D: initial counts in boxes 1, 2, 3, 4
// target_box: the box we are checking (1, 2, 3, or 4)
//
// The logic is based on analyzing the parity of negative numbers and the possibility of
// achieving a magnitude >= 1 or < 1.
//
// `neg_parity_can_be_odd`: true if the final product can be negative
// `neg_parity_can_be_even`: true if the final product can be positive
// `mag_can_be_ge1`: true if the final product can have magnitude >= 1
// `mag_can_be_lt1`: true if the final product can have magnitude < 1
//
// The core idea is that we can control the parity of negative numbers by strategically
// pairing them. If we have N negative numbers, we can make the final product negative
// if N is odd, or positive if N is even. If N > 0, we can always make it positive
// by pairing two negative numbers first. If N > 1, we can always make it negative
// by pairing a negative with a positive, and then another negative with a positive, etc.,
// until one negative remains.
//
// For magnitude, if there's at least one toy with magnitude >= 1 (from Box 1 or Box 4),
// and we have enough "magnifying" power (e.g., other toys with magnitude >= 1, or
// we can arrange multiplications to keep the magnitude large), we can potentially
// keep the final magnitude >= 1. Conversely, if there are toys with magnitude < 1
// (from Box 2 or Box 3), we can always make the final magnitude < 1 by multiplying
// everything by a very small number from Box 2 or Box 3 at the very end.
//
// The strategy for magnitude is:
// To get magnitude >= 1: We need at least one initial toy with magnitude >= 1 (A > 0 or D > 0).
// If we have such a toy, we can try to preserve its magnitude or increase it.
// If we have only toys with magnitude < 1 (B > 0 or C > 0), the final magnitude will always be < 1.
//
// To get magnitude < 1: If we have at least one toy with magnitude < 1 (B > 0 or C > 0),
// we can always make the final magnitude < 1. We can pick a very small number from B or C
// and multiply it last, or multiply it with a large number to bring it down.
// If all initial toys have magnitude >= 1 (A > 0 or D > 0, and B=0, C=0), then the final
// magnitude will always be >= 1.

bool check_box(long long initial_A, long long initial_B, long long initial_C, long long initial_D, int target_box) {
    long long total_toys = initial_A + initial_B + initial_C + initial_D;

    if (total_toys == 0) return false; // Should not happen based on constraints A+B+C+D > 0

    // Case 1: Only one toy initially
    if (total_toys == 1) {
        if (initial_A == 1 && target_box == 1) return true;
        if (initial_B == 1 && target_box == 2) return true;
        if (initial_C == 1 && target_box == 3) return true;
        if (initial_D == 1 && target_box == 4) return true;
        return false;
    }

    // Determine if the final product can be negative or positive
    bool neg_parity_can_be_odd = false; // Can the final product be negative?
    bool neg_parity_can_be_even = false; // Can the final product be positive?

    long long initial_neg_count = initial_A + initial_B;

    if (initial_neg_count == 0) {
        // All initial toys are positive. Final product must be positive.
        neg_parity_can_be_even = true;
    } else if (initial_neg_count == 1) {
        // One negative toy.
        // If we multiply it with positive toys, the result is negative.
        neg_parity_can_be_odd = true;
    } else { // initial_neg_count >= 2
        // We have at least two negative toys.
        // We can pair two negatives to make a positive, then proceed.
        // This means we can effectively reduce the number of negatives by 2.
        // So, if initial_neg_count is even, we can make it positive.
        // If initial_neg_count is odd, we can make it negative.
        //
        // However, we can also choose to multiply a negative with a positive,
        // keeping the negative count the same.
        //
        // If initial_neg_count is even:
        //   - We can pair all negatives to get a positive result (neg_parity_can_be_even = true).
        //   - If total_toys > initial_neg_count (i.e., there are positive toys),
        //     we can pair one negative with a positive, then pair the remaining
        //     (initial_neg_count - 1) negatives. If initial_neg_count is even,
        //     then initial_neg_count - 1 is odd, so the result can be negative.
        //     So, if initial_neg_count is even and there's at least one positive toy,
        //     both parities are possible.
        //   - If total_toys == initial_neg_count (all toys are negative),
        //     then the final product must be positive (neg_parity_can_be_even = true).
        //
        // If initial_neg_count is odd:
        //   - We can pair (initial_neg_count - 1) negatives to get a positive,
        //     leaving one negative. The final result will be negative (neg_parity_can_be_odd = true).
        //   - If total_toys > initial_neg_count (i.e., there are positive toys),
        //     we can pair one negative with a positive, then pair the remaining
        //     (initial_neg_count - 1) negatives. If initial_neg_count is odd,
        //     then initial_neg_count - 1 is even, so the result can be positive.
        //     So, if initial_neg_count is odd and there's at least one positive toy,
        //     both parities are possible.
        //   - If total_toys == initial_neg_count (all toys are negative),
        //     then the final product must be negative (neg_parity_can_be_odd = true).

        if (initial_neg_count % 2 == 0) { // Even number of negatives
            neg_parity_can_be_even = true;
            if (total_toys > initial_neg_count) { // There are positive toys
                neg_parity_can_be_odd = true;
            }
        } else { // Odd number of negatives
            neg_parity_can_be_odd = true;
            if (total_toys > initial_neg_count) { // There are positive toys
                neg_parity_can_be_even = true;
            }
        }
    }

    // Determine if the final product can have magnitude >= 1 or < 1
    bool mag_can_be_ge1 = false; // Can the final product have magnitude >= 1?
    bool mag_can_be_lt1 = false; // Can the final product have magnitude < 1?

    long long initial_ge1_count = initial_A + initial_D;
    long long initial_lt1_count = initial_B + initial_C;

    if (initial_ge1_count == 0) {
        // All initial toys have magnitude < 1. Final product must have magnitude < 1.
        mag_can_be_lt1 = true;
    } else if (initial_lt1_count == 0) {
        // All initial toys have magnitude >= 1. Final product must have magnitude >= 1.
        mag_can_be_ge1 = true;
    } else {
        // We have both types of magnitudes.
        // We can always make the final magnitude < 1 by multiplying by a very small number last.
        mag_can_be_lt1 = true;

        // Can we make the final magnitude >= 1?
        // Yes, if we have at least one toy with magnitude >= 1, and we can arrange
        // multiplications such that the final product remains >= 1.
        // This is always possible if initial_ge1_count > 0.
        // We can pick a large number (from A or D) and multiply it with other large numbers,
        // or with numbers close to 1. We can always avoid multiplying it with a very small
        // number if we have other options.
        // The only edge case is if we have only one large number and many small numbers.
        // But even then, we can choose the values such that the product remains large.
        // For example, if we have {10, 0.1, 0.1}, we can do (10 * 0.1) * 0.1 = 1 * 0.1 = 0.1 (mag < 1)
        // or we can choose values like {10, 0.9, 0.9} -> (10 * 0.9) * 0.9 = 9 * 0.9 = 8.1 (mag >= 1).
        // Since we don't know the exact values, we assume we can pick values to achieve this.
        // The problem states "fun values, a real number", implying we can pick values
        // arbitrarily close to 1 or 0, or very large.
        // So, if initial_ge1_count > 0, we can always achieve mag_can_be_ge1 = true.
        mag_can_be_ge1 = true;
    }

    // Check if the target box is possible based on the derived properties
    if (target_box == 1) { // Negative, magnitude >= 1
        return neg_parity_can_be_odd && mag_can_be_ge1;
    } else if (target_box == 2) { // Negative, magnitude < 1
        return neg_parity_can_be_odd && mag_can_be_lt1;
    } else if (target_box == 3) { // Positive, magnitude < 1
        return neg_parity_can_be_even && mag_can_be_lt1;
    } else if (target_box == 4) { // Positive, magnitude >= 1
        return neg_parity_can_be_even && mag_can_be_ge1;
    }
    return false; // Should not reach here
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int T;
    std::cin >> T;
    while (T--) {
        long long A, B, C, D;
        std::cin >> A >> B >> C >> D;

        std::string result[4];
        for (int i = 0; i < 4; ++i) {
            if (check_box(A, B, C, D, i + 1)) {
                result[i] = "Ya";
            } else {
                result[i] = "Tidak";
            }
        }
        std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareA(const Element& a, const Element& b) {
    return a.value < b.value;
}

bool compareB(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<Element> a_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a_elements[i].value;
        a_elements[i].original_index = i;
    }

    std::vector<Element> b_elements(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_elements[i].value;
        b_elements[i].original_index = i;
    }

    std::sort(a_elements.begin(), a_elements.end(), compareA);
    std::sort(b_elements.begin(), b_elements.end(), compareB);

    std::vector<long long> result_a(m);
    for (int i = 0; i < m; ++i) {
        // The i-th smallest B value (b_elements[i].value) should be paired
        // with the (m-1-i)-th largest A value (a_elements[m-1-i].value).
        // The original index of this B value is b_elements[i].original_index.
        // So, result_a[b_elements[i].original_index] should be a_elements[m-1-i].value.
        result_a[b_elements[i].original_index] = a_elements[m - 1 - i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a[i] << (i == m - 1 ? "" : " ");
    }
