#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    std::vector<int> counts(n + 1, 0);
    int max_val_prefix = 0;
    bool distinct_prefix = true;

    std::vector<bool> is_prefix_perm(n + 1, false);

    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        if (distinct_prefix) {
            if (a[i] > n || counts[a[i]] > 0) {
                distinct_prefix = false;
            } else {
                counts[a[i]]++;
                max_val_prefix = std::max(max_val_prefix, a[i]);
            }
        }
        if (distinct_prefix && max_val_prefix == (i + 1)) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::fill(counts.begin(), counts.end(), 0);
    int max_val_suffix = 0;
    bool distinct_suffix = true;
    std::vector<bool> is_suffix_perm(n + 1, false);

    for (int i = n - 1; i >= 0; --i) {
        int current_suffix_len = n - i;
        if (distinct_suffix) {
            if (a[i] > n || counts[a[i]] > 0) {
                distinct_suffix = false;
            } else {
                counts[a[i]]++;
                max_val_suffix = std::max(max_val_suffix, a[i]);
            }
        }
        if (distinct_suffix && max_val_suffix == current_suffix_len) {
            is_suffix_perm[current_suffix_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_score = 0;
        int wins_count = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                wins_count++;
                if (i > 0 && s[i-1] == 'W') {
                    initial_score += 2;
                } else {
                    initial_score += 1;
                }
            }
        }

        if (wins_count == 0) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                // Change k 'L's to 'W's. Best to make them consecutive.
                // 1 point for the first W, 2 points for each subsequent W.
                std::cout << 1 + (k - 1) * 2 << "\n";
            }
            continue;
        }

        // If we reach here, there's at least one 'W' initially.
        // We want to convert 'L's to 'W's.
        // Each 'L' converted to 'W' costs 1 k.
        // It gives 1 point if it's isolated or starts a new streak.
        // It gives 2 points if it extends a streak.
        // It gives 1 point if it connects two streaks, and potentially 1 more point for the other side.
        // The most efficient way to use k is to connect existing 'W' streaks.

        std::vector<int> gaps;
        int first_W = -1, last_W = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_W == -1) first_W = i;
                last_W = i;
            }
        }

        // Count 'L's before the first 'W'
        int leading_Ls = first_W;
        // Count 'L's after the last 'W'
        int trailing_Ls = n - 1 - last_W;

        // Collect lengths of 'L' segments between 'W's
        int current_gap = 0;
        for (int i = first_W + 1; i <= last_W; ++i) {
            if (s[i] == 'L') {
                current_gap++;
            } else { // s[i] == 'W'
                if (current_gap > 0) {
                    gaps.push_back(current_gap);
                }
                current_gap = 0;
            }
        }
        std::sort(gaps.begin(), gaps.end());

        int current_k = k;
        int additional_score = 0;

        // 1. Fill internal gaps
        for (int gap_len : gaps) {
            if (current_k >= gap_len) {
                current_k -= gap_len;
                additional_score += gap_len * 2 + 1; // Each L becomes W, connects two Ws, adds 2 points. The L itself becomes W, adds 1. The W after it now gets 2 instead of 1, adds 1. Total 2.
                                                      // No, it's simpler: each L becomes W, adds 2 points.
                                                      // Example: W L W -> W W W. L becomes W, adds 2.
                                                      // W L L W -> W W W W. First L becomes W, adds 2. Second L becomes W, adds 2.
                                                      // So, each L in a gap adds 2 points.
            } else {
                additional_score += current_k * 2;
                current_k = 0;
                break;
            }
        }

        // 2. Extend streaks (convert leading/trailing 'L's)
        // Each 'L' converted to 'W' at the ends adds 1 point.
        // If it connects to an existing 'W', it becomes 2 points.
        // If it's the first 'W' in a new streak, it's 1 point.
        // If it's the second 'W' in a new streak, it's 2 points.
        // The logic for initial_score already counts 1 for first W, 2 for subsequent Ws.
        // So, if we convert an 'L' next to a 'W', it becomes a 'W' and gets 2 points.
        // If we convert an 'L' not next to a 'W', it gets 1 point.
        // The current `additional_score` is for filling gaps, where each `L` becomes `W` and gets 2 points.
        // The `wins_count` is the number of 'W's after filling gaps.
        // The `initial_score` is the score from original 'W's.
        // The `additional_score` is from filling gaps.
        // Now we have `current_k` remaining.
        // We can convert `current_k` 'L's at the ends.
        // Each such 'L' will become a 'W'.
        // If it's adjacent to an existing 'W' (or a newly converted 'W'), it will contribute 2 points.
        // If it's not adjacent to any 'W' (e.g., converting LLL to WWL), the first 'W' contributes 1, subsequent 2.
        // The simplest way to think about this is:
        // We have `wins_count` 'W's.
        // We filled `sum(gaps)` 'L's.
        // Total 'W's so far: `wins_count + sum(gaps)`.
        // Each of these `sum(gaps)` 'L's added 2 points.
        // Now we have `current_k` changes left.
        // We can convert `current_k` 'L's from `leading_Ls` and `trailing_Ls`.
        // Each of these will be adjacent to an existing 'W' (or a newly converted 'W').
        // So each will add 2 points.
        // The only exception is if `wins_count` was 0 initially, which is handled.
        // If `wins_count > 0`, then `first_W` and `last_W` exist.
        // Any 'L' converted in `leading_Ls` or `trailing_Ls` will be adjacent to a 'W' (either `s[first_W]` or `s[last_W]`).
        // So, each of these `current_k` conversions will add 2 points.
        additional_score += current_k * 2;

        std::cout << initial_score + additional_score << "\n";
    }
    return 0;
}

