#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end()); // Sort w to easily separate w_i=1 and w_i>1

        long long total_happiness = 0;
        int a_ptr_left = 0;
        int a_ptr_right = n - 1;

        // First, handle friends with w_i = 1.
        // These friends get 2 * largest available numbers.
        // They are at the end of sorted w.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += a[a_ptr_right] * 2;
                a_ptr_right--;
            } else {
                // All remaining w_i will be > 1, as w is sorted.
                // Break and handle them in the next loop.
                break;
            }
        }

        // Now, handle friends with w_i > 1.
        // These friends get one largest available number (as max_val)
        // and one smallest available number (as min_val).
        // The w_i values are sorted, so the smallest w_i (which are > 1) are at the beginning.
        // We assign the largest remaining 'a' values as max_val.
        // We assign the smallest remaining 'a' values as min_val.
        // The w_i values determine how many intermediate numbers are skipped.
        for (int i = 0; i < k; ++i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_right]; // Max value for this friend
                a_ptr_right--;
                total_happiness += a[a_ptr_left]; // Min value for this friend
                a_ptr_left += (w[i] - 1); // Skip w[i]-1 smallest numbers
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

