void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append elements b1, b2, ... such that
        // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

        // Let's try to append two elements.
        // Let the first element be X = current_xor_sum.
        // New XOR sum becomes current_xor_sum ^ X = current_xor_sum ^ current_xor_sum = 0.
        // New sum becomes current_sum + X.
        // The condition would be (current_sum + X) = 2 * 0, which means current_sum + X = 0.
        // Since all numbers are non-negative, this implies current_sum = 0 and X = 0.
        // This is not generally true.

        // Let's try to append two elements: X and S_prime.
        // Where X is the current_xor_sum.
        // The new XOR sum will be current_xor_sum ^ X = 0.
        // We need the final sum to be 2 * 0 = 0.
        // So, current_sum + X + S_prime = 0.
        // This implies S_prime = -(current_sum + X).
        // Since S_prime must be non-negative, this only works if current_sum + X = 0,
        // which means current_sum = 0 and X = 0.
        // This is not a general solution.

        // Let's try to append two elements: current_xor_sum and current_sum + current_xor_sum.
        // Let b1 = current_xor_sum.
        // Let b2 = current_sum + current_xor_sum.
        // New XOR sum: current_xor_sum ^ b1 ^ b2
        // = current_xor_sum ^ current_xor_sum ^ (current_sum + current_xor_sum)
        // = 0 ^ (current_sum + current_xor_sum)
        // = current_sum + current_xor_sum.
        // Let's call this new_X = current_sum + current_xor_sum.

        // New sum: current_sum + b1 + b2
        // = current_sum + current_xor_sum + (current_sum + current_xor_sum)
        // = 2 * (current_sum + current_xor_sum).
        // Let's call this new_S = 2 * (current_sum + current_xor_sum).

        // The condition is new_S = 2 * new_X.
        // Substituting: 2 * (current_sum + current_xor_sum) = 2 * (current_sum + current_xor_sum).
        // This is always true!
        // So, we can always append two elements: current_xor_sum and current_sum + current_xor_sum.
        // These elements are non-negative because current_sum and current_xor_sum are non-negative.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << "\n";
        std::cout << b1 << " " << b2 << "\n";
    }
}

