#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<int> count_x(n + 1, 0);
    std::vector<int> count_y(n + 1, 0);
    std::vector<int> count_z(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        count_x[i + 1] = count_x[i];
        count_y[i + 1] = count_y[i];
        count_z[i + 1] = count_z[i];
        if (s[i] == 'x') {
            count_x[i + 1]++;
        } else if (s[i] == 'y') {
            count_y[i + 1]++;
        } else { // s[i] == 'z'
            count_z[i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        if (r - l + 1 < 3) {
            std::cout << "YES\n";
            continue;
        }

        int num_x = count_x[r] - count_x[l - 1];
        int num_y = count_y[r] - count_y[l - 1];
        int num_z = count_z[r] - count_z[l - 1];

        int min_count = std::min({num_x, num_y, num_z});
        int max_count = std::max({num_x, num_y, num_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

