long long power(long long base, int exp) {
    long long res = 1;
    for (int i = 0; i < exp; ++i) {
        if (__builtin_mul_overflow(res, base, &res)) {
            return -1; // Indicate overflow
        }
    }
    return res;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p;
        int q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x | p such that x % q != 0.
        // This means x must not be a multiple of q.
        // Let q = q1^a1 * q2^a2 * ... * qk^ak be the prime factorization of q.
        // For x to not be a multiple of q, there must be at least one prime factor qi
        // such that the power of qi in x is less than the power of qi in q.

        long long max_x = 0;
        int temp_q = q;

        // Find prime factors of q
        for (long long i = 2; i * i <= temp_q; ++i) {
            if (temp_q % i == 0) {
                // i is a prime factor of q
                long long current_p = p;
                while (current_p % q == 0) {
                    current_p /= i;
                }
                max_x = std::max(max_x, current_p);
                while (temp_q % i == 0) {
                    temp_q /= i;
                }
            }
        }
        if (temp_q > 1) { // temp_q is a prime factor itself
            long long current_p = p;
            while (current_p % q == 0) {
                current_p /= temp_q;
            }
            max_x = std::max(max_x, current_p);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

