void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    bool possible = true;

    // Step 1: Propagate known characters based on s[i] == s[i+k]
    for (int i = 0; i < n - k; ++i) {
        if (s[i] != '?' && s[i+k] != '?') {
            if (s[i] != s[i+k]) {
                possible = false;
                break;
            }
        } else if (s[i] != '?') {
            s[i+k] = s[i];
        } else if (s[i+k] != '?') {
            s[i] = s[i+k];
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    // Step 2: Check the first k characters for balance
    // For each remainder i % k, count 0s, 1s, and ?s
    // Then try to fill '?'s to satisfy the k/2 balance for the first block

    // counts[j][0] = count of '0's at indices i such that i % k == j
    // counts[j][1] = count of '1's at indices i such that i % k == j
    // counts[j][2] = count of '?'s at indices i such that i % k == j
    std::vector<std::vector<int>> counts(k, std::vector<int>(3, 0));

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            counts[i][0]++;
        } else if (s[i] == '1') {
            counts[i][1]++;
        } else { // s[i] == '?'
            counts[i][2]++;
        }
    }

    int total_zeros = 0;
    int total_ones = 0;
    int total_q_marks = 0;

    for (int i = 0; i < k; ++i) {
        total_zeros += counts[i][0];
        total_ones += counts[i][1];
        total_q_marks += counts[i][2];
    }

    // If we have too many 0s or 1s already in the first k characters, it's impossible
    if (total_zeros > k / 2 || total_ones > k / 2) {
        possible = false;
    } else {
        // We need (k/2 - total_zeros) more zeros and (k/2 - total_ones) more ones.
        // The remaining '?'s must be filled to satisfy this.
        // The number of '?'s available is total_q_marks.
        // If (k/2 - total_zeros) + (k/2 - total_ones) == total_q_marks, it's possible.
        // This is equivalent to k - total_zeros - total_ones == total_q_marks,
        // which is always true by definition of total_q_marks.
        // So, if total_zeros <= k/2 and total_ones <= k/2, it's possible to fill the first k characters.
        // The actual filling is not needed, just the check.
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

