int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // If robot cannot move left (f1=0), it must end up at x >= its current x.
            // So, the target X must be >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // If robot cannot move up (f2=0), it must end up at y <= its current y.
            // So, the target Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
            // If robot cannot move right (f3=0), it must end up at x <= its current x.
            // So, the target X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // If robot cannot move down (f4=0), it must end up at y >= its current y.
            // So, the target Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val;
    if (b == 1) { // If b=1, r must be 0, but r!=0 is required. So no nice integers.
        sum_r_val = 0;
    } else {
        sum_r_val = (b - 1);
        sum_r_val = (sum_r_val * b) / 2;
        sum_r_val %= MOD;
    }

    // Sum of (k*b + 1) from k=1 to a
    // This is sum_kb_plus_1_val
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_kb_plus_1_val;
    long long sum_k_val = (a * (a + 1)) / 2;
    sum_k_val %= MOD;

    sum_kb_plus_1_val = (b % MOD * sum_k_val) % MOD;
    sum_kb_plus_1_val = (sum_kb_plus_1_val + a) % MOD;

    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> d_left(n);
    std::deque<std::pair<long long, int>> dq_left; // {height, index}

    for (int i = 0; i < n; ++i) {
        while (!dq_left.empty() && dq_left.back().first >= h[i]) {
            dq_left.pop_back();
        }
        long long prev_max_h = 0;
        if (!dq_left.empty()) {
            prev_max_h = dq_left.back().first;
        }

        long long val = h[i] - prev_max_h;
        if (!dq_left.empty()) {
            val = std::min(val, d_left[dq_left.back().second] + (i - dq_left.back().second));
        } else {
            val = std::min(val, (long long)i + 1);
        }
        d_left[i] = val;
        dq_left.push_back({h[i], i});
    }

    std::vector<long long> d_right(n);
    std::deque<std::pair<long long, int>> dq_right; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        while (!dq_right.empty() && dq_right.back().first >= h[i]) {
            dq_right.pop_back();
        }
        long long prev_max_h = 0;
        if (!dq_right.empty()) {
            prev_max_h = dq_right.back().first;
        }

        long long val = h[i] - prev_max_h;
        if (!dq_right.empty()) {
            val = std::min(val, d_right[dq_right.back().second] + (dq_right.back().second - i));
        } else {
            val = std::min(val, (long long)(n - i));
        }
        d_right[i] = val;
        dq_right.push_back({h[i], i});
    }

    long long max_ops = 0;
    for (int i = 0; i < n; ++i) {
        max_ops = std::max(max_ops, std::min(d_left[i], d_right[i]));
    }

    std::cout << max_ops << std::endl;

    return 0;
}

