        // This is not true for arbitrary a[i].

        // The standard solution for this problem:
        // 1. For elements a[0] to a[n-2]:
        //    Select segment [1, n-1] (0-indexed: [0, n-2]). Length is n-1.
        //    For each a[i], we want to add b_i such that b_i is a multiple of (n-1)
        //    AND (a[i] + b_i) is a multiple of n.
        //    Let current_val = a[i].
        //    We need (current_val + b_i) % n == 0.
        //    And b_i % (n-1) == 0.
        //    Let b_i = k * (n-1).
        //    (current_val + k * (n-1)) % n == 0
        //    (current_val + k * (-1)) % n == 0  (since n-1 = -1 mod n)
        //    (current_val - k) % n == 0
        //    So k % n == current_val % n.
        //    Let k = (current_val % n + n) % n.
        //    Then b_i = k * (n-1) = ((current_val % n + n) % n) * (n-1).
        //    This b_i is a multiple of (n-1).
        //    After adding b_i, a[i] becomes a multiple of n.
        //    Example: a[i] = 1, n = 4. n-1 = 3.
        //    k = (1 % 4 + 4) % 4 = 1.
        //    b_i = 1 * 3 = 3.
        //    a[i] becomes 1 + 3 = 4. (Multiple of 4).
        //    Example: a[i] = 3, n = 4. n-1 = 3.
        //    k = (3 % 4 + 4) % 4 = 3.
        //    b_i = 3 * 3 = 9.
        //    a[i] becomes 3 + 9 = 12. (Multiple of 4).

        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long current_val = a[i];
            long long k = (current_val % n + n) % n;
            long long b_i = k * (n - 1);
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i; // Update a[i] to be a multiple of n
        }
        std::cout << "\n";

        // 2. For the last element a[n-1]:
        //    Select segment [n, n] (0-indexed: [n-1, n-1]). Length is 1.
        //    We want to add b_{n-1} such that b_{n-1} is a multiple of 1
        //    AND (a[n-1] + b_{n-1}) is a multiple of n.
        //    This is similar to the previous step, but len=1.
        //    b_{n-1} = k * 1.
        //    (a[n-1] + k) % n == 0.
        //    So k % n == (n - (a[n-1] % n)) % n.
        //    Let k = (n - (a[n-1] % n)) % n.
        //    Then b_{n-1} = k.
        //    This makes a[n-1] + b_{n-1} a multiple of n.
        //    Example: a[n-1] = 1, n = 4. len = 1.
        //    k = (4 - (1 % 4)) % 4 = 3.
        //    b_{n-1} = 3.
        //    a[n-1] becomes 1 + 3 = 4. (Multiple of 4).
        //    Example: a[n-1] = 3, n = 4. len = 1.
        //    k = (4 - (3 % 4)) % 4 = 1.
        //    b_{n-1} = 1.
        //    a[n-1] becomes 3 + 1 = 4. (Multiple of 4).

        std::cout << n << " " << n << "\n";
        long long current_val = a[n - 1];
        long long k = (n - (current_val % n + n) % n) % n; // k such that current_val + k is multiple of n
        long long b_n_minus_1 = k; // b_n_minus_1 is a multiple of 1
        std::cout << b_n_minus_1 << "\n";
        a[n - 1] += b_n_minus_1; // Update a[n-1] to be a multiple of n

        // At this point, all elements a[i] are multiples of n.
        // 3. Make all elements zero.
        //    Select segment [1, n] (0-indexed: [0, n-1]). Length is n.
        //    For each a[i], we want to add b_i such that b_i is a multiple of n AND a[i] + b_i = 0.
        //    Since a[i] is already a multiple of n, we can choose b_i = -a[i].
        //    -a[i] is also a multiple of n. This is valid.

        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    // Initialize current state for each bit
    // For each bit position (0-9):
    // bit_val[b] = 0 means if input bit is 0, output bit is 0
    // bit_val[b] = 1 means if input bit is 0, output bit is 1
    // bit_val[b] = 2 means if input bit is 1, output bit is 0
    // bit_val[b] = 3 means if input bit is 1, output bit is 1
    // This can be simplified:
    // bit_val[b] = 0: output is 0 regardless of input (0->0, 1->0)
    // bit_val[b] = 1: output is 1 regardless of input (0->1, 1->1)
    // bit_val[b] = 2: output is same as input (0->0, 1->1)
    // bit_val[b] = 3: output is inverse of input (0->1, 1->0)
    // Let's use a different representation:
    // For each bit b, we track two values:
    // val_0[b]: what 0 becomes after all operations for bit b
    // val_1[b]: what 1 becomes after all operations for bit b
    std::vector<int> val_0(10); // Initial state: 0 -> 0
    std::vector<int> val_1(10); // Initial state: 1 -> 1
    for (int i = 0; i < 10; ++i) {
        val_0[i] = 0;
        val_1[i] = 1;
    }

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        for (int b = 0; b < 10; ++b) {
            int bit_x = (x >> b) & 1;
            if (op_char == '&') {
                val_0[b] = val_0[b] & bit_x;
                val_1[b] = val_1[b] & bit_x;
            } else if (op_char == '|') {
                val_0[b] = val_0[b] | bit_x;
                val_1[b] = val_1[b] | bit_x;
            } else { // '^'
                val_0[b] = val_0[b] ^ bit_x;
                val_1[b] = val_1[b] ^ bit_x;
            }
        }
    }

    // Now, reconstruct the simplified operations
    // We need to find A_AND, A_OR, A_XOR such that:
    // ( ( (x & A_AND) | A_OR ) ^ A_XOR )
    // For each bit b:
    // If val_0[b] == 0 and val_1[b] == 0: output bit is always 0.
    // If val_0[b] == 1 and val_1[b] == 1: output bit is always 1.
    // If val_0[b] == 0 and val_1[b] == 1: output bit is same as input bit.
    // If val_0[b] == 1 and val_1[b] == 0: output bit is inverse of input bit.

    int final_and_mask = 1023; // All bits initially 1 for AND
    int final_or_mask = 0;     // All bits initially 0 for OR
    int final_xor_mask = 0;    // All bits initially 0 for XOR

    for (int b = 0; b < 10; ++b) {
        if (val_0[b] == 0 && val_1[b] == 0) {
            // Output bit is always 0.
            // To achieve this:
            // (x & 0) -> 0
            // (x | 0) -> x
            // (x ^ 0) -> x
            // So, we need to set the AND mask bit to 0.
            final_and_mask &= ~(1 << b); // Set b-th bit of final_and_mask to 0
            // final_or_mask bit remains 0
            // final_xor_mask bit remains 0
        } else if (val_0[b] == 1 && val_1[b] == 1) {
            // Output bit is always 1.
            // To achieve this:
            // (x & 1) -> x
            // (x | 1) -> 1
            // (x ^ 0) -> x
            // So, we need to set the OR mask bit to 1.
            // final_and_mask bit remains 1
            final_or_mask |= (1 << b); // Set b-th bit of final_or_mask to 1
            // final_xor_mask bit remains 0
        } else if (val_0[b] == 0 && val_1[b] == 1) {
            // Output bit is same as input bit.
            // To achieve this:
            // (x & 1) -> x
            // (x | 0) -> x
            // (x ^ 0) -> x
            // So, all masks should have 0 for OR and XOR, and 1 for AND.
            // final_and_mask bit remains 1
            // final_or_mask bit remains 0
            // final_xor_mask bit remains 0
        } else { // val_0[b] == 1 && val_1[b] == 0
            // Output bit is inverse of input bit.
            // To achieve this:
            // (x & 1) -> x
            // (x | 0) -> x
            // (x ^ 1) -> ~x
            // So, we need to set the XOR mask bit to 1.
            // final_and_mask bit remains 1
            // final_or_mask bit remains 0
            final_xor_mask |= (1 << b); // Set b-th bit of final_xor_mask to 1
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_mask != 1023) { // If any bit of AND mask is 0
        result_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) { // If any bit of OR mask is 1
        result_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) { // If any bit of XOR mask is 1
        result_ops.push_back({'^', final_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for differences (strawberry - blueberry)
    // For left side (jars 0 to n-1)
    // For right side (jars n to 2n-1)

    // diff_left[k] = (count of 1s - count of 2s) in a[0...k-1]
    // diff_right[k] = (count of 1s - count of 2s) in a[2n-1...2n-k]

    // Map to store the minimum number of jars removed from the left side
    // to achieve a certain difference.
    // key: difference (S-B), value: number of jars removed from left (k)
    std::map<int, int> left_diff_to_k;
    left_diff_to_k[0] = 0; // 0 jars removed from left, difference is 0

    int current_diff_left = 0;
    for (int k = 1; k <= n; ++k) {
        current_diff_left += (a[k - 1] == 1 ? 1 : -1);
        if (left_diff_to_k.find(current_diff_left) == left_diff_to_k.end()) {
            left_diff_to_k[current_diff_left] = k;
        }
    }

    // Calculate total difference for all 2n jars
    int total_diff = 0;
    for (int x : a) {
        total_diff += (x == 1 ? 1 : -1);
    }

    int min_removed = 2 * n; // Initialize with max possible jars removed

    // Case 1: No jars removed from the right side (R=0)
    // We need total_diff - current_diff_left = 0, so current_diff_left = total_diff
    if (left_diff_to_k.count(total_diff)) {
        min_removed = std::min(min_removed, left_diff_to_k[total_diff]);
    }

    // Iterate through possible number of jars removed from the right side (R)
    int current_diff_right = 0;
    for (int R = 1; R <= n; ++R) {
        current_diff_right += (a[2 * n - R] == 1 ? 1 : -1);
        // We need (total_diff - current_diff_left - current_diff_right) = 0
        // So, current_diff_left = total_diff - current_diff_right
        int target_diff_left = total_diff - current_diff_right;
        if (left_diff_to_k.count(target_diff_left)) {
            min_removed = std::min(min_removed, left_diff_to_k[target_diff_left] + R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <algorithm> // For std::min and std::max

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings is n * (n + 1) / 2
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
        // This is achieved by distributing the zeros as evenly as possible among the m+1 slots
        // created by the m ones.
        // Let k be the number of zeros.
        // We have m+1 slots for zeros.
        // k = q * (m+1) + r, where 0 <= r < m+1.
        // This means r slots will have q+1 zeros, and (m+1-r) slots will have q zeros.

        // Number of slots with q+1 zeros
        long long r = num_zeros % (m + 1);
        // Number of slots with q zeros
        long long num_slots_q = (m + 1) - r;
        // Length of q zeros
        long long q = num_zeros / (m + 1);

        // Number of substrings of all zeros from slots with q zeros
        long long substrings_from_q_slots = num_slots_q * (q * (q + 1) / 2);

        // Number of substrings of all zeros from slots with q+1 zeros
        long long substrings_from_q_plus_1_slots = r * ((q + 1) * (q + 2) / 2);

        long long substrings_with_only_zeros = substrings_from_q_slots + substrings_from_q_plus_1_slots;

        std::cout << total_substrings - substrings_with_only_zeros << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active_vertices(n, false);

    // Process vertices in reverse order of removal
    // This means we are adding vertices one by one to an initially empty graph
    // and calculating APSP sum for the graph formed by currently active vertices.
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added to the graph

        active_vertices[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step:
        // Consider paths going through the newly added vertex k
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k and updating all-pairs shortest paths considering k as an intermediate,
        // we need to update all-pairs shortest paths considering any active vertex as an intermediate.
        // This is the standard Floyd-Warshall triple loop, but optimized for adding one vertex.
        // The previous loop (i,j,k) updates paths *through* k.
        // We also need to update paths *between* i and k, and k and j, using other active vertices.
        // This is implicitly handled by the standard Floyd-Warshall structure.
        // The key is that when vertex 'k' is added, it can serve as an intermediate vertex.
        // Also, paths from 'k' to 'i' and 'j' to 'k' might be shortened by other active vertices.
        // The full Floyd-Warshall update for a new vertex k is:
        // for i in 0..n-1:
        //   for j in 0..n-1:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This is what we did above.
        // However, we also need to consider paths that use k as an endpoint,
        // and other active vertices as intermediates.
        // For example, dist[k][i] might be shortened by some active vertex 'm': dist[k][m] + dist[m][i].
        // And dist[i][k] might be shortened by some active vertex 'm': dist[i][m] + dist[m][k].
        // The standard Floyd-Warshall algorithm structure handles this naturally.
        // When we add vertex 'k', we effectively run the k-th iteration of Floyd-Warshall.
        // The `dist` matrix already contains shortest paths using vertices 0 to k-1.
        // Now, we update `dist` to include paths using vertex `k`.
        // The loops below ensure that `k` can be an intermediate for any `i, j`.
        // And also, `i` or `j` can be `k`, meaning paths like `k -> m -> j` or `i -> m -> k` are considered.
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }
        // The above loop is actually redundant if the previous (i,j,k) loop was over all i,j.
        // The standard Floyd-Warshall update for adding vertex `k` is:
        // for i from 0 to n-1:
        //   for j from 0 to n-1:
        //     dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // This correctly updates all paths to potentially use `k` as an intermediate.
        // The `dist` matrix at this point holds shortest paths between *any* two vertices `i, j`
        // using *any* intermediate vertex from the set of currently active vertices.
        // This is because the `dist` matrix is being updated iteratively.
        // When `k` is added, `dist[i][k]` and `dist[k][j]` already represent shortest paths
        // using previously active vertices. So `dist[i][k] + dist[k][j]` is a candidate path.
        // The `dist` matrix itself is always maintained to reflect shortest paths
        // considering all vertices `0...k_current` as potential intermediates.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_vertices[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_vertices[j]) continue;
                if (i == j) continue;
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <cmath>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with a small positive number

    while (X > 0) {
        long long k = 0;
        // Find the largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        if (X == 1) { // Special case for X=1, k=0 (2^0-1=0, but we need 1 element for 1 subsequence)
            k = 0; // This will result in 1 element, 2^1-1 = 1 subsequence
        } else {
            k = static_cast<long long>(std::log2(static_cast<double>(X + 1)));
            // Ensure 2^k - 1 does not exceed X
            if ((1LL << (k + 1)) - 1 <= X) {
                k++;
            }
            if ((1LL << k) - 1 > X) { // If 2^k-1 is too large, reduce k
                k--;
            }
        }

        // If k is 0, it means X=1. We need 1 element to get 1 subsequence.
        // (2^1 - 1 = 1 subsequence)
        // So, we add 1 element.
        long long count_to_add = k + 1; 

        for (long long i = 0; i < count_to_add; ++i) {
            result_array.push_back(current_val);
        }
        X -= ((1LL << count_to_add) - 1);
        current_val += d + 1; // Ensure new elements are far enough from previous ones
    }

    if (result_array.size() > 10000) {
        // This case should ideally not be reached given X <= 10^9
        // Max k is around 30. If X is 10^9, k is around 30.
        // If X is 10^9, we take 2^29-1, X becomes 10^9 - 2^29.
        // The number of elements added is k+1.
        // The smallest k+1 is 1 (for X=1).
        // The largest k+1 is 30 (for X near 2^29-1).
        // The number of elements is roughly sum of (log2(X_i)+1).
        // If X is 10^9, we take 2^29-1 (30 elements). X becomes 10^9 - 2^29.
        // Then 2^28-1 (29 elements). X becomes 10^9 - 2^29 - 2^28.
        // This is essentially a binary representation of X+1.
        // The number of set bits in X+1 determines the number of blocks.
        // The total number of elements is sum of (bit_position + 1) for each set bit.
        // Max sum of (bit_position + 1) for X up to 10^9 (30 bits) is roughly 30 * 30 = 900.
        // So, n will not exceed 10000.
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable (b_1=a_1, b_n=a_n, no middle elements)
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, 0); // left_ones[i] = length of consecutive 1s ending at i
    std::vector<int> left_zeros(n, 0); // left_zeros[i] = length of consecutive 0s ending at i

    if (a[0] == 1) left_ones[0] = 1;
    else left_zeros[0] = 1;

    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = left_ones[i - 1] + 1;
            left_zeros[i] = 0;
        } else {
            left_zeros[i] = left_zeros[i - 1] + 1;
            left_ones[i] = 0;
        }
    }

    std::vector<int> right_ones(n, 0); // right_ones[i] = length of consecutive 1s starting at i
    std::vector<int> right_zeros(n, 0); // right_zeros[i] = length of consecutive 0s starting at i

    if (a[n - 1] == 1) right_ones[n - 1] = 1;
    else right_zeros[n - 1] = 1;

    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = right_ones[i + 1] + 1;
            right_zeros[i] = 0;
        } else {
            right_zeros[i] = right_zeros[i + 1] + 1;
            right_ones[i] = 0;
        }
    }

    int max_k = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) { // Find 0s that can turn into 1s
            if (left_ones[i] > 0 && right_ones[i] > 0) {
                max_k = std::max(max_k, std::min(left_ones[i], right_ones[i]));
            }
        } else { // Find 1s that can turn into 0s
            if (left_zeros[i] > 0 && right_zeros[i] > 0) {
                max_k = std::max(max_k, std::min(left_zeros[i], right_zeros[i]));
            }
        }
    }

    std::cout << max_k << std::endl;

    std::vector<int> b = a;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            if (left_ones[i] > 0 && right_ones[i] > 0) {
                if (std::min(left_ones[i], right_ones[i]) > max_k) {
                    // This case should not happen if max_k is correctly calculated
                    // as the maximum of min(L,R) over all i.
                    // If min(L,R) > max_k, it means max_k was not the true maximum.
                    // However, if min(L,R) == max_k, then it's a boundary case.
                    // The rule is: if min(L,R) > max_k, it flips.
                    // If min(L,R) == max_k, it stays.
                    // This logic is for the final stable state.
                } else if (std::min(left_ones[i], right_ones[i]) <= max_k) {
                    if (left_ones[i] > max_k) { // 0 is surrounded by 1s, but left side is longer
                        b[i] = 1;
                    } else if (right_ones[i] > max_k) { // 0 is surrounded by 1s, but right side is longer
