                        // The rule is: if a[i] is 0, and it's surrounded by 1s, it flips to 1 if its distance to *either* end of the 1-block is > max_k.
                        // This means if left_ones[i] > max_k OR right_ones[i] > max_k, it flips.
                        // If left_ones[i] == max_k AND right_ones[i] == max_k, it stays 0.
                        // This is because it's exactly at the "edge" of the max_k influence.
                        // The current logic for b[i] = 1 is correct.
                    }
                }
            }
        } else { // a[i] == 1
            if (left_zeros[i] > 0 && right_zeros[i] > 0) {
                if (std::min(left_zeros[i], right_zeros[i]) <= max_k) {
                    if (left_zeros[i] > max_k) {
                        b[i] = 0;
                    } else if (right_zeros[i] > max_k) {
                        b[i] = 0;
                    }
                }
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <map>

char get_winning_move(char bot_move) {
    if (bot_move == 'R') {
        return 'P';
    } else if (bot_move == 'S') {
        return 'R';
    } else { // bot_move == 'P'
        return 'S';
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();

        int countR = 0;
        int countS = 0;
        int countP = 0;

        for (char c : s) {
            if (c == 'R') {
                countR++;
            } else if (c == 'S') {
                countS++;
            } else { // c == 'P'
                countP++;
            }
        }

        char most_frequent_bot_move;
        if (countR >= countS && countR >= countP) {
            most_frequent_bot_move = 'R';
        } else if (countS >= countR && countS >= countP) {
            most_frequent_bot_move = 'S';
        } else {
            most_frequent_bot_move = 'P';
        }

        char my_optimal_move = get_winning_move(most_frequent_bot_move);

        for (int i = 0; i < n; ++i) {
            std::cout << my_optimal_move;
        }
        std::cout << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric> // For std::iota

struct Child {
    long long v;
    long long d;
    long long p;
    int original_index;
    bool active; // To mark if child is still in line
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].original_index = i + 1;
        children[i].active = true;
    }

    std::vector<int> cured_children_indices;

    for (int i = 0; i < n; ++i) {
        if (!children[i].active) {
            continue;
        }

        // Child i goes to the doctor
        cured_children_indices.push_back(children[i].original_index);
        children[i].active = false; // Mark as cured

        long long current_v_cry = children[i].v;
        long long hall_cry_sum = 0; // Accumulator for d_j cries

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].active) {
                continue;
            }

            // Apply current_v_cry effect
            if (current_v_cry > 0) {
                children[j].p -= current_v_cry;
                current_v_cry = std::max(0LL, current_v_cry - 1);
            }

            // Apply accumulated hall_cry_sum effect
            children[j].p -= hall_cry_sum;

            // Check if child j cries and leaves
            if (children[j].p < 0) {
                hall_cry_sum += children[j].d;
                children[j].active = false; // Mark as left
            }
        }
    }

    std::cout << cured_children_indices.size() << "\n";
    for (size_t i = 0; i < cured_children_indices.size(); ++i) {
        std::cout << cured_children_indices[i] << (i == cured_children_indices.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

