struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    std::vector<int> p(n);

    // Case 1: All elements in one subsequence (e.g., all 1s)
    // This means all f(a_i, a_j) = a_i + a_j.
    // min_f = elements[0].value + elements[1].value
    // max_f = elements[n-1].value + elements[n-2].value
    // Goodness = (elements[n-1].value + elements[n-2].value) - (elements[0].value + elements[1].value)
    long long goodness_all_same = (elements[n - 1].value + elements[n - 2].value) - (elements[0].value + elements[1].value);
    long long min_goodness = goodness_all_same;
    std::vector<int> best_p(n, 1); // Default partition for all same

    // Case 2: At least one element in each subsequence
    // This means there will be f values of type a_i + a_j and a_i + a_j + h.
    // The minimum possible f value is elements[0].value + elements[1].value.
    // The maximum possible f value is elements[n-1].value + elements[n-2].value + h.
    // This is because elements[0] and elements[n-1] can be in different subsequences.
    // If elements[0] and elements[n-1] are in different subsequences, then
    // min_f = min(elements[0].value + elements[1].value, elements[0].value + elements[n-1].value + h)
    // max_f = max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Consider the partition where elements[0] is in S1 and all others are in S2.
    // min_f:
    //   - elements[1].value + elements[2].value (from S2)
    //   - elements[0].value + elements[1].value + h (from S1 and S2)
    //   So, min_f = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h)
    // max_f:
    //   - elements[n-1].value + elements[n-2].value (from S2)
    //   - elements[0].value + elements[n-1].value + h (from S1 and S2)
    //   So, max_f = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h)
    //
    // Goodness = max_f - min_f
    //
    // Let's analyze the specific partition: elements[0] in S1, elements[1...n-1] in S2.
    // min_f_val = min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    // max_f_val = max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    //
    // This is only valid if n >= 3. If n=2, elements[0] in S1, elements[1] in S2.
    // min_f = elements[0].value + elements[1].value + h
    // max_f = elements[0].value + elements[1].value + h
    // Goodness = 0.
    //
    // For n=2, goodness_all_same is 0. So min_goodness is 0.
    // The logic below handles n=2 correctly.
    //
    // For n >= 3:
    // The minimum possible sum of two elements is elements[0].value + elements[1].value.
    // The maximum possible sum of two elements is elements[n-1].value + elements[n-2].value.
    //
    // Consider the partition where elements[0] is in S1, and elements[1...n-1] are in S2.
    // Values of f:
    //   - elements[i].value + elements[j].value for i,j in [1, n-1] (both in S2)
    //   - elements[0].value + elements[k].value + h for k in [1, n-1] (elements[0] in S1, elements[k] in S2)
    //
    // min_f_val = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    // max_f_val = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    //
    // This partition is only relevant if elements[0].value + elements[1].value + h is not too large.
    //
    // Let's consider two main strategies:
    // Strategy A: Try to make all f values of the same type (all a_i + a_j or all a_i + a_j + h).
    //   - All elements in one subsequence: goodness_all_same. (Already calculated)
    //   - All elements in different subsequences: This is impossible as we only have two subsequences.
    //     If n=2, elements[0] in S1, elements[1] in S2. Then f(a_0, a_1) = a_0 + a_1 + h. min_f=max_f, goodness=0.
    //     This is covered by the general case below.
    //
    // Strategy B: Allow both types of f values.
    //   The minimum possible f value is `elements[0].value + elements[1].value`.
    //   The maximum possible f value is `elements[n-1].value + elements[n-2].value + h`.
    //   This is achieved if elements[0] and elements[n-1] are in different subsequences.
    //   Let's try to put elements[0] in S1 and elements[1]...elements[n-1] in S2.
    //   min_f_val_B = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
    //   max_f_val_B = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
    //   goodness_B = max_f_val_B - min_f_val_B;
    //
    //   This is for n >= 3.
    //   If n=2: elements[0] in S1, elements[1] in S2.
    //   min_f_val_B = elements[0].value + elements[1].value + h;
    //   max_f_val_B = elements[0].value + elements[1].value + h;
    //   goodness_B = 0;
    //
    //   Let's refine the calculation for n >= 3 for Strategy B.
    //   Partition: elements[0] in S1, elements[1...n-1] in S2.
    //   Possible sums:
    //     - `elements[i].value + elements[j].value` for `i,j \in [1, n-1]` (both in S2)
    //     - `elements[0].value + elements[k].value + h` for `k \in [1, n-1]` (elements[0] in S1, elements[k] in S2)
    //
    //   Min value among these:
    //     `min_same_S2 = elements[1].value + elements[2].value` (if n >= 3)
    //     `min_diff_S1S2 = elements[0].value + elements[1].value + h`
    //     `min_f_val_B = std::min(min_same_S2, min_diff_S1S2)`
    //
    //   Max value among these:
    //     `max_same_S2 = elements[n-1].value + elements[n-2].value` (if n >= 3)
    //     `max_diff_S1S2 = elements[0].value + elements[n-1].value + h`
    //     `max_f_val_B = std::max(max_same_S2, max_diff_S1S2)`
    //
    //   Goodness_B = max_f_val_B - min_f_val_B.
    //
    //   If n=2: elements[0] in S1, elements[1] in S2.
    //   Only one f value: elements[0].value + elements[1].value + h.
    //   min_f_val_B = max_f_val_B = elements[0].value + elements[1].value + h.
    //   goodness_B = 0.
    //
    //   This is a special case. If n=2, goodness_all_same is 0, goodness_B is 0.
    //   So min_goodness is 0.
    //   The partition 1 2 is valid.

    if (n == 2) {
        min_goodness = 0;
        best_p[elements[0].original_index] = 1;
        best_p[elements[1].original_index] = 2;
    } else { // n >= 3
        long long min_f_val_B = std::min(elements[1].value + elements[2].value, elements[0].value + elements[1].value + h);
        long long max_f_val_B = std::max(elements[n-1].value + elements[n-2].value, elements[0].value + elements[n-1].value + h);
        long long goodness_B = max_f_val_B - min_f_val_B;

        if (goodness_B < min_goodness) {
            min_goodness = goodness_B;
            best_p[elements[0].original_index] = 1;
            for (int i = 1; i < n; ++i) {
                best_p[elements[i].original_index] = 2;
            }
        }
    }

    std::cout << min_goodness << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << best_p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

