int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the minimum r such that [l, r] contains a bad triplet.
                                                // Using 1-based indexing for l and r.
                                                // Initialize with n+1, meaning no such r found yet.

    // Iterate through all possible starting positions x (0-indexed)
    // and all possible k (distance between elements)
    for (int x = 0; x < n; ++x) {
        // k can be 1, 2, 3, ...
        // x + 2k must be less than n
        // So 2k < n - x
        // k < (n - x) / 2
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, x+k, x+2k)
                // This triplet covers the range [x, x+2k] (0-indexed)
                // In 1-based indexing, this is [x+1, x+2k+1]
                int l_val = x + 1;
                int r_val = x + 2 * k + 1;

                // For any l' from 1 to l_val, if l' <= l_val,
                // the pair (l', r_val) contains this bad triplet.
                // We are interested in the minimum r_val for a given l'.
                // So, for l_val, we update min_r_for_l[l_val] = min(min_r_for_l[l_val], r_val).
                // This is the core idea: for a fixed l, what is the smallest r that satisfies the condition?
                // We only need to store the smallest r_val for each l_val.
                min_r_for_l[l_val] = std::min(min_r_for_l[l_val], r_val);

                // Optimization: If k is large, say k >= 6, then x+2k is at least x+12.
                // The problem constraints on n (300,000) and the small number of distinct characters (2)
                // suggest that such triplets are very rare for large k.
                // The maximum possible k is (n-1)/2.
                // If k is large, the range [x, x+2k] is wide.
                // If we find a triplet for a large k, it's likely that a smaller k
                // would have already covered the same or a smaller range.
                // For example, if s[x] == s[x+k] == s[x+2k], then for any l' <= x+1,
                // the pair (l', x+2k+1) is valid.
                // The maximum k we need to check is relatively small.
                // If k >= 6, then x+2k >= x+12.
                // Any triplet (x, x+k, x+2k) implies that s[x], s[x+k], s[x+2k] are the same.
                // If we have s[i] == s[i+1] == s[i+2] == s[i+3] == s[i+4] == s[i+5] == s[i+6],
                // then we have triplets like (i, i+1, i+2), (i, i+2, i+4), (i, i+3, i+6), etc.
                // The smallest possible range for a triplet is [x, x+2].
                // The maximum k to check can be limited.
                // If k > 5, then 2k > 10.
                // If we have a triplet (x, x+k, x+2k) with k > 5,
                // then the length of the segment is at least 12.
                // It's highly probable that a shorter segment already exists.
                // For example, if s[x] == s[x+k] == s[x+2k] for k=6,
                // then s[x] == s[x+6] == s[x+12].
                // This means we have a segment of length 13.
                // The maximum length of a segment that does NOT contain a triplet is 11.
                // (e.g., 00110011001 or 01010101010)
                // If a segment has length 12 or more, it must contain a triplet.
                // So, we only need to check k up to 5.
                // If k=1, (x, x+1, x+2)
                // If k=2, (x, x+2, x+4)
                // If k=3, (x, x+3, x+6)
                // If k=4, (x, x+4, x+8)
                // If k=5, (x, x+5, x+10)
                // The maximum length of a segment we need to check for a triplet is 11 (x to x+10).
                // If x+2k >= x+11, then k >= 6.
                // So, we can break if k > 5.
                if (k > 5) {
