    for (int l = n; l >= 1; --l) {
        // Update current_min_r:
        // For the current l, the minimum r that satisfies the condition is either
        // min_r_for_l[l] (if a triplet starts exactly at l)
        // OR current_min_r (if a triplet starts at some l' > l, but still covers l).
        // Since we are iterating l downwards, current_min_r already holds the minimum r
        // for any l' > l. So, we take the minimum of min_r_for_l[l] and current_min_r.
        current_min_r = std::min(current_min_r, min_r_for_l[l]);

        // If current_min_r is still n+1, it means no triplet covers any range starting at or after l.
        // So, no valid (l, r) pairs for this l.
        if (current_min_r == n + 1) {
            // No valid r for this l, and for any smaller l, current_min_r will remain n+1
            // unless a new triplet is found.
            // Since we are iterating l downwards, if current_min_r is n+1, it means
            // no triplet starts at or after l.
            // So, for this l and any smaller l, there are no valid r's.
            // We can break early.
            break;
        }

        // For the current l, any r such that current_min_r <= r <= n is a valid pair (l, r).
        // The number of such r's is (n - current_min_r + 1).
        total_count += (n - current_min_r + 1);
    }

    std::cout << total_count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current index for target tracks
    for (int i = 0; i < n; ++i) { // Iterate through each head
        if (p_idx == m) { // All target tracks covered
            return true;
        }

        long long current_head_pos = h[i];
        long long head_left_reach = current_head_pos - T;
        long long head_right_reach = current_head_pos + T;

        // If the current head cannot reach the current target track p[p_idx]
        // even by moving left as much as possible, then this head cannot cover it.
        // We need to find the first target track that this head can cover.
        // This is implicitly handled by the loop below.

        // Find the first target track p[p_idx] that is within reach of current_head_pos - T
        // If p[p_idx] is already to the right of head_right_reach, this head cannot cover it.
        // If p[p_idx] is to the left of head_left_reach, this head cannot cover it.
        // We need to find the first p[p_idx] such that p[p_idx] >= head_left_reach.
        // This is not quite right. The head can move.
        // The head can cover any track k such that |h_i - k| <= T.
        // So, the head can cover tracks in [h_i - T, h_i + T].

        // The strategy is greedy: for each head, cover as many *uncovered* tracks as possible,
        // starting from the leftmost uncovered track.

        // If the current head h[i] can reach p[p_idx] (the first uncovered track)
        // i.e., p[p_idx] <= h[i] + T
        if (p[p_idx] <= current_head_pos + T) {
            // This head can cover p[p_idx].
            // Now, determine the maximum rightmost track this head can cover.
            // This depends on whether p[p_idx] is to the left or right of h[i].

            long long effective_right_reach;
            if (p[p_idx] <= current_head_pos) {
                // If p[p_idx] is to the left or at h[i], the head can move right from h[i]
                // to cover tracks up to h[i] + T.
                // Or it can move left to p[p_idx] and then move right from p[p_idx]
                // for a total of T time.
                // The range covered is [h[i] - T, h[i] + T].
                // If p[p_idx] is covered, the head can then move right from p[p_idx]
                // for the remaining time.
                // The total range covered by this head is [h[i] - T, h[i] + T].
                // The rightmost track it can cover is h[i] + T.
                effective_right_reach = current_head_pos + T;
            } else { // p[p_idx] > current_head_pos
                // If p[p_idx] is to the right of h[i], the head must move right to reach p[p_idx].
                // Time spent to reach p[p_idx] is p[p_idx] - h[i].
                // Remaining time is T - (p[p_idx] - h[i]).
                // From p[p_idx], it can move further right by this remaining time.
                // So, it can reach up to p[p_idx] + (T - (p[p_idx] - h[i])) = h[i] + T.
                // This is the same as the previous case.
                // The head can cover any track in [h[i] - T, h[i] + T].
                // The crucial part is that it must cover p[p_idx].
                // If p[p_idx] is covered, the head can then move to cover other tracks.
                // The maximum rightmost track it can cover is h[i] + T.
                // However, if p[p_idx] is far to the right, say h[i] + T_prime,
                // then the head spends T_prime time to reach p[p_idx].
                // It has T - T_prime time left.
                // It can use this time to move left or right from p[p_idx].
                // So it can cover tracks in [p[p_idx] - (T - T_prime), p[p_idx] + (T - T_prime)].
                // This simplifies to [p[p_idx] - (T - (p[p_idx] - h[i])), p[p_idx] + (T - (p[p_idx] - h[i]))]
                // = [2*p[p_idx] - h[i] - T, h[i] + T].
                // The rightmost point is h[i] + T.
                // The leftmost point is 2*p[p_idx] - h[i] - T.
                // This leftmost point must be <= h[i] - T.
                // 2*p[p_idx] - h[i] - T <= h[i] - T
                // 2*p[p_idx] <= 2*h[i]
                // p[p_idx] <= h[i]. This is a contradiction for this branch.

                // Let's re-evaluate.
                // A head at h_i can cover a range [L, R] such that R - L + 1 tracks are covered,
                // and the total time spent is min_k (abs(h_i - k) + abs(k - L) + abs(k - R))
                // This is not how it works. A head can visit any track k such that |h_i - k| <= T.
                // If it visits k, then k is read.
                // We need to cover all p_j.
                // The greedy strategy is: for the current head h[i], find the leftmost uncovered track p[p_idx].
                // If h[i] can reach p[p_idx] (i.e., p[p_idx] <= h[i] + T), then this head can cover p[p_idx].
                // To maximize the number of tracks covered by this head, it should cover p[p_idx]
                // and then move as far right as possible.
                // The total distance it can travel is T.
                // If it moves from h[i] to p[p_idx], it uses |h[i] - p[p_idx]| time.
                // It has T - |h[i] - p[p_idx]| time remaining.
                // It can use this remaining time to move further right from p[p_idx].
                // So, the rightmost track it can cover is p[p_idx] + (T - |h[i] - p[p_idx]|).
                effective_right_reach = p[p_idx] + (T - std::abs(current_head_pos - p[p_idx]));
            }

            // Advance p_idx past all tracks covered by this head
            while (p_idx < m && p[p_idx] <= effective_right_reach) {
                p_idx++;
            }
        }
    }
    return p_idx == m; // All target tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // Max possible T: (max_p - min_h) or (max_h - min_p) or (max_p - min_p)
    // A safe upper bound is the distance between the furthest head and furthest track,
    // or simply the maximum possible coordinate value.
    // Max coordinate is 10^10. So 2 * 10^10 is a safe upper bound.
    long long high = 20000000000LL; // 2 * 10^10
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long n, m, k;
        std::cin >> n >> m >> k;
        long long abs_n = std::abs(n);
        long long abs_m = std::abs(m);
        long long min_coord = std::min(abs_n, abs_m);
        long long max_coord = std::max(abs_n, abs_m);

        if (k < max_coord) {
            std::cout << -1 << "\n";
        } else {
            long long remaining_moves = k - max_coord;
            long long diagonal_moves = min_coord;
            long long axial_moves = max_coord - min_coord;

            if (remaining_moves % 2 == 0) {
                // If remaining_moves is even, we can use pairs of moves that cancel out
                // or move along an axis without changing parity of total moves.
                // E.g., (1,0) then (-1,0) or (1,1) then (-1,-1)
                // Each such pair uses 2 moves and doesn't change final position.
                // We can convert 2 axial moves into 2 diagonal moves if needed,
                // or just add 2 diagonal moves that cancel out.
                // The maximum number of diagonal moves is k.
                std::cout << k << "\n";
            } else {
                // If remaining_moves is odd, we must end up with an odd number of axial moves.
                // This means we must use at least one axial move that doesn't cancel out.
                // The parity of (k - max_coord) determines the parity of the number of axial moves
                // that contribute to the final position.
                // If (k - max_coord) is odd, we must have an odd number of axial moves.
                // This means we cannot make all moves diagonal.
                // We can achieve k-1 diagonal moves by using one axial move and k-1 diagonal moves.
                // For example, if we need to reach (X,Y) in K moves, and K-max(X,Y) is odd.
                // We can reach (X,Y) in max(X,Y) moves, with min(X,Y) diagonal and max(X,Y)-min(X,Y) axial.
                // The remaining K-max(X,Y) moves are odd.
                // We can use one axial move (e.g., (1,0) then (-1,0) is 2 moves, (1,1) then (-1,-1) is 2 moves).
                // If we have an odd number of remaining moves, we must use one move that changes parity.
                // This means we can't make all k moves diagonal.
                // We can make k-1 moves diagonal and one axial.
                // Example: (0,0) -> (1,0) -> (0,0) -> (1,0) ...
                // If we have an odd number of remaining moves, we can use one axial move and then
                // (remaining_moves - 1) / 2 pairs of (1,1) and (-1,-1) moves.
                // This means we will have one axial move that doesn't cancel out.
                // So, the maximum diagonal moves would be k-1.
                std::cout << k - 1 << "\n";
            }
        }
    }
    return 0;
}

