#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> a_initial(n);
    std::vector<long long> current_delta(n, 0);

    // Initialize a_initial with a very large positive value
    // This ensures that a_initial[j] + current_delta[j] will be at least m_k
    // and we can then reduce a_initial[j] to satisfy the <= m_k constraint.
    // The maximum possible m_k is 5*10^7.
    // The maximum possible delta is 5000 * 10^4 = 5*10^7.
    // So a_initial[j] could be around 5*10^7 - (-5*10^7) = 10^8.
    // A value like 10^9 is safe.
    for (int i = 0; i < n; ++i) {
        a_initial[i] = 1000000000LL; // Max allowed initial value is 10^9
    }

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            // Type 1 operation: increase a[j] by d
            // This means the initial value a_initial[j] effectively decreases
            // by d for future type 2 queries to maintain the same current value.
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else {
            // Type 2 operation: max(a[l...r]) = m
            // For each j in [l, r], a_initial[j] + current_delta[j] <= m
            // So, a_initial[j] <= m - current_delta[j]
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a_initial[j] = std::min(a_initial[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Verify the solution
    std::vector<long long> a_current = a_initial;
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                a_current[j] += ops[i].val;
            }
        } else {
            long long max_val = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val = std::max(max_val, a_current[j]);
            }
            if (max_val != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a_initial[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

