#include <string>
#include <vector>
#include <algorithm>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_z = 0;
    int count_e = 0;
    int count_r = 0;
    int count_o = 0;
    int count_n = 0;

    for (char c : s) {
        if (c == 'z') {
            count_z++;
        } else if (c == 'e') {
            count_e++;
        } else if (c == 'r') {
            count_r++;
        } else if (c == 'o') {
            count_o++;
        } else if (c == 'n') {
            count_n++;
        }
    }

    // To maximize the binary number, prioritize '1's (from "one")
    // "one" uses 'o', 'n', 'e'
    int num_ones = count_n; // 'n' is unique to "one" among the letters 'o', 'n', 'e' for "one" and 'z', 'e', 'r', 'o' for "zero"

    // "zero" uses 'z', 'e', 'r', 'o'
    int num_zeros = count_z; // 'z' is unique to "zero"

    // The problem guarantees that it's possible to form a sequence of "one"s and "zero"s.
    // This implies that the counts of 'n' directly determine the number of '1's,
    // and the counts of 'z' directly determine the number of '0's.
    // The other letters ('e', 'r', 'o') are shared or used in specific ways that
    // are consistent with these counts.
    // For example, if we have `k` 'n's, we must form `k` "one"s.
    // If we have `m` 'z's, we must form `m` "zero"s.
    // The total count of 'e's, 'r's, 'o's must match `k` * (e_in_one) + `m` * (e_in_zero) etc.
    // Since 'n' only appears in "one" and 'z' only appears in "zero",
    // the number of '1's is simply `count_n` and the number of '0's is simply `count_z`.

    std::vector<int> result;
    for (int i = 0; i < num_ones; ++i) {
        result.push_back(1);
    }
    for (int i = 0; i < num_zeros; ++i) {
        result.push_back(0);
    }

    // Print the result
    for (size_t i = 0; i < result.size(); ++i) {
        std::cout << result[i] << (i == result.size() - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

