int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;

        // To craft k torches, we need k sticks and k coal.
        // Each coal costs y sticks. So, k coal costs k * y sticks.
        // Total sticks needed for crafting and buying coal: k + k * y = k * (y + 1)
        long long total_sticks_required = k * (y + 1);

        // We start with 1 stick.
        // We need to acquire (total_sticks_required - 1) additional sticks using trade offer 1.
        // Trade offer 1: exchange 1 stick for x sticks. Net gain is (x - 1) sticks per trade.
        // Number of times we need to use trade offer 1:
        // (total_sticks_required - 1) / (x - 1)
        // If (total_sticks_required - 1) is not perfectly divisible by (x - 1),
        // we need one more trade to get the remaining sticks.
        long long trades_for_sticks = (total_sticks_required - 1 + (x - 1) - 1) / (x - 1);

        // Number of trades for coal: k trades (1 trade for each coal)
        long long trades_for_coal = k;

        // Total trades = trades for sticks + trades for coal
        long long total_trades = trades_for_sticks + trades_for_coal;

        std::cout << total_trades << "\n";
    }
    return 0;
}

