    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        std::vector<long long> b(n);
        bool has_one = false;
        bool has_minus_one = false;
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
            if (a[i] == 1) {
                has_one = true;
            } else if (a[i] == -1) {
                has_minus_one = true;
            }
        }
        for (int i = 0; i < n; ++i) {
            std::cin >> b[i];
        }

        bool possible = true;
        if (a[0] != b[0]) {
            possible = false;
        }

        for (int i = n - 1; i >= 1; --i) {
            if (!possible) break;

            if (a[i] == b[i]) {
                continue;
            }

            if (a[i] < b[i]) { // Need to increase a[i]
                if (!has_one) {
                    possible = false;
                    break;
                }
            } else { // a[i] > b[i], Need to decrease a[i]
                if (!has_minus_one) {
                    possible = false;
                    break;
                }
            }
        }

        if (possible) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }
    return 0;
}

