    // In that case, min(p[i], p[j]) = p[i]. So p[i] would be one of the values in the row.
    // If p[i] is the largest element (n), then all other p[j] are smaller, so min(p[i], p[j]) = p[j].
    // The maximum of these p[j] would be n-1.
    // So, if max_val_in_row is n-1, it means p[i] must be n.
    // Otherwise, p[i] is simply max_val_in_row.

    bool found_n = false;
    for (int i = 0; i < n; ++i) {
        if (p[i] == n - 1 && !found_n) {
