void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the first index `i` from the right such that a[i] > a[i+1]
    // This marks the end of the longest non-decreasing suffix.
    int i = n - 2;
    while (i >= 0 && a[i] <= a[i+1]) {
        i--;
    }
    // After this loop, a[i+1 ... n-1] is non-decreasing.
    // If i < 0, the whole array is non-decreasing.

    // Find the first index `j` from the right such that a[j] < a[j+1]
    // This marks the end of the longest non-increasing suffix.
    // We start from `i` because any elements to the right of `i` are already part of a non-decreasing sequence.
    // If we want to find a non-increasing sequence, it must start at or before `i`.
    int j = i; // Start from where the non-decreasing suffix ended
    while (j >= 0 && a[j] >= a[j+1]) {
        j--;
    }
    // After this loop, a[j+1 ... i] is non-increasing.
    // The segment a[j+1 ... n-1] is a "mountain" or "valley" shape:
    // a[j+1] >= a[j+2] >= ... >= a[i] <= a[i+1] <= ... <= a[n-1]
    // Or more precisely, a[j+1 ... i] is non-increasing, and a[i+1 ... n-1] is non-decreasing.
    // The combined segment a[j+1 ... n-1] is the longest suffix that can be made good.

    // The length of the prefix to erase is j + 1.
    std::cout << j + 1 << std::endl;
