void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
        pos[p[i]] = i;
    }

    std::string result = "";
    int current_min_idx = pos[1];
    int current_max_idx = pos[1];

    for (int m = 1; m <= n; ++m) {
        // For m=1, the segment is just [1].
        // For m > 1, we need to expand the segment to include 'm'.
        // The segment must contain all numbers from 1 to m.
        // This means the segment must span from min_idx_of_1_to_m to max_idx_of_1_to_m.
        // The length of this segment must be exactly m.

        // Update current_min_idx and current_max_idx to include 'm'
        // These variables track the minimum and maximum indices encountered so far
        // for numbers 1 to current_m.
        current_min_idx = std::min(current_min_idx, pos[m]);
        current_max_idx = std::max(current_max_idx, pos[m]);

        // A number 'm' is beautiful if the segment p[current_min_idx ... current_max_idx]
        // contains exactly the numbers 1, 2, ..., m.
        // This implies two conditions:
        // 1. The length of the segment must be 'm'.
        //    (current_max_idx - current_min_idx + 1 == m)
        // 2. The minimum value in this segment must be 1, and the maximum value must be m.
        //    This is implicitly handled by how current_min_idx and current_max_idx are updated.
        //    By construction, current_min_idx and current_max_idx define the smallest contiguous
        //    range of indices that contains all numbers from 1 to m.
        //    If this range has length 'm', it means all numbers from 1 to m are present,
        //    and no other numbers are present (because if another number 'x' was present,
        //    and x > m, then max would be > m. If x < 1, then min would be < 1.
        //    But we are only considering numbers 1 to m, and the range is minimal for these.
        //    So if length is m, it must be exactly 1..m).

        if (current_max_idx - current_min_idx + 1 == m) {
            result += '1';
        } else {
            result += '0';
        }
    }
    std::cout << result << "\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

