int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int current_diff_01 = 0; // Count of positions where a[k]='0', b[k]='1'
    int current_diff_10 = 0; // Count of positions where a[k]='1', b[k]='0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') {
            // Current position is '0' but should be '1'
            if (current_diff_10 > 0) {
                // We have a pending '1' that should be '0'.
                // We can swap a[i] ('0') with a[j] ('1') where a[j] should be '0'.
                // This fixes both positions. Cost is 0 for this pair, as it's already accounted for.
                // The '1' from a[j] goes to a[i], making a[i] correct.
                // The '0' from a[i] goes to a[j], making a[j] correct.
                current_diff_10--;
            } else {
                // No pending '1' that should be '0'.
                // This '0' needs to become '1'.
                // It contributes to the count of '0's that need to become '1's.
                current_diff_01++;
            }
        } else if (a[i] == '1' && b[i] == '0') {
            // Current position is '1' but should be '0'
            if (current_diff_01 > 0) {
                // We have a pending '0' that should be '1'.
                // We can swap a[i] ('1') with a[j] ('0') where a[j] should be '1'.
                // This fixes both positions. Cost is 0 for this pair, as it's already accounted for.
                // The '0' from a[j] goes to a[i], making a[i] correct.
                // The '1' from a[i] goes to a[j], making a[j] correct.
                current_diff_01--;
            } else {
                // No pending '0' that should be '1'.
                // This '1' needs to become '0'.
                // It contributes to the count of '1's that need to become '0's.
                current_diff_10++;
            }
        }
        // If a[i] == b[i], nothing changes for this position.
        // The cost for any pending mismatches (current_diff_01 or current_diff_10)
        // is accumulated at each step.
        cost += current_diff_01 + current_diff_10;
    }

    std::cout << cost << std::endl;

    return 0;
}

