int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point x_k such that x_k - x_i <= d

    for (int i = 0; i < n; ++i) {
        // For each x[i] as the leftmost point of a triplet,
        // find the maximum index 'right_ptr' such that x[right_ptr] - x[i] <= d.
        // Since x is sorted, we can advance right_ptr monotonically.
        while (right_ptr < n && x[right_ptr] - x[i] <= d) {
            right_ptr++;
        }
        // At this point, all points x[j] where i < j < right_ptr satisfy x[j] - x[i] <= d.
        // And all points x[k] where i < k < right_ptr satisfy x[k] - x[i] <= d.
        // We need to choose two points x_j and x_k such that i < j < k < right_ptr.
        // The number of available points for x_j and x_k is (right_ptr - 1) - (i + 1) + 1 = right_ptr - 1 - i.
        // Let m = right_ptr - 1 - i. These are the points x[i+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = right_ptr - 1 - i; // Number of points between x[i] and x[right_ptr] (exclusive of x[i], exclusive of x[right_ptr])
                                         // These are points x[i+1], x[i+2], ..., x[right_ptr-1].
                                         // If m < 2, we cannot form a triplet, so this term will be 0 or negative.
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

