int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n, k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins + k >= n) { // Can make all games 'W'
            if (n == 0) { // Should not happen based on constraints n >= 1
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + 2 * (n - 1) << "\n";
            }
            continue;
        }

        // Calculate initial score
        long long current_score = 0;
        if (s[0] == 'W') {
            current_score = 1;
        }
        for (int i = 1; i < n; ++i) {
            if (s[i] == 'W') {
                if (s[i - 1] == 'W') {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
            }
        }

        // Find segments of 'L's between 'W's
        std::vector<int> l_segments;
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        if (first_w == -1) { // All 'L's initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else {
                std::cout << 1 + 2 * (k - 1) << "\n";
            }
            continue;
        }

        // Fill 'L's between first_w and last_w
        int current_l_count = 0;
        for (int i = first_w + 1; i <= last_w; ++i) {
            if (s[i] == 'L') {
                current_l_count++;
            } else {
                if (current_l_count > 0) {
                    l_segments.push_back(current_l_count);
                }
                current_l_count = 0;
            }
        }
        std::sort(l_segments.begin(), l_segments.end());

        for (int segment_len : l_segments) {
            if (k >= segment_len) {
                k -= segment_len;
                current_score += 1 + 2 * segment_len; // 1 for connecting, 2 for each new W in segment
            } else {
                break;
            }
        }

        // Use remaining k to convert 'L's to 'W's at ends or within existing 'L's
        current_score += 2 * k;

        std::cout << current_score << "\n";
    }
    return 0;
}

