    // More precisely, if we have at least one toy with |v| >= 1 (A+D > 0), we can always make the final product's magnitude >= 1.
    // We can pick a toy from Box 1 or Box 4 (say, value X with |X| >= 1).
    // For all other toys, we can pick values very close to 1 (e.g., 0.999 for Box 3, -0.999 for Box 2).
    // Then the product of all these "close to 1" values will still be close to 1.
    // So X * (product of close to 1 values) will have magnitude >= 1.
    // This means if A+D > 0, we can always achieve |final_product| >= 1.
    // So, for Box 1: total_negatives is odd AND (A+D > 0).
    if (A + D > 0) {
        return true;
    } else {
        // If A+D == 0, all initial toys have magnitude < 1 (from Box 2 or Box 3).
        // Any product of these will also have magnitude < 1.
        // So, if A+D == 0, it's impossible to get |final_product| >= 1.
        return false;
    }
}

// Function to determine if Box 2 can be the special box
bool can_be_box2(long long A, long long B, long long C, long long D) {
    // Box 2: Negative, |v| < 1
    // To end up in Box 2, the final product must be negative and its magnitude must be < 1.

    // Sign: total_negatives must be odd.
    long long total_negatives = A + B;
    if (total_negatives % 2 == 0) {
        return false;
    }

    // Magnitude: |final_product| < 1.
    // This is always possible if there is at least one toy with |v| < 1 (B+C > 0).
    // If B+C > 0, we can pick a toy with value X where |X| < 1.
    // For all other toys, we can pick values very close to 1 (e.g., 1.001 for Box 4, -1.001 for Box 1).
    // Then the product of all these "close to 1" values will still be close to 1.
    // So X * (product of close to 1 values) will have magnitude < 1.
    // This means if B+C > 0, we can always achieve |final_product| < 1.
    // So, for Box 2: total_negatives is odd AND (B+C > 0).
    if (B + C > 0) {
        return true;
    } else {
        // If B+C == 0, all initial toys have magnitude >= 1 (from Box 1 or Box 4).
        // Any product of these will also have magnitude >= 1.
        // So, if B+C == 0, it's impossible to get |final_product| < 1.
        return false;
    }
}

// Function to determine if Box 3 can be the special box
bool can_be_box3(long long A, long long B, long long C, long long D) {
    // Box 3: Positive, |v| < 1
    // To end up in Box 3, the final product must be positive and its magnitude must be < 1.

    // Sign: total_negatives must be even.
    long long total_negatives = A + B;
    if (total_negatives % 2 == 1) {
        return false;
    }

    // Magnitude: |final_product| < 1.
    // This is possible if B+C > 0 (at least one toy with |v| < 1).
    // So, for Box 3: total_negatives is even AND (B+C > 0).
    if (B + C > 0) {
        return true;
    } else {
        // If B+C == 0, all initial toys have magnitude >= 1.
        // Any product of these will also have magnitude >= 1.
        // So, if B+C == 0, it's impossible to get |final_product| < 1.
        return false;
    }
}

// Function to determine if Box 4 can be the special box
bool can_be_box4(long long A, long long B, long long C, long long D) {
    // Box 4: Positive, |v| >= 1
    // To end up in Box 4, the final product must be positive and its magnitude must be >= 1.

    // Sign: total_negatives must be even.
    long long total_negatives = A + B;
    if (total_negatives % 2 == 1) {
        return false;
    }

    // Magnitude: |final_product| >= 1.
    // This is possible if A+D > 0 (at least one toy with |v| >= 1).
    // So, for Box 4: total_negatives is even AND (A+D > 0).
    if (A + D > 0) {
        return true;
    } else {
        // If A+D == 0, all initial toys have magnitude < 1.
        // Any product of these will also have magnitude < 1.
        // So, if A+D == 0, it's impossible to get |final_product| >= 1.
        return false;
    }
}

