#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

bool is_permutation(const std::vector<int>& arr, int len) {
    if (len == 0) {
        return false; // Permutations must have non-zero length
    }
    if (arr.size() < len) {
        return false;
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        if (arr[i] < 1 || arr[i] > len) {
            return false;
        }
        if (seen[arr[i]]) {
            return false;
        }
        seen[arr[i]] = true;
        if (arr[i] > max_val) {
            max_val = arr[i];
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<int> prefix_max(n + 1, 0);
    std::vector<bool> prefix_is_perm(n + 1, false);
    std::vector<bool> prefix_seen(n + 1, false);
    int current_max = 0;
    int distinct_count = 0;

    for (int i = 0; i < n; ++i) {
        int val = a[i];
        if (val > n || val < 1) { // Value out of possible range for any permutation up to length n
            // This path will never form a permutation, so we can stop tracking
            // or just let the logic below handle it.
            // For safety, we can mark future prefix_is_perm as false.
            // However, the problem states a_i <= n-1, so val <= n-1.
            // This check is mostly for robustness if constraints change.
        }

        if (val > current_max) {
            current_max = val;
        }

        if (val <= i + 1) { // Only consider values that could be part of a permutation of length i+1
            if (!prefix_seen[val]) {
                prefix_seen[val] = true;
                distinct_count++;
            } else {
                // Duplicate found, this prefix cannot be a permutation
                // Mark future prefix_is_perm as false
                // We can break here for this prefix check, but need to continue for prefix_max
                // A simpler way is to just let distinct_count not match i+1
            }
        } else {
            // Value is too large for a permutation of length i+1
            // This prefix cannot be a permutation
        }

        prefix_max[i + 1] = current_max;
        if (distinct_count == i + 1 && current_max == i + 1) {
            prefix_is_perm[i + 1] = true;
        }
    }

    std::vector<int> suffix_max(n + 1, 0);
    std::vector<bool> suffix_is_perm(n + 1, false);
    std::fill(prefix_seen.begin(), prefix_seen.end(), false); // Reuse prefix_seen for suffix
    current_max = 0;
    distinct_count = 0;

    for (int i = n - 1; i >= 0; --i) {
        int val = a[i];
        int len = n - i; // Length of the suffix starting at index i

        if (val > current_max) {
            current_max = val;
        }

        if (val <= len) { // Only consider values that could be part of a permutation of length len
            if (!prefix_seen[val]) { // Using prefix_seen as a generic 'seen' array
                prefix_seen[val] = true;
                distinct_count++;
            } else {
                // Duplicate found
            }
        } else {
            // Value too large for permutation of length len
        }

        suffix_max[len] = current_max;
        if (distinct_count == len && current_max == len) {
            suffix_is_perm[len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (prefix_is_perm[l1] && suffix_is_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

