#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end()); // Sort w in ascending order

    long long total_happiness = 0;

    // Friends with w_i = 1 get two times the largest available numbers.
    // These are the k_ones largest numbers.
    // Since w is sorted, friends with w_i = 1 are at the beginning of the sorted w array.
    // We iterate from the end of w to find friends with w_i = 1.
    // No, this is incorrect. w_i=1 friends should get the largest numbers.
    // The problem states "Lee would like to make his friends as happy as possible".
    // If w_i = 1, happiness is 2 * a_j. To maximize this, a_j should be as large as possible.
    // So, the k_ones friends with w_i = 1 should get the k_ones largest numbers from 'a'.
    // These are a[n-1], a[n-2], ..., a[n-k_ones].
    // Let's count how many friends have w_i = 1.
    int count_w_one = 0;
    for (int i = 0; i < k; ++i) {
        if (w[i] == 1) {
            count_w_one++;
        }
    }

    // Assign largest numbers to friends with w_i = 1
    // These friends are at the end of the sorted 'w' array if we sort 'w' in ascending order.
    // Or, if we sort 'w' in descending order, they are at the beginning.
    // Let's sort 'w' in descending order to process friends with w_i=1 first.
    std::sort(w.rbegin(), w.rend()); // Sort w in descending order

    int a_ptr_large = n - 1; // Pointer to the largest available number in 'a'
    int a_ptr_small = 0;     // Pointer to the smallest available number in 'a'

    // First, handle friends with w_i = 1. They get 2 * largest_available.
    // These are the first 'count_w_one' friends in the descending sorted 'w' array.
    for (int i = 0; i < count_w_one; ++i) {
        total_happiness += 2 * a[a_ptr_large];
        a_ptr_large--;
    }

    // Now handle friends with w_i > 1.
    // These are the remaining k - count_w_one friends.
    // They are at indices from 'count_w_one' to 'k-1' in the descending sorted 'w' array.
    // For each such friend, they get the largest available number as their max_val,
    // and the smallest available number as their min_val.
    // The largest available numbers are taken from a_ptr_large downwards.
    // The smallest available numbers are taken from a_ptr_small upwards.
    for (int i = count_w_one; i < k; ++i) {
        // This friend gets w[i] integers.
        // Their max_val will be a[a_ptr_large].
        total_happiness += a[a_ptr_large];
        a_ptr_large--;

        // Their min_val will be a[a_ptr_small].
        total_happiness += a[a_ptr_small];

        // The friend needs w[i] - 2 additional integers.
        // These should be the smallest available integers to leave larger ones for other friends.
        // So, we advance a_ptr_small by w[i] - 1 (one for the min_val, w[i]-2 for the others).
        a_ptr_small += (w[i] - 1);
    }

    std::cout << total_happiness << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

