int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long a_count = 0;
    long long mod = 1e9 + 7;

    // Iterate the string from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it means any 'a's to its left
            // will eventually interact with this 'b'.
            // Each 'a' to its left will cause this 'b' to duplicate
            // and move past the 'a'.
            // The number of 'a's currently accumulated (a_count)
            // represents the number of 'a's that will "pass through"
            // this 'b'.
            // Each such 'a' passing through this 'b' contributes
            // a_count steps.
            total_steps = (total_steps + a_count) % mod;
            // After all 'a's pass through this 'b', this 'b' effectively
            // becomes two 'b's for the 'a's further to the left.
            // So, the effective 'a_count' for the next 'b' (or 'a')
            // to its left doubles.
            a_count = (a_count * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' will eventually
            // need to move past all 'b's to its right.
            // This 'a' itself contributes 1 to the 'a_count' for
            // 'b's further to its left.
            a_count = (a_count + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n, k;
    std::cin >> n >> k;
    long long total_disassemble_cost = 0;
    long long total_assemble_cost = n - 1; // To form 1->2->...->n, we need n-1 nesting operations.
    long long saved_operations = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // Calculate disassemble cost for this chain
        // A chain of length m has m-1 direct nestings.
        // To disassemble it completely, we need m-1 operations.
        total_disassemble_cost += (m - 1);

        // Check for segments that are already in the target configuration
        // A segment a_j -> a_{j+1} is correct if a_j+1 == a_{j+1}
        // And if a_j is 1, then it's the start of the target chain.
        // If a_j is not 1, then it must be a_j-1 -> a_j -> a_j+1
        // The problem statement guarantees ascending order in chains.
        // So we only need to check if a_j+1 == a_{j+1}.

        // If the first element of a chain is 1, it's a potential start of the target chain.
        // We can save operations for the initial segment 1 -> 2 -> ... -> X
        if (chain[0] == 1) {
            long long current_saved_segment_length = 1; // For matryoshka 1 itself
            for (int j = 0; j < m - 1; ++j) {
                if (chain[j] + 1 == chain[j+1]) {
                    current_saved_segment_length++;
                } else {
                    break; // Chain breaks the 1->2->... pattern
                }
            }
            // If we have a segment 1 -> 2 -> ... -> X, it means X-1 nestings are already correct.
            // These X-1 nestings don't need to be disassembled and reassembled.
            // So we save (X-1) disassemble operations and (X-1) assemble operations.
            saved_operations += (current_saved_segment_length - 1);
        }
    }

    // The total time is:
    // (Total operations to disassemble all initial chains)
    // + (Total operations to assemble the final 1->...->n chain)
    // - (2 * operations saved by existing correct segments)
    // Each saved nesting means we don't disassemble it (1 op saved) and don't reassemble it (1 op saved).
    long long result = total_disassemble_cost + total_assemble_cost - (2 * saved_operations);

    std::cout << result << std::endl;

    return 0;
}

