}

#include <iostream>
#include <algorithm>

long long solve() {
    long long n;
    std::cin >> n;

    if (n == 1) {
        return 1;
    }
    if (n == 2) {
        return 1;
    }
    if (n == 3) {
        return 2;
    }

    // Case 1: N is odd
    // Chanek must take 1. N becomes N-1 (even).
    // Now it's opponent's turn with N-1 coins.
    // Opponent can take 1 or (N-1)/2.
    // If opponent takes 1, N becomes N-2 (odd).
    // If opponent takes (N-1)/2, N becomes (N-1)/2 (odd).
    // This path is complex. Let's consider the optimal strategy.

    // If N is odd, Chanek must take 1.
    // Remaining coins: N-1 (even).
    // Chanek's current coins: 1.
    // Now it's opponent's turn with N-1 coins.
    // Opponent will try to maximize their share from N-1.
    // The remaining N-1 coins will be split between opponent and Chanek.
    // The opponent will get (N-1)/2 coins from the remaining N-1.
    // Chanek will get (N-1)/2 coins from the remaining N-1.
    // So, Chanek's total coins = 1 + (N-1)/2 = (N+1)/2.
    // This is because if N-1 is even, the optimal strategy for the player whose turn it is
    // is to take (N-1)/2 if (N-1)/2 is odd, or take 1 if (N-1)/2 is even and small.
    // But for large N, taking N/2 is generally better.
    // If N-1 is even, the game on N-1 coins will result in a split of (N-1)/2 for the current player
    // and (N-1)/2 for the next player, if both play optimally.
    // This is because if the current player takes (N-1)/2, the remaining (N-1)/2 coins are left for the next player.
    // If the current player takes 1, the remaining N-2 coins are left.
    // The game on N-1 coins, where N-1 is even:
    // If current player takes (N-1)/2, they get (N-1)/2. Next player gets (N-1)/2.
    // If current player takes 1, they get 1. Next player plays on N-2.
    // The total coins for the current player from N-1 coins will be (N-1)/2.
    // So, if N is odd, Chanek takes 1. Remaining N-1. Chanek gets 1 + (N-1)/2 = (N+1)/2.

    // If N is even:
    // Chanek has two choices:
    // 1. Take 1 coin. Remaining N-1 (odd).
    //    Chanek's current coins: 1.
    //    Now it's opponent's turn with N-1 coins.
    //    Opponent will take 1 coin (since N-1 is odd). Remaining N-2 (even).
    //    Opponent's current coins: 1.
    //    Now it's Chanek's turn with N-2 coins.
    //    From N-2 coins, Chanek will get (N-2)/2.
    //    So, Chanek's total coins = 1 + (N-2)/2 = N/2.
    // 2. Take N/2 coins. Remaining N/2.
    //    Chanek's current coins: N/2.
    //    Now it's opponent's turn with N/2 coins.
    //    If N/2 is odd: Opponent takes 1. Remaining N/2 - 1 (even).
    //       Opponent's current coins: 1.
    //       Now it's Chanek's turn with N/2 - 1 coins.
    //       From N/2 - 1 coins, Chanek will get (N/2 - 1)/2.
    //       So, Chanek's total coins = N/2 + (N/2 - 1)/2 = (2N/2 + N/2 - 1)/2 = (3N/2 - 1)/2.
    //    If N/2 is even: Opponent takes N/4. Remaining N/4.
    //       Opponent's current coins: N/4.
    //       Now it's Chanek's turn with N/4 coins.
    //       From N/4 coins, Chanek will get N/8.
    //       So, Chanek's total coins = N/2 + N/8 = 5N/8.

    // Let's re-evaluate the optimal strategy for a player on their turn with X coins.
    // Let f(X) be the maximum coins the current player can get from X coins.
    // If X is odd: Current player must take 1. Remaining X-1.
    //   Current player gets 1 + (X-1 - f_opponent(X-1)).
    //   Since both play optimally, f_opponent(X-1) is the opponent's max from X-1.
    //   The total coins from X-1 will be split.
    //   If X-1 is even, the game on X-1 coins will result in (X-1)/2 for the current player (opponent)
    //   and (X-1)/2 for the next player (Chanek).
    //   So, if X is odd, Chanek takes 1. Chanek gets 1 + (X-1)/2 = (X+1)/2.

    // If X is even:
    //   Option 1: Take 1. Remaining X-1 (odd).
    //     Current player gets 1 + (X-1 - f_opponent(X-1)).
    //     f_opponent(X-1) = (X-1+1)/2 = X/2.
    //     So, current player gets 1 + (X-1 - X/2) = 1 + X/2 - 1 = X/2.
    //   Option 2: Take X/2. Remaining X/2.
    //     Current player gets X/2 + (X/2 - f_opponent(X/2)).
    //     f_opponent(X/2) is the opponent's max from X/2.
    //     This is where it gets recursive.

    // Let's consider the total coins. Chanek wants to maximize his share. Opponent wants to maximize their share.
