                        } else {
                            possible = false;
                            break;
                        }
                    } else { // current_digit == (char)('0' + k)
                        // Try to put it in color 1 if possible
                        if (can_color1) {
                            result[i] = '1';
                            last1 = current_digit;
                        } else if (can_color2) { // If not possible for color 1, try color 2
                            result[i] = '2';
                            last2 = current_digit;
                        } else { // Not possible for either
                            possible = false;
                            break;
                        }
                    }
                }
            } else if (can_color1) {
                result[i] = '1';
                last1 = current_digit;
            } else if (can_color2) {
                result[i] = '2';
                last2 = current_digit;
            } else {
                possible = false;
                break;
            }
        }

        if (possible) {
            std::cout << result << "\n";
            return;
        }
    }

    std::cout << "-\n";
}

