void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    // Step 1: Propagate known characters within k-spaced indices
    for (int i = 0; i < k; ++i) {
        char known_char = '?';
        for (int j = i; j < n; j += k) {
            if (s[j] != '?') {
                if (known_char != '?' && s[j] != known_char) {
                    std::cout << "NO\n";
                    return;
                }
                known_char = s[j];
            }
        }
        if (known_char != '?') {
            for (int j = i; j < n; j += k) {
                s[j] = known_char;
            }
        }
    }

    // Step 2: Check the first k characters for k/2 zeros and k/2 ones
    int zeros = 0;
    int ones = 0;
    int q_marks = 0;

    for (int i = 0; i < k; ++i) {
        if (s[i] == '0') {
            zeros++;
        } else if (s[i] == '1') {
            ones++;
        } else { // s[i] == '?'
            q_marks++;
        }
    }

    if (zeros > k / 2 || ones > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // The remaining '?' can always be filled to satisfy the k/2 condition
    // if zeros <= k/2 and ones <= k/2.
    // We need (k/2 - zeros) ones and (k/2 - ones) zeros from the '?'s.
    // The total '?'s needed is (k/2 - zeros) + (k/2 - ones).
    // This sum is k - (zeros + ones).
    // This must be equal to q_marks.
    // Since we already checked zeros <= k/2 and ones <= k/2,
    // and q_marks = k - (zeros + ones), this condition is implicitly met.

    std::cout << "YES\n";
}

