#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of r from 1 to b-1: (b-1) * b / 2
    // This is sum_r_val
    long long sum_r_val;
    if (b == 1) { // If b=1, then r must be 0, but r!=0. So sum_r_val is 0.
        sum_r_val = 0;
    } else {
        long long b_minus_1 = b - 1;
        long long b_val = b;

        // One of b_minus_1 or b_val must be even.
        // Divide by 2 first to avoid overflow before modulo, then multiply.
        // (X * Y / 2) % MOD = ((X % (2*MOD)) * (Y % (2*MOD)) / 2) % MOD
        // Or, more simply, if X is even, (X/2 * Y) % MOD. If Y is even, (X * Y/2) % MOD.
        if (b_minus_1 % 2 == 0) {
            sum_r_val = (b_minus_1 / 2) % MOD;
            sum_r_val = (sum_r_val * (b_val % MOD)) % MOD;
        } else { // b_val must be even
            sum_r_val = (b_val / 2) % MOD;
            sum_r_val = (sum_r_val * (b_minus_1 % MOD)) % MOD;
        }
    }

    // Sum of (k*b + 1) from k=1 to a
    // This is sum_kb_plus_1_val
    // sum_{k=1 to a} (k*b + 1) = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // = b * (a * (a+1) / 2) + a
    long long sum_k_val;
    long long a_val = a;
    long long a_plus_1 = a + 1;

    if (a_val % 2 == 0) {
        sum_k_val = (a_val / 2) % MOD;
        sum_k_val = (sum_k_val * (a_plus_1 % MOD)) % MOD;
    } else { // a_plus_1 must be even
        sum_k_val = (a_plus_1 / 2) % MOD;
        sum_k_val = (sum_k_val * (a_val % MOD)) % MOD;
    }

    long long sum_kb_plus_1_val = ( ( (b % MOD) * sum_k_val ) % MOD + (a % MOD) ) % MOD;

    // Total sum = sum_r_val * sum_kb_plus_1_val
    long long total_sum = (sum_r_val * sum_kb_plus_1_val) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

long long solve() {
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 1) {
        return (h[0] + 1) / 2;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {value, index}

    for (int i = 0; i < n; ++i) {
        long long current_val = h[i] - i;
        while (!dq_L.empty() && dq_L.back().first >= current_val) {
            dq_L.pop_back();
        }
        dq_L.push_back({current_val, i});

        while (dq_L.front().second < i - h[i] + 1) { // Equivalent to i - (h[i]-1) - 1
            dq_L.pop_front();
        }
        L[i] = dq_L.front().first + i;
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {value, index}

    for (int i = n - 1; i >= 0; --i) {
        long long current_val = h[i] + i;
        while (!dq_R.empty() && dq_R.back().first >= current_val) {
            dq_R.pop_back();
        }
        dq_R.push_back({current_val, i});

        while (dq_R.front().second > i + h[i] - 1) { // Equivalent to i + (h[i]-1) + 1
            dq_R.pop_front();
        }
        R[i] = dq_R.front().first - i;
    }

    long long max_k = 0;
    for (int i = 0; i < n; ++i) {
        max_k = std::max(max_k, std::min(h[i], std::min(L[i], R[i])));
    }

    return max_k;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::cout << solve() << std::endl;
    return 0;
}

