#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits initially 1
    int current_or_mask = 0;    // All bits initially 0
    int current_xor_mask = 0;   // All bits initially 0

    for (int k = 0; k < n; ++k) {
        char op_char;
        int val;
        std::cin >> op_char >> val;

        if (op_char == '&') {
            current_and_mask &= val;
            current_or_mask &= val;
            current_xor_mask &= val;
        } else if (op_char == '|') {
            current_and_mask |= val;
            current_or_mask |= val;
            current_xor_mask |= val;
        } else if (op_char == '^') {
            current_and_mask ^= val;
            current_or_mask ^= val;
            current_xor_mask ^= val;
        }
    }

    // Now we have the final state of 0, 1, and x after all operations.
    // Let's denote the final state of an input bit 0 as f(0) and an input bit 1 as f(1).
    // For each bit position i:
    // f(0)_i = (0 & current_and_mask_i) | current_or_mask_i ^ current_xor_mask_i
    // f(1)_i = (1 & current_and_mask_i) | current_or_mask_i ^ current_xor_mask_i

    // Simplified:
    // f(0)_i = current_or_mask_i ^ current_xor_mask_i
    // f(1)_i = current_and_mask_i | current_or_mask_i ^ current_xor_mask_i

    // We need to find A, B, C such that for any input bit x_i:
    // (x_i & A_i) | B_i ^ C_i = f(x_i)_i

    // Let's determine the equivalent single AND, OR, XOR constants.
    int final_and_const = 1023; // Represents the A in (x & A)
    int final_or_const = 0;     // Represents the B in | B
    int final_xor_const = 0;    // Represents the C in ^ C

    for (int i = 0; i < 10; ++i) { // Iterate through bits 0 to 9
        int bit_0_result = ((current_or_mask >> i) & 1) ^ ((current_xor_mask >> i) & 1);
        int bit_1_result = (((current_and_mask >> i) & 1) | ((current_or_mask >> i) & 1)) ^ ((current_xor_mask >> i) & 1);

        // Case 1: f(0)_i = 0, f(1)_i = 0
        // This means the bit is always 0, regardless of input.
        // (x & 0) | 0 ^ 0 = 0
        // (x & 1) | 0 ^ 1 = x ^ 1
        // (x & 0) | 1 ^ 0 = 1
        // (x & 1) | 1 ^ 1 = 1 | 1 = 1
        // To make it always 0:
        // A_i = 0, B_i = 0, C_i = 0 -> (x & 0) | 0 ^ 0 = 0
        // A_i = 0, B_i = 1, C_i = 1 -> (x & 0) | 1 ^ 1 = 0
        if (bit_0_result == 0 && bit_1_result == 0) {
            final_and_const &= ~(1 << i); // A_i = 0
            final_or_const &= ~(1 << i);  // B_i = 0
            final_xor_const &= ~(1 << i); // C_i = 0
        }
        // Case 2: f(0)_i = 0, f(1)_i = 1
        // This means the bit is always x_i (identity).
        // (x & 1) | 0 ^ 0 = x
        if (bit_0_result == 0 && bit_1_result == 1) {
            final_and_const |= (1 << i);  // A_i = 1
            final_or_const &= ~(1 << i);  // B_i = 0
            final_xor_const &= ~(1 << i); // C_i = 0
        }
        // Case 3: f(0)_i = 1, f(1)_i = 0
        // This means the bit is always ~x_i (NOT x_i).
        // (x & 1) | 0 ^ 1 = ~x
        if (bit_0_result == 1 && bit_1_result == 0) {
            final_and_const |= (1 << i);  // A_i = 1
            final_or_const &= ~(1 << i);  // B_i = 0
            final_xor_const |= (1 << i);  // C_i = 1
        }
        // Case 4: f(0)_i = 1, f(1)_i = 1
        // This means the bit is always 1, regardless of input.
        // (x & 0) | 1 ^ 0 = 1
        if (bit_0_result == 1 && bit_1_result == 1) {
            final_and_const &= ~(1 << i); // A_i = 0
            final_or_const |= (1 << i);   // B_i = 1
            final_xor_const &= ~(1 << i); // C_i = 0
        }
    }

    std::vector<std::pair<char, int>> result_ops;
    if (final_and_const != 1023) { // If A is not all 1s, we need an AND operation
        result_ops.push_back({'&', final_and_const});
    }
    if (final_or_const != 0) { // If B is not all 0s, we need an OR operation
        result_ops.push_back({'|', final_or_const});
    }
    if (final_xor_const != 0) { // If C is not all 0s, we need an XOR operation
        result_ops.push_back({'^', final_xor_const});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: [1, 1], add -a[0]
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        // Operation 2: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        // Operation 3: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] divisible by n
        // For each a[i], we want a[i] + b_i = k * n for some integer k.
        // We need a[i] + b_i = 0 (mod n).
        // So, b_i = (n - (a[i] % n)) % n.
        // If a[i] % n == 0, b_i = 0.
        // If a[i] % n != 0, b_i = n - (a[i] % n).
        // This b_i is a multiple of 1 (the length of the segment [i+1, i+1] if we were to do it individually).
        // But we are doing it on segment [1, n-1] (length n-1).
        // The problem states "add a multiple of len".
        // Let's use the strategy:
        // 1. Make a[0]...a[n-2] multiples of n.
        //    For each a[i] (0 <= i < n-1), calculate x_i such that (a[i] + x_i) % n == 0.
        //    x_i = (n - (a[i] % n)) % n.
        //    Then add x_i * n to a[i]. This makes a[i] a multiple of n.
        //    The added value is x_i * n. This is a multiple of n.
        //    This is not what the problem implies. The problem implies we add a multiple of *segment length*.
        //    Let's re-read: "add a multiple of len to it".
        //    This means for a segment [l, r] with length `len = r-l+1`, we can add `k * len` to `a[i]` for `i` in `[l, r]`.
        //    We want `a[i] + k * len = 0`. This means `a[i]` must be a multiple of `len`.
        //    This is the key. We need to make `a[i]` a multiple of `len`.

        // Strategy:
        // 1. For elements a[0] to a[n-2]:
        //    Select segment [1, n-1]. Length is n-1.
        //    For each a[i] (0 <= i < n-1), we want to add b_i such that (a[i] + b_i) % (n-1) == 0.
        //    And b_i must be a multiple of (n-1).
        //    So, we need a[i] % (n-1) == 0.
        //    If a[i] % (n-1) != 0, we can add (n-1 - (a[i] % (n-1))) * (n-1) to a[i].
        //    This makes a[i] a multiple of (n-1).
        //    Let's call this value `add_val_i`.
        //    `add_val_i = ( (n-1) - (a[i] % (n-1) + (n-1)) % (n-1) ) % (n-1) * (n-1)`
        //    This is wrong. `add_val_i` must be `k * (n-1)`.
        //    We want `a[i] + b_i = 0`. So `b_i = -a[i]`.
        //    This means `-a[i]` must be a multiple of `len`.
        //    So `a[i]` must be a multiple of `len`.
        //    This is the core issue. If `a[i]` is not a multiple of `len`, we can't make it zero in one step.

        // The trick is to make `a[i]` a multiple of `n` for all `i`.
        // Then in the last step, we can make them all zero.
        // Consider `a[i]`. We want to add `x_i` such that `a[i] + x_i = 0`.
        // `x_i` must be a multiple of `len`. So `a[i]` must be a multiple of `len`.

        // Let's use the specific construction for N > 1:
        // Operation 1: Segment [1, n-1] (elements a[0]...a[n-2]). Length is n-1.
        // For each a[i] (0 <= i < n-1):
        // We want to add `b_i` such that `a[i] + b_i` becomes a multiple of `n`.
        // And `b_i` must be a multiple of `n-1`.
        // Let `rem = a[i] % n`. If `rem < 0`, `rem += n`.
        // We want `a[i] + b_i = k * n`.
        // `b_i = k * n - a[i]`.
        // We also need `b_i` to be a multiple of `n-1`.
        // So `k * n - a[i]` must be a multiple of `n-1`.
        // `k * (n-1 + 1) - a[i]` must be a multiple of `n-1`.
        // `k * (n-1) + k - a[i]` must be a multiple of `n-1`.
        // So `k - a[i]` must be a multiple of `n-1`.
        // `k % (n-1) == a[i] % (n-1)`.
        // Let `k_0 = a[i] % (n-1)`. If `k_0 < 0`, `k_0 += (n-1)`.
        // We can choose `k = k_0`.
        // Then `b_i = k_0 * n - a[i]`.
        // This `b_i` is a multiple of `n-1` because `k_0 * n - a[i] = k_0 * (n-1 + 1) - a[i] = k_0 * (n-1) + k_0 - a[i]`.
        // Since `k_0 % (n-1) == a[i] % (n-1)`, `k_0 - a[i]` is a multiple of `n-1`.
        // So `b_i` is a multiple of `n-1`.
        // After this operation, `a[i]` becomes `a[i] + b_i = k_0 * n`. This is a multiple of `n`.

        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long current_a_i = a[i];
            long long rem_mod_n_minus_1 = (current_a_i % (n - 1) + (n - 1)) % (n - 1);
            long long k_val = rem_mod_n_minus_1;
            long long b_i = k_val * n - current_a_i;
            std::cout << b_i << (i == n - 2 ? "" : " ");
            a[i] += b_i; // Update a[i]
        }
        std::cout << "\n";

        // Operation 2: Segment [n, n] (element a[n-1]). Length is 1.
        // For a[n-1], we want to add `b_{n-1}` such that `a[n-1] + b_{n-1}` becomes a multiple of `n`.
        // And `b_{n-1}` must be a multiple of 1. This is always true.
        // Let `rem = a[n-1] % n`. If `rem < 0`, `rem += n`.
        // We want `a[n-1] + b_{n-1} = k * n`.
        // We can choose `k = 0`. Then `b_{n-1} = -a[n-1]`.
        // This makes `a[n-1]` zero.
        // But we need it to be a multiple of `n`.
        // Let `rem_mod_n = (a[n-1] % n + n) % n`.
        // We want to add `b_{n-1}` such that `a[n-1] + b_{n-1}` is a multiple of `n`.
        // `b_{n-1} = (n - rem_mod_n) % n`.
        // This `b_{n-1}` is a multiple of 1.
        // After this, `a[n-1]` becomes `a[n-1] + b_{n-1}` which is a multiple of `n`.

        std::cout << n << " " << n << "\n";
        long long current_a_n_minus_1 = a[n - 1];
        long long rem_mod_n = (current_a_n_minus_1 % n + n) % n;
        long long b_n_minus_1 = (n - rem_mod_n) % n;
        std::cout << b_n_minus_1 << "\n";
        a[n - 1] += b_n_minus_1; // Update a[n-1]

        // Now all elements a[i] are multiples of n.
