#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    int initial_s = 0;
    int initial_b = 0;
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
        if (a[i] == 1) {
            initial_s++;
        } else {
            initial_b++;
        }
    }

    int initial_diff = initial_s - initial_b;

    if (initial_diff == 0) {
        std::cout << 0 << std::endl;
        return;
    }

    // Calculate prefix sums for the left half (jars 1 to n)
    // diff_L[k] = (count of 1s - count of 2s) in jars 1 to k
    std::vector<int> diff_L(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_L[i + 1] = diff_L[i] + (a[i] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the right half (jars n+1 to 2n)
    // diff_R[k] = (count of 1s - count of 2s) in jars 2n-k+1 to 2n
    std::vector<int> diff_R(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        diff_R[i + 1] = diff_R[i] + (a[2 * n - 1 - i] == 1 ? 1 : -1);
    }

    // Store the minimum k_L for each diff_L value
    // map: diff_value -> min_k_L
    std::map<int, int> min_kL_for_diff;
    for (int k = 0; k <= n; ++k) {
        if (min_kL_for_diff.find(diff_L[k]) == min_kL_for_diff.end()) {
            min_kL_for_diff[diff_L[k]] = k;
        }
    }

    int min_removed = 2 * n; // Max possible jars to remove

    // Iterate through possible number of jars removed from the right (k_R)
    // For each k_R, we calculate the required diff from the left side
    // to make the total remaining diff zero.
    for (int k_R = 0; k_R <= n; ++k_R) {
        // If k_L jars are removed from left and k_R jars from right,
        // the remaining jars are from index k_L to 2n-1-k_R.
        // The total difference in remaining jars is:
        // initial_diff - (diff_L[k_L] + diff_R[k_R])
        // We want this to be 0.
        // So, initial_diff - diff_L[k_L] - diff_R[k_R] = 0
        // This means diff_L[k_L] = initial_diff - diff_R[k_R]

        int target_diff_L = initial_diff - diff_R[k_R];

        if (min_kL_for_diff.count(target_diff_L)) {
            int k_L = min_kL_for_diff[target_diff_L];
            min_removed = std::min(min_removed, k_L + k_R);
        }
    }

    std::cout << min_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

