long long solve() {
    long long n, m;
    std::cin >> n >> m;

    if (m == 0) {
        return 0;
    }

    long long total_substrings = n * (n + 1) / 2;

    // Number of zeros
    long long num_zeros = n - m;

    // To minimize substrings of all zeros, distribute zeros as evenly as possible.
    // This means placing '1's to break up long sequences of '0's.
    // If there are m ones, they can create m+1 potential blocks of zeros.
    // However, if we place '1's like 01010, we use m-1 ones to separate m blocks of zeros.
    // The remaining 1s can be placed anywhere.
    // The optimal strategy is to distribute the 'num_zeros' into 'm + 1' groups as evenly as possible.
    // This creates 'm + 1' blocks of zeros, some of which might be empty.
    // For example, if s = "01010", n=5, m=2. num_zeros = 3.
    // We have m+1 = 3 blocks of zeros: "0", "0", "0".
    // The '1's are placed between these blocks.
    // The number of '1's is m. These 'm' ones can separate 'm+1' groups of zeros.
    // For example, _0_1_0_1_0_ where underscores are positions for zeros.
    // The number of '1's is m. These 'm' ones divide the string into m+1 segments.
    // The zeros are distributed among these m+1 segments.
    // Let k be the number of zeros in each of the 'm+1' segments.
    // We want to make these k's as equal as possible.
    // num_zeros = q * (m + 1) + r, where q is quotient, r is remainder.
    // This means r segments will have (q + 1) zeros, and (m + 1 - r) segments will have q zeros.

    long long q = num_zeros / (m + 1);
    long long r = num_zeros % (m + 1);

    long long num_blocks_q_plus_1 = r;
    long long num_blocks_q = (m + 1) - r;

    long long substrings_from_zeros = 0;
    if (q > 0) {
        substrings_from_zeros += num_blocks_q * (q * (q + 1) / 2);
    }
    if (q + 1 > 0) { // This condition is always true if r > 0, or if q > 0 and r = 0.
                     // If q=0 and r=0, then num_zeros=0, so this term is 0.
                     // If q=0 and r>0, then q+1=1, so 1*(1+1)/2 = 1.
        substrings_from_zeros += num_blocks_q_plus_1 * ((q + 1) * (q + 2) / 2);
    }

    return total_substrings - substrings_from_zeros;
}

