int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks vertices currently in the graph

    // Iterate through the removal steps in reverse
    // This means we are effectively adding vertices one by one
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being "added" back to the graph

        active[k] = true; // Mark vertex k as active

        // Floyd-Warshall update: consider paths going through k
        // For all pairs (i, j) of currently active vertices,
        // check if path i -> k -> j is shorter than current i -> j
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;

                // Update paths involving k as an intermediate node
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After updating paths using k as an intermediate,
        // k itself can be a source or destination for other active vertices.
        // So, we also need to update paths where k is an endpoint.
        // This is implicitly handled by the above triple loop if we consider
        // i, j, k to be any of the currently active vertices.
        // The standard Floyd-Warshall structure is:
        // for k:
        //   for i:
        //     for j:
        //       dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        // Here, k is the *newest* vertex, so it's the one that can potentially
        // shorten paths. The loops for i and j should only consider active vertices.
        // The current implementation of the triple loop correctly does this.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (from first step to last)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

