int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << std::endl;
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << std::endl;
        return 0;
    }

    std::vector<int> left_ones(n, 0);
    std::vector<int> right_ones(n, 0);

    // Calculate left_ones: distance to the nearest 1 on the left (inclusive)
    // If a[i] is 1, left_ones[i] = 0. If a[i] is 0, left_ones[i] = left_ones[i-1] + 1.
    // If no 1 on left, it's effectively infinity.
    if (a[0] == 1) {
        left_ones[0] = 0;
    } else {
        left_ones[0] = n + 1; // Represents infinity
    }
    for (int i = 1; i < n; ++i) {
        if (a[i] == 1) {
            left_ones[i] = 0;
        } else {
            left_ones[i] = left_ones[i - 1] + 1;
        }
    }

    // Calculate right_ones: distance to the nearest 1 on the right (inclusive)
    // If a[i] is 1, right_ones[i] = 0. If a[i] is 0, right_ones[i] = right_ones[i+1] + 1.
    // If no 1 on right, it's effectively infinity.
    if (a[n - 1] == 1) {
        right_ones[n - 1] = 0;
    } else {
        right_ones[n - 1] = n + 1; // Represents infinity
    }
    for (int i = n - 2; i >= 0; --i) {
        if (a[i] == 1) {
            right_ones[i] = 0;
        } else {
            right_ones[i] = right_ones[i + 1] + 1;
        }
    }

    int max_dist = 0;
    for (int i = 0; i < n; ++i) {
        if (a[i] == 0) {
            int dist_to_nearest_one = std::min(left_ones[i], right_ones[i]);
            max_dist = std::max(max_dist, dist_to_nearest_one);
        }
    }

    int k = (max_dist + 1) / 2;

    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];

    for (int i = 1; i < n - 1; ++i) {
        if (a[i] == 1) {
            b[i] = 1; // 1s never change to 0s
        } else { // a[i] == 0
            if (left_ones[i] <= k && right_ones[i] <= k) {
                b[i] = 1; // Becomes 1 if within k distance of 1s on both sides
            } else {
                b[i] = 0; // Remains 0 otherwise
            }
        }
    }

    std::cout << k << std::endl;
    for (int i = 0; i < n; ++i) {
        std::cout << b[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

