        // Initial state: (start_x, 0)
        // Step 2: x = start_x + current_a_x, y = 0 + current_a_x
        long long x_after_step2 = start_x + current_a_x;
        long long y_after_step2 = current_a_x;

        // Check termination after step 2
        if (x_after_step2 > n || x_after_step2 <= 0) {
            dp_y[start_x] = y_after_step2;
            dp_x[start_x] = x_after_step2;
            continue;
        }

        // Step 3: y = y_after_step2 + a_x_after_step2, x = x_after_step2 - a_x_after_step2
        long long a_x_after_step2 = a_suffix[x_after_step2 - 2];
        long long x_after_step3 = x_after_step2 - a_x_after_step2;
        long long y_after_step3 = y_after_step2 + a_x_after_step2;

        // Check termination after step 3
        if (x_after_step3 > n || x_after_step3 <= 0) {
            dp_y[start_x] = y_after_step3;
            dp_x[start_x] = x_after_step3;
            continue;
        }

        // If it doesn't terminate, it transitions to (x_after_step3, y_after_step3)
        // We need to look up the result for x_after_step3
        // If x_after_step3 is greater than start_x, it means we are looking up a value that has already been computed.
        // If x_after_step3 is less than or equal to start_x, it means we are looking up a value that has not been computed yet,
        // or it's a cycle.
        // Since we iterate backwards, x_after_step3 will always be < start_x or > n or <= 0.
        // If x_after_step3 is within [1, n], it must be < start_x.
        // This means we need to use the values from the DP table.

        if (dp_y[x_after_step3] == -1) { // If the subsequent state leads to an infinite loop
            dp_y[start_x] = -1;
            dp_x[start_x] = -1;
