            // This implies `b_j + sum_d_applied_to_j <= m` for all `j` in `[l, r]`.
            // So, `b_j <= m - sum_d_applied_to_j`.
            // To maximize `b_j`, we need to minimize `sum_d_applied_to_j`.
            // The `sum_d_applied_to_j` is the sum of `d` values from type 1 operations
            // that cover index `j` *before* the current type 2 operation.
            // This is still not quite right. The `sum_d_applied_to_j` is the sum of `d` values
            // from type 1 operations that cover index `j` *throughout the entire sequence*.

            // Let `b_i` be the initial array.
            // Let `delta_i` be the total sum of `d` values applied to `a_i` over all type 1 operations.
            // Then the final value of `a_i` would be `b_i + delta_i`.
            // This is not correct. The `delta_i` changes over time.

            // Let's define `b_i` as the initial array.
            // For each type 2 operation `(l, r, m_i)`, we know that `max_{j=l}^{r} (b_j + current_delta_j) = m_i`.
            // This implies `b_j + current_delta_j <= m_i` for all `j` in `[l, r]`.
            // So, `b_j <= m_i - current_delta_j`.
            // To satisfy all these upper bounds, `b_j` must be less than or equal to the minimum of all such `m_i - current_delta_j`.
            // The problem is `current_delta_j` depends on the operations *before* the current one.

            // Let's try a different approach.
            // We want to find `a_i` such that `|a_i| <= 10^9`.
            // Let `a_i` be the initial array.
            // For each type 2 operation `(l, r, m_i)`, we know that `max_{j=l}^{r} (a_j + \sum_{k \text{ s.t. op } k \text{ is type 1 and } j \in [l_k, r_k] \text{ and } k < i} d_k) = m_i`.
            // This is the key. The `\sum d_k` is the sum of `d` values from type 1 operations *before* the current type 2 operation.
            // Let `D_j` be the total sum of `d` values applied to index `j` by *all* type 1 operations.
            // We can compute `D_j` by iterating through all type 1 operations.
            // `D_j = \sum_{k \text{ s.t. op } k \text{ is type 1 and } j \in [l_k, r_k]} d_k`.
            // Then, we can set `a_j = -D_j`. This makes the array `a` effectively zero initially.
            // Then, for each type 2 operation `(l, r, m_i)`, we need `max_{j=l}^{r} (a_j + \text{current_delta}_j) = m_i`.
            // This is still not working.

            // The problem asks for *any* suitable array.
            // Let's define `b_i` as the initial array.
            // For each type 2 operation `(l, r, m_i)`, we know that `max_{j=l}^{r} (b_j + \text{current_delta}_j) = m_i`.
            // This implies `b_j + \text{current_delta}_j <= m_i` for all `j \in [l, r]`.
            // So, `b_j <= m_i - \text{current_delta}_j`.
            // Let `b_j_upper_bound = \min (m_i - \text{current_delta}_j)` over all type 2 operations `i` and ranges `[l, r]` that include `j`.
            // We can initialize `b_j` to `b_j_upper_bound`.
            // This is a greedy approach.

            // Let's try to find the initial array `a_i` such that `a_i` is as small as possible.
            // Or, let's find `a_i` such that `a_i` is as large as possible.
            // The problem is that `current_delta_j` depends on the operations *before* the current one.

            // Let `b_i` be the initial array.
            // For each type 2 operation `(l, r, m_i)`, we know that `max_{j=l}^{r} (b_j + \text{current_delta}_j) = m_i`.
            // This means there exists at least one `k \in [l, r]` such that `b_k + \text{current_delta}_k = m_i`.
            // And for all `j \in [l, r]`, `b_j + \text{current_delta}_j <= m_i`.
            // So, `b_j <= m_i - \text{current_delta}_j`.

            // Let's define `a_i` as the initial array.
            // We can iterate through the operations.
            // For type 1 `(l, r, d)`, we add `d` to a temporary array `current_values`.
            // For type 2 `(l, r, m)`, we check `max(current_values[j])` for `j \in [l, r]`.
            // If it's not `m`, then we have a problem.
            // But `current_values` depends on `a_i`.

            // Let `a_i` be the initial array.
            // Let `add_val[j]` be the total sum of `d` values applied to index `j` by *all* type 1 operations.
            // We can compute `add_val[j]` by iterating through all type 1 operations.
            // `add_val[j] = \sum_{k \text{ s.t. op } k \text{ is type 1 and } j \in [l_k, r_k]} d_k`.
            // Then, for each `j`, we can set `a_j = M_j - add_val[j]`, where `M_j` is the maximum value `a_j` ever reaches.
            // This is not correct.

            // Let's define `b_i` as the initial array.
            // For each type 2 operation `(l, r, m_i)`, we know that `max_{j=l}^{r} (b_j + \text{current_delta}_j) = m_i`.
            // This implies `b_j <= m_i - \text{current_delta}_j` for all `j \in [l, r]`.
            // Let `b_j_candidate = m_i - \text{current_delta}_j`.
            // We need to find `b_j` such that `b_j <= b_j_candidate` for all relevant `m_i`.
            // So, `b_j = \min (m_i - \text{current_delta}_j)` over all type 2 operations `i` and ranges `[l, r]` that include `j`.
            // This is the maximum possible value for `b_j` that satisfies all upper bounds.
            // Let's call this `b_j_max_possible`.
            // We can initialize `b_j = b_j_max_possible`.

            // To compute `b_j_max_possible`:
            // Initialize `b_j_max_possible[j] = infinity` for all `j`.
            // Initialize `current_delta[j] = 0` for all `j`.
            // Iterate through operations:
            // If type 1 `(l, r, d)`:
            //   For `j` from `l` to `r`, `current_delta[j] += d`.
            // If type 2 `(l, r, m)`:
            //   For `j` from `l` to `r`, `b_j_max_possible[j] = min(b_j_max_possible[j], m - current_delta[j])`.

            // After this first pass, we have `b_j_max_possible`.
            // Let's set `initial_a[j] = b_j_max_possible[j]`.
            // If `b_j_max_possible[j]` is still infinity, it means `j` was never part of a type 2 query.
            // In this case, we can set `initial_a[j] = 0` (or any value within `[-10^9, 10^9]`).
            // Let's use 0 for simplicity.

            // Now, we need to verify this `initial_a`.
            // Initialize `current_values[j] = initial_a[j]`.
            // Initialize `current_delta[j] = 0`.
            // Iterate through operations again:
            // If type 1 `(l, r, d)`:
            //   For `j` from `l` to `r`, `current_delta[j] += d`.
            // If type 2 `(l, r, m)`:
            //   Calculate `max_val = -infinity`.
            //   For `j` from `l` to `r`, `max_val = max(max_val, initial_a[j] + current_delta[j])`.
            //   If `max_val != m`, then no solution exists. Print "NO" and exit.

            // If all checks pass, print "YES" and `initial_a`.

            // Let's refine the `b_j_max_possible` initialization.
            // `b_j_max_possible` should be initialized to a very large value, e.g., `10^9 + 1`.
            // If after the first pass, `b_j_max_possible[j]` is still `10^9 + 1`, it means `j` was never constrained by a type 2 operation.
            // In this case, we can set `initial_a[j] = 0`.
            // Otherwise, `initial_a[j] = b_j_max_possible[j]`.

            // Constraints on `a_i`: `|a_i| <= 10^9`.
            // `m_i` is between `-5 * 10^7` and `5 * 10^7`.
            // `d_i` is between `-10^4` and `10^4`.
            // `m` is up to 5000.
            // `current_delta[j]` can be up to `5000 * 10^4 = 5 * 10^7`.
            // So `m - current_delta[j]` can be `5 * 10^7 - (-5 * 10^7) = 10^8`.
            // Or `-5 * 10^7 - (5 * 10^7) = -10^8`.
            // These values are within `[-10^9, 10^9]`. So `initial_a[j]` will be within bounds.

            // First pass: Determine upper bounds for initial_a[j]
            std::vector<long long> current_delta(n, 0);
            std::vector<long long> initial_a_upper_bound(n, std::numeric_limits<long long>::max()); // Use max for upper bound

            for (const auto& op : ops) {
                if (op.type == 1) {
                    for (int j = op.l; j <= op.r; ++j) {
                        current_delta[j] += op.val;
                    }
                } else { // op.type == 2
                    for (int j = op.l; j <= op.r; ++j) {
                        initial_a_upper_bound[j] = std::min(initial_a_upper_bound[j], op.val - current_delta[j]);
                    }
                }
            }

            // Construct the candidate initial array
            for (int j = 0; j < n; ++j) {
                if (initial_a_upper_bound[j] == std::numeric_limits<long long>::max()) {
                    initial_a[j] = 0; // If no upper bound, set to 0
                } else {
                    initial_a[j] = initial_a_upper_bound[j];
                }
            }

            // Second pass: Verify the constructed initial array
            std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta
            bool possible = true;

            for (const auto& op : ops) {
                if (op.type == 1) {
                    for (int j = op.l; j <= op.r; ++j) {
                        current_delta[j] += op.val;
                    }
                } else { // op.type == 2
                    long long max_val_in_range = std::numeric_limits<long long>::min();
                    for (int j = op.l; j <= op.r; ++j) {
                        max_val_in_range = std::max(max_val_in_range, initial_a[j] + current_delta[j]);
                    }
                    if (max_val_in_range != op.val) {
                        possible = false;
                        break;
                    }
                }
            }

            if (possible) {
                std::cout << "YES\n";
                for (int j = 0; j < n; ++j) {
                    std::cout << initial_a[j] << (j == n - 1 ? "" : " ");
                }
                std::cout << "\n";
            } else {
                std::cout << "NO\n";
            }

            return 0;
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a0 = elements[0].value;
    long long a1 = elements[1].value;
    long long an_2 = elements[n - 2].value;
    long long an_1 = elements[n - 1].value;

    // Case 1: All elements in one subsequence (e.g., S1). S2 is empty.
    // All f(ai, aj) = ai + aj.
    // min_f = a0 + a1
    // max_f = an_2 + an_1
    // goodness = (an_2 + an_1) - (a0 + a1)
    long long goodness1 = (an_2 + an_1) - (a0 + a1);
    std::vector<int> partition1(n, 1); // All in subsequence 1

    // Case 2: Partition into two non-empty subsequences.
    // The strategy is to put a0 and an_1 into different subsequences.
    // For example, a0 in S1, an_1 in S2.
    // The minimum possible sum is a0 + a1 (if a1 is in S1) or a0 + an_1 + h (if a0 in S1, an_1 in S2).
    // The maximum possible sum is an_2 + an_1 (if an_2 in S2) or a0 + an_1 + h (if a0 in S1, an_1 in S2).

    // Let's try to put a0 in S1 and an_1 in S2.
    // The smallest sum is min(a0 + a1, a0 + an_1 + h, a1 + an_1 + h)
    // The largest sum is max(an_2 + an_1, a0 + an_1 + h, a0 + an_2 + h)

    // Consider a specific partition:
    // S1 = {a0, a1, ..., ak}
    // S2 = {ak+1, ..., an-1}
    // This is not general enough.

    // Let's consider the two main candidates for minimal goodness:
    // 1. All elements in one group. Goodness = (an_1 + an_2) - (a0 + a1).
    // 2. a0 and an_1 are in different groups.
    //    The minimum possible sum is a0 + a1 (if a1 is in the same group as a0)
    //    OR a0 + an_1 + h (if a0 and an_1 are in different groups).
    //    The maximum possible sum is an_1 + an_2 (if an_2 is in the same group as an_1)
    //    OR a0 + an_1 + h (if a0 and an_1 are in different groups).

    // Let's try a specific partition for Case 2:
    // Put a0 in S1. Put an_1 in S2.
    // Put all other elements (a1, ..., an-2) into S1.
    // S1 = {a0, a1, ..., an-2}
    // S2 = {an-1}
    // min_f = min(a0 + a1, a0 + an_1 + h)
    // max_f = max(an_2 + an_1 + h, an_2 + an_3 (if n>=3, else a0+a1))
    // If n=2, S1={a0}, S2={a1}. min_f = a0+a1+h, max_f = a0+a1+h. Goodness = 0.
    // If n>2:
    // min_f = min(a0 + a1, a0 + an_1 + h)
    // max_f = max(an_2 + an_1 + h, an_2 + an_3 (if n>=3, else a0+a1))
    // This is not quite right. The max sum within S1 is a_{n-3} + a_{n-2}.
    // The max sum within S2 is not possible as S2 has only one element.
    // The max sum between S1 and S2 is a_{n-2} + an_1 + h.

    // Let's consider the two main candidates for the optimal partition:
    // Candidate A: All elements in one group (e.g., all 1s).
    //   min_f = a0 + a1
    //   max_f = an_1 + an_2
    //   Goodness = (an_1 + an_2) - (a0 + a1)
    //   Partition: all 1s.

    // Candidate B: a0 is in group 1, an_1 is in group 2.
    //   All other elements (a1, ..., an-2) are in group 1.
    //   S1 = {a0, a1, ..., an-2}
    //   S2 = {an-1}
    //   Possible sums:
    //     - a_i + a_j where a_i, a_j in S1: min is a0+a1, max is a_{n-3}+a_{n-2} (if n>=3)
    //     - a_i + a_j where a_i in S1, a_j in S2: min is a0+an_1+h, max is a_{n-2}+an_1+h
    //   Overall min_f = min(a0 + a1, a0 + an_1 + h) (if n>=2)
    //   Overall max_f = max(a_{n-3} + a_{n-2}, a_{n-2} + an_1 + h) (if n>=3)
    //   If n=2: S1={a0}, S2={an_1}. min_f = a0+an_1+h, max_f = a0+an_1+h. Goodness = 0.
    //   If n>2:
    //     min_f = std::min(a0 + a1, a0 + an_1 + h);
    //     max_f = std::max(elements[n-3].value + elements[n-2].value, an_2 + an_1 + h);
    //     Goodness = max_f - min_f;
    //     Partition: a0, a1, ..., an-2 in group 1; an-1 in group 2.

    // Let's re-evaluate the minimum and maximum values for Candidate B more carefully.
    // S1 = {a_0, a_1, ..., a_{n-2}}
    // S2 = {a_{n-1}}
    //
    // Values of f:
    // 1. Pairs within S1: `a_i + a_j` for `i, j < n-1`.
    //    Min of these: `a_0 + a_1`.
    //    Max of these: `a_{n-3} + a_{n-2}` (if `n-1 >= 2`, i.e., `n >= 3`).
    //    If `n=2`, S1 has only `a_0`, no pairs within S1.
    // 2. Pairs between S1 and S2: `a_i + a_{n-1} + h` for `i < n-1`.
    //    Min of these: `a_0 + a_{n-1} + h`.
    //    Max of these: `a_{n-2} + a_{n-1} + h`.
    //
    // Overall min_f_B:
    // If n=2: `a_0 + a_1 + h`
    // If n>2: `std::min(a_0 + a_1, a_0 + a_{n-1} + h)`
    //
    // Overall max_f_B:
    // If n=2: `a_0 + a_1 + h`
    // If n>2: `std::max(a_{n-3} + a_{n-2}, a_{n-2} + a_{n-1} + h)`

    long long goodness2;
    if (n == 2) {
        goodness2 = 0; // Only one pair (a0, a1), they must be in different groups for this partition.
    } else {
        long long min_f_B = std::min(a0 + a1, a0 + an_1 + h);
        long long max_f_B = std::max(elements[n-3].value + an_2, an_2 + an_1 + h);
        goodness2 = max_f_B - min_f_B;
    }

    std::vector<int> partition2(n);
    partition2[elements[0].original_index] = 1; // a0 in S1
    partition2[elements[n-1].original_index] = 2; // an_1 in S2
    for (int i = 1; i < n - 1; ++i) {
        partition2[elements[i].original_index] = 1; // a1 to an-2 in S1
    }

    // Compare goodness values
    if (goodness1 <= goodness2) {
        std::cout << goodness1 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition1[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << goodness2 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << partition2[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <numeric>

bool check(long long T, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    int p_idx = 0; // Current target track index
    int h_idx = 0; // Current head index

    while (p_idx < m) {
        if (h_idx >= n) {
            return false; // No more heads, but still tracks to cover
        }

        // Find the first head h_idx that can reach p_idx
        // A head h_idx can reach p_idx if h_idx - T <= p_idx
        // Or, more precisely, if p[p_idx] is within [h[h_idx] - T, h[h_idx] + T]
        // We need to find a head that can reach p[p_idx].
        // Since both h and p are sorted, we can advance h_idx.
        while (h_idx < n && h[h_idx] + T < p[p_idx]) {
            h_idx++;
        }

        if (h_idx >= n) {
            return false; // No head can reach the current p[p_idx]
        }

        // Now, h[h_idx] is the first head that *might* be able to cover p[p_idx].
        // Its range is [h[h_idx] - T, h[h_idx] + T].
        // If p[p_idx] is not in this range, then no subsequent head can cover it either
        // because subsequent heads are further to the right.
        if (h[h_idx] - T > p[p_idx]) {
            return false; // Current head h[h_idx] is too far right to cover p[p_idx]
        }

        // If we reach here, h[h_idx] can cover p[p_idx].
        // We use this head h[h_idx] to cover as many subsequent tracks as possible.
        long long current_head_left_reach = h[h_idx] - T;
        long long current_head_right_reach = h[h_idx] + T;

        // The head h[h_idx] can cover tracks from max(p[p_idx], current_head_left_reach)
        // up to current_head_right_reach.
        // Since p is sorted, we just need to find the furthest p_j that this head can cover.
        // The actual range covered by this head is [current_head_left_reach, current_head_right_reach].
        // We need to cover p[p_idx], so the head must be able to reach p[p_idx].
        // The head is at h[h_idx]. It can move to any point in [h[h_idx]-T, h[h_idx]+T].
        // To cover p[p_idx], it must be able to reach it.
        // The effective range it can cover, starting from p[p_idx], is [p[p_idx], p[p_idx] + (h[h_idx]+T - p[p_idx])].
        // No, this is not correct. The head can move to any point X in [h[h_idx]-T, h[h_idx]+T].
        // From X, it can cover tracks in [X-T, X+T].
        // This is not how it works. A head at h_i can cover any track p_j if |h_i - p_j| <= T.
        // The problem states: "A track is considered read if at least one head has visited this track."
        // "For each of the reading heads, the hard drive's firmware can move the head exactly one track to the right or to the left, or leave it on the current track."
        // This means in T seconds, a head at h_i can reach any track X such that |h_i - X| <= T.
        // So, the range covered by head h_i is [h_i - T, h_i + T].

        // We are at p_idx. We found h_idx such that h[h_idx] - T <= p[p_idx].
        // This head can cover p[p_idx].
        // It can also cover all tracks p_k such that p_k <= h[h_idx] + T.
        long long current_head_max_covered_p = h[h_idx] + T;

        // Advance p_idx past all tracks covered by h[h_idx]
        while (p_idx < m && p[p_idx] <= current_head_max_covered_p) {
            p_idx++;
        }
        h_idx++; // Move to the next head for the remaining tracks
    }

    return true; // All tracks covered
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    long long high = 2e10 + 7; // Max possible difference between p_m and h_1, or p_1 and h_n
    long long ans = high;

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

bool is_palindrome(const std::string& str) {
    std::string reversed_str = str;
    std::reverse(reversed_str.begin(), reversed_str.end());
    return str == reversed_str;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    int n = s.length();

    // Check for k=1
    // A single cut divides s into s1 and s2.
    // We reorder them to s2 + s1.
    // We need s2 + s1 to be a palindrome and s2 + s1 != s.
    // Since s is already a palindrome, s2 + s1 will be a palindrome
    // if and only if s1 + s2 is a palindrome (which it is) AND
    // s1 is a palindrome AND s2 is a palindrome. This is not generally true.
    // The condition for s2+s1 to be a palindrome is simply that it reads the same forwards and backwards.
    // We iterate through all possible cut points.
    for (int i = 1; i < n; ++i) { // i is the length of s1
        std::string s1 = s.substr(0, i);
        std::string s2 = s.substr(i);
        std::string reordered_s = s2 + s1;
        if (reordered_s != s && is_palindrome(reordered_s)) {
            std::cout << 1 << std::endl;
            return 0;
        }
    }

    // Check for k=2
    // If k=1 didn't work, we need to check if k=2 is always possible,
    // unless all characters in s are the same.
    // If all characters are the same (e.g., "aaaa"), then any reordering of pieces
