        current_sum += a;
        current_xor_sum ^= a;
    }

    // If the array is already good, append 0 elements.
    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    // We need to append elements b1, b2, ... such that:
    // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))

    // Strategy: Append two elements.
    // Let the two elements be X and S.
    // New sum: current_sum + X + S
    // New XOR sum: current_xor_sum ^ X ^ S
    // We want: current_sum + X + S = 2 * (current_xor_sum ^ X ^ S)

    // Let's try to make the new XOR sum equal to current_xor_sum.
    // This means we need X ^ S = 0, which implies X = S.
    // If we append X and X, then the new XOR sum is current_xor_sum ^ X ^ X = current_xor_sum.
    // The new sum is current_sum + X + X = current_sum + 2X.
    // The condition becomes: current_sum + 2X = 2 * current_xor_sum.
    // This simplifies to 2X = 2 * current_xor_sum - current_sum.
    // X = current_xor_sum - current_sum / 2.
    // This requires current_sum to be even, and current_xor_sum - current_sum / 2 to be non-negative.
