    // Let b1 = X_orig.
    // Let b2 = S_orig + X_orig.
    // New sum: S_orig + b1 + b2 = S_orig + X_orig + (S_orig + X_orig) = 2 * S_orig + 2 * X_orig.
    // New XOR sum: X_orig ^ b1 ^ b2 = X_orig ^ X_orig ^ (S_orig + X_orig) = S_orig + X_orig.
    // Check condition: S_new = 2 * X_new
    // (2 * S_orig + 2 * X_orig) = 2 * (S_orig + X_orig)
    // This is always true!
    // The appended elements are X_orig and S_orig + X_orig.
    // These are non-negative since X_orig >= 0 and S_orig >= 0.
    // The values can be large, up to 10^5 * 10^9 + 10^9 approx 10^14, which fits in long long.

    // This strategy uses 2 elements.
    // The problem statement says "at most 3 elements".
    // This strategy is simple and always works.

    long long b1 = current_xor_sum;
    long long b2 = current_sum + current_xor_sum;

    std::cout << 2 << std::endl;
    std::cout << b1 << " " << b2 << std::endl;
}

