    // For that p_k, max_{j!=k} min(p_k, p_j) = max_{j!=k} p_j = n-1.
    // So, if max_p_val is n-1, we need to find one of the elements that is n-1 and change it to n.
    // Since all other values 1 to n-1 are unique, there will be exactly one 'n-1' that should be 'n'.
    // We can just find the first occurrence of n-1 and change it to n.

    bool n_found_in_p = false;
    for (int val : p) {
        if (val == n) {
            n_found_in_p = true;
            break;
        }
    }

    if (!n_found_in_p) {
        // If n is not found, it means one of the elements that should be n was calculated as n-1.
        // Find the first occurrence of n-1 and change it to n.
        for (int i = 0; i < n; ++i) {
            if (p[i] == n - 1) {
                p[i] = n;
                break;
            }
        }
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

