int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int t; // Declare variable t for the number of test cases.
    std::cin >> t; // Read the number of test cases.

    // Loop through each test case.
    while (t--) {
        int n; // Declare variable n for the number of days.
        std::cin >> n; // Read the number of days.

        // Declare a vector 'a' of size n to store prices.
        // Using std::vector is efficient for dynamic arrays.
        std::vector<int> a(n);
        // Read n prices into the vector 'a'.
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        // Declare 'bad_prices_count' to store the total number of bad prices.
        // Initialize to 0.
        int bad_prices_count = 0;
        // Declare 'min_price_suffix' to store the minimum price encountered
        // from the current position to the end of the array.
        // Initialize with the last price, as it's the minimum for the suffix
        // starting from the last element itself.
        // If n=0 or n=1, the loop below won't run, and bad_prices_count will remain 0, which is correct.
        // For n=1, there are no later days, so no bad prices.
        if (n == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        int min_price_suffix = a[n - 1];

        // Iterate from the second-to-last day backwards to the first day.
        // The last day (index n-1) can never be a bad price because there are no days after it.
        for (int i = n - 2; i >= 0; --i) {
            // If the current day's price 'a[i]' is greater than the minimum price
            // found in any subsequent day ('min_price_suffix'), then 'a[i]' is a bad price.
            if (a[i] > min_price_suffix) {
                bad_prices_count++; // Increment the counter for bad prices.
            } else {
                // If 'a[i]' is not greater than 'min_price_suffix', it means 'a[i]'
                // is a new minimum for the suffix ending at 'i'.
                // Update 'min_price_suffix' to be the minimum of its current value
                // and 'a[i]'. This ensures 'min_price_suffix' always holds the
                // minimum value from 'a[i+1]' to 'a[n-1]' for the next iteration.
                min_price_suffix = a[i];
            }
        }

        // Print the total number of bad prices for the current test case,
        // followed by a newline character.
        std::cout << bad_prices_count << "\n";
    }

    return 0; // Indicate successful execution.
}

