#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        long long count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the number of stairs in the current nice staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate the number of cells for a nice staircase with k stairs
            // A nice staircase with k stairs has k columns, heights 1 to k.
            // The total cells are k * (k + 1) / 2.
            // The sequence of k for nice staircases is 1, 3, 7, 15, ... which is 2^p - 1.
            // Let's denote the p-th nice staircase (p=1 for k=1, p=2 for k=3, etc.)
            // The number of cells for the p-th nice staircase is (2^p - 1) * (2^p) / 2.
            // This can be rewritten as (2^p - 1) * 2^(p-1).
            // Let's use the variable `k` directly.
            // k = 2^p - 1.
            // Cost = k * (k + 1) / 2 = (2^p - 1) * (2^p - 1 + 1) / 2 = (2^p - 1) * 2^p / 2 = (2^p - 1) * 2^(p-1).

            long long cost_of_k_staircase = k * (k + 1) / 2;

            if (current_cost + cost_of_k_staircase <= x) {
                current_cost += cost_of_k_staircase;
                count++;
                // Move to the next nice staircase size: k_next = 2 * k + 1
                // This is equivalent to 2^(p+1) - 1 if k = 2^p - 1
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x, y, k;
        std::cin >> x >> y >> k;
        // To craft k torches, we need k sticks and k coal.
        // To get k coal, we need k * y sticks. This takes k trades (y sticks -> 1 coal).
        // So, total sticks required for coal: k * y
        // Total sticks required for crafting torches: k
        // Total sticks we need to acquire/have: k * y + k
        // We start with 1 stick.
        // So, we need to generate (k * y + k) - 1 additional sticks using the first trade.
        // The first trade (1 stick -> x sticks) gives a net gain of (x - 1) sticks per trade.
        // Number of trades to generate (k * y + k) - 1 sticks:
        // Let N be the number of trades of type 1.
        // N * (x - 1) >= (k * y + k) - 1
        // N = ceil(((k * y + k) - 1) / (x - 1))
        // Using integer division: N = ((k * y + k) - 1 + (x - 1) - 1) / (x - 1)
        // Or simply: N = ((k * y + k) - 1 + (x - 2)) / (x - 1) if x > 1
        // Since x >= 2, x - 1 >= 1.

        long long sticks_needed_for_coal = k * y;
        long long total_sticks_to_have = sticks_needed_for_coal + k;

        // We start with 1 stick, so we need to acquire (total_sticks_to_have - 1) more sticks.
        // Each trade of type 1 (1 stick for x sticks) effectively increases our stick count by (x - 1).
        // Let's say we perform 'trades_type1' trades of type 1.
        // The number of sticks we have after these trades will be 1 + trades_type1 * (x - 1).
        // We need this to be at least total_sticks_to_have.
        // 1 + trades_type1 * (x - 1) >= total_sticks_to_have
        // trades_type1 * (x - 1) >= total_sticks_to_have - 1
        // trades_type1 = ceil((total_sticks_to_have - 1) / (x - 1))

        long long trades_type1 = (total_sticks_to_have - 1 + (x - 1) - 1) / (x - 1);

        // Total trades = trades_type1 (to get enough sticks) + k (to get k coal)
        long long total_trades = trades_type1 + k;

        std::cout << total_trades << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p[0] must be q[0]
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q[i] is a new maximum, then p[i] must be q[i]
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid, as q_i are distinct when increasing
                // But good to check for robustness
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else {
            // If q[i] == q[i-1], then p[i] must be some number less than or equal to q[i]
            // and not yet used. To maximize chances of finding a solution, we should pick
            // the smallest available number that satisfies the condition.
            // The smallest available number is the smallest number from 1 to n that is not in used_numbers.
            // We need to find the smallest number 'x' such that 1 <= x <= n, x is not in used_numbers,
            // AND x <= q[i].
            // Since we are filling p_i with the smallest available number, we can iterate from 1 upwards.
            // A more efficient way is to use a set of available numbers.
            // Or, since we know q[i] is the current max, p[i] must be <= q[i].
            // We need to find the smallest unused number.
            // The numbers that are not yet used are 1, 2, ..., n excluding those in used_numbers.
            // We need to pick the smallest 'x' from these unused numbers such that x <= q[i].
            // If we pick the smallest available number, it will always be <= q[i] because q[i] is the current max.
            // If q[i] is the current max, it means all numbers 1 to q[i] that are not yet used are candidates for p[i].
            // We should pick the smallest one to leave larger numbers for future q[j] == q[j-1] cases.

            // Find the smallest number 'x' such that 1 <= x <= n and x is not in used_numbers.
            int current_val = 1;
            while (current_val <= n && used_numbers.count(current_val)) {
                current_val++;
            }

            if (current_val > n || current_val > q[i]) {
                // If no unused number is found, or the smallest unused number is greater than q[i],
                // then it's impossible.
                possible = false;
                break;
            }
            p[i] = current_val;
            used_numbers.insert(current_val);
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

