int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        // The maximum number of teams is limited by three factors:
        // 1. The number of coders (each team needs at least one coder)
        // 2. The number of mathematicians (each team needs at least one mathematician)
        // 3. The total number of students available (each team needs 3 students)
        // So, the number of teams 'k' must satisfy:
        // k <= c
        // k <= m
        // 3 * k <= c + m + x  =>  k <= (c + m + x) / 3
        // Therefore, k <= min(c, m, (c + m + x) / 3)
        // We can prove that this minimum value is always achievable.
        // Let k_max = min(c, m, (c + m + x) / 3).
        // We need to show that we can form k_max teams.
        // We have enough coders (c >= k_max) and mathematicians (m >= k_max).
        // We have enough total students (c + m + x >= 3 * k_max).
        // The remaining students (c - k_max coders, m - k_max mathematicians, x unspecialized)
        // can be used to fill the remaining slots in the k_max teams.
        // Each of the k_max teams needs 3 students. We've already assigned 1 coder and 1 mathematician to each.
        // So, 1 slot per team remains, totaling k_max slots.
        // The number of remaining students is (c - k_max) + (m - k_max) + x.
        // This sum is (c + m + x) - 2 * k_max.
        // Since k_max <= (c + m + x) / 3, we have 3 * k_max <= c + m + x.
        // This implies k_max <= (c + m + x) - 2 * k_max.
        // So, the number of remaining students is always sufficient to fill the remaining k_max slots.
        // These remaining students can be coders, mathematicians, or unspecialized,
        // and they can fill the remaining slots without violating the "at least one coder/mathematician" rule,
        // as those minimums are already met.
        long long ans = std::min({c, m, (c + m + x) / 3});
        std::cout << ans << "\n";
    }
    return 0;
}

