    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::string result = "";
    int open_needed = k / 2;
    int close_needed = k / 2;

    for (char c : s) {
        if (c == '(' && open_needed > 0) {
            result += '(';
            open_needed--;
        } else if (c == ')' && close_needed > 0) {
            // Only add ')' if it can be matched and we still need closing brackets
            // The problem guarantees a solution exists, and this greedy approach
            // of taking the first k/2 '(' and first k/2 ')' will form a valid RBS
            // because the original string s is an RBS.
            // We don't need to explicitly check for balance here, as long as we
            // take k/2 open and k/2 close brackets in order, it will be balanced
            // if the original string was balanced.
            result += ')';
            close_needed--;
        }
        if (open_needed == 0 && close_needed == 0) {
            break;
        }
    }

    std::cout << result << std::endl;

    return 0;
}

