int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        std::vector<int> pos(n + 1); // pos[x] stores the 0-indexed position of x in p
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
            pos[p[i]] = i;
        }

        std::string result(n, '0');

        // For m=1, the subsegment is just [1] at pos[1].
        // Its length is 1, min is 1, max is 1. So m=1 is always beautiful.
        result[0] = '1';

        // Initialize current min_idx and max_idx for the segment containing 1...k
        int min_idx = pos[1];
        int max_idx = pos[1];

        // Iterate for m from 2 to n
        for (int m = 2; m <= n; ++m) {
            // Update min_idx and max_idx to include the position of 'm'
            min_idx = std::min(min_idx, pos[m]);
            max_idx = std::max(max_idx, pos[m]);

            // The current segment spans from min_idx to max_idx.
            // Its length is (max_idx - min_idx + 1).
            // If this length is equal to 'm', it means all numbers from 1 to m
            // are contained within this segment, and no other numbers are.
            // This implies that the segment [p[min_idx], ..., p[max_idx]]
            // is a permutation of 1, ..., m.
            if ((max_idx - min_idx + 1) == m) {
                result[m - 1] = '1';
            }
        }
        std::cout << result << "\n";
    }
    return 0;
}

