void solve() {
    int n;
    std::cin >> n;
    std::vector<int> p(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> p[i];
    }

    std::vector<int> result_subsequence;
    result_subsequence.push_back(p[0]);

    for (int i = 1; i < n - 1; ++i) {
        // Check if p[i] is a local extremum
        // p[i] is a peak if p[i-1] < p[i] > p[i+1]
        // p[i] is a valley if p[i-1] > p[i] < p[i+1]
        // If p[i] is neither, it's monotonic, and including it would not increase the sum of differences
        // compared to skipping it, but would increase length.
        if ((p[i] > p[i-1] && p[i] > p[i+1]) || (p[i] < p[i-1] && p[i] < p[i+1])) {
            result_subsequence.push_back(p[i]);
        }
    }

    result_subsequence.push_back(p[n-1]);

    std::cout << result_subsequence.size() << "\n";
    for (size_t i = 0; i < result_subsequence.size(); ++i) {
        std::cout << result_subsequence[i] << (i == result_subsequence.size() - 1 ? "" : " ");
    }
    std::cout << "\n";
}

