    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[left_ptr] <= d

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Advance right_ptr until x[right_ptr] - x[left_ptr] > d
        // or until right_ptr reaches the end of the array.
        // The condition x[right_ptr] <= x[left_ptr] + d is equivalent to x[right_ptr] - x[left_ptr] <= d.
        while (right_ptr < n && x[right_ptr] <= x[left_ptr] + d) {
            right_ptr++;
        }
        // At this point, all points from x[left_ptr] to x[right_ptr - 1] satisfy the condition
        // x[k] - x[left_ptr] <= d.
        // We need to choose two more points (x_j, x_k) such that left_ptr < j < k < right_ptr.

        // The number of points available to choose from (excluding x[left_ptr]) is (right_ptr - 1) - (left_ptr + 1) + 1
        // which simplifies to right_ptr - 1 - left_ptr.
        // Let m = right_ptr - 1 - left_ptr. These are the points x[left_ptr+1], ..., x[right_ptr-1].
        // We need to choose 2 points from these m points.
        // The number of ways to choose 2 points from m points is m * (m - 1) / 2.

        long long m = right_ptr - 1 - left_ptr; // Number of points between x[left_ptr] and x[right_ptr] (exclusive of x[left_ptr], inclusive of x[right_ptr-1])
                                                // i.e., points x[left_ptr+1], ..., x[right_ptr-1]
        if (m >= 2) {
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

