int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    int count01 = 0; // count of indices k where a[k]='0' and b[k]='1'
    int count10 = 0; // count of indices k where a[k]='1' and b[k]='0'

    for (int i = 0; i < n; ++i) {
        if (a[i] == '0' && b[i] == '1') {
            if (count10 > 0) { // We have a '1' at some j that needs to be '0'
                               // and a '0' at i that needs to be '1'.
                               // We can swap a[j] and a[i].
                               // This effectively fixes both positions.
                count10--;
            } else { // No '1->0' mismatch available to swap with.
                     // This '0->1' mismatch must be fixed by a flip or
                     // by a future swap with a '1->0' mismatch.
                     // For now, we count it as an open '0->1' mismatch.
                count01++;
            }
        } else if (a[i] == '1' && b[i] == '0') {
            if (count01 > 0) { // We have a '0' at some j that needs to be '1'
                               // and a '1' at i that needs to be '0'.
                               // We can swap a[j] and a[i].
                               // This effectively fixes both positions.
                count01--;
            } else { // No '0->1' mismatch available to swap with.
                     // This '1->0' mismatch must be fixed by a flip or
                     // by a future swap with a '0->1' mismatch.
                     // For now, we count it as an open '1->0' mismatch.
                count10++;
            }
        }
    }

    // After iterating through all positions, any remaining count01 or count10
    // represents mismatches that could not be resolved by a swap with an
    // opposite mismatch. These must be fixed by flipping.
    // Each flip costs 1.
    cost = static_cast<long long>(count01 + count10);

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    std::vector<std::string> result(4);

    // Box 1: (-inf, -1]
    // Can be special box if final product is negative and magnitude >= 1
    // This requires an odd number of negative factors AND (at least one large magnitude factor OR all factors are small magnitude and there are enough of them to grow the product)
    // The simplest way to get a negative product is an odd number of initial negative toys (A+B is odd).
    // If A+B is odd:
    //   If A > 0 or D > 0: We can always make the magnitude large.
    //   If A == 0 and D == 0: All initial toys are from B and C.
    //     If B is odd: The product will be negative.
    //     If B is odd and B+C > 0: The product will be negative.
    //     If B is odd and B+C > 0, can we make magnitude >= 1?
    //       If B is odd and B+C > 0, and A=0, D=0:
    //         We have B negative small, C positive small.
    //         The product will be negative.
    //         If B+C >= 2, we can make the product negative and small.
    //         Can we make it negative and large? No, if all initial values are small, the product will always be small.
    //         Unless B+C=1, then it's just one toy from B, which is small.
    // So, for Box 1:
    // Condition 1: (A + B) % 2 == 1 (odd number of negative toys)
    // Condition 2: (A > 0 || D > 0) (at least one large magnitude toy to ensure product can be large)
    // If A+B is odd, and A+D > 0, then Ya.
    // What if A+B is odd, but A=0 and D=0? Then all toys are from B and C.
    // The product will be negative (from B). But its magnitude will be < 1. So it cannot be in Box 1.
    // So, Box 1 requires (A + B) % 2 == 1 AND (A > 0 || D > 0).
    // Exception: If A+B+C+D == 1 and that toy is in Box 1, then it's Ya.
    if ((a + b + c + d == 1 && a == 1) || ((a + b) % 2 == 1 && (a > 0 || d > 0))) {
        result[0] = "Ya";
    } else {
        result[0] = "Tidak";
    }

    // Box 2: (-1, 0)
    // Can be special box if final product is negative and magnitude < 1
    // This requires an odd number of negative factors AND (all factors are small magnitude OR we can arrange multiplications to make it small)
    // Condition 1: (A + B) % 2 == 1 (odd number of negative toys)
    // Condition 2: (A == 0 && D == 0) (all initial toys are small magnitude, so product will be small)
    // OR (A > 0 || D > 0) AND (A+B+C+D > 1) (we have large magnitude toys, but can make the product small)
    // If A+B is odd:
    //   If A=0 and D=0: All toys are from B and C. Product will be negative and small. Ya.
    //   If A>0 or D>0: We have large magnitude toys.
    //     If we have at least one large magnitude toy (A>0 or D>0) and at least one small magnitude toy (B>0 or C>0),
    //     we can always make the final product small by multiplying a large toy with a small toy at the end.
    //     Example: (large * large * ... * large) * small.
    //     So if A+B is odd, and (A>0 or D>0), and (B>0 or C>0), then Ya.
    //     What if A+B is odd, and (A>0 or D>0), but (B=0 and C=0)?
    //       Then all toys are from A and D.
    //       If A is odd, D is even: product is negative. All large. Product is large. Not Box 2.
    //       If A is even, D is odd: product is positive. All large. Product is large. Not Box 2.
    //       This case is covered by (B>0 or C>0).
    // So, Box 2 requires (A + B) % 2 == 1.
    // If A+B is odd:
    //   If A=0 and D=0: Ya.
    //   If A>0 or D>0:
    //     If B>0 or C>0: Ya.
    //     If B=0 and C=0: Then all toys are from A and D. Product will be large. Not Box 2.
    // This simplifies to: (A + B) % 2 == 1 AND (A == 0 && D == 0 || B > 0 || C > 0).
    // Exception: If A+B+C+D == 1 and that toy is in Box 2, then it's Ya.
    if ((a + b + c + d == 1 && b == 1) || ((a + b) % 2 == 1 && (a == 0 && d == 0 || b > 0 || c > 0))) {
        result[1] = "Ya";
    } else {
        result[1] = "Tidak";
    }

    // Box 3: (0, 1)
    // Can be special box if final product is positive and magnitude < 1
    // This requires an even number of negative factors AND (all factors are small magnitude OR we can arrange multiplications to make it small)
    // Condition 1: (A + B) % 2 == 0 (even number of negative toys)
    // Condition 2: (A == 0 && D == 0) (all initial toys are small magnitude, so product will be small)
    // OR (A > 0 || D > 0) AND (A+B+C+D > 1) (we have large magnitude toys, but can make the product small)
    // If A+B is even:
    //   If A=0 and D=0: All toys are from B and C. Product will be positive and small. Ya.
    //   If A>0 or D>0: We have large magnitude toys.
    //     If B>0 or C>0: Ya.
    //     If B=0 and C=0: Then all toys are from A and D. Product will be large. Not Box 3.
    // This simplifies to: (A + B) % 2 == 0 AND (A == 0 && D == 0 || B > 0 || C > 0).
    // Exception: If A+B+C+D == 1 and that toy is in Box 3, then it's Ya.
    if ((a + b + c + d == 1 && c == 1) || ((a + b) % 2 == 0 && (a == 0 && d == 0 || b > 0 || c > 0))) {
        result[2] = "Ya";
    } else {
        result[2] = "Tidak";
    }

    // Box 4: [1, inf)
    // Can be special box if final product is positive and magnitude >= 1
    // This requires an even number of negative factors AND (at least one large magnitude factor OR all factors are small magnitude and there are enough of them to grow the product)
    // Condition 1: (A + B) % 2 == 0 (even number of negative toys)
    // Condition 2: (A > 0 || D > 0) (at least one large magnitude toy to ensure product can be large)
    // If A+B is even, and A+D > 0, then Ya.
    // What if A+B is even, but A=0 and D=0? Then all toys are from B and C.
    // The product will be positive (from B*B or C*C or B*C). But its magnitude will be < 1. So it cannot be in Box 4.
    // So, Box 4 requires (A + B) % 2 == 0 AND (A > 0 || D > 0).
    // Exception: If A+B+C+D == 1 and that toy is in Box 4, then it's Ya.
    if ((a + b + c + d == 1 && d == 1) || ((a + b) % 2 == 0 && (a > 0 || d > 0))) {
        result[3] = "Ya";
    } else {
        result[3] = "Tidak";
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

