// Function to check if a sub-array is a permutation of 1 to len
// Uses a boolean array for seen elements and finds the maximum
bool is_permutation(const std::vector<int>& arr, int start_idx, int len) {
    if (len == 0) { // A permutation must have non-zero length
        return false;
    }
    std::vector<bool> seen(len + 1, false);
    int max_val = 0;
    for (int i = 0; i < len; ++i) {
        int val = arr[start_idx + i];
        if (val < 1 || val > len || seen[val]) {
            return false;
        }
        seen[val] = true;
        if (val > max_val) {
            max_val = val;
        }
    }
    return max_val == len;
}

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    // Precompute max prefix and max suffix values
    std::vector<int> max_prefix(n);
    max_prefix[0] = a[0];
    for (int i = 1; i < n; ++i) {
        max_prefix[i] = std::max(max_prefix[i - 1], a[i]);
    }

    std::vector<int> max_suffix(n);
    max_suffix[n - 1] = a[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        max_suffix[i] = std::max(max_suffix[i + 1], a[i]);
    }

    // Precompute frequency counts for prefixes and suffixes
    // Using std::vector<int> as a frequency map for values up to n
    // freq_prefix[i][val] stores count of 'val' in a[0...i]
    // freq_suffix[i][val] stores count of 'val' in a[i...n-1]
    std::vector<std::vector<int>> freq_prefix(n, std::vector<int>(n + 1, 0));
    freq_prefix[0][a[0]] = 1;
    for (int i = 1; i < n; ++i) {
        freq_prefix[i] = freq_prefix[i - 1];
        freq_prefix[i][a[i]]++;
    }

    std::vector<std::vector<int>> freq_suffix(n, std::vector<int>(n + 1, 0));
    freq_suffix[n - 1][a[n - 1]] = 1;
    for (int i = n - 2; i >= 0; --i) {
        freq_suffix[i] = freq_suffix[i + 1];
        freq_suffix[i][a[i]]++;
    }

    std::vector<std::pair<int, int>> results;

    // Iterate through all possible split points l1
    // l1 is the length of p1, so it ranges from 1 to n-1
    for (int l1 = 1; l1 < n; ++l1) {
        int l2 = n - l1;

        // Check if the first l1 elements form a permutation of length l1
        // Condition 1: Max element in a[0...l1-1] must be l1
        if (max_prefix[l1 - 1] != l1) {
            continue;
        }
        // Condition 2: All elements from 1 to l1 must appear exactly once
        bool p1_is_perm = true;
        for (int val = 1; val <= l1; ++val) {
            if (freq_prefix[l1 - 1][val] != 1) {
                p1_is_perm = false;
                break;
            }
        }
        if (!p1_is_perm) {
            continue;
        }

        // Check if the last l2 elements form a permutation of length l2
        // The last l2 elements start at index l1
        // Condition 1: Max element in a[l1...n-1] must be l2
        if (max_suffix[l1] != l2) {
            continue;
        }
        // Condition 2: All elements from 1 to l2 must appear exactly once
        bool p2_is_perm = true;
        for (int val = 1; val <= l2; ++val) {
            if (freq_suffix[l1][val] != 1) {
                p2_is_perm = false;
                break;
            }
        }
        if (!p2_is_perm) {
            continue;
        }

        results.push_back({l1, l2});
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

