int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        long long k;
        std::cin >> n >> k;
        std::string s;
        std::cin >> s;

        int initial_wins = 0;
        for (char c : s) {
            if (c == 'W') {
                initial_wins++;
            }
        }

        if (initial_wins == 0) { // All games are 'L' initially
            if (k == 0) {
                std::cout << 0 << "\n";
            } else { // Change k 'L's to 'W's
                std::cout << 2 * k - 1 << "\n"; // 1 + 2*(k-1)
            }
            continue;
        }

        // If k is large enough to turn all games into 'W'
        if (initial_wins + k >= n) {
            std::cout << 2 * n - 1 << "\n"; // 1 + 2*(n-1)
            continue;
        }

        // Calculate initial score
        long long current_score = 0;
        bool last_was_win = false;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (last_was_win) {
                    current_score += 2;
                } else {
                    current_score += 1;
                }
                last_was_win = true;
            } else {
                last_was_win = false;
            }
        }

        // Find segments of 'L's between 'W's
        std::vector<int> l_segments;
        int first_w = -1, last_w = -1;
        for (int i = 0; i < n; ++i) {
            if (s[i] == 'W') {
                if (first_w == -1) {
                    first_w = i;
                }
                last_w = i;
            }
        }

        if (first_w != -1) { // There is at least one 'W'
            int current_l_count = 0;
            for (int i = first_w + 1; i < last_w; ++i) {
                if (s[i] == 'L') {
                    current_l_count++;
                } else { // s[i] == 'W'
                    if (current_l_count > 0) {
                        l_segments.push_back(current_l_count);
                    }
                    current_l_count = 0;
                }
            }
            if (current_l_count > 0) { // Last segment of L's
                l_segments.push_back(current_l_count);
            }
        }

        std::sort(l_segments.begin(), l_segments.end());

        // Greedily fill 'L' segments between 'W's
        for (int segment_len : l_segments) {
            if (k >= segment_len) {
                k -= segment_len;
                current_score += 2 * segment_len + 1; // Each L becomes W (2*len points) + 1 for connecting
            } else {
                break; // Cannot fill this segment
            }
        }

        // Use remaining k to convert 'L's at ends or isolated 'L's
        current_score += 2 * k; // Each remaining k converts an L to W, adding 2 points (1 for the W, 1 for connecting to previous W or starting a new W sequence)

        std::cout << current_score << "\n";
    }
    return 0;
}

