#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <functional>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        int k;
        std::cin >> n >> k;
        std::vector<long long> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }
        std::vector<int> w(k);
        for (int i = 0; i < k; ++i) {
            std::cin >> w[i];
        }

        std::sort(a.begin(), a.end());
        std::sort(w.begin(), w.end());

        long long total_happiness = 0;

        // Friends with w_i = 1: they get one number, which is both max and min.
        // To maximize happiness, give them the largest available numbers.
        // These are the k largest numbers from 'a'.
        // Since w is sorted, w[0]...w[k-1] are the counts.
        // The friends with w_i = 1 are at the beginning of the sorted w array.
        // The largest numbers in 'a' are at the end.

        int a_ptr_max = n - 1; // Pointer to the largest available number in 'a'

        // First, handle friends with w_i = 1.
        // These are the first 'count_ones' friends in the sorted 'w' array.
        // They should get the largest numbers from 'a'.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] == 1) {
                total_happiness += a[a_ptr_max] * 2;
                a_ptr_max--;
            } else {
                // All remaining w_i will be > 1 because w is sorted.
                // Break and handle them in the next loop.
                break;
            }
        }

        // Now handle friends with w_i > 1.
        // These friends need a max and a min.
        // To maximize sum of happiness:
        // - Give them the remaining largest numbers as their max_val.
        // - Give them the smallest available numbers as their min_val.
        // The friends with larger w_i values (who need more numbers) should get
        // smaller numbers as their min_val to "save" larger numbers for other friends.
        // So, iterate w from smallest w_i > 1 to largest w_i > 1.
        // The smallest w_i > 1 will be at the beginning of the remaining w array.
        // The largest w_i > 1 will be at the end of the remaining w array.
        // We need to pair the largest remaining a[a_ptr_max] with the smallest a[a_ptr_min].
        // The friends with larger w_i values will consume more numbers from the middle.
        // So, iterate w from largest w_i (which are at the end of the sorted w array)
        // down to the smallest w_i > 1.
        // The largest w_i values should get the smallest available numbers as their min_val.
        // The smallest w_i values should get the largest available numbers as their min_val.
        // This means we pair w[i] with a[a_ptr_max] (for max_val) and a[a_ptr_min] (for min_val).
        // The a_ptr_min should advance by w[i]-1 for each friend.

        int a_ptr_min = 0; // Pointer to the smallest available number in 'a'

        // Iterate through w from largest w_i (that are > 1) down to smallest w_i (> 1).
        // These are the friends who did not get w_i = 1.
        for (int i = k - 1; i >= 0; --i) {
            if (w[i] > 1) {
                total_happiness += a[a_ptr_max]; // Max value for this friend
                a_ptr_max--;
                total_happiness += a[a_ptr_min]; // Min value for this friend
                a_ptr_min += (w[i] - 1); // Consume w[i]-1 numbers from the smallest end
            } else {
                // All remaining w_i are 1, which have already been handled.
                break;
            }
        }

        std::cout << total_happiness << "\n";
    }
    return 0;
}

