void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append at most 3 elements.
        // Let S be current_sum and X be current_xor_sum.
        // We want S' = 2 * X'.
        // S' = S + b1 + b2 + ...
        // X' = X ^ b1 ^ b2 ^ ...

        // Strategy: Append two elements, X and S+X.
        // New XOR sum: X' = X ^ X ^ (S + X) = S + X
        // New SUM: S' = S + X + (S + X) = 2 * S + 2 * X
        // Check condition: S' == 2 * X'
        // 2 * S + 2 * X == 2 * (S + X)
        // This is always true.

        // So, we can always append X and S+X.
        // The problem states that appended elements don't have to be different.
        // If X = 0, then we append 0 and S.
        // If S+X can be very large, up to 10^18.
        // current_sum can be up to 10^5 * 10^9 = 10^14.
        // current_xor_sum can be up to 2^30 (approx 10^9).
        // So S+X can be up to 10^14 + 10^9, which fits in long long.

        std::cout << 2 << "\n";
        std::cout << current_xor_sum << " " << current_sum + current_xor_sum << "\n";
    }
}

