    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>
#include <utility> // For std::pair

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<long long> a(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> a[i];
    }

    std::vector<std::pair<long long, int>> b_indexed(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> b_indexed[i].first;
        b_indexed[i].second = i; // Store original index
    }

    // Sort array A in ascending order
    std::sort(a.begin(), a.end());

    // Sort array B in ascending order based on its values
    std::sort(b_indexed.begin(), b_indexed.end());

    // Create the result array A'
    // The i-th element of the sorted B array (b_indexed[i].first)
    // should be paired with the (m-1-i)-th element of the sorted A array (a[m-1-i])
    // to maximize F(A', B) = (A' + 1) / (B + 1)
    // This means we pair the largest A with the smallest B,
    // the second largest A with the second smallest B, and so on.
    // This is because F(n, k) = (n+1)/(k+1).
    // To maximize sum((A_i+1)/(B_i+1)), we want to pair large (A_i+1) with small (B_i+1).
    // Since A is sorted ascending and B is sorted ascending,
    // a[m-1-i] is the (i+1)-th largest A value.
    // b_indexed[i].first is the (i+1)-th smallest B value.
    std::vector<long long> result_a_prime(m);
    for (int i = 0; i < m; ++i) {
        // The element a[m - 1 - i] (which is the (i+1)-th largest A value)
        // should be placed at the original index of b_indexed[i].first
        result_a_prime[b_indexed[i].second] = a[m - 1 - i];
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result_a_prime[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

