#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    std::string s;
    std::cin >> s;
    int x;
    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // First pass: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then w[i-x] (if exists) must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            // And w[i+x] (if exists) must be '0'
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Second pass: Verify if the constructed w can produce s
    std::string s_reconstructed(n, '0');
    for (int i = 0; i < n; ++i) {
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            s_reconstructed[i] = '1';
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            s_reconstructed[i] = '1';
        }
    }

    if (s_reconstructed == s) {
        std::cout << w << std::endl;
    } else {
        std::cout << -1 << std::endl;
    }
}

