int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int n = s.length();
        int max_gap = 0;
        int last_r_pos = -1; // Represents the position of the last 'R' or the starting point 0.
                             // If last_r_pos is -1, it means the frog is at cell 0.
                             // If last_r_pos is i, it means the frog is at cell i.
                             // The distance is calculated from the previous 'R' cell to the current 'R' cell.

        for (int i = 0; i < n; ++i) {
            if (s[i] == 'R') {
                // The current cell is i+1 (1-indexed).
                // The previous 'R' cell was last_r_pos (0-indexed, or -1 for start).
                // The distance between them is (i+1) - (last_r_pos + 1) if last_r_pos >= 0,
                // or (i+1) - 0 if last_r_pos == -1.
                // This simplifies to (i+1) - (last_r_pos + 1) = i - last_r_pos.
                // If last_r_pos is -1, it's (i+1) - 0 = i+1.
                max_gap = std::max(max_gap, (i + 1) - (last_r_pos + 1) + 1); // +1 because it's distance between cells, not indices
                                                                             // (i+1) is current cell, (last_r_pos+1) is previous R cell.
                                                                             // The jump distance needed is (current_cell - previous_cell) + 1.
                                                                             // Example: from 0 to 1, distance is 1. (1-0)+1 = 2. No, this is wrong.
                                                                             // If frog is at cell X, and wants to reach cell Y, it needs to jump Y-X cells.
                                                                             // So, if last_r_pos is -1 (cell 0), and current 'R' is at index i (cell i+1),
                                                                             // the jump is from 0 to i+1. Distance is (i+1) - 0 = i+1.
                                                                             // If last_r_pos is j (cell j+1), and current 'R' is at index i (cell i+1),
                                                                             // the jump is from j+1 to i+1. Distance is (i+1) - (j+1) = i-j.
                                                                             // The maximum of these distances is what we need.

                // Let's re-evaluate:
                // The frog must be able to jump from the previous 'R' cell (or 0) to the current 'R' cell.
                // If previous 'R' cell was at index `prev_idx` (so cell `prev_idx + 1`),
                // and current 'R' cell is at index `curr_idx` (so cell `curr_idx + 1`),
                // the distance is `(curr_idx + 1) - (prev_idx + 1) = curr_idx - prev_idx`.
                // If starting from cell 0, `prev_idx` is effectively -1.
                // So, distance is `(curr_idx + 1) - 0 = curr_idx + 1`.
                // The `d` must be at least this distance.
                // So, `d >= curr_idx - prev_idx` (if prev_idx >= 0)
                // and `d >= curr_idx + 1` (if prev_idx == -1).
                // This can be unified as `d >= (curr_idx + 1) - (prev_idx + 1)` where `prev_idx + 1` is the cell number.
                // Let `prev_cell = last_r_pos + 1` (if `last_r_pos == -1`, `prev_cell = 0`).
                // Let `curr_cell = i + 1`.
                // The required jump distance is `curr_cell - prev_cell`.
                // `max_gap` should store the maximum of these required jump distances.

                int current_cell_idx = i + 1;
                int previous_cell_idx = (last_r_pos == -1) ? 0 : (last_r_pos + 1);
                max_gap = std::max(max_gap, current_cell_idx - previous_cell_idx + 1); // +1 because jump from X to Y means Y-X cells, but d is max jump length.
                                                                                        // If we need to jump from cell A to cell B, the distance is B-A.
                                                                                        // The frog can jump by no more than d cells. So d must be >= B-A.
                                                                                        // The problem states "jump by no more than d cells at once".
                                                                                        // If frog is at i, and s[i] is 'R', it can jump to [i+1; min(n+1; i+d)].
                                                                                        // So, if it needs to reach cell `target_cell` from `current_cell`,
                                                                                        // it needs `target_cell <= current_cell + d`.
                                                                                        // So `d >= target_cell - current_cell`.
                                                                                        // The minimum `d` is the maximum of `target_cell - current_cell` over all necessary jumps.

                // Let's re-re-evaluate.
                // The frog starts at cell 0.
                // It needs to reach cell n+1.
                // It can only jump right from 0.
                // If it lands on an 'L' cell, it must jump left. This is bad for progress.
                // So, to guarantee reaching n+1, it must be able to jump over all 'L' segments.
                // This means it must be able to jump from cell 0 to the first 'R' cell,
                // then from that 'R' cell to the next 'R' cell, and so on,
                // until the last 'R' cell, and then from the last 'R' cell to n+1.
                // The maximum distance between consecutive 'R' cells (or 0 and first 'R', or last 'R' and n+1)
                // determines the minimum `d`.

                // `last_r_pos` stores the 0-indexed position of the last 'R' character encountered.
                // If `last_r_pos == -1`, it means we are considering the jump from cell 0.
                // The current 'R' character is at `s[i]`, which corresponds to cell `i+1`.
                // The distance from the previous 'R' cell (or 0) to the current 'R' cell is:
                // If `last_r_pos == -1`: distance from cell 0 to cell `i+1` is `(i+1) - 0 = i+1`.
                // If `last_r_pos >= 0`: distance from cell `last_r_pos + 1` to cell `i+1` is `(i+1) - (last_r_pos + 1) = i - last_r_pos`.
                // We need `d` to be at least this distance.
                max_gap = std::max(max_gap, i - last_r_pos);
                last_r_pos = i;
            }
        }
        // After iterating through all characters, we need to consider the jump from the last 'R' cell
        // to the target cell `n+1`.
        // If `last_r_pos == -1`, it means there were no 'R' characters. The frog must jump from cell 0 to cell `n+1`.
        // The distance is `(n+1) - 0 = n+1`.
        // If `last_r_pos >= 0`, it means the last 'R' was at `s[last_r_pos]`, corresponding to cell `last_r_pos + 1`.
        // The distance from cell `last_r_pos + 1` to cell `n+1` is `(n+1) - (last_r_pos + 1) = n - last_r_pos`.
        max_gap = std::max(max_gap, n - last_r_pos);

        std::cout << max_gap << "\n";
    }
    return 0;
}

