int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::string s;
    std::cin >> s;

    int n = s.length();

    std::vector<std::vector<int>> prefix_counts(3, std::vector<int>(n + 1, 0));

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < 3; ++j) {
            prefix_counts[j][i + 1] = prefix_counts[j][i];
        }
        if (s[i] == 'x') {
            prefix_counts[0][i + 1]++;
        } else if (s[i] == 'y') {
            prefix_counts[1][i + 1]++;
        } else { // s[i] == 'z'
            prefix_counts[2][i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = prefix_counts[0][r] - prefix_counts[0][l - 1];
        int count_y = prefix_counts[1][r] - prefix_counts[1][l - 1];
        int count_z = prefix_counts[2][r] - prefix_counts[2][l - 1];

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n; // Number of matryoshkas
    int k; // Number of initial chains
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_pairs_in_sequence = 0; // Counts how many times (i, i+1) is found in sequence

    for (int i = 0; i < k; ++i) {
        int m; // Length of the current chain
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        // If the first doll in a chain is 1, it's the start of the target sequence.
        // We count how many subsequent dolls are also in the correct sequence.
        if (chain[0] == 1) {
            for (int j = 0; j < m - 1; ++j) {
                if (chain[j+1] == chain[j] + 1) {
                    correct_pairs_in_sequence++;
                } else {
                    // The sequence 1 -> 2 -> ... -> X is broken.
                    // Any further dolls in this chain are not part of the initial correct sequence.
                    break; 
                }
            }
        }
    }

    // Total operations = (n - 1) operations to assemble the final chain
    //                  + (n - k) operations to disassemble chains (each chain needs m-1 unnestings,
    //                                                               but the last doll in each chain doesn't need to be unnested from anything,
    //                                                               so it's sum(m_i - 1) = sum(m_i) - k = n - k)
    //
    // However, we can optimize.
    //
    // The number of dolls that need to be "taken out" from their current nesting
    // is (n - k). This is because each chain of length m_i has m_i - 1 nested pairs.
    // To break all chains into individual dolls, we need sum(m_i - 1) = sum(m_i) - k = n - k operations.
    //
    // The number of dolls that need to be "put in" to form the final chain 1->2->...->n
    // is (n - 1). This is because there are n-1 pairs (i, i+1) that need to be formed.
    //
    // Total operations if we disassemble everything and reassemble: (n - k) + (n - 1).
    //
    // Now, consider the "correct_pairs_in_sequence".
    // If we have 1 -> 2 -> ... -> X, this means X-1 pairs are already correctly formed.
    // These X-1 pairs do not need to be disassembled (taken out) and do not need to be reassembled (put in).
    // So, for each such correct pair (i, i+1) where i is part of the 1->2->... sequence,
    // we save 1 disassembly operation and 1 assembly operation.
    //
    // The number of dolls that are part of the initial 1 -> 2 -> ... -> X sequence is (correct_pairs_in_sequence + 1).
    // These (correct_pairs_in_sequence + 1) dolls form a contiguous block that is already in the target configuration.
    //
    // The number of "put in" operations saved is `correct_pairs_in_sequence`.
    // The number of "take out" operations saved is also `correct_pairs_in_sequence`.
    //
    // So, the total operations are:
    // (n - k)  // Disassemble all other dolls
    // + (n - 1) // Assemble all other dolls
    // - (2 * correct_pairs_in_sequence) // Subtract operations saved by the 1->2->... sequence
    //
    // Example 1: n=3, k=2. Chains: 2 1 2, 1 3.
    // correct_pairs_in_sequence = 1 (for 1->2)
    // Total = (3 - 2) + (3 - 1) - (2 * 1) = 1 + 2 - 2 = 1. Correct.
    //
    // Example 2: n=7, k=3. Chains: 3 1 3 7, 2 2 5, 2 4 6.
    // No chain starts with 1 and continues as 1->2.
    // correct_pairs_in_sequence = 0.
    // Total = (7 - 3) + (7 - 1) - (2 * 0) = 4 + 6 - 0 = 10. Correct.

    total_operations = (long long)(n - k) + (n - 1) - (2LL * correct_pairs_in_sequence);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>

long long solve() {
    long long n;
    std::cin >> n;

    long long chanek_coins = 0;

    // Turn 1: Mr. Chanek
    if (n % 2 == 1) {
        // N is odd. Chanek must take 1.
        chanek_coins += 1;
        n -= 1;
    } else {
        // N is even. Chanek has two choices: take 1 or take N/2.
        // If Chanek takes 1, N becomes odd.
        // If Chanek takes N/2, N becomes N/2.
        // We need to consider the opponent's optimal play after Chanek's move.

        // Case A: Chanek takes 1.
        // N becomes n-1 (odd).
        // Opponent's turn with n-1 coins. Opponent takes 1. N becomes n-2 (even).
        // Chanek's turn with n-2 coins.
        // This path seems less optimal for Chanek if N/2 is a good move.

        // Case B: Chanek takes N/2.
        // N becomes N/2.
        // Opponent's turn with N/2 coins.
        // If N/2 is odd, opponent takes 1. N becomes N/2 - 1.
        // If N/2 is even, opponent can take 1 or (N/2)/2 = N/4.
        // The opponent will try to maximize their own coins.

        // Let's analyze the game structure.
        // If N is even, Chanek can take N/2. This is generally a strong move.
        // If N becomes N/2, the opponent faces N/2.
        // If N/2 is odd, the opponent takes 1.
        // If N/2 is even, the opponent can take (N/2)/2 = N/4.

        // The strategy for Chanek is to take N/2 if it leads to a better outcome.
        // The opponent will also try to take N/2 if possible.
        // The game essentially boils down to who gets to take N/2 when N is a power of 2.

        // Consider N = 6.
        // Chanek's turn. N=6.
        // Option 1: Take 1. Chanek=1, N=5.
        //   Opponent's turn. N=5. Opponent takes 1. Opponent=1, N=4.
        //   Chanek's turn. N=4. Chanek takes 2. Chanek=1+2=3, N=2.
        //   Opponent's turn. N=2. Opponent takes 1. Opponent=1+1=2, N=1.
        //   Chanek's turn. N=1. Chanek takes 1. Chanek=3+1=4, N=0.
        //   Result: Chanek=4, Opponent=2.

        // Option 2: Take N/2 = 3. Chanek=3, N=3.
        //   Opponent's turn. N=3. Opponent takes 1. Opponent=1, N=2.
        //   Chanek's turn. N=2. Chanek takes 1. Chanek=3+1=4, N=1.
        //   Opponent's turn. N=1. Opponent takes 1. Opponent=1+1=2, N=0.
        //   Result: Chanek=4, Opponent=2.

        // In this case, both options lead to Chanek getting 4.
        // The example output for N=6 is 4.

        // Consider N = 5.
        // Chanek's turn. N=5. Chanek takes 1. Chanek=1, N=4.
        // Opponent's turn. N=4. Opponent takes 2. Opponent=2, N=2.
        // Chanek's turn. N=2. Chanek takes 1. Chanek=1+1=2, N=1.
        // Opponent's turn. N=1. Opponent takes 1. Opponent=2+1=3, N=0.
        // Result: Chanek=2, Opponent=3.
        // The example output for N=5 is 2.

        // The core idea is that players will always try to take N/2 if N is even,
        // unless taking 1 leads to a better outcome for them.
        // Taking N/2 is generally better because it reduces the total coins faster,
        // giving the current player a larger share.

        // Let's simulate the game with a greedy approach:
        // If N is odd, take 1.
        // If N is even, take N/2.
        // This is the optimal strategy for the current player to maximize their immediate gain.
        // We need to see if this greedy strategy holds for the overall game.

        // Let's trace N=6 with this greedy strategy:
        // Chanek: N=6. Takes N/2=3. Chanek=3. N=3.
        // Opponent: N=3. Takes 1. Opponent=1. N=2.
        // Chanek: N=2. Takes N/2=1. Chanek=3+1=4. N=1.
        // Opponent: N=1. Takes 1. Opponent=1+1=2. N=0.
        // Result: Chanek=4, Opponent=2. This matches the example.

        // Let's trace N=5 with this greedy strategy:
        // Chanek: N=5. Takes 1. Chanek=1. N=4.
        // Opponent: N=4. Takes N/2=2. Opponent=2. N=2.
        // Chanek: N=2. Takes N/2=1. Chanek=1+1=2. N=1.
        // Opponent: N=1. Takes 1. Opponent=2+1=3. N=0.
        // Result: Chanek=2, Opponent=3. This matches the example.

        // This greedy strategy seems to work for the examples.
        // The only time a player might deviate from taking N/2 when N is even
        // is if taking 1 coin leaves the opponent in a worse position,
        // and thus the current player gets more in the long run.

        // Consider N = 4.
        // Chanek: N=4.
        // Option 1: Take 1. Chanek=1, N=3.
        //   Opponent: N=3. Takes 1. Opponent=1, N=2.
        //   Chanek: N=2. Takes 1. Chanek=1+1=2, N=1.
        //   Opponent: N=1. Takes 1. Opponent=1+1=2, N=0.
        //   Result: Chanek=2, Opponent=2.

        // Option 2: Take N/2 = 2. Chanek=2, N=2.
        //   Opponent: N=2. Takes 1. Opponent=1, N=1.
        //   Chanek: N=1. Takes 1. Chanek=2+1=3, N=0.
        //   Result: Chanek=3, Opponent=1.
        // Chanek chooses Option 2. Chanek gets 3.

        // The greedy strategy (always take N/2 if even, else 1) for N=4:
        // Chanek: N=4. Takes N/2=2. Chanek=2. N=2.
        // Opponent: N=2. Takes N/2=1. Opponent=1. N=1.
        // Chanek: N=1. Takes 1. Chanek=2+1=3. N=0.
        // Result: Chanek=3, Opponent=1. This matches.

        // It seems the greedy strategy (take N/2 if even, else 1) is optimal for both players.
        // The only exception is when N is even, and taking 1 coin leads to a better outcome.
        // This happens when N is a power of 2, say N = 2^k.
        // If Chanek takes N/2 = 2^(k-1), then opponent faces 2^(k-1).
        // If Chanek takes 1, then N becomes 2^k - 1 (odd). Opponent takes 1, N becomes 2^k - 2 (even).
        // This seems complicated.

        // Let's re-evaluate the optimal strategy for an even N.
        // If N is even, Chanek can take 1 or N/2.
        // If Chanek takes 1: Chanek gets 1. Remaining N-1. Opponent plays optimally on N-1.
        // If Chanek takes N/2: Chanek gets N/2. Remaining N/2. Opponent plays optimally on N/2.

        // Let f(k) be the maximum coins Chanek can get if it's his turn and k coins are left.
        // Let g(k) be the maximum coins opponent can get if it's opponent's turn and k coins are left.
        // Chanek wants to maximize f(N).
        // Opponent wants to maximize g(N).

        // If k is odd:
        // Chanek must take 1. Chanek gets 1 + (total_coins_left - g(k-1)).
        // Opponent must take 1. Opponent gets 1 + (total_coins_left - f(k-1)).

        // If k is even:
        // Chanek can take 1 or k/2.
        // Option 1 (take 1): Chanek gets 1 + (total_coins_left - g(k-1)).
        // Option 2 (take k/2): Chanek gets k/2 + (total_coins_left - g(k/2)).
        // Chanek chooses max(Option 1, Option 2).

        // This is a minimax problem.
        // The total coins are N.
        // Let C(k) be coins Chanek gets if k coins are left and it's Chanek's turn.
        // Let O(k) be coins Opponent gets if k coins are left and it's Opponent's turn.
        // We want to find C(N).

        // C(k):
        // If k is odd: Chanek takes 1. Chanek gets 1. Remaining k-1. Opponent plays on k-1.
        //   Chanek's total = 1 + (k-1 - O(k-1)).
        // If k is even:
        //   Option 1 (take 1): Chanek gets 1. Remaining k-1. Opponent plays on k-1.
        //     Chanek's total = 1 + (k-1 - O(k-1)).
        //   Option 2 (take k/2): Chanek gets k/2. Remaining k/2. Opponent plays on k/2.
        //     Chanek's total = k/2 + (k/2 - O(k/2)).
        //   C(k) = max(1 + (k-1 - O(k-1)), k/2 + (k/2 - O(k/2))).

        // O(k):
        // If k is odd: Opponent takes 1. Opponent gets 1. Remaining k-1. Chanek plays on k-1.
        //   Opponent's total = 1 + (k-1 - C(k-1)).
        // If k is even:
        //   Option 1 (take 1): Opponent gets 1. Remaining k-1. Chanek plays on k-1.
        //     Opponent's total = 1 + (k-1 - C(k-1)).
        //   Option 2 (take k/2): Opponent gets k/2. Remaining k/2. Chanek plays on k/2.
        //     Opponent's total = k/2 + (k/2 - C(k/2)).
        //   O(k) = max(1 + (k-1 - C(k-1)), k/2 + (k/2 - C(k/2))).

        // Base cases:
        // C(0) = 0, O(0) = 0.
        // C(1): Chanek takes 1. Chanek=1. N=0. Opponent gets 0. C(1)=1.
        // O(1): Opponent takes 1. Opponent=1. N=0. Chanek gets 0. O(1)=1.

        // Let's simplify. The total coins are always split.
        // Let P1(k) be coins player 1 gets if k coins are left and it's player 1's turn.
        // Let P2(k) be coins player 2 gets if k coins are left and it's player 2's turn.
        // P1(k) + P2_from_k(k) = k.
        // P1(k) = k - P2_from_k(k).
        // P2_from_k(k) is the coins player 2 gets when player 1 starts with k coins.
        // This is equivalent to P2(k) if player 2 starts with k coins.

        // Let's use a simpler state: (current_N, current_player_turn).
        // We want to find the maximum coins for Mr. Chanek.
        // The game state is just N.
        // We can simulate the game turn by turn.

        // Mr. Chanek's turn:
        // If N is odd: Chanek takes 1. chanek_coins += 1. N -= 1.
        // If N is even:
        //   Option A: Chanek takes 1. chanek_coins += 1. N -= 1.
        //   Option B: Chanek takes N/2. chanek_coins += N/2. N -= N/2.
        //   Which one to choose?
        //   If N is a power of 2 (e.g., 2, 4, 8, 16, ...):
        //     If Chanek takes N/2, opponent faces N/2 (also a power of 2).
        //     If Chanek takes 1, opponent faces N-1 (odd). Opponent takes 1, faces N-2 (even).
        //     Example N=4:
        //       Take 1: Chanek=1, N=3. Opponent takes 1. Opponent=1, N=2. Chanek takes 1. Chanek=1+1=2, N=1. Opponent takes 1. Opponent=1+1=2, N=0. Chanek=2.
        //       Take N/2=2: Chanek=2, N=2. Opponent takes 1. Opponent=1, N=1. Chanek takes 1. Chanek=2+1=3, N=0. Chanek=3.
        //     So for N=4, Chanek takes N/2.
        //     It seems for N=2^k, Chanek always takes N/2.
