                //     If k is odd: Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^0.
                //       This is (2^k - 1)/3. No.
                //       Example N=2 (k=1): Chanek gets 2^0 = 1.
                //       Example N=8 (k=3): Chanek gets 2^2 + 2^0 = 4+1=5.
                //     If k is even: Chanek gets 2^(k-1) + 2^(k-3) + ... + 2^1.
                //       Example N=4 (k=2): Chanek gets 2^1 = 2. But we found 3.
                //       This means the "take N/2" strategy is not always optimal for powers of 2.

                // The special case is N=2.
                // If N=2, Chanek takes 1. Chanek=1, N=1. Opponent takes 1. Opponent=1, N=0. Chanek=1.
                // If N=2, Chanek takes N/2=1. Chanek=1, N=1. Opponent takes 1. Opponent=1, N=0. Chanek=1.
                // So for N=2, it doesn't matter.

                // Let's reconsider N=4.
                // Chanek's turn, N=4.
                // Option 1: Take 1. Chanek=1, N=3.
                //   Opponent's turn, N=3. Opponent takes 1. Opponent=1, N=2.
                //   Chanek's turn, N=2. Chanek takes 1. Chanek=1+1=2, N=1.
                //   Opponent's turn, N=1. Opponent takes 1. Opponent=1+1=2, N=0.
                //   Total for Chanek: 2.
                // Option 2: Take N/2=2. Chanek=2, N=2.
                //   Opponent's turn, N=2. Opponent takes 1. Opponent=1, N=1.
                //   Chanek's turn, N=1. Chanek takes 1. Chanek=2+1=3, N=0.
                //   Total for Chanek: 3.
                // Chanek chooses Option 2.

                // The strategy is:
                // If N is odd: take 1.
                // If N is even:
                //   If N is a power of 2:
                //     If N=2, take 1 (or N/2).
                //     If N > 2 and N is a power of 2, take 1. (This is the key insight for powers of 2 > 2)
                //     Why? If Chanek takes 1, N becomes N-1 (odd). Opponent takes 1. N becomes N-2 (even).
                //     If Chanek takes N/2, N becomes N/2 (power of 2). Opponent takes N/4. N becomes N/4.
                //     Example N=4.
                //       Take 1: Chanek=1, N=3. Opponent takes 1. Opponent=1, N=2. Chanek takes 1. Chanek=2, N=1. Opponent takes 1. Opponent=2, N=0. Chanek gets 2.
                //       Take N/2=2: Chanek=2, N=2. Opponent takes 1. Opponent=1, N=1. Chanek takes 1. Chanek=3, N=0. Chanek gets 3.
                //     So for N=4, Chanek takes N/2. My previous analysis was correct.
                //     The rule "If N > 2 and N is a power of 2, take 1" is wrong.

                // Let's stick to the simple greedy simulation and see if it matches all examples.
                // The examples N=5 (output 2) and N=6 (output 4) are matched by the greedy strategy:
                // N=5: C:1, N=4. O:2, N=2. C:1, N=1. O:1, N=0. C_total=1+1=2.
                // N=6: C:3, N=3. O:1, N=2. C:1, N=1. O:1, N=0. C_total=3+1=4.

                // The only time the greedy strategy (take N/2 if even, else 1) might not be optimal
                // is if taking 1 coin when N is even leads to a better outcome for the current player.
                // This happens when taking N/2 would give the opponent a very good position.
                // The opponent's "very good position" would be facing a large N that is a power of 2.

                // Let's consider the total coins.
                // If N is even, and N is not a power of 2, then N/2 is not a power of 2 (unless N/2 is odd, which means N=2*odd).
                // If N is even and not a power of 2, then N has an odd factor.
                // E.g., N=6. N/2=3. Opponent faces 3 (odd). Opponent takes 1. N=2.
                // E.g., N=10. N/2=5. Opponent faces 5 (odd). Opponent takes 1. N=4.
                // E.g., N=12. N/2=6. Opponent faces 6 (even, not power of 2). Opponent takes 3. N=3.
                // It seems that if N is even and not a power of 2, taking N/2 is always the best move.
                // Because it reduces N significantly, and the opponent will likely face an odd number or another non-power-of-2 even number.

                // The only tricky case is when N is a power of 2.
                // N = 2^k.
                // If Chanek takes N/2, he gets 2^(k-1). Opponent faces 2^(k-1).
                // If Chanek takes 1, he gets 1. Opponent faces 2^k - 1. Opponent takes 1. Chanek faces 2^k - 2.
                // Let's compare the outcomes for Chanek.
                // Outcome 1 (take N/2): Chanek gets 2^(k-1) + (coins Chanek gets from 2^(k-1) when opponent starts).
                // Outcome 2 (take 1): Chanek gets 1 + (coins Chanek gets from 2^k-2 when Chanek starts).

                // This is a known game theory problem. The optimal strategy is:
                // If N is odd, take 1.
                // If N is even:
                //   If N is a power of 2 (N = 2^k):
                //     Take 1. (This is the key deviation from simple greedy)
                //   If N is even but not a power of 2:
                //     Take N/2.

                // Let's test this refined strategy:
                // N=1: C:1, N=0. Chanek=1. (Matches)
                // N=2: C:1, N=1. O:1, N=0. Chanek=1. (Matches)
                // N=3: C:1, N=2. O:1, N=1. C:1, N=0. Chanek=2. (Matches)
                // N=4: N is even, power of 2. Take 1.
                //   C:1, N=3. O:1, N=2. C:1, N=1. O:1, N=0. Chanek=2.
                //   This is different from my previous N=4 analysis where Chanek got 3.
                //   My previous N=4 analysis:
                //     Option 1 (take 1): Chanek=2.
                //     Option 2 (take N/2=2): Chanek=3.
                //   So Chanek should take N/2 for N=4.
                //   This means the rule "If N is a power of 2, take 1" is incorrect.

                // The simple greedy strategy (always take N/2 if even, else 1) seems to be the correct one.

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <cmath>

// Function to get prime factors of a number
// Returns a vector of pairs: (prime_factor, exponent)
std::vector<std::pair<long long, int>> get_prime_factors(long long n) {
    std::vector<std::pair<long long, int>> factors;
    for (long long i = 2; i * i <= n; ++i) {
        if (n % i == 0) {
            int count = 0;
            while (n % i == 0) {
                n /= i;
                count++;
            }
            factors.push_back({i, count});
        }
    }
    if (n > 1) {
        factors.push_back({n, 1});
    }
    return factors;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long p;
        long long q;
        std::cin >> p >> q;

        if (p % q != 0) {
            std::cout << p << "\n";
            continue;
        }

        // p is divisible by q. We need to find the largest x such that p % x == 0 and x % q != 0.
        // This means x must be p / k for some k, and (p / k) % q != 0.
        // The largest such x will be p / smallest_k_that_makes_it_work.
        // Or, equivalently, we are looking for the largest divisor of p that is not divisible by q.

        // Let's find prime factors of q.
        std::vector<std::pair<long long, int>> q_factors = get_prime_factors(q);

        long long max_x = 0;

        // Iterate through each prime factor of q
        for (const auto& q_factor_pair : q_factors) {
            long long prime_factor = q_factor_pair.first;
            // int q_exponent = q_factor_pair.second; // Not directly used, but conceptually important

            // Calculate the highest power of prime_factor that divides p
            long long temp_p = p;
            long long current_p_prime_power_val = 1;
            while (temp_p > 0 && temp_p % prime_factor == 0) {
                temp_p /= prime_factor;
                current_p_prime_power_val *= prime_factor;
            }

            // We want to remove just enough factors of prime_factor from p
            // such that the resulting number is no longer divisible by q.
            // If p = A * (prime_factor)^k and q = B * (prime_factor)^m,
            // where A and B are not divisible by prime_factor, and k >= m.
            // We want to find x = p / (prime_factor)^j such that x % q != 0.
            // To make x not divisible by q, we need to reduce the power of prime_factor in x
            // to be less than the power of prime_factor in q.
            // The smallest j that achieves this is j = k - m + 1.
            // So, x = p / (prime_factor)^(k - m + 1).
            // This is equivalent to x = (p / (prime_factor)^k) * (prime_factor)^(m-1).
            // Or simply, x = p / (current_p_prime_power_val / prime_factor).
            // This x is p divided by the highest power of prime_factor that divides p,
            // then multiplied by prime_factor.
            // This is equivalent to p divided by (prime_factor raised to the power of (count of prime_factor in p)).
            // Then multiply by prime_factor.
            // Or, more simply, p / (prime_factor ^ (count of prime_factor in p)) * (prime_factor ^ (count of prime_factor in q) - 1)
            // No, it's p / (prime_factor ^ (count of prime_factor in p - count of prime_factor in q + 1))
            // This is p / (current_p_prime_power_val / prime_factor).

            // The value of x we are considering is p divided by (prime_factor raised to the power of (count of prime_factor in p) - (count of prime_factor in q) + 1)
            // This is equivalent to p / (current_p_prime_power_val / prime_factor)
            // Let's calculate p_prime_power_val = prime_factor ^ (count of prime_factor in p)
            // The candidate x is p / (p_prime_power_val / prime_factor)
            // This ensures that the resulting x has one less factor of prime_factor than q has.
            // Example: p=12, q=6. q_factors: (2,1), (3,1).
            // For prime_factor=2: p_prime_power_val for 2 in 12 is 4 (2^2).
            // Candidate x = 12 / (4/2) = 12 / 2 = 6. (6 % 6 == 0, not valid)
            // This logic is flawed.

            // Correct logic:
            // We want to find x = p / (prime_factor^k) such that x is not divisible by q.
            // For a specific prime_factor of q, let its exponent in q be `exp_q`.
            // Let its exponent in p be `exp_p`. Since p % q == 0, `exp_p >= exp_q`.
            // To make x not divisible by q, we need to reduce the exponent of `prime_factor` in x
            // to be less than `exp_q`. The largest such x would have `exp_q - 1` factors of `prime_factor`.
            // So, we need to divide p by `prime_factor` `(exp_p - (exp_q - 1))` times.
            // This is `exp_p - exp_q + 1` times.
            // So, the candidate x is `p / (prime_factor ^ (exp_p - exp_q + 1))`.

            long long current_p_val = p;
            long long divisor_for_this_factor = 1;
            while (current_p_val % q == 0) { // Keep dividing p by prime_factor as long as p is divisible by q
                current_p_val /= prime_factor;
                divisor_for_this_factor *= prime_factor;
            }
            // After the loop, current_p_val is p / (prime_factor ^ k) such that (p / (prime_factor ^ k)) % q != 0.
            // The actual x we are looking for is p / divisor_for_this_factor.
            // This is the largest divisor of p that is not divisible by q, considering only this prime_factor.
            // We need to find the maximum among all such candidates.
            max_x = std::max(max_x, p / divisor_for_this_factor);
        }
        std::cout << max_x << "\n";
    }
    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        int min_x = -100000;
        int max_x = 100000;
        int min_y = -100000;
        int max_y = 100000;

        for (int i = 0; i < n; ++i) {
            int x, y, f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0 means cannot move left (x-1). So target X must be >= current x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f3 = 0 means cannot move right (x+1). So target X must be <= current x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 0 means cannot move down (y-1). So target Y must be >= current y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
            // f2 = 0 means cannot move up (y+1). So target Y must be <= current y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>

void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<char> fixed_chars(k, '?'); // Stores the determined character for each position modulo k

    // Step 1: Propagate known characters and check for conflicts
    for (int i = 0; i < n; ++i) {
        if (s[i] != '?') {
            int remainder = i % k;
            if (fixed_chars[remainder] == '?') {
                fixed_chars[remainder] = s[i];
            } else if (fixed_chars[remainder] != s[i]) {
                // Conflict: s[i] is '0' but fixed_chars[remainder] is '1', or vice versa
                std::cout << "NO\n";
                return;
            }
        }
    }

    // Step 2: Count '0's and '1's among the fixed characters in the first k positions
    int count0 = 0;
    int count1 = 0;
    for (int i = 0; i < k; ++i) {
        if (fixed_chars[i] == '0') {
            count0++;
        } else if (fixed_chars[i] == '1') {
            count1++;
        }
    }

    // Step 3: Check if it's possible to fill '?'s to satisfy k/2 balance
    // We need k/2 zeros and k/2 ones in total for the first k positions.
    // The remaining '?'s (k - count0 - count1) must be filled such that
    // (count0 + new_zeros) = k/2 and (count1 + new_ones) = k/2.
    // This means new_zeros = k/2 - count0 and new_ones = k/2 - count1.
    // Both new_zeros and new_ones must be non-negative.
    // Also, new_zeros + new_ones must equal the number of '?'s.

    if (count0 > k / 2 || count1 > k / 2) {
        std::cout << "NO\n";
        return;
    }

    // If we reach here, it means we can fill the '?'s in fixed_chars
    // to satisfy the k/2 balance for the first k characters.
    // Since s[i] must be equal to s[i+k], and we've ensured consistency
    // for all known characters, and we can fill the first k characters
    // to be k-balanced, then the entire string can be made k-balanced.
    std::cout << "YES\n";
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    // Sum of k from 1 to a: a * (a + 1) / 2
    // Sum of r from 1 to b-1: (b-1) * b / 2

    // The formula derived is:
    // sum_x = (sum_{k=1 to a} k) * (sum_{r=1 to b-1} r) * b + (sum_{r=1 to b-1} r)
    // sum_x = (sum_{k=1 to a} k) * (sum_{r=1 to b-1} r * b) + (sum_{r=1 to b-1} r)
    // sum_x = (sum_{k=1 to a} k) * (sum_{r=1 to b-1} r * b + 1)

    // Let S_k = sum_{k=1 to a} k = a * (a + 1) / 2
    // Let S_r = sum_{r=1 to b-1} r = (b-1) * b / 2

    // S_k_mod = (a % MOD * ((a + 1) % MOD)) % MOD * inv2 % MOD
    // S_r_mod = ((b - 1) % MOD * (b % MOD)) % MOD * inv2 % MOD

    // The sum is (S_k * b + 1) * S_r
    // This is equivalent to (S_k * b) * S_r + S_r

    // Calculate S_k = a * (a + 1) / 2
    long long sum_k_term = (a % MOD * ((a + 1) % MOD)) % MOD;
    long long inv2 = (MOD + 1) / 2; // Modular inverse of 2 modulo MOD
    long long S_k_mod = (sum_k_term * inv2) % MOD;

    // Calculate S_r = (b - 1) * b / 2
    long long sum_r_term = ((b - 1) % MOD * (b % MOD)) % MOD;
    long long S_r_mod = (sum_r_term * inv2) % MOD;

    // Calculate the first part: (S_k * b) % MOD
    long long part1 = (S_k_mod * (b % MOD)) % MOD;

    // Add 1 to part1: (part1 + 1) % MOD
    long long part1_plus_1 = (part1 + 1) % MOD;

    // Multiply by S_r_mod: (part1_plus_1 * S_r_mod) % MOD
    long long total_sum = (part1_plus_1 * S_r_mod) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <numeric>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (char p_char = '0'; p_char <= '9'; ++p_char) {
        int p = p_char - '0';
        std::string current_coloring(n, ' ');

        std::vector<int> s1_digits;
        std::vector<int> s2_digits;

        bool possible_for_p = true;

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                current_coloring[i] = '1';
                s1_digits.push_back(digit);
            } else if (digit > p) {
                current_coloring[i] = '2';
                s2_digits.push_back(digit);
            } else { // digit == p
                // For digits equal to p, we try to assign them to color 1 first,
                // then switch to color 2 once we encounter the first digit > p.
                // This greedy approach ensures S1 is as long as possible with p's,
                // and S2 starts with p's.
                // This is incorrect. The logic for p needs to be more careful.
                // Let's refine: all digits < p go to S1. All digits > p go to S2.
                // Digits == p: some go to S1, some go to S2.
                // The split point for 'p' digits must be such that all 'p's before a certain index go to S1,
                // and all 'p's after that index go to S2.
                // This is equivalent to finding the *first* occurrence of a digit > p.
                // All p's before that digit can go to S1. All p's after that digit must go to S2.
                // This is still not quite right.
                // The correct logic for 'p' is:
                // All digits < p are color 1.
                // All digits > p are color 2.
                // For digits == p:
                //   The first block of 'p's (up to the first digit > p) can be color 1.
                //   The second block of 'p's (after the first digit > p) must be color 2.
                //   This means we need to find the *last* digit 'p' that can be colored '1'.
                //   All 'p's before or at this index are '1'. All 'p's after this index are '2'.
                //   This is equivalent to finding the first digit 'p' that we *must* color '2'.
                //   This happens if we encounter a digit 'd_k > p' and then later a digit 'd_j = p'.
                //   Then 'd_j' must be color '2'.
                //   So, we can find the first index `first_gt_p_idx` where `s[first_gt_p_idx] > p`.
                //   All `s[i] == p` for `i < first_gt_p_idx` can be '1'.
                //   All `s[i] == p` for `i >= first_gt_p_idx` must be '2'.
                //   This is the strategy.

                // Let's re-evaluate the coloring for 'p'.
                // We need to find the first index `idx_first_gt_p` such that `s[idx_first_gt_p] > p`.
                // If no such index exists, all digits `p` can be '1'.
                // If such an index exists, all `p`s before it are '1', all `p`s after it are '2'.
                // This is the most flexible way to assign 'p's.

                // Let's try a simpler greedy approach for 'p':
                // Assign '1' to 'p's as long as possible, then switch to '2'.
                // The switch point for 'p's is determined by the first digit that is strictly greater than 'p'.
                // All 'p's before this point can be '1'. All 'p's after this point must be '2'.
                // This is the standard approach for this type of problem.

                // Let's find the split point for 'p's.
                // `split_p_idx` is the index where we switch from coloring 'p's as '1' to coloring 'p's as '2'.
                // Initially, assume all 'p's can be '1'.
                // If we encounter a digit `d_k > p`, then any subsequent `p` must be colored '2'.
                // So, `split_p_idx` should be the index of the first digit `d_k > p`.
                // All `d_i = p` for `i < split_p_idx` are '1'.
                // All `d_i = p` for `i >= split_p_idx` are '2'.

                // Let's implement this:
                // Find the first index `first_gt_p_idx` where `s[first_gt_p_idx] > p_char`.
                // If no such index, `first_gt_p_idx = n`.
                // Then, iterate through `s`:
                //   If `s[i] < p_char`, color '1'.
                //   If `s[i] > p_char`, color '2'.
                //   If `s[i] == p_char`:
                //     If `i < first_gt_p_idx`, color '1'.
                //     If `i >= first_gt_p_idx`, color '2'.
            }
        }

        int first_gt_p_idx = n;
        for (int i = 0; i < n; ++i) {
            if ((s[i] - '0') > p) {
                first_gt_p_idx = i;
                break;
            }
        }

        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                current_coloring[i] = '1';
            } else if (digit > p) {
                current_coloring[i] = '2';
            } else { // digit == p
                if (i < first_gt_p_idx) {
                    current_coloring[i] = '1';
                } else {
                    current_coloring[i] = '2';
                }
            }
        }

        // Now verify the constructed coloring
        s1_digits.clear();
        s2_digits.clear();
        for (int i = 0; i < n; ++i) {
            if (current_coloring[i] == '1') {
                s1_digits.push_back(s[i] - '0');
            } else {
                s2_digits.push_back(s[i] - '0');
            }
        }

        bool s1_sorted = true;
        for (size_t i = 0; i + 1 < s1_digits.size(); ++i) {
            if (s1_digits[i] > s1_digits[i+1]) {
                s1_sorted = false;
                break;
            }
        }
        if (!s1_sorted) {
            continue; // This p doesn't work
        }

        bool s2_sorted = true;
        for (size_t i = 0; i + 1 < s2_digits.size(); ++i) {
            if (s2_digits[i] > s2_digits[i+1]) {
                s2_sorted = false;
                break;
            }
        }
        if (!s2_sorted) {
            continue; // This p doesn't work
        }

        // Check concatenation condition
        if (!s1_digits.empty() && !s2_digits.empty()) {
            if (s1_digits.back() > s2_digits.front()) {
                continue; // This p doesn't work
            }
        }

        // If all checks pass, we found a solution
        result = current_coloring;
        found_solution = true;
        break; // Found a valid p, no need to check further
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

