#include <iostream>
#include <vector>
#include <algorithm>
#include <deque>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    if (n == 0) {
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<long long> L(n);
    std::deque<std::pair<long long, int>> dq_L; // {height, index}

    for (int i = 0; i < n; ++i) {
        while (!dq_L.empty() && dq_L.back().first >= h[i]) {
            dq_L.pop_back();
        }
        long long current_max_L = h[i];
        if (!dq_L.empty()) {
            current_max_L = std::max(current_max_L, dq_L.back().first + (i - dq_L.back().second));
        }
        L[i] = current_max_L;
        dq_L.push_back({h[i], i});
    }

    std::vector<long long> R(n);
    std::deque<std::pair<long long, int>> dq_R; // {height, index}

    for (int i = n - 1; i >= 0; --i) {
        while (!dq_R.empty() && dq_R.back().first >= h[i]) {
            dq_R.pop_back();
        }
        long long current_max_R = h[i];
        if (!dq_R.empty()) {
            current_max_R = std::max(current_max_R, dq_R.back().first + (dq_R.back().second - i));
        }
        R[i] = current_max_R;
        dq_R.push_back({h[i], i});
    }

    long long max_min_val = 0;
    for (int i = 0; i < n; ++i) {
        max_min_val = std::max(max_min_val, std::min(L[i], R[i]));
    }

    std::cout << max_min_val << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_val_0 = 0;
    int current_val_1023 = 1023;

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_val_0 &= x;
            current_val_1023 &= x;
        } else if (op_char == '|') {
            current_val_0 |= x;
            current_val_1023 |= x;
        } else if (op_char == '^') {
            current_val_0 ^= x;
            current_val_1023 ^= x;
        }
    }

    int final_and_mask = 1023; // Represents the 'a' in (x & a)
    int final_or_mask = 0;    // Represents the 'b' in | b
    int final_xor_mask = 0;   // Represents the 'c' in ^ c

    for (int j = 0; j < 10; ++j) {
        int bit_0_result = (current_val_0 >> j) & 1;
        int bit_1_result = (current_val_1023 >> j) & 1;

        if (bit_0_result == 0 && bit_1_result == 0) {
            // If input bit is 0, output is 0. If input bit is 1, output is 0.
            // This means the bit is always 0, regardless of input.
            // Achieved by (x & 0)
            final_and_mask &= ~(1 << j);
        } else if (bit_0_result == 1 && bit_1_result == 1) {
            // If input bit is 0, output is 1. If input bit is 1, output is 1.
            // This means the bit is always 1, regardless of input.
            // Achieved by (| 1)
            final_or_mask |= (1 << j);
        } else if (bit_0_result == 0 && bit_1_result == 1) {
            // If input bit is 0, output is 0. If input bit is 1, output is 1.
            // This means the bit is unchanged.
            // Achieved by (x & 1)
            // No change to final_and_mask, final_or_mask, final_xor_mask for this bit
        } else { // bit_0_result == 1 && bit_1_result == 0
            // If input bit is 0, output is 1. If input bit is 1, output is 0.
            // This means the bit is flipped.
            // Achieved by (^ 1)
            final_xor_mask |= (1 << j);
        }
    }

    std::vector<std::pair<char, int>> simplified_ops;

    if (final_and_mask != 1023) {
        simplified_ops.push_back({'&', final_and_mask});
    }
    if (final_or_mask != 0) {
        simplified_ops.push_back({'|', final_or_mask});
    }
    if (final_xor_mask != 0) {
        simplified_ops.push_back({'^', final_xor_mask});
    }

    std::cout << simplified_ops.size() << "\n";
    for (const auto& op : simplified_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n == 1) {
        // Operation 1: Make a[0] zero
        std::cout << "1 1\n";
        std::cout << -a[0] << "\n";
        a[0] = 0;

        // Operation 2: Dummy operation
        std::cout << "1 1\n";
        std::cout << "0\n";

        // Operation 3: Dummy operation
        std::cout << "1 1\n";
        std::cout << "0\n";
    } else {
        // Operation 1: Make a[0]...a[n-2] divisible by n
        // For each a[i] (0 <= i < n-1), we want a[i] + b[i] to be a multiple of n.
        // b[i] = (n - (a[i] % n) % n) % n * n
        // This makes a[i] + b[i] a multiple of n.
        // The length of the segment is n.
        std::cout << "1 " << n - 1 << "\n";
        for (int i = 0; i < n - 1; ++i) {
            long long remainder = (a[i] % n + n) % n; // Ensure positive remainder
            long long add_val = (n - remainder) % n;
            std::cout << add_val * n << (i == n - 2 ? "" : " ");
            a[i] += add_val * n; // Update a[i]
        }
        std::cout << "\n";

        // Operation 2: Make a[n-1] divisible by n
        // For a[n-1], we want a[n-1] + b[n-1] to be a multiple of n.
        // The length of the segment is 1.
        std::cout << n << " " << n << "\n";
        long long remainder_n_minus_1 = (a[n - 1] % n + n) % n; // Ensure positive remainder
        long long add_val_n_minus_1 = (n - remainder_n_minus_1) % n;
        std::cout << add_val_n_minus_1 * n << "\n";
        a[n - 1] += add_val_n_minus_1 * n; // Update a[n-1]

        // Operation 3: Make all elements zero
        // Now all a[i] are multiples of n.
        // Select segment [1, n]. Length is n.
        // For each a[i], we add -a[i]. Since a[i] is a multiple of n, -a[i] is also a multiple of n.
        std::cout << "1 " << n << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << -a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }

    return 0;
}

#include <iostream>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings in a string of length n
        long long total_substrings = n * (n + 1) / 2;

        // Number of zeros
        long long num_zeros = n - m;

        // To maximize f(s), we need to minimize the number of substrings consisting only of zeros.
        // This is achieved by distributing the 'm' ones as evenly as possible to break up the '0's.
        // The 'm' ones create 'm + 1' possible blocks for zeros (before the first '1', between '1's, after the last '1').
        // We want to place the 'num_zeros' into these 'm + 1' blocks as evenly as possible.

        // Number of blocks that will have one more zero than others
        long long k = num_zeros % (m + 1);
        // Number of zeros in these k blocks
        long long zeros_in_larger_blocks = num_zeros / (m + 1) + 1;
        // Number of blocks that will have the base number of zeros
        long long m_plus_1_minus_k = (m + 1) - k;
        // Number of zeros in these smaller blocks
        long long zeros_in_smaller_blocks = num_zeros / (m + 1);

        // Calculate the number of substrings consisting only of zeros
        long long all_zeros_substrings = 0;

        // Contribution from the k larger blocks
        all_zeros_substrings += k * (zeros_in_larger_blocks * (zeros_in_larger_blocks + 1) / 2);

        // Contribution from the (m+1-k) smaller blocks
        all_zeros_substrings += m_plus_1_minus_k * (zeros_in_smaller_blocks * (zeros_in_smaller_blocks + 1) / 2);

        // The maximum value of f(s) is total_substrings - all_zeros_substrings
        long long max_f_s = total_substrings - all_zeros_substrings;

        std::cout << max_f_s << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <map>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars 1 to n)
    // diff_L[k] = (count of 1s among a[0...k-1]) - (count of 2s among a[0...k-1])
    // diff_L[0] = 0
    // diff_L[k] = diff_L[k-1] + (a[k-1] == 1 ? 1 : -1)
    std::vector<int> diff_L(n + 1);
    diff_L[0] = 0;
    for (int k = 0; k < n; ++k) {
        diff_L[k + 1] = diff_L[k] + (a[k] == 1 ? 1 : -1);
    }

    // Calculate suffix sums for the right side (jars n+1 to 2n)
    // diff_R[k] = (count of 1s among a[2n-k...2n-1]) - (count of 2s among a[2n-k...2n-1])
    // diff_R[0] = 0
    // diff_R[k] = diff_R[k-1] + (a[2n-k] == 1 ? 1 : -1)
    std::vector<int> diff_R(n + 1);
    diff_R[0] = 0;
    for (int k = 0; k < n; ++k) {
        diff_R[k + 1] = diff_R[k] + (a[2 * n - 1 - k] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left side for each diff_L value
    // map: diff_value -> jars_removed_from_left
    std::map<int, int> left_diff_to_removed_count;
    for (int k = 0; k <= n; ++k) { // k is number of jars removed from left (0 to n)
        int current_diff = diff_L[n] - diff_L[k]; // diff of remaining jars on left side
        if (left_diff_to_removed_count.find(current_diff) == left_diff_to_removed_count.end()) {
            left_diff_to_removed_count[current_diff] = k;
        } else {
            left_diff_to_removed_count[current_diff] = std::min(left_diff_to_removed_count[current_diff], k);
        }
    }

    int min_total_removed = 2 * n; // Initialize with max possible removals

    // Iterate through possible removals from the right side
    for (int k = 0; k <= n; ++k) { // k is number of jars removed from right (0 to n)
        int current_diff_right_removed = diff_R[n] - diff_R[k]; // diff of remaining jars on right side
        int target_diff_left = -current_diff_right_removed; // We need diff_left + diff_right = 0

        if (left_diff_to_removed_count.count(target_diff_left)) {
            int removed_from_left = left_diff_to_removed_count[target_diff_left];
            min_total_removed = std::min(min_total_removed, removed_from_left + k);
        }
    }

    std::cout << min_total_removed << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

