    int n;
    std::cin >> n;

    std::vector<std::vector<long long>> dist(n, std::vector<long long>(n));
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            std::cin >> dist[i][j];
        }
    }

    std::vector<int> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
        x[i]--; // Convert to 0-indexed
    }

    std::vector<long long> results;
    std::vector<bool> active(n, false); // Tracks which vertices are currently in the graph

    // Process vertices in reverse order of removal
    for (int k_idx = n - 1; k_idx >= 0; --k_idx) {
        int k = x[k_idx]; // The vertex being added back to the graph

        active[k] = true; // Mark vertex k as active

        // Floyd-Warshall update step for the newly added vertex k
        // For all pairs (i, j) of currently active vertices,
        // check if path i -> k -> j is shorter than current i -> j
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue; // Only consider active vertices
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue; // Only consider active vertices

                // Update paths involving k as an intermediate vertex
                if (dist[i][k] + dist[k][j] < dist[i][j]) {
                    dist[i][j] = dist[i][k] + dist[k][j];
                }
            }
        }

        // After adding k and updating all paths through k,
        // we also need to consider paths where k is an endpoint
        // and other active vertices are intermediates.
        // This is implicitly handled by the standard Floyd-Warshall triple loop structure
        // if we consider k as the "outermost" loop variable.
        // The previous loop updates dist[i][j] using k as an intermediate.
        // Now, we need to ensure that all paths between active vertices are shortest.
        // The standard Floyd-Warshall algorithm iterates k from 0 to n-1.
        // Here, k is added incrementally.
        // When k is added, it can be an intermediate for any pair (i, j)
        // where i, j are already active.
        // It can also be an intermediate for paths involving itself, e.g., i -> k -> j.
        // The previous nested loops (i, j) update paths using k as an intermediate.
        // However, the full Floyd-Warshall logic requires that for a given k,
        // all pairs (i, j) are updated using k.
        // The current `dist` matrix already contains shortest paths considering
        // all vertices that were active *before* `k` was added.
        // When `k` is added, we need to update `dist[i][j]` for all active `i, j`
        // using `k` as an intermediate.
        // The loops above correctly do this:
        // `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])`
        // This ensures that for any pair of active vertices `i, j`,
        // the path `i -> k -> j` is considered.
        // This is the core of the Floyd-Warshall algorithm when adding a new vertex.

        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before x_1, before x_2, ..., before x_n)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

