#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost index `p` such that a[p...n-1] is non-decreasing.
    // This means a[p] <= a[p+1] <= ... <= a[n-1].
    // If such a `p` exists, then a[p-1] > a[p].
    int p = n - 1;
    while (p > 0 && a[p - 1] <= a[p]) {
        p--;
    }

    // Now, a[p...n-1] is non-decreasing.
    // We need to find the rightmost index `q` such that a[q...p-1] is non-increasing.
    // This means a[q] >= a[q+1] >= ... >= a[p-1].
    // If such a `q` exists, then a[q-1] < a[q].
    // Note: if p is 0, then the entire array is non-decreasing, so q will also be 0.
    int q = p;
    while (q > 0 && a[q - 1] >= a[q]) {
        q--;
    }

    std::cout << q << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    std::vector<long long> initial_a(n);
    std::vector<long long> min_val_at_idx(n, std::numeric_limits<long long>::max());

    // Process operations in reverse to find constraints on initial_a
    for (int i = m - 1; i >= 0; --i) {
        if (ops[i].type == 2) { // Type 2: max(a_j) = m_i
            long long current_m = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                min_val_at_idx[j] = std::min(min_val_at_idx[j], current_m);
            }
        } else { // Type 1: a_j += d_i
            long long d = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                if (min_val_at_idx[j] != std::numeric_limits<long long>::max()) {
                    min_val_at_idx[j] -= d;
                }
            }
        }
    }

    // Initialize initial_a based on derived constraints
    for (int i = 0; i < n; ++i) {
        if (min_val_at_idx[i] == std::numeric_limits<long long>::max()) {
            initial_a[i] = 0; // No max constraint, set to 0 (or any value within bounds)
        } else {
            initial_a[i] = min_val_at_idx[i];
        }
    }

    // Verify the solution
    std::vector<long long> current_a = initial_a;
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) { // Type 1: a_j += d_i
            long long d = ops[i].val;
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_a[j] += d;
            }
        } else { // Type 2: max(a_j) = m_i
            long long expected_m = ops[i].val;
            long long actual_max = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                actual_max = std::max(actual_max, current_a[j]);
            }
            if (actual_max != expected_m) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << initial_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
