#include <algorithm>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool in_line;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].in_line = true;
    }

    std::vector<int> treated_children_ids;

    for (int i = 0; i < n; ++i) {
        if (!children[i].in_line) {
            continue;
        }

        treated_children_ids.push_back(children[i].id);
        children[i].in_line = false;

        long long current_office_cry_volume = children[i].v;
        long long total_chain_cry_volume = 0;

        for (int j = i + 1; j < n; ++j) {
            if (!children[j].in_line) {
                continue;
            }

            // Apply office cry volume
            if (current_office_cry_volume > 0) {
                children[j].p -= current_office_cry_volume;
                current_office_cry_volume--;
            }

            // Apply chain cry volume
            children[j].p -= total_chain_cry_volume;

            if (children[j].p < 0) {
                children[j].in_line = false;
                total_chain_cry_volume += children[j].d;
            }
        }
    }

    std::cout << treated_children_ids.size() << "\n";
    for (size_t i = 0; i < treated_children_ids.size(); ++i) {
        std::cout << treated_children_ids[i] << (i == treated_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

