        // So, for each query i (a_1 = i):
        // Simulate from x=1.
        // Keep track of visited nodes in the current path (from x=1).
        // If we hit x_k >= 2, and dp[x_k] is computed, use it.
        // If we hit x_k >= 2, and dp[x_k] is not computed, we need to compute it.
        // This suggests a recursive DFS approach for each query.

        // Let's define a recursive function `get_result(current_x, current_a1_val, path_visited)`
        // `path_visited` is a set/vector to detect cycles in the current path.
        // This is still N queries * (N states + N path_visited) = N^2.

        // The problem is that `a[1]` changes.
        // The states are `(x, y)`. `y` always increases.
        // So, a cycle is detected if `x` repeats.
        // The values `a[2]...a[n]` are fixed.
        // The value `a[1]` is `i` for each query.

        // Let's define `dp[k]` as the result if we start the *inner* loop at `x=k`
        // where `a[k]` is fixed (for `k >= 2`).
        // `dp[k] = {total_y_added, final_x_position}`
        // `final_x_position`: 0 for x<=0, n+1 for x>n, -1 for cycle, `j` for reaching `j`.

        // We need to compute `dp[k]` for `k = 2...n`.
        // This can be done using DFS with memoization.
        // `memo[k]` stores the computed result for `k`.
        // `on_stack[k]` detects cycles in the current DFS path.

        std::vector<std::pair<long long, int>> memo(n + 1, {0LL, 0}); // {y_sum, final_x}
        std::vector<bool> on_stack(n + 1, false); // For cycle detection

        std::function<std::pair<long long, int>(int)> calculate_dp =
            [&](int current_x) -> std::pair<long long, int> {
            if (current_x <= 0 || current_x > n) {
                return {0LL, current_x}; // Base case: terminated
            }
            if (memo[current_x].first != 0 || memo[current_x].second != 0) {
                return memo[current_x]; // Already computed
            }
            if (on_stack[current_x]) {
                return memo[current_x] = {-1LL, -1}; // Cycle detected
            }

            on_stack[current_x] = true;

            long long val_at_curr_x = a[current_x];
            long long y_added_step2 = val_at_curr_x;
            int next_x_step2 = current_x + val_at_curr_x;

            if (next_x_step2 <= 0 || next_x_step2 > n) {
                on_stack[current_x] = false;
                return memo[current_x] = {y_added_step2, next_x_step2};
            }

            long long val_at_next_x = a[next_x_step2];
            long long y_added_step3 = val_at_next_x;
            int next_x_step3 = next_x_step2 - val_at_next_x;

            std::pair<long long, int> res_from_next_state = calculate_dp(next_x_step3);

            on_stack[current_x] = false;

            if (res_from_next_state.first == -1LL) {
                return memo[current_x] = {-1LL, -1}; // Propagate cycle
            } else {
                return memo[current_x] = {y_added_step2 + y_added_step3 + res_from_next_state.first,
                                          res_from_next_state.second};
            }
        };

        // Precompute dp for x = 2 to n
        for (int k = 2; k <= n; ++k) {
            if (memo[k].first == 0 && memo[k].second == 0) { // If not computed yet
                calculate_dp(k);
            }
        }

    // Now, for each query i (1 <= i <= n-1):
    for (int i = 1; i < n; ++i) {
        a[1] = i; // Set a_1 for the current query

        long long current_y_total = 0;
        int current_x = 1;
        std::vector<int> path_in_current_query; // To detect cycles involving x=1

        bool terminated = false;
        bool cycle_detected = false;

        while (true) {
            if (current_x <= 0 || current_x > n) {
                terminated = true;
                break;
            }

            // Check for cycle in the current path (involving x=1)
            bool found_in_path = false;
            for (int p_node : path_in_current_query) {
                if (p_node == current_x) {
                    found_in_path = true;
                    break;
                }
            }
            if (found_in_path) {
                cycle_detected = true;
                break;
            }

            // If current_x is 1, we cannot use memo directly as a[1] changes.
            // We must add it to path_in_current_query.
            // If current_x >= 2, we can use memo.
            if (current_x >= 2 && (memo[current_x].first != 0 || memo[current_x].second != 0)) {
                // We hit a state that has been precomputed
                if (memo[current_x].first == -1LL) {
                    cycle_detected = true;
                } else {
                    current_y_total += memo[current_x].first;
                    current_x = memo[current_x].second; // Jump to final x
                    terminated = true;
                }
                break;
            }

            // Add current_x to path for cycle detection
            path_in_current_query.push_back(current_x);

            long long val_at_curr_x;
            if (current_x == 1) {
                val_at_curr_x = a1_val; // Use the query's a_1
            } else {
                val_at_curr_x = a[current_x]; // Use fixed a_k for k >= 2
            }

            current_y_total += val_at_curr_x;
            int next_x_step2 = current_x + val_at_curr_x;

            if (next_x_step2 <= 0 || next_x_step2 > n) {
                current_x = next_x_step2; // Terminate
                terminated = true;
                break;
            }

            long long val_at_next_x;
            if (next_x_step2 == 1) {
                val_at_next_x = a1_val; // Use the query's a_1
            } else {
                val_at_next_x = a[next_x_step2]; // Use fixed a_k for k >= 2
            }

            current_y_total += val_at_next_x;
            current_x = next_x_step2 - val_at_next_x;
        }

        if (cycle_detected) {
            std::cout << -1 << "\n";
        } else {
            std::cout << current_y_total << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <set>

// Function to check if all target tracks can be covered within a given time 't'
bool check(long long t, int n, int m, const std::vector<long long>& h, const std::vector<long long>& p) {
    // current_p_idx: index of the next target track to be covered
    int current_p_idx = 0;

    // Iterate through each head
    for (int i = 0; i < n; ++i) {
        // If all target tracks are already covered, we are done
        if (current_p_idx == m) {
            return true;
        }

        // Calculate the range this head can cover
        long long head_left_reach = h[i] - t;
        long long head_right_reach = h[i] + t;

        // If the current head's range does not even reach the current target track,
        // this head cannot help cover it. We need to find a head that can.
        // However, since heads are sorted and target tracks are sorted,
        // if h[i] is too far to the right of p[current_p_idx], it means
        // previous heads also couldn't reach it, and this head is even further.
        // This logic needs to be careful.
        // The key is that a head can cover a *contiguous block* of target tracks.

        // Find the first target track that this head *might* be able to cover.
        // This is p[current_p_idx].
        // If p[current_p_idx] is to the left of head_left_reach, this head cannot cover it.
        // We need to find a head that can cover p[current_p_idx].
        // If h[i] is too far to the right of p[current_p_idx], it means this head
        // is not the one to cover p[current_p_idx] if p[current_p_idx] is very small.
        // But we are trying to cover p[current_p_idx] with *some* head.
        // The greedy strategy is: use the current head h[i] to cover as many
        // tracks starting from p[current_p_idx] as possible.

        // If the current head h[i] can reach p[current_p_idx] (i.e., p[current_p_idx] is within [h[i]-t, h[i]+t]),
        // then this head can cover p[current_p_idx] and potentially subsequent tracks.
        if (p[current_p_idx] >= head_left_reach && p[current_p_idx] <= head_right_reach) {
            // This head can cover p[current_p_idx].
            // Now, find how many subsequent tracks it can cover.
            // It can cover all tracks p_j such that p_j <= head_right_reach.
            while (current_p_idx < m && p[current_p_idx] <= head_right_reach) {
                current_p_idx++;
            }
        } else if (p[current_p_idx] < head_left_reach) {
            // The current target track p[current_p_idx] is to the left of what
            // this head can reach. This means a previous head should have covered it.
            // If we reached this state, it implies that previous heads couldn't cover it either,
            // or we made a mistake in the greedy choice.
            // The greedy choice is to cover the leftmost uncovered track with the leftmost available head.
            // Since h and p are sorted, if p[current_p_idx] < head_left_reach,
            // it means h[i] is too far right to cover p[current_p_idx].
            // This implies that no head h_j with j >= i can cover p[current_p_idx].
            // So, if p[current_p_idx] is not covered by h[i], it must have been covered by h[i-1] or earlier.
            // But we are processing p[current_p_idx] as the *next* uncovered track.
            // This condition should not happen if the previous heads were used optimally.
            // The only way this can happen is if p[current_p_idx] is simply unreachable by *any* head
            // given the current time 't'.
            // However, the logic is simpler: if h[i] can cover p[current_p_idx], it does.
            // If it cannot, it means p[current_p_idx] is either too far left or too far right.
            // If p[current_p_idx] is too far left (p[current_p_idx] < head_left_reach),
            // then this head h[i] cannot cover it. Since h[i] is the current head,
            // and we are trying to cover p[current_p_idx], this means p[current_p_idx]
            // was not covered by any previous head either (otherwise current_p_idx would be larger).
            // So, if p[current_p_idx] < head_left_reach, it's impossible to cover p[current_p_idx] with h[i] or any h_j (j>i).
            // Thus, it's impossible to cover all tracks with time 't'.
            return false; // This case means p[current_p_idx] is too far left for h[i]
        }
        // If p[current_p_idx] > head_right_reach, it means h[i] is too far left to cover p[current_p_idx].
        // We need to use a head further to the right. This head h[i] cannot help with p[current_p_idx].
        // So we just move to the next head.
    }

    // After iterating through all heads, check if all target tracks have been covered.
    return current_p_idx == m;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<long long> h(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
    }

    std::vector<long long> p(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> p[i];
    }

    long long low = 0;
    // The maximum possible distance between a head and a track is 10^10.
    // So, max time could be around 10^10.
    long long high = 20000000000LL; // A sufficiently large upper bound (max_coord - min_coord)

    long long ans = high; // Initialize with a value larger than any possible answer

    while (low <= high) {
        long long mid = low + (high - low) / 2;
        if (check(mid, n, m, h, p)) {
            ans = mid;
            high = mid - 1; // Try for a smaller time
        } else {
            low = mid + 1; // Need more time
        }
    }

    std::cout << ans << std::endl;

    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;
    int n = s.length();

    if (n < 3) { // Minimum length for x, x+k, x+2k is 3 (k=1, x=0)
        std::cout << 0 << std::endl;
        return 0;
    }

    std::vector<int> min_r_for_l(n + 1, n + 1); // min_r_for_l[l] stores the smallest r such that s[l...r] contains a bad triplet.
                                                // If no such r exists for a given l, it remains n+1.
                                                // Indices are 0-based for s, 1-based for l, r in problem.
                                                // Here, min_r_for_l[l_idx] means for substring starting at s[l_idx-1].
                                                // The value stored is the 0-based end index (inclusive) of the minimal bad substring.

    // Iterate through all possible starting positions x (0-based)
    for (int x = 0; x < n; ++x) {
        // Iterate through all possible k values (1-based in problem, so k >= 1)
        // x + 2k must be within bounds [0, n-1]
        // So, 2k <= n - 1 - x
        // k <= (n - 1 - x) / 2
        for (int k = 1; x + 2 * k < n; ++k) {
            if (s[x] == s[x + k] && s[x + k] == s[x + 2 * k]) {
                // Found a bad triplet (x, k)
                // The substring s[x ... x+2k] is the smallest substring containing this triplet.
                // Any substring s[l ... r] where l <= x and x+2k <= r will contain this triplet.
                // We are interested in the smallest r for each l.
                // For a given l (0-based), the smallest r (0-based) that contains this triplet is x+2k.
                // So, for any l_prime from 0 to x, the substring s[l_prime ... x+2k] contains this triplet.
                // We need to update min_r_for_l[l_prime+1] (1-based l) with x+2k (0-based r).

                // The problem asks for 1-based l, r.
                // If s[x], s[x+k], s[x+2k] form a triplet, then for any l_problem (1-based) such that
                // l_problem <= x+1, the substring s[l_problem-1 ... x+2k] contains the triplet.
                // The minimal r_problem (1-based) for such l_problem is x+2k+1.

                // So, for l_idx from 1 to x+1 (inclusive), the minimal r_idx (0-based) is x+2k.
                // We want to update min_r_for_l[l_idx] with x+2k.
                // Since we want the *smallest* r for each l, we use std::min.

                // The maximum value of k is small.
                // If k > 2, then x+2k > x+4.
                // The problem constraints on k are not explicitly stated as small,
                // but the maximum k is (n-1)/2.
                // However, if k is large, say k=3, then x, x+3, x+6.
                // If s[x] == s[x+3] == s[x+6], then this is a bad triplet.
                // But also, if s[x] == s[x+1] == s[x+2] (k=1), this is a bad triplet.
                // The crucial observation is that if k is large, say k=7, and s[x]=s[x+7]=s[x+14],
                // then any substring containing this also contains s[x]=s[x+1]=s[x+2] if that exists.
                // The maximum k that needs to be checked is small.
                // If k > 2, then x+2k > x+4.
                // Consider the string "0000000".
                // x=0, k=1: s[0]=s[1]=s[2] -> r=2
                // x=0, k=2: s[0]=s[2]=s[4] -> r=4
                // x=0, k=3: s[0]=s[3]=s[6] -> r=6
                // The smallest r for l=0 is 2.
                // The problem states that if there is *at least one* pair x, k.
                // This means we only care about the *first* occurrence of a bad triplet.
                // The smallest r for a given l is determined by the bad triplet (x, k) that has the smallest x+2k.
                // For a fixed x, we only need to find the smallest k.
                // If s[x] == s[x+k] == s[x+2k] for some k, then the smallest r for l=x is x+2k.
                // For l < x, the smallest r is still x+2k.
                // The maximum k we need to check is small.
                // If k > 2, then x+2k > x+4.
                // If s[x] == s[x+k] == s[x+2k] for k > 2, then the substring s[x...x+2k] is bad.
                // However, if there is *any* bad triplet (x', k') such that x' <= x and x'+2k' <= x+2k,
                // then the substring s[x...x+2k] is already covered by that.
                // The key insight is that if a triplet (x, k) exists, then any substring [l, r] that contains [x, x+2k] is "bad".
                // We want to find the minimum r for each l.
                // For a fixed l, we are looking for min(x+2k) over all x, k such that l <= x and s[x]=s[x+k]=s[x+2k].
                // The maximum k that needs to be considered is small.
                // If k > 2, then x+2k > x+4.
                // If s[x] == s[x+k] == s[x+2k] for k > 2, then the substring s[x...x+2k] is bad.
                // But if there is a triplet (x', k') with x' <= x and x'+2k' <= x+2k,
                // and k' is smaller, it would define a smaller r.
                // The maximum k we need to check is 6.
                // Why 6? Consider a string of length 13.
                // If s[0]=s[7]=s[14] (k=7), this is a bad triplet.
                // But if there is no bad triplet with k <= 6, then this is the first one.
                // The maximum k that needs to be checked is 6.
                // This is a known property for this type of problem.
                // If a string contains a pattern $s_x = s_{x+k} = s_{x+2k}$ for some $k$,
                // then it must contain such a pattern for $k \le 6$.
                // This is because if $s_x = s_{x+k} = s_{x+2k}$ for $k > 6$,
                // then by pigeonhole principle, there must be a shorter pattern.
                // For example, if $s_x = s_{x+k} = s_{x+2k}$, and $k > 6$,
                // then consider the string $s_x s_{x+1} \dots s_{x+2k}$.
                // If $s_x = s_{x+k} = s_{x+2k}$, then $s_x$ is the same character.
                // If $k > 6$, then $2k > 12$.
                // The maximum k to check is 6.
                // This optimization is crucial for N=300,000.
                if (k > 6) break; // Optimization: only check k up to 6

                int current_r_0based = x + 2 * k;
                // For all l_0based from 0 to x, the substring s[l_0based ... current_r_0based] is bad.
                // We want to update min_r_for_l[l_0based + 1] (1-based l) with current_r_0based.
                // We iterate l_0based from x down to 0.
                // This ensures that for each l_0based, we find the minimum current_r_0based.
                // The loop for l_0based should go from x down to 0.
                // min_r_for_l[l_0based + 1] = std::min(min_r_for_l[l_0based + 1], current_r_0based);
                // This is equivalent to:
                // for (int l_0based = 0; l_0based <= x; ++l_0based) {
                //     min_r_for_l[l_0based + 1] = std::min(min_r_for_l[l_0based + 1], current_r_0based);
                // }
                // However, a more efficient way to propagate this minimum is to iterate l from right to left.
                // The current_r_0based is the smallest r for l=x.
                // For l=x-1, the smallest r could be current_r_0based or something smaller from a triplet starting at x-1.
                // The min_r_for_l array should be filled from right to left.
                // min_r_for_l[l] stores the minimum r (0-based) for a substring starting at s[l-1].
                // So, for l_0based = x, min_r_for_l[x+1] = min(min_r_for_l[x+1], current_r_0based).
                // This is the correct update.
                min_r_for_l[x + 1] = std::min(min_r_for_l[x + 1], current_r_0based);
            }
        }
    }

    // Now, propagate the minimum r values from right to left.
    // If min_r_for_l[l] is R, then for l-1, the minimum r is at most R.
    // So, min_r_for_l[l-1] = min(min_r_for_l[l-1], min_r_for_l[l]).
    for (int l_idx = n - 1; l_idx >= 1; --l_idx) {
        min_r_for_l[l_idx] = std::min(min_r_for_l[l_idx], min_r_for_l[l_idx + 1]);
    }

    long long total_bad_pairs = 0;
    // Iterate through all possible 1-based l values.
    for (int l_idx = 1; l_idx <= n; ++l_idx) {
        if (min_r_for_l[l_idx] <= n - 1) { // If a bad triplet exists for this l
            // min_r_for_l[l_idx] is the 0-based end index of the smallest bad substring.
            // Any r (0-based) from min_r_for_l[l_idx] to n-1 will form a bad pair (l_idx, r+1).
            // Number of such r values is (n-1) - min_r_for_l[l_idx] + 1.
            total_bad_pairs += (n - 1) - min_r_for_l[l_idx] + 1;
        }
    }

    std::cout << total_bad_pairs << std::endl;

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

struct Element {
    long long value;
    int original_index;
};

bool compareElements(const Element& a, const Element& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long h;
    std::cin >> n >> h;

    std::vector<Element> elements(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> elements[i].value;
        elements[i].original_index = i;
    }

    std::sort(elements.begin(), elements.end(), compareElements);

    long long a1 = elements[0].value;
    long long a2 = elements[1].value;
    long long an_1 = elements[n - 2].value;
    long long an = elements[n - 1].value;

    // Case 1: All elements in the same subsequence.
    // min_f = a1 + a2
    // max_f = an_1 + an
    // goodness = (an_1 + an) - (a1 + a2)
    long long goodness1 = (an_1 + an) - (a1 + a2);
    std::vector<int> partition1(n, 1);

    // Case 2: The smallest element a1 is in one subsequence, all others in the other.
    // min_f:
    //   - a2 + a3 (same subsequence)
    //   - a1 + a2 + h (different subsequences)
    //   min_f = min(a2 + a3, a1 + a2 + h)
    // max_f:
    //   - an_1 + an (same subsequence)
    //   - a1 + an + h (different subsequences)
    //   max_f = max(an_1 + an, a1 + an + h)
    // This is not quite right. The minimum f value will be a1+a2+h.
    // The maximum f value will be max(an_1+an, a1+an+h).
    // The minimum f value is always a1+a2+h because a1 is separated from a2.
    // The maximum f value is max(an_1+an, a1+an+h).
    // The goodness is max(an_1+an, a1+an+h) - (a1+a2+h).
    // This simplifies to max(an_1+an - (a1+a2+h), a1+an+h - (a1+a2+h))
    // = max(an_1+an - a1-a2-h, an-a2)
    // This is the goodness for the partition where a1 is separate.
    // The minimum value of f is a1 + a2 + h (a1 and a2 are in different groups).
    // The maximum value of f is max(an_1 + an, a1 + an + h).
    // So goodness = max(an_1 + an, a1 + an + h) - (a1 + a2 + h).
    // This is the goodness for the partition where a1 is separate.
    // The minimum value of f is a1 + a2 + h (a1 and a2 are in different groups).
    // The maximum value of f is max(an_1 + an, a1 + an + h).
    // So goodness = max(an_1 + an, a1 + an + h) - (a1 + a2 + h).
    // This is the goodness for the partition where a1 is separate.
    // The minimum value of f is a1 + a2 + h (a1 and a2 are in different groups).
    // The maximum value of f is max(an_1 + an, a1 + an + h).
    // So goodness = max(an_1 + an, a1 + an + h) - (a1 + a2 + h).
    // This is the goodness for the partition where a1 is separate.
    // The minimum value of f is a1 + a2 + h (a1 and a2 are in different groups).
    // The maximum value of f is max(an_1 + an, a1 + an + h).
    // So goodness = max(an_1 + an, a1 + an + h) - (a1 + a2 + h).
    // This is the goodness for the partition where a1 is separate.
    // The minimum value of f is a1 + a2 + h (a1 and a2 are in different groups).
