#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    int count_n = 0; // for 'one' -> 1
    int count_z = 0; // for 'zero' -> 0

    for (char c : s) {
        if (c == 'n') {
            count_n++;
        } else if (c == 'z') {
            count_z++;
        }
    }

    // To maximize the binary number, we should print all '1's first, then all '0's.
    bool first_output = true;

    for (int i = 0; i < count_n; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 1;
        first_output = false;
    }

    for (int i = 0; i < count_z; ++i) {
        if (!first_output) {
            std::cout << " ";
        }
        std::cout << 0;
        first_output = false;
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        // The strategy is to pick n numbers starting from 2n+2,
        // incrementing by 2. This ensures all numbers are even,
        // preventing gcd(a,b)=1.
        // Also, by picking numbers in a range like (2n, 4n],
        // specifically 2n+2, 2n+4, ..., 4n,
        // we ensure that no number divides another.
        // For example, if a = 2k and b = 2j are chosen, and a divides b,
        // then 2k divides 2j, which means k divides j.
        // If we pick numbers from 2n+2 up to 4n,
        // the smallest number is 2n+2.
        // The largest number is 4n.
        // If a divides b, then b >= 2a.
        // If a = 2n+2, then 2a = 4n+4.
        // But the maximum number we pick is 4n.
        // Since 4n < 4n+4, no number 'a' can divide another number 'b'
        // if 'a' is 2n+2 or larger, because 2a would be outside the range [2n+2, 4n].
        // This logic holds for any 'a' in the chosen set:
        // if a >= 2n+2, then 2a >= 4n+4.
        // Since all chosen numbers are <= 4n, it's impossible for 'a' to divide 'b'
        // because 'b' would have to be at least 2a, which is > 4n.
        // The numbers are 2n+2, 2n+4, ..., 2n+2*n = 4n.
        // This gives exactly n numbers.
        for (int i = 0; i < n; ++i) {
            std::cout << 2 * n + 2 * (i + 1) << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
    return 0;
}

