int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    int k;
    std::cin >> n >> k;

    std::vector<long long> a(n);
    long long total_sum = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
        total_sum += a[i];
    }

    if (total_sum % k != 0) {
        std::cout << "No\n";
        return 0;
    }

    long long target_duration = total_sum / k;
    std::vector<int> s_values;
    long long current_post_sum = 0;
    int current_post_videos_count = 0;
    int posts_found = 0;

    for (int i = 0; i < n; ++i) {
        current_post_sum += a[i];
        current_post_videos_count++;

        if (current_post_sum == target_duration) {
            s_values.push_back(current_post_videos_count);
            current_post_sum = 0;
            current_post_videos_count = 0;
            posts_found++;
        } else if (current_post_sum > target_duration) {
            std::cout << "No\n";
            return 0;
        }
    }

    if (posts_found == k) {
        std::cout << "Yes\n";
        for (int i = 0; i < s_values.size(); ++i) {
            std::cout << s_values[i] << (i == s_values.size() - 1 ? "" : " ");
        }
        std::cout << "\n";
    } else {
        std::cout << "No\n";
    }

    return 0;
}

#include <algorithm>
#include <iostream>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<long long> a(2 * n);
        for (int i = 0; i < 2 * n; ++i) {
            std::cin >> a[i];
        }
        std::sort(a.begin(), a.end());
        // The problem asks to minimize the absolute difference between the medians of two classes.
        // Each class must have an odd number of students.
        // Let the sorted skill levels be a_0, a_1, ..., a_{2n-1}.
        //
        // Consider the case where one class has size 1 and the other has size 2n-1.
        // If class 1 has size 1, its median is its single element.
        // If class 2 has size 2n-1, its median is the (n)-th element (0-indexed) after sorting its elements.
        //
        // It can be proven that the optimal strategy is to assign the smallest n elements to one class
        // and the largest n elements to the other class, or more generally, to split the sorted array
        // into two halves.
        //
        // If we sort all 2n skill levels, a_0, a_1, ..., a_{2n-1}.
        // The first class will consist of elements a_0, ..., a_{n-1}.
        // The second class will consist of elements a_n, ..., a_{2n-1}.
        //
        // The size of the first class is n.
        // The size of the second class is n.
        //
        // This strategy works if n is odd.
        // If n is odd, then both classes have odd sizes.
        // The median of the first class (a_0, ..., a_{n-1}) is a_{(n-1)/2}.
        // The median of the second class (a_n, ..., a_{2n-1}) is a_{n + (n-1)/2}.
        //
        // The problem statement implies that we can choose any odd sizes S1 and S2 such that S1+S2=2n.
        // For example, if n=3, 2n=6. We can have (1,5), (3,3), (5,1) students.
        //
        // The crucial observation is that to minimize the difference between medians,
        // the medians themselves should be as close as possible in the sorted global array.
        //
        // If we sort all 2n students, a_0, a_1, ..., a_{2n-1}.
        // The median of a class of size 2k+1 is the (k+1)-th element (1-indexed) or k-th element (0-indexed).
        //
        // Consider the two elements a_{n-1} and a_n.
        // If we can make a_{n-1} the median of one class and a_n the median of the other,
        // this would likely minimize the difference.
        //
        // To make a_{n-1} the median of a class, that class must contain a_{n-1} and have (n-1) elements
        // smaller than or equal to a_{n-1} and (n-1) elements larger than or equal to a_{n-1}.
        // This is not quite right. For a class of size 2k+1, its median is the k-th element (0-indexed).
        // So, there are k elements before it and k elements after it.
        //
        // If we take the first n elements for one class and the next n elements for the second class,
        // i.e., Class 1: {a_0, ..., a_{n-1}} and Class 2: {a_n, ..., a_{2n-1}}.
        // Both classes have size n.
        // If n is odd, this is a valid partition.
        // The median of Class 1 is a_{(n-1)/2}.
        // The median of Class 2 is a_{n + (n-1)/2}.
        // The difference is a_{n + (n-1)/2} - a_{(n-1)/2}.
        //
        // However, the problem statement implies that we can choose any odd sizes.
        // The example for n=3 (2n=6 students) shows:
        // [6, 5, 4, 1, 2, 3] -> sorted: [1, 2, 3, 4, 5, 6]
        // n=3.
        // If we split into two classes of size 3:
        // Class 1: [1, 2, 3], median = 2
        // Class 2: [4, 5, 6], median = 5
        // Difference = |5-2| = 3.
        //
        // The example output is 1. This is achieved by:
        // Class 1: [6, 4, 2], median = 4
        // Class 2: [5, 1, 3], median = 3
        // Difference = |4-3| = 1.
        //
        // This means the simple split into first n and last n elements is not necessarily optimal
        // if n is odd.
        //
        // The key insight for this problem is that the two medians will always be adjacent elements
        // in the globally sorted array.
        //
        // Consider the sorted array a_0, a_1, ..., a_{2n-1}.
        // We need to pick two elements, say a_i and a_j, to be the medians of the two classes.
        // Let's say a_i is the median of Class 1 (size 2k_1+1) and a_j is the median of Class 2 (size 2k_2+1).
        //
        // For a_i to be the median of Class 1, there must be k_1 elements smaller than or equal to a_i
        // and k_1 elements larger than or equal to a_i in Class 1.
        // Similarly for a_j and Class 2.
        //
        // The total number of elements is 2n.
        // The total number of elements "before" the medians (in their respective classes) is k_1 + k_2.
        // The total number of elements "after" the medians is k_1 + k_2.
        // The total number of elements is (k_1 + k_2) + 2 + (k_1 + k_2) = 2(k_1 + k_2) + 2 = 2n.
        // So, k_1 + k_2 = n - 1.
        //
        // This means that if a_i is the median of Class 1 and a_j is the median of Class 2,
        // then there are exactly n-1 elements that are smaller than a_i or a_j (in their respective classes)
        // and n-1 elements that are larger than a_i or a_j (in their respective classes).
        //
        // This implies that the two medians must be a_{n-1} and a_n in the globally sorted array.
        //
        // Let's prove this. Suppose we pick two elements $x$ and $y$ from the $2n$ students to be the medians,
        // with $x \le y$.
        // Let $C_x$ be the class with median $x$ and $C_y$ be the class with median $y$.
        // Let $|C_x| = 2k_x+1$ and $|C_y| = 2k_y+1$.
        // We know $k_x + k_y = n-1$.
        //
        // To form $C_x$ with median $x$, we need $k_x$ elements $\le x$ and $k_x$ elements $\ge x$.
        // To form $C_y$ with median $y$, we need $k_y$ elements $\le y$ and $k_y$ elements $\ge y$.
        //
        // Consider the sorted array $a_0, \dots, a_{2n-1}$.
        // To make $x$ the median of $C_x$, we must pick $k_x$ elements from $a_0, \dots, x$ (excluding $x$)
        // and $k_x$ elements from $x, \dots, a_{2n-1}$ (excluding $x$).
        //
        // The optimal strategy is to make the two medians $a_{n-1}$ and $a_n$.
        //
        // We can form Class 1 with median $a_{n-1}$ and Class 2 with median $a_n$.
        // For Class 1, we need $k_1$ elements smaller than $a_{n-1}$ and $k_1$ elements larger than $a_{n-1}$.
        // For Class 2, we need $k_2$ elements smaller than $a_n$ and $k_2$ elements larger than $a_n$.
        //
        // We can choose $k_1 = 0, k_2 = n-1$.
        // Class 1: $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$).
        // The elements for Class 2 would be $a_0, \dots, a_{n-2}$ (n-1 elements), $a_n$ (median), $a_{n+1}, \dots, a_{2n-1}$ (n-1 elements).
        // This is not quite right. The elements for Class 2 would be $a_0, \dots, a_{n-2}$ and $a_n, \dots, a_{2n-1}$.
        // This is $n-1$ elements from the left and $n$ elements from the right.
        // The median of these $2n-1$ elements would be $a_n$.
        //
        // So, one class can be $\{a_{n-1}\}$ (median $a_{n-1}$).
        // The other class can be $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$.
        // This class has $2n-1$ elements. Its median is the $n$-th element (0-indexed) when sorted.
        // The elements are $a_0, \dots, a_{n-2}$ (n-1 elements), then $a_n, \dots, a_{2n-1}$ (n elements).
        // The $n$-th element (0-indexed) in this combined list is $a_n$.
        // So, the medians are $a_{n-1}$ and $a_n$.
        // The difference is $a_n - a_{n-1}$.
        //
        // This construction is always possible.
        // Class 1: $\{a_{n-1}\}$ (size 1, median $a_{n-1}$)
        // Class 2: $\{a_0, \dots, a_{n-2}, a_n, \dots, a_{2n-1}\}$ (size $2n-1$, median $a_n$)
        // All students are assigned. Both classes have odd sizes.
        //
        // This difference $a_n - a_{n-1}$ is the minimum possible.
        // Any other choice of medians $a_i$ and $a_j$ (with $i < j$) would result in $a_j - a_i \ge a_n - a_{n-1}$
        // if $i \le n-1$ and $j \ge n$.
        // If $i$ and $j$ are both less than $n-1$ or both greater than $n$, it's impossible to satisfy the $k_1+k_2=n-1$ condition.
        //
        // The minimum difference is always $a_n - a_{n-1}$ after sorting the entire array.
        //
        // Example 1: n=1, 2n=2. a = [1, 1]. Sorted: [1, 1].
        // n-1 = 0, n = 1.
        // a_0 = 1, a_1 = 1.
        // Difference = a_1 - a_0 = 1 - 1 = 0. Correct.
        //
        // Example 2: n=3, 2n=6. a = [6, 5, 4, 1, 2, 3]. Sorted: [1, 2, 3, 4, 5, 6].
        // n-1 = 2, n = 3.
        // a_2 = 3, a_3 = 4.
        // Difference = a_3 - a_2 = 4 - 3 = 1. Correct.
        //
        // Example 3: n=5, 2n=10. a = [13, 4, 20, 13, 2, 5, 8, 3, 17, 16].
        // Sorted: [2, 3, 4, 5, 8, 13, 13, 16, 17, 20].
        // n-1 = 4, n = 5.
        // a_4 = 8, a_5 = 13.
        // Difference = a_5 - a_4 = 13 - 8 = 5. Correct.

        std::cout << a[n] - a[n - 1] << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm> // For std::min

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> a(n);
        for (int i = 0; i < n; ++i) {
            std::cin >> a[i];
        }

        if (n <= 1) {
            std::cout << 0 << "\n";
            continue;
        }

        int bad_prices_count = 0;
        int min_suffix_price = a[n - 1]; // Initialize with the last element

        // Iterate from the second to last element backwards
        for (int i = n - 2; i >= 0; --i) {
            if (a[i] > min_suffix_price) {
                bad_prices_count++;
            } else {
                // If a[i] is not greater than min_suffix_price,
                // it means a[i] is a new minimum for the suffix starting from i.
                min_suffix_price = a[i];
            }
        }
        std::cout << bad_prices_count << "\n";
    }
    return 0;
}

#include <iostream>
#include <string>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        std::string s;
        std::cin >> s;
        int max_dist = 0;
        int last_R_pos = -1; // Represents the position of the last 'R' or the starting point 0
        for (int i = 0; i < s.length(); ++i) {
            if (s[i] == 'R') {
                max_dist = std::max(max_dist, i - last_R_pos);
                last_R_pos = i;
            }
        }
        // After iterating through the string, consider the jump from the last 'R' to n+1
        // or from 0 to n+1 if no 'R's were found.
        // The distance from the last 'R' (or -1) to n+1 is (n+1) - last_R_pos.
        max_dist = std::max(max_dist, (int)s.length() + 1 - last_R_pos);
        std::cout << max_dist << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long x;
        std::cin >> x;
        int count = 0;
        long long current_cost = 0;
        long long k = 1; // Represents the 'n' for the current staircase (1, 3, 7, 15, ...)
        while (true) {
            // Calculate the number of cells for a staircase with k stairs
            // k = 2^p - 1
            // Cost = k * (k + 1) / 2
            // Since k is always odd, k+1 is even.
            // (k+1)/2 is an integer.
            // Cost = k * ((k+1)/2)
            long long cost_of_staircase = k * ((k + 1) / 2);

            if (current_cost + cost_of_staircase <= x) {
                current_cost += cost_of_staircase;
                count++;
                // Next k will be 2*k + 1 (e.g., 1 -> 3 -> 7 -> 15)
                k = 2 * k + 1;
            } else {
                break;
            }
        }
        std::cout << count << "\n";
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> q(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> q[i];
    }

    std::vector<int> p(n);
    std::set<int> used_numbers;
    bool possible = true;

    // p_1 must be q_1
    p[0] = q[0];
    used_numbers.insert(q[0]);

    // For i > 0
    for (int i = 1; i < n; ++i) {
        if (q[i] > q[i-1]) {
            // If q_i is a new maximum, then p_i must be q_i
            p[i] = q[i];
            if (used_numbers.count(q[i])) {
                // This should not happen if q is valid and p is a permutation
                // because q_i > q_{i-1} implies q_i is a new value.
                // However, it's good to check for robustness.
                possible = false;
                break;
            }
            used_numbers.insert(q[i]);
        } else { // q_i == q_{i-1}
            // p_i must be some number x such that x < q_i and x has not been used yet.
            // To maximize chances of finding a solution, we should pick the smallest available number.
            // The smallest available number that is less than q_i is the largest number
            // in [1, q_i-1] that has not been used.
            // Or, more simply, we need to fill p_i with an unused number.
            // We can use a set of available numbers.
            // The numbers available for p_i are those in [1, n] that are not in used_numbers.
            // We need to find the largest available number that is less than q_i.
            // Or, to make it simpler, we can just fill these slots later.
            // Let's try to fill them greedily with the smallest available numbers.
            p[i] = 0; // Placeholder for now
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    std::vector<int> available_for_fill;
    for (int i = 1; i <= n; ++i) {
        if (used_numbers.find(i) == used_numbers.end()) {
            available_for_fill.push_back(i);
        }
    }
    std::sort(available_for_fill.rbegin(), available_for_fill.rend()); // Sort descending for greedy fill

    int current_fill_idx = 0;
    for (int i = 0; i < n; ++i) {
        if (p[i] == 0) { // This is a slot where q_i == q_{i-1}
            if (current_fill_idx >= available_for_fill.size()) {
                possible = false; // Not enough numbers to fill
                break;
            }
            int val_to_fill = available_for_fill[current_fill_idx];
            if (val_to_fill > q[i]) { // If the smallest available number is greater than q_i, it's impossible
                possible = false;
                break;
            }
            p[i] = val_to_fill;
            current_fill_idx++;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
        return;
    }

    // Final check for validity (optional, but good for debugging)
    // Recompute prefix maximums and compare with q
    int current_max = 0;
    for (int i = 0; i < n; ++i) {
        current_max = std::max(current_max, p[i]);
        if (current_max != q[i]) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << -1 << "\n";
    } else {
        for (int i = 0; i < n; ++i) {
            std::cout << p[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
    }
}

