#include <iostream>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        long long c, m, x;
        std::cin >> c >> m >> x;
        long long low = 0;
        long long high = std::min({c, m, (c + m + x) / 3});
        long long ans = 0;

        while (low <= high) {
            long long mid = low + (high - low) / 2;
            // To form 'mid' teams:
            // We need 'mid' coders and 'mid' mathematicians for the minimum requirement.
            // This leaves c - mid coders and m - mid mathematicians.
            // The remaining 'mid' spots in the teams can be filled by any student.
            // The total number of students available for these 'mid' remaining spots is
            // (c - mid) + (m - mid) + x.
            // If this sum is >= mid, then it's possible to form 'mid' teams.
            if ((c - mid) + (m - mid) + x >= mid) {
                ans = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        std::cout << ans << "\n";
    }
    return 0;
}

