    // The numbers used are 1, 2, ..., k+1.
    // The remaining numbers are k+2, k+3, ..., n.
    // We can append these in increasing order to maintain a difference of 1.

    for (int i = k + 1; i < n; ++i) {
        p[i] = i + 1; // This will be k+2, k+3, ..., n
    }

    for (int i = 0; i < n; ++i) {
        std::cout << p[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

