#include <iostream>
#include <string>
#include <algorithm>
#include <map>

void solve() {
    std::string s;
    std::cin >> s;

    std::map<char, int> counts;
    for (char c : s) {
        counts[c]++;
    }

    int horizontal_moves = std::min(counts['L'], counts['R']);
    int vertical_moves = std::min(counts['U'], counts['D']);

    if (horizontal_moves == 0 && vertical_moves == 0) {
        std::cout << 0 << std::endl << std::endl;
        return;
    }

    if (horizontal_moves == 0) { // Only vertical moves possible
        // To form a valid path, we need at least one U and one D.
        // If we only have U or only D, we can't return to (0,0).
        // If we have both, we can use one U and one D.
        // The problem states "if the path is empty then it is visited only once".
        // If we have 0 horizontal moves, and 0 vertical moves, it's 0 length.
        // If we have 0 horizontal moves, and >0 vertical moves, we can only make a path of length 2 (UD or DU).
        // This is because any longer path like UUDD would visit (0,1) twice.
        // So, if horizontal_moves is 0, we can only form "UD" or "DU" if vertical_moves > 0.
        // The problem statement implies that if horizontal_moves is 0, and vertical_moves is 0, the length is 0.
        // If horizontal_moves is 0, and vertical_moves > 0, we can form "UD" (length 2).
        // This is handled by the general logic below, as vertical_moves will be 1.
        vertical_moves = std::min(vertical_moves, 1); // Limit to one pair (U,D)
    }

    if (vertical_moves == 0) { // Only horizontal moves possible
        // Similar to vertical_moves == 0, we can only form "LR" or "RL" if horizontal_moves > 0.
        horizontal_moves = std::min(horizontal_moves, 1); // Limit to one pair (L,R)
    }

    int total_length = 2 * horizontal_moves + 2 * vertical_moves;
    std::cout << total_length << std::endl;

    std::string result = "";
    for (int i = 0; i < horizontal_moves; ++i) result += 'L';
    for (int i = 0; i < vertical_moves; ++i) result += 'U';
    for (int i = 0; i < horizontal_moves; ++i) result += 'R';
    for (int i = 0; i < vertical_moves; ++i) result += 'D';

    std::cout << result << std::endl;
}

