int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        int n;
        std::cin >> n;
        std::vector<int> p(n);
        std::vector<int> pos(n + 1); // pos[val] stores the index of val in p
        for (int i = 0; i < n; ++i) {
            std::cin >> p[i];
            pos[p[i]] = i;
        }

        std::string result = "";
        int current_min_idx = pos[1];
        int current_max_idx = pos[1];

        for (int m = 1; m <= n; ++m) {
            // For m=1, the subsegment is just [1].
            // current_min_idx and current_max_idx are already initialized to pos[1].
            // The length is 1, which is m.
            // The min value is 1, max value is 1.
            // So m=1 is always beautiful.

            // For m > 1, we extend the current range to include m.
            // We need to find the minimum and maximum indices encountered so far
            // for values 1 to m.
            if (m > 1) {
                current_min_idx = std::min(current_min_idx, pos[m]);
                current_max_idx = std::max(current_max_idx, pos[m]);
            }

            // A number m is beautiful if the subsegment p[current_min_idx ... current_max_idx]
            // contains all numbers from 1 to m, and its length is exactly m.
            // The length of this subsegment is (current_max_idx - current_min_idx + 1).
            // If this length equals m, it means all numbers from 1 to m are within this range
            // and no other numbers are needed to bridge the gap.
            if (current_max_idx - current_min_idx + 1 == m) {
                result += '1';
            } else {
                result += '0';
            }
        }
        std::cout << result << "\n";
    }
    return 0;
}

