#include <iostream>
#include <vector>
#include <string>
#include <numeric>
#include <algorithm>

void solve() {
    long long a, b, c, d;
    std::cin >> a >> b >> c >> d;

    long long total_toys = a + b + c + d;

    std::vector<std::string> result(4);

    // Box 1: (-inf, -1] (Negative, magnitude >= 1)
    // To end up in Box 1, the final product must be negative and its magnitude must be >= 1.
    // The final product's sign is determined by the parity of negative numbers multiplied.
    // The final product's magnitude is determined by the number of values > 1 and < 1.

    // Can Box 1 be special?
    // Final product must be negative. This means an odd number of negative values must be multiplied.
    // The initial number of negative toys is A + B.
    // If A + B is odd, it's possible to have a negative final product.
    // If A + B is even, it's possible to have a positive final product.
    // If A + B is 0, the final product must be positive.

    // Case 1: Final product is negative (odd number of negative factors)
    // This requires (A + B) to be odd.
    // If A + B is odd:
    //   - If A > 0, we can pick a value like -2.
    //   - If B > 0, we can pick a value like -0.5.
    //   - If A + B is odd, we can always arrange for the final product to be negative.
    //     For example, if A=1, B=0, C=0, D=0, final product is negative.
    //     If A=0, B=1, C=0, D=0, final product is negative.
    //     If A=1, B=1, C=0, D=0, final product is positive.
    //     If A=2, B=1, C=0, D=0, final product is negative.
    // So, if (A + B) % 2 == 1, the final product can be negative.

    // Case 2: Final product's magnitude >= 1.
    // This requires at least one initial toy with magnitude >= 1 (from Box 1 or Box 4)
    // OR, if all initial toys have magnitude < 1 (from Box 2 or Box 3),
    // then the final product will have magnitude < 1.
    // So, if A + D > 0, it's possible to have magnitude >= 1.
    // If A + D == 0, then all initial toys are from Box 2 or Box 3, so the final product will have magnitude < 1.

    // Box 1 (Negative, magnitude >= 1):
    // Possible if:
    // 1. (A + B) is odd (for negative sign)
    // 2. (A + D) > 0 (for magnitude >= 1)
    // Exception: If total_toys == 1 and the toy is in Box 1, then it's possible.
    // If total_toys == 1:
    //   - If A=1, B=0, C=0, D=0: Box 1 is special.
    //   - If A=0, B=1, C=0, D=0: Box 2 is special.
    //   - If A=0, B=0, C=1, D=0: Box 3 is special.
    //   - If A=0, B=0, C=0, D=1: Box 4 is special.

    // Let's handle total_toys == 1 first.
    if (total_toys == 1) {
        result[0] = (a == 1 ? "Ya" : "Tidak");
        result[1] = (b == 1 ? "Ya" : "Tidak");
        result[2] = (c == 1 ? "Ya" : "Tidak");
        result[3] = (d == 1 ? "Ya" : "Tidak");
    } else {
        // Box 1: Negative, magnitude >= 1
        // Condition for negative sign: (A + B) % 2 == 1
        // Condition for magnitude >= 1: (A + D) > 0
        // If A+D=0, all toys are from B or C, so final product magnitude < 1.
        // If A+B=0, all toys are from C or D, so final product is positive.
        if ((a + b) % 2 == 1 && (a + d) > 0) {
            result[0] = "Ya";
        } else {
            result[0] = "Tidak";
        }

        // Box 2: Negative, magnitude < 1
        // Condition for negative sign: (A + B) % 2 == 1
        // Condition for magnitude < 1:
        //   - If A + D == 0, then all toys are from B or C, so final product magnitude < 1.
        //   - If A + D > 0, it's still possible to get magnitude < 1.
        //     Example: -2 * 0.1 = -0.2 (Box 1 * Box 3 -> Box 2)
        //     Example: 2 * -0.1 = -0.2 (Box 4 * Box 2 -> Box 2)
        //     The only way to *guarantee* magnitude >= 1 is if all toys are from Box 1 or Box 4,
        //     and there are at least two such toys.
        //     If A+D >= 1, and B+C >= 1, we can always make magnitude < 1.
        //     If A+D >= 1, and B+C == 0, then all toys are from A or D.
        //       If A+D >= 2, then magnitude will be >= 1.
        //       If A+D == 1, this case is covered by total_toys == 1.
        //     So, if A+D >= 2 and B+C == 0, then magnitude will be >= 1.
        //     Otherwise, it's possible to get magnitude < 1.
        //     This means, if not (A+D >= 2 AND B+C == 0), then magnitude < 1 is possible.
        //     Simplified: magnitude < 1 is possible UNLESS all toys are from A or D AND there are at least 2 such toys.
        //     This is equivalent to: (A+D < 2) OR (B+C > 0).
        //     This is equivalent to: (A+D == 0 OR A+D == 1) OR (B+C > 0).
        //     Since total_toys > 1, A+D == 1 implies B+C > 0.
        //     So, magnitude < 1 is possible UNLESS (A+D >= 2 AND B+C == 0).
        //     This means, if (A+D >= 2 && B+C == 0), then Box 2 is impossible.
        //     Otherwise, Box 2 is possible.

        if ((a + b) % 2 == 1 && !((a + d >= 2) && (b + c == 0))) {
            result[1] = "Ya";
        } else {
            result[1] = "Tidak";
        }

        // Box 3: Positive, magnitude < 1
        // Condition for positive sign: (A + B) % 2 == 0
        // Condition for magnitude < 1: Same as Box 2.
        if ((a + b) % 2 == 0 && !((a + d >= 2) && (b + c == 0))) {
            result[2] = "Ya";
        } else {
            result[2] = "Tidak";
        }

        // Box 4: Positive, magnitude >= 1
        // Condition for positive sign: (A + B) % 2 == 0
        // Condition for magnitude >= 1: (A + D) > 0
        if ((a + b) % 2 == 0 && (a + d) > 0) {
            result[3] = "Ya";
        } else {
            result[3] = "Tidak";
        }
    }

    std::cout << result[0] << " " << result[1] << " " << result[2] << " " << result[3] << std::endl;
}

