    while (t--) {
        solve();
    }
    return 0;
}

#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::string a, b;
    std::cin >> a >> b;

    long long cost = 0;
    long long count01 = 0; // count of positions where a[i] = '0' and b[i] = '1'
    long long count10 = 0; // count of positions where a[i] = '1' and b[i] = '0'

    for (int i = 0; i < n; ++i) {
        if (a[i] != b[i]) {
            if (a[i] == '0') { // a[i] = '0', b[i] = '1'
                if (count10 > 0) { // We have a '1' that needs to become '0'
                    // We can swap a '0' from current position with a '1' from a previous '10' position.
                    // This effectively fixes both positions. Cost is |i - j|, but we don't track j.
                    // The key insight is that a swap operation can be seen as two flips for free,
                    // if the bits are '0' and '1' and they need to be '1' and '0' respectively.
                    // Or, more accurately, if we have a '0' that needs to be '1' and a '1' that needs to be '0',
                    // swapping them fixes both. The cost is 0 for these two 'flips' if we consider them as
                    // a pair.
                    // So, we pair up a '01' mismatch with a '10' mismatch.
                    // Each such pair effectively costs 0 if we consider the 'swap' as fixing both.
                    // This is equivalent to saying we don't need to pay for a flip for this '01' mismatch,
                    // because it can be resolved by a swap with a '10' mismatch.
                    count10--; // Use up one '10' mismatch
                } else {
                    // No '10' mismatch to pair with, so this '01' mismatch must be flipped.
                    // Or, it could be part of a future swap.
                    // For now, we increment the count of '01' mismatches that are "unpaired".
                    count01++;
                }
            } else { // a[i] = '1', b[i] = '0'
                if (count01 > 0) { // We have a '0' that needs to become '1'
                    // Similar logic: pair up this '10' mismatch with a '01' mismatch.
                    count01--; // Use up one '01' mismatch
                } else {
                    // No '01' mismatch to pair with.
                    count10++;
                }
            }
        }
    }

    // After iterating through all positions, any remaining '01' or '10' mismatches
    // must be resolved by individual flips.
    // Each remaining mismatch (either '01' or '10') requires one flip operation.
    cost = count01 + count10;

    std::cout << cost << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    long long d;
    std::cin >> n >> d;

    std::vector<long long> x(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> x[i];
    }

    long long count = 0;
    int right_ptr = 0; // This pointer will mark the rightmost point that satisfies x[right_ptr] - x[left_ptr] <= d

    for (int left_ptr = 0; left_ptr < n; ++left_ptr) {
        // Advance right_ptr until x[right_ptr] - x[left_ptr] > d
        // or right_ptr reaches the end of the array.
        // The condition x[right_ptr] <= x[left_ptr] + d is equivalent.
        while (right_ptr < n && x[right_ptr] - x[left_ptr] <= d) {
            right_ptr++;
        }
        // At this point, all points from x[left_ptr] to x[right_ptr - 1]
        // satisfy the condition with x[left_ptr].
        // The number of such points is (right_ptr - 1) - left_ptr + 1 = right_ptr - left_ptr.
        // Let this be 'k' points, including x[left_ptr] itself.
        // We need to choose 2 additional points from these 'k-1' points (excluding x[left_ptr]).
        // So, we need to choose 2 points from (right_ptr - left_ptr - 1) available points.
        // This is C(right_ptr - left_ptr - 1, 2).

        long long num_available_points = right_ptr - left_ptr;
        if (num_available_points >= 3) {
            // We need to choose 3 points. The first point is x[left_ptr].
            // We need to choose 2 more points from the remaining (num_available_points - 1) points.
            // The number of ways to do this is C(num_available_points - 1, 2).
            // C(m, 2) = m * (m - 1) / 2
            long long m = num_available_points - 1;
            count += m * (m - 1) / 2;
        }
    }

    std::cout << count << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    long long s;
    std::cin >> n >> s;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::sort(a.begin(), a.end());

    long long operations = 0;
    int median_idx = n / 2;

    // Cost to make the median element equal to s
    operations += std::abs(a[median_idx] - s);

    // Adjust elements to the left of the median
    // They must be <= s
    for (int i = 0; i < median_idx; ++i) {
        if (a[i] > s) {
            operations += (a[i] - s);
        }
    }

    // Adjust elements to the right of the median
    // They must be >= s
    for (int i = median_idx + 1; i < n; ++i) {
        if (a[i] < s) {
            operations += (s - a[i]);
        }
    }

    std::cout << operations << std::endl;

    return 0;
}

