struct ElementA {
    long long value;
    int original_index;
};

struct ElementB {
    long long value;
    int original_index;
};

bool compareElementA(const ElementA& a, const ElementA& b) {
    return a.value < b.value;
}

bool compareElementB(const ElementB& a, const ElementB& b) {
    return a.value < b.value;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int m;
    std::cin >> m;

    std::vector<ElementA> A(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> A[i].value;
        A[i].original_index = i;
    }

    std::vector<ElementB> B(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> B[i].value;
        B[i].original_index = i;
    }

    std::sort(A.begin(), A.end(), compareElementA);
    std::sort(B.begin(), B.end(), compareElementB);

    std::vector<long long> result(m);
    for (int i = 0; i < m; ++i) {
        // A[i] is the i-th smallest value from original A
        // B[m-1-i] is the i-th largest value from original B
        // We want to assign A[i] to the original position of B[m-1-i]
        result[B[m - 1 - i].original_index] = A[i].value;
    }

    for (int i = 0; i < m; ++i) {
        std::cout << result[i] << (i == m - 1 ? "" : " ");
    }
    std::cout << std::endl;

