}

#include <iostream>
#include <vector>
#include <numeric>
#include <algorithm>
#include <set>

void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    std::vector<bool> is_prefix_perm(n + 1, false);
    std::vector<bool> seen_prefix(n + 1, false);
    int max_val_prefix = 0;
    bool possible_prefix = true;
    for (int i = 0; i < n; ++i) {
        int current_val = a[i];
        if (current_val > i + 1 || seen_prefix[current_val]) {
            possible_prefix = false;
        }
        seen_prefix[current_val] = true;
        max_val_prefix = std::max(max_val_prefix, current_val);

        if (possible_prefix && max_val_prefix == i + 1) {
            is_prefix_perm[i + 1] = true;
        }
    }

    std::vector<bool> is_suffix_perm(n + 1, false);
    std::vector<bool> seen_suffix(n + 1, false);
    int max_val_suffix = 0;
    bool possible_suffix = true;
    for (int i = n - 1; i >= 0; --i) {
        int current_val = a[i];
        int suffix_len = n - i;
        if (current_val > suffix_len || seen_suffix[current_val]) {
            possible_suffix = false;
        }
        seen_suffix[current_val] = true;
        max_val_suffix = std::max(max_val_suffix, current_val);

        if (possible_suffix && max_val_suffix == suffix_len) {
            is_suffix_perm[suffix_len] = true;
        }
    }

    std::vector<std::pair<int, int>> results;
    for (int l1 = 1; l1 < n; ++l1) { // l1 must be at least 1, and l2 must be at least 1, so l1 < n
        int l2 = n - l1;
        if (is_prefix_perm[l1] && is_suffix_perm[l2]) {
            results.push_back({l1, l2});
        }
    }

    std::cout << results.size() << "\n";
    for (const auto& p : results) {
        std::cout << p.first << " " << p.second << "\n";
    }
}

