void solve() {
    int n;
    int k;
    std::cin >> n >> k;
    std::vector<long long> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }
    std::vector<int> w(k);
    for (int i = 0; i < k; ++i) {
        std::cin >> w[i];
    }

    std::sort(a.begin(), a.end());
    std::sort(w.begin(), w.end());

    long long total_happiness = 0;

    // Friends with w_i = 1 get two copies of the largest available numbers.
    // These are the k_ones largest numbers from 'a'.
    // Since 'a' is sorted, these are a[n-1], a[n-2], ..., a[n-k_ones].
    // We iterate from the largest w_i values downwards.
    // Friends with w_i = 1 are at the end of the sorted 'w' array.
    int a_ptr_large = n - 1;
    for (int i = k - 1; i >= 0; --i) {
        if (w[i] == 1) {
            total_happiness += 2 * a[a_ptr_large];
            a_ptr_large--;
        } else {
            // All remaining w[i] will be > 1.
            // Break because we've processed all w_i = 1.
            // The loop for w_i > 1 will handle the rest.
            break;
        }
    }

    // Friends with w_i > 1.
    // They get one largest available number (for max_val) and one smallest available number (for min_val).
    // The largest available numbers are taken from a_ptr_large downwards.
    // The smallest available numbers are taken from a_ptr_small upwards.
    // We iterate through w from smallest to largest.
    // The smallest w_i values (which are > 1) are at the beginning of the sorted 'w' array.
    int a_ptr_small = 0;
    for (int i = 0; i < k; ++i) {
        if (w[i] > 1) {
            total_happiness += a[a_ptr_large]; // Max value for this friend
            a_ptr_large--;
            total_happiness += a[a_ptr_small]; // Min value for this friend
            a_ptr_small += (w[i] - 1); // Move pointer past the w[i]-1 intermediate numbers
        }
    }

    std::cout << total_happiness << std::endl;
}

