#include <string>
#include <numeric>
#include <algorithm>

int calculate_score(int n, const std::string& s) {
    if (n == 0) return 0;
    int current_score = 0;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (i == 0 || s[i - 1] == 'L') {
                current_score += 1;
            } else { // s[i-1] == 'W'
                current_score += 2;
            }
        }
    }
    return current_score;
}

void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    int initial_wins = 0;
    for (char c : s) {
        if (c == 'W') {
            initial_wins++;
        }
    }

    if (initial_wins + k == 0) { // No wins possible even after changing k games
        std::cout << 0 << std::endl;
        return;
    }

    if (initial_wins + k >= n) { // Can make all games 'W'
        std::cout << 1 + 2 * (n - 1) << std::endl;
        return;
    }

    // Strategy:
    // 1. Convert 'L's to 'W's to fill gaps between existing 'W's.
    //    This connects 'W' blocks, turning 1-point wins into 2-point wins.
    //    Prioritize smaller gaps.
    // 2. Convert remaining 'L's to 'W's at the ends or in isolated 'L' blocks.
    //    Each such conversion adds 1 point.

    std::vector<int> gaps;
    int first_W = -1, last_W = -1;
    for (int i = 0; i < n; ++i) {
        if (s[i] == 'W') {
            if (first_W == -1) {
                first_W = i;
            }
            last_W = i;
        }
    }

    if (first_W == -1) { // All 'L's initially
        // Change k 'L's to 'W's.
        // The best way is to make them consecutive to maximize score.
        // If k=0, score is 0.
        // If k>0, make first k games 'W'. Score will be 1 + 2*(k-1).
        std::cout << (k > 0 ? (1 + 2 * (k - 1)) : 0) << std::endl;
        return;
    }

    // Collect internal gaps
    int current_gap = 0;
    for (int i = first_W + 1; i <= last_W; ++i) {
        if (s[i] == 'L') {
            current_gap++;
        } else { // s[i] == 'W'
            if (current_gap > 0) {
                gaps.push_back(current_gap);
            }
            current_gap = 0;
        }
    }
    std::sort(gaps.begin(), gaps.end());

    int current_score = calculate_score(n, s);

    // Fill internal gaps
    for (int gap_len : gaps) {
        if (k >= gap_len) {
            k -= gap_len;
            current_score += 2 * gap_len + 1; // Each L becomes W, connecting two Ws.
                                              // The gap_len L's become W's.
                                              // The first L in the gap connects to the previous W, giving +1.
                                              // The remaining gap_len-1 L's connect to Ws, giving +2 each.
                                              // Total: 1 + 2*(gap_len-1) = 2*gap_len - 1.
                                              // This is wrong.
                                              // When a gap of length `g` is filled, `g` 'L's become 'W's.
                                              // The `W` before the gap was giving 2 points to the `W` after it.
                                              // Now, the `W` before the gap gives 2 points to the first `W` in the gap.
                                              // The `W` after the gap was giving 1 point to the `W` before it.
                                              // Now, the last `W` in the gap gives 2 points to the `W` after it.
                                              // The `g` 'L's were giving 0 points.
                                              // Now they give `1 + 2*(g-1)` points.
                                              // The score increases by `(1 + 2*(g-1)) - 0` for the new wins.
                                              // But also, the `W` after the gap now gets 2 points instead of 1.
                                              // So, total increase is `(1 + 2*(g-1)) + 1 = 2*g`.
                                              // Example: W L L W -> W W W W. Score: (1+1) -> (1+2+2+2). Increase: 5-2=3. Gap=2. 2*2-1=3.
                                              // Example: W L W -> W W W. Score: (1+1) -> (1+2+2). Increase: 3-2=1. Gap=1. 2*1-1=1.
                                              // The increase is 2*gap_len - 1.
                                              // No, it's simpler. Each L becomes a W.
                                              // If it connects two Ws, it means the W after it was getting 1 point (from L) and now gets 2 (from W). +1 point.
                                              // The L itself becomes a W. If it's the first in the gap, it gets 1 point. If it's subsequent, it gets 2 points.
                                              // So, for a gap of length `g`:
                                              // The `g` 'L's become `g` 'W's. These `g` 'W's contribute `1 + 2*(g-1)` points.
                                              // The `W` immediately after the gap now gets 2 points instead of 1 (because the last `L` in the gap became `W`). This is an additional `+1` point.
                                              // Total increase: `(1 + 2*(g-1)) + 1 = 2*g`.
                                              // This is correct.
            current_score += 2 * gap_len;
        } else {
            // Can't fill the whole gap, fill as much as possible
            current_score += 2 * k;
            k = 0;
            break;
        }
    }

    // Use remaining k changes for 'L's outside the first_W to last_W block
    // These will always add 1 point per 'L' changed to 'W'
    current_score += k;

    std::cout << current_score << std::endl;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

