void solve() {
    int n;
    std::cin >> n;
    long long current_sum = 0;
    long long current_xor_sum = 0;
    for (int i = 0; i < n; ++i) {
        long long a;
        std::cin >> a;
        current_sum += a;
        current_xor_sum ^= a;
    }

    if (current_sum == 2 * current_xor_sum) {
        std::cout << 0 << "\n\n";
    } else {
        // We need to append elements b1, b2, ..., bs such that
        // (current_sum + sum(b_i)) = 2 * (current_xor_sum ^ xor_sum(b_i))
        // Let X = current_xor_sum
        // Let S = current_sum
        // We want S + b1 + b2 = 2 * (X ^ b1 ^ b2)
        // A simple strategy is to append two elements: X and S + X.
        // Let b1 = X.
        // Then new_xor_sum = X ^ b1 = X ^ X = 0.
        // The condition becomes S + b1 + b2 = 2 * 0 = 0.
        // This is not generally true for non-negative numbers.

        // Let's try to make the final XOR sum 0.
        // If we append current_xor_sum, the new XOR sum becomes 0.
        // Let b1 = current_xor_sum.
        // New XOR sum X' = current_xor_sum ^ b1 = current_xor_sum ^ current_xor_sum = 0.
        // New sum S' = current_sum + b1 = current_sum + current_xor_sum.
        // For the array to be good, S' must be 2 * X' = 2 * 0 = 0.
        // So, current_sum + current_xor_sum must be 0.
        // This is only true if current_sum = 0 and current_xor_sum = 0.
        // If current_sum + current_xor_sum != 0, we need to add more elements.

        // Strategy:
        // 1. Append current_xor_sum.
        //    New XOR sum becomes 0.
        //    New sum becomes current_sum + current_xor_sum.
        //    Let S_new = current_sum + current_xor_sum.
        //    Let X_new = 0.
        //    Now we need S_new = 2 * X_new, which means S_new = 0.
        //    If S_new is not 0, we need to append another element.
        // 2. We need to append an element 'k' such that:
        //    (S_new + k) = 2 * (X_new ^ k)
        //    (S_new + k) = 2 * (0 ^ k)
        //    (S_new + k) = 2 * k
        //    S_new = k
        //    So, we append k = S_new.

        // This means we append two elements:
        // b1 = current_xor_sum
        // b2 = current_sum + current_xor_sum
        // Let's verify:
        // Initial: sum = S, xor_sum = X
        // After adding b1 = X:
        //   sum' = S + X
        //   xor_sum' = X ^ X = 0
        // After adding b2 = S + X:
        //   final_sum = sum' + b2 = (S + X) + (S + X) = 2 * (S + X)
        //   final_xor_sum = xor_sum' ^ b2 = 0 ^ (S + X) = S + X
        // Check condition: final_sum == 2 * final_xor_sum
        //   2 * (S + X) == 2 * (S + X)
        // This holds true.

        // So, we append 2 elements: current_xor_sum and (current_sum + current_xor_sum).
        // The problem statement guarantees that a solution always exists by appending at most 3 elements.
        // This strategy uses 2 elements.

        long long b1 = current_xor_sum;
        long long b2 = current_sum + current_xor_sum;

        std::cout << 2 << "\n";
        std::cout << b1 << " " << b2 << "\n";
    }
}

