    std::cin >> x;

    int n = s.length();
    std::string w(n, '1'); // Initialize w with all '1's

    // Step 1: Determine necessary '0's in w based on '0's in s
    for (int i = 0; i < n; ++i) {
        if (s[i] == '0') {
            // If s[i] is '0', then w[i-x] (if exists) must be '0'
            if (i - x >= 0) {
                w[i - x] = '0';
            }
            // And w[i+x] (if exists) must be '0'
            if (i + x < n) {
                w[i + x] = '0';
            }
        }
    }

    // Step 2: Verify if the constructed w can produce s
    // For each s[i], check if it can be formed by w
    for (int i = 0; i < n; ++i) {
        bool can_be_one = false;
        // Check w[i-x]
        if (i - x >= 0 && w[i - x] == '1') {
            can_be_one = true;
        }
        // Check w[i+x]
        if (i + x < n && w[i + x] == '1') {
            can_be_one = true;
        }

        // If s[i] is '1' but our w cannot make it '1', then no solution
        if (s[i] == '1' && !can_be_one) {
            std::cout << -1 << std::endl;
            return;
        }
        // If s[i] is '0' but our w makes it '1', this should not happen
        // because we only set w[j] to '0' if s[j+x] or s[j-x] is '0'.
        // If s[i] is '0', then both w[i-x] and w[i+x] must be '0'
        // (if they exist), so can_be_one would be false.
        // This check is implicitly covered by the logic.
    }

    std::cout << w << std::endl;
