#include <string>
#include <vector>
#include <algorithm>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    std::string s;
    std::cin >> s;

    long long total_steps = 0;
    long long count_a = 0;
    long long mod = 1000000007;

    // Iterate from right to left
    for (int i = s.length() - 1; i >= 0; --i) {
        if (s[i] == 'b') {
            // If we encounter a 'b', it can potentially form 'ab' with preceding 'a's.
            // Each 'a' before this 'b' will contribute to steps.
            // The number of 'a's currently accumulated (count_a) represents
            // the number of 'ab' pairs that can be formed with this 'b'
            // if we process them from right to left.
            // When an 'ab' is replaced by 'bba', the 'a' effectively moves past the 'b'
            // and creates a new 'b'. This new 'b' can then interact with other 'a's.
            // The key insight is that each 'a' effectively doubles the number of 'b's
            // it can interact with as it moves past them.
            // If we have 'a's and then a 'b', like 'aaab', and we process from right to left:
            // 'aab' -> 'abba' (1 step, 1 'a' processed, 1 'b' created)
            // 'a' + 'abba' -> 'bba' + 'bba' (2 steps, 1 'a' processed, 2 'b's created)
            // The 'a' at the beginning effectively interacts with 2 'b's.
            // The number of steps for an 'a' is 2 * (steps for the 'a' to its right) + 1.
            // This is equivalent to saying that each 'a' effectively doubles the number of 'b's
            // it can interact with.
            // So, when we see a 'b', it means all 'a's encountered so far (count_a)
            // will form 'ab' pairs with this 'b'.
            // The number of steps added by this 'b' is equal to the current count_a.
            total_steps = (total_steps + count_a) % mod;
            // After processing this 'b', it effectively becomes two 'b's for future 'a's.
            // So, we double the count of 'a's that are "waiting" to be processed
            // by a 'b' to their left.
            // This is because each 'a' that passes this 'b' will create a new 'b'.
            // The 'a' itself will move past, and the 'b' will be replaced by 'bba'.
            // The 'a' effectively moves past two 'b's.
            // No, this is not correct.
            // Let's re-evaluate:
            // 'a's are processed from right to left.
            // When we see a 'b', it means any 'a's to its left will form 'ab' with it.
            // The number of 'a's currently accumulated (count_a) represents the number of 'ab' pairs
            // that can be formed with this 'b'.
            // Each such 'ab' replacement adds 1 step.
            // So, total_steps += count_a.
            // After this 'b' is processed by all 'a's to its left, it effectively becomes two 'b's.
            // For example, 'aab'.
            // i=2, s[2]='b'. count_a=0. total_steps=0.
            //   This 'b' is the rightmost.
            //   It will interact with 'a' at index 1.
            //   'a' at index 1 will become 'bba'.
            //   The 'b' at index 2 effectively becomes two 'b's for the 'a' at index 0.
            //   So, count_a should be doubled.
            count_a = (count_a * 2) % mod;
        } else { // s[i] == 'a'
            // If we encounter an 'a', it means this 'a' is now available to form 'ab'
            // with any 'b's to its right (which we have already processed and accounted for
            // in count_a).
            // So, we increment the count of 'a's.
            count_a = (count_a + 1) % mod;
        }
    }

    std::cout << total_steps << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, k;
    std::cin >> n >> k;

    long long total_operations = 0;
    int correct_sequence_length = 0;

    for (int i = 0; i < k; ++i) {
        int m;
        std::cin >> m;
        std::vector<int> chain(m);
        for (int j = 0; j < m; ++j) {
            std::cin >> chain[j];
        }

        if (chain[0] == 1) {
            // This chain starts with 1. Check how long the sequence 1, 2, 3... continues.
            int current_val = 1;
            int j = 0;
            while (j < m && chain[j] == current_val) {
                correct_sequence_length++;
                current_val++;
                j++;
            }
            // The remaining part of this chain (if any) needs to be disassembled.
            // Each matryoshka in the remaining part needs 1 "get out" operation.
            // The number of such matryoshkas is m - correct_sequence_length.
            // Each such matryoshka also needs 1 "put in" operation later.
            // So, for each matryoshka in the remaining part, it's 2 operations.
            total_operations += 2LL * (m - correct_sequence_length);
        } else {
            // This chain does not start with 1.
            // All m matryoshkas need to be taken out (m-1 "get out" operations for nesting, 1 for the outermost).
            // And all m matryoshkas need to be put in later.
            // Total operations for this chain: (m-1) + m = 2m - 1.
            total_operations += 2LL * m - 1;
        }
    }

    // The matryoshkas 1, 2, ..., correct_sequence_length are already in place.
    // We need to form the chain 1 -> 2 -> ... -> n.
    // This requires n-1 total nesting operations.
    // correct_sequence_length - 1 of these are already done.
    // So, (n-1) - (correct_sequence_length - 1) = n - correct_sequence_length "put in" operations are still needed.
    total_operations += (n - correct_sequence_length);

    std::cout << total_operations << std::endl;

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>
#include <cmath>

long long get_largest_x(long long p, long long q) {
    if (p % q != 0) {
        return p;
    }

    std::vector<long long> prime_factors_q;
    long long temp_q = q;
    for (long long i = 2; i * i <= temp_q; ++i) {
        if (temp_q % i == 0) {
            prime_factors_q.push_back(i);
            while (temp_q % i == 0) {
                temp_q /= i;
            }
        }
    }
    if (temp_q > 1) {
        prime_factors_q.push_back(temp_q);
    }

    long long max_x = 0;

    for (long long factor_q : prime_factors_q) {
        long long current_p = p;
        while (current_p % q == 0) {
            current_p /= factor_q;
        }
        max_x = std::max(max_x, current_p);
    }

    return max_x;
}

