    // p_x[i] stores count of 'x' in s[0...i-1]
    std::vector<int> p_x(n + 1, 0);
    std::vector<int> p_y(n + 1, 0);
    std::vector<int> p_z(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        p_x[i + 1] = p_x[i];
        p_y[i + 1] = p_y[i];
        p_z[i + 1] = p_z[i];
        if (s[i] == 'x') {
            p_x[i + 1]++;
        } else if (s[i] == 'y') {
            p_y[i + 1]++;
        } else { // s[i] == 'z'
            p_z[i + 1]++;
        }
    }

    int m;
    std::cin >> m;

    for (int k = 0; k < m; ++k) {
        int l, r;
        std::cin >> l >> r;

        // Adjust to 0-based indexing
        // Substring is s[l-1 ... r-1]
        // Length of substring is r - l + 1
        int len = r - l + 1;

        if (len < 3) {
            std::cout << "YES\n";
            continue;
        }

        int count_x = p_x[r] - p_x[l - 1];
        int count_y = p_y[r] - p_y[l - 1];
        int count_z = p_z[r] - p_z[l - 1];

        // The condition for termination is that the counts of 'x', 'y', 'z'
        // in any 3-character window can be made equal (or differ by at most 1).
        // This means the total counts of 'x', 'y', 'z' in the substring
        // must not differ by more than 1.
        // If they differ by more than 1, say count_x is 5, count_y is 1, count_z is 1,
        // then no matter how we rearrange, we will always have a 3-char window
        // that is not 'x', 'y', 'z' (e.g., 'xxx', 'xxy', etc.)
        // and thus not one of the forbidden permutations.
        // If we have counts like (5,1,1), we can always find a 'xxx' or 'xxy' etc.
        // and rearrange it to 'xyz' or 'yzx' or 'zxy'.
        // The algorithm terminates if and only if the counts of 'x', 'y', 'z'
        // in the substring can be made to differ by at most 1.
        // This is equivalent to checking if the current counts already satisfy this.

        int min_count = std::min({count_x, count_y, count_z});
        int max_count = std::max({count_x, count_y, count_z});

        if (max_count - min_count <= 1) {
            std::cout << "YES\n";
        } else {
            std::cout << "NO\n";
        }
    }

    return 0;
}

#include <iostream>
