void solve() {
    int n, k;
    std::cin >> n >> k;
    std::string s;
    std::cin >> s;

    std::vector<int> counts_0(k, 0);
    std::vector<int> counts_1(k, 0);
    std::vector<int> counts_q(k, 0);

    for (int i = 0; i < n; ++i) {
        int remainder = i % k;
        if (s[i] == '0') {
            counts_0[remainder]++;
        } else if (s[i] == '1') {
            counts_1[remainder]++;
        } else { // s[i] == '?'
            counts_q[remainder]++;
        }
    }

    bool possible = true;
    for (int i = 0; i < k; ++i) {
        if (counts_0[i] > 0 && counts_1[i] > 0) {
            possible = false;
            break;
        }
    }

    if (!possible) {
        std::cout << "NO\n";
        return;
    }

    int total_0_fixed = 0;
    int total_1_fixed = 0;

    for (int i = 0; i < k; ++i) {
        if (counts_0[i] > 0) {
            total_0_fixed++;
        } else if (counts_1[i] > 0) {
            total_1_fixed++;
        }
    }

    int required_0 = k / 2;
    int required_1 = k / 2;

    if (total_0_fixed > required_0 || total_1_fixed > required_1) {
        possible = false;
    } else {
        int remaining_q_slots = k - total_0_fixed - total_1_fixed;
        int needed_0_from_q = required_0 - total_0_fixed;
        int needed_1_from_q = required_1 - total_1_fixed;

        if (needed_0_from_q + needed_1_from_q > remaining_q_slots) {
            possible = false;
        }
    }

    if (possible) {
        std::cout << "YES\n";
    } else {
        std::cout << "NO\n";
    }
}

