#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

void solve() {
    int n;
    std::cin >> n;
    std::string s;
    std::cin >> s;

    std::string result(n, ' ');
    bool found_solution = false;

    for (char p_char = '0'; p_char <= '9'; ++p_char) {
        int p = p_char - '0';

        std::string current_result(n, ' ');
        char last_d1 = '0'; // Last digit colored 1
        char last_d2 = '0'; // Last digit colored 2

        bool possible_for_p = true;
        for (int i = 0; i < n; ++i) {
            int digit = s[i] - '0';
            if (digit < p) {
                // Must be color 1
                if (s[i] < last_d1) {
                    possible_for_p = false;
                    break;
                }
                current_result[i] = '1';
                last_d1 = s[i];
            } else if (digit > p) {
                // Must be color 2
                if (s[i] < last_d2) {
                    possible_for_p = false;
                    break;
                }
                current_result[i] = '2';
                last_d2 = s[i];
            } else { // digit == p
                // Can be color 1 or 2. Try to put it in color 2 if possible.
                // This greedy choice (put p into color 2 if possible) is crucial.
                // If we put p into color 1, it must be >= last_d1.
                // If we put p into color 2, it must be >= last_d2.
                // To maximize flexibility for future digits, we want to keep last_d1 as small as possible.
                // So, if s[i] (which is p) can go into color 2, put it there.
                if (s[i] >= last_d2) {
                    current_result[i] = '2';
                    last_d2 = s[i];
                } else if (s[i] >= last_d1) { // If it can't go into color 2, try color 1
                    current_result[i] = '1';
                    last_d1 = s[i];
                } else { // Can't go into either
                    possible_for_p = false;
                    break;
                }
            }
        }

        if (possible_for_p) {
            // Final check: last_d1 <= first_d2.
            // In our construction, last_d1 is the largest digit assigned to color 1.
            // last_d2 is the largest digit assigned to color 2.
            // The condition is that the last digit of S1 must be <= the first digit of S2.
            // Our greedy strategy for 'p' digits ensures that if a 'p' digit is assigned to color 1,
            // it's because it couldn't be assigned to color 2 (i.e., it was less than last_d2).
            // This means all 'p' digits assigned to color 1 come before all 'p' digits assigned to color 2
            // in the final sorted sequence.
            // The overall condition is that the sequence formed by S1 then S2 is non-decreasing.
            // This means max(S1) <= min(S2).
            // Our `last_d1` and `last_d2` track the maximums within their respective sequences.
            // The critical point is the transition from S1 to S2.
            // If `last_d1` is the largest digit in S1, and `first_d2` is the smallest digit in S2,
            // we need `last_d1 <= first_d2`.
            // Our construction ensures that `last_d1` is the maximum of all digits colored 1.
            // And `last_d2` is the maximum of all digits colored 2.
            // The crucial part is that any digit `d_i` colored 1 must be <= any digit `d_j` colored 2.
            // This is implicitly handled by the pivot `p`.
            // All digits < p are 1. All digits > p are 2.
            // Digits == p are split.
            // The split point for 'p' digits is where we switch from assigning 'p' to color 1 to assigning 'p' to color 2.
            // Let's find the actual max_1 and min_2.
            char actual_max_1 = '0' - 1; // Smaller than any digit
            char actual_min_2 = '9' + 1; // Larger than any digit
            bool has_1 = false;
            bool has_2 = false;

            for(int i=0; i<n; ++i) {
                if (current_result[i] == '1') {
                    actual_max_1 = std::max(actual_max_1, s[i]);
                    has_1 = true;
                } else { // current_result[i] == '2'
                    actual_min_2 = std::min(actual_min_2, s[i]);
                    has_2 = true;
                }
            }

            if (!has_1 || !has_2 || actual_max_1 <= actual_min_2) {
                result = current_result;
                found_solution = true;
                break;
            }
        }
    }

    if (found_solution) {
        std::cout << result << "\n";
    } else {
        std::cout << "-\n";
    }
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        solve();
    }
    return 0;
}

