int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int n;
    std::cin >> n;
    std::vector<long long> h(n);
    long long max_h = 0;
    for (int i = 0; i < n; ++i) {
        std::cin >> h[i];
        if (h[i] > max_h) {
            max_h = h[i];
        }
    }

    std::vector<long long> d(n);
    std::deque<int> q;

    // Calculate d_i for left-to-right pass
    for (int i = 0; i < n; ++i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = (q.empty() ? 0 : d[q.back()]);
        d[i] = prev_d + 1;
        q.push_back(i);
    }

    q.clear();
    // Calculate d_i for right-to-left pass and combine
    for (int i = n - 1; i >= 0; --i) {
        while (!q.empty() && h[q.back()] >= h[i]) {
            q.pop_back();
        }
        long long prev_d = (q.empty() ? 0 : d[q.back()]);
        d[i] = std::min(d[i], prev_d + 1);
        q.push_back(i);
    }

    long long max_d = 0;
    for (int i = 0; i < n; ++i) {
        if (d[i] > max_d) {
            max_d = d[i];
        }
    }

    long long ans = max_d;
    long long remaining_height = max_h - max_d + 1;
    if (remaining_height > 0) {
        ans += (remaining_height + 1) / 2;
    }

    std::cout << ans << std::endl;

    return 0;
}

