    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 1) {
        std::cout << 0 << std::endl;
        return;
    }

    // Find the rightmost peak of the suffix that is non-increasing
    // This is the first part of the "valley" structure
    int p1 = n - 1;
    while (p1 > 0 && a[p1 - 1] >= a[p1]) {
        p1--;
    }

    // Find the rightmost peak of the suffix that is non-decreasing
    // This is the second part of the "valley" structure
    int p2 = p1;
    while (p2 > 0 && a[p2 - 1] <= a[p2]) {
        p2--;
    }

    std::cout << p2 << std::endl;
}

