        std::cout << "0\n";
        // Operation 3: [1, 1], add 0
        std::cout << "1 1\n";
        std::cout << "0\n";
        return 0;
    }

    // Operation 1: Make a[0]...a[n-2] divisible by n
    // Select segment [1, n-1] (0-indexed: [0, n-2])
    // Length is n-1.
    // For each a[i] in this segment, we want to add a multiple of (n-1) such that a[i] becomes 0 mod n.
    // Specifically, we want a[i] + k * (n-1) = 0 mod n.
    // This is equivalent to a[i] + k * (-1) = 0 mod n.
    // So, k = a[i] mod n.
    // The value to add is k * (n-1) = (a[i] mod n) * (n-1).
    // After this, a[i] becomes a[i] + (a[i] % n) * (n-1).
    // Let's check: a[i] + (a[i] % n) * (n-1) = a[i] + (a[i] % n) * (-1) (mod n)
    // = a[i] - (a[i] % n) (mod n)
    // = (a[i] % n) - (a[i] % n) (mod n) = 0 (mod n).
    // So, after this operation, a[i] is divisible by n.

    std::cout << "1 " << n - 1 << "\n";
    for (int i = 0; i < n - 1; ++i) {
        long long remainder = a[i] % n;
        if (remainder < 0) { // Handle negative remainders to ensure 0 <= remainder < n
            remainder += n;
        }
        long long add_val = remainder * (n - 1);
        std::cout << add_val << (i == n - 2 ? "" : " ");
        a[i] += add_val;
    }
    std::cout << "\n";

    // Operation 2: Make a[n-1] divisible by n
    // Select segment [n, n] (0-indexed: [n-1, n-1])
    // Length is 1.
    // For a[n-1], we want to add a multiple of 1 such that a[n-1] becomes 0 mod n.
    // Specifically, we want a[n-1] + k * 1 = 0 mod n.
    // So, k = a[n-1] mod n.
    // The value to add is k * 1 = a[n-1] mod n.
    // After this, a[n-1] becomes a[n-1] + (a[n-1] % n).
    // Let's check: a[n-1] + (a[n-1] % n) = (a[n-1] % n) + (a[n-1] % n) (mod n)
    // This is not what we want. We want a[n-1] to become 0 mod n.
    // The simplest way to make a[n-1] divisible by n is to add (n - (a[n-1] % n)) % n.
    // Let `rem = a[n-1] % n`. If `rem` is 0, add 0. Otherwise, add `n - rem`.
