    // After this, a[n-1] is divisible by n.

    std::cout << n << " " << n << "\n";
    long long remainder_n_minus_1 = a[n - 1] % n;
    if (remainder_n_minus_1 < 0) {
        remainder_n_minus_1 += n;
    }
    long long add_val_n_minus_1 = (n - remainder_n_minus_1) % n;
    std::cout << add_val_n_minus_1 << "\n";
    a[n - 1] += add_val_n_minus_1;

    // After operations 1 and 2, all a[i] are divisible by n.
    // Operation 3: Make all elements zero.
    // Select segment [1, n] (0-indexed: [0, n-1])
    // Length is n.
    // Since all a[i] are now divisible by n, we can add -a[i] to each a[i].
    // -a[i] is a multiple of n.

