int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    int current_and_mask = 1023; // All bits are 1
    int current_or_mask = 0;    // All bits are 0
    int current_xor_mask = 0;   // All bits are 0

    for (int i = 0; i < n; ++i) {
        char op_char;
        int x;
        std::cin >> op_char >> x;

        if (op_char == '&') {
            current_and_mask &= x;
            current_or_mask &= x;
            current_xor_mask &= x;
        } else if (op_char == '|') {
            current_and_mask |= x;
            current_or_mask |= x;
            current_xor_mask |= x;
        } else if (op_char == '^') {
            current_and_mask ^= x;
            current_or_mask ^= x;
            current_xor_mask ^= x;
        }
    }

    std::vector<std::pair<char, int>> result_ops;

    // Determine the final AND mask
    // If a bit is 0 in current_and_mask, it means the final value of that bit will be 0, regardless of input.
    // This is equivalent to an AND operation with a mask where that bit is 0.
    // So, the final AND mask is current_and_mask.
    // We need to apply an AND operation with current_and_mask.
    // However, if current_and_mask is 1023 (all ones), then this AND operation is redundant.
    if (current_and_mask != 1023) {
        result_ops.push_back({'&', current_and_mask});
    }

    // Determine the final OR mask
    // If a bit is 1 in current_or_mask, it means the final value of that bit will be 1, regardless of input.
    // This is equivalent to an OR operation with a mask where that bit is 1.
    // So, the final OR mask is current_or_mask.
    // We need to apply an OR operation with current_or_mask.
    // However, if current_or_mask is 0 (all zeros), then this OR operation is redundant.
    if (current_or_mask != 0) {
        result_ops.push_back({'|', current_or_mask});
    }

    // Determine the final XOR mask
    // If a bit is 1 in current_xor_mask, it means the final value of that bit will be flipped.
    // This is equivalent to an XOR operation with a mask where that bit is 1.
    // So, the final XOR mask is current_xor_mask.
    // We need to apply an XOR operation with current_xor_mask.
    // However, if current_xor_mask is 0 (all zeros), then this XOR operation is redundant.
    if (current_xor_mask != 0) {
        result_ops.push_back({'^', current_xor_mask});
    }

    std::cout << result_ops.size() << "\n";
    for (const auto& op : result_ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}

