void solve() {
    int n;
    std::cin >> n;
    std::vector<int> a(2 * n);
    for (int i = 0; i < 2 * n; ++i) {
        std::cin >> a[i];
    }

    // Calculate prefix sums for the left side (jars n-1 down to 0)
    // diff_left[k] = (count of 1s - count of 2s) in jars n-1, n-2, ..., n-k
    // This is equivalent to (count of 1s - count of 2s) in jars 0, ..., k-1 if we reverse the left part.
    // Let's use the original indexing for clarity:
    // diff_left[k] is the balance if we remove k jars from the left (jars n-1, n-2, ..., n-k)
    // No, this is not correct.
    // Let's define `balance_left[k]` as the balance of jars `n-k` to `n-1`.
    // `balance_left[k]` is the balance of the `k` jars immediately to Karlsson's left.
    // `balance_left[0] = 0`
    // `balance_left[1] = (a[n-1] == 1 ? 1 : -1)`
    // `balance_left[k] = balance_left[k-1] + (a[n-k] == 1 ? 1 : -1)`
    std::vector<int> balance_left(n + 1, 0);
    for (int k = 1; k <= n; ++k) {
        balance_left[k] = balance_left[k - 1] + (a[n - k] == 1 ? 1 : -1);
    }

    // Calculate prefix sums for the right side (jars n up to 2n-1)
    // `balance_right[k]` is the balance of the `k` jars immediately to Karlsson's right.
    // `balance_right[0] = 0`
    // `balance_right[1] = (a[n] == 1 ? 1 : -1)`
    // `balance_right[k] = balance_right[k-1] + (a[n+k-1] == 1 ? 1 : -1)`
    std::vector<int> balance_right(n + 1, 0);
    for (int k = 1; k <= n; ++k) {
        balance_right[k] = balance_right[k - 1] + (a[n + k - 1] == 1 ? 1 : -1);
    }

    // Store the minimum number of jars removed from the left to achieve a certain balance
    // map_left[balance_value] = k (number of jars removed from left)
    std::map<int, int> map_left;
    for (int k = 0; k <= n; ++k) {
        if (map_left.find(balance_left[k]) == map_left.end()) {
            map_left[balance_left[k]] = k;
        }
    }

    int min_removed = 2 * n; // Initialize with max possible jars removed

    // Iterate through all possible numbers of jars removed from the right (k_right)
    for (int k_right = 0; k_right <= n; ++k_right) {
        int current_right_balance = balance_right[k_right];
        // We need to find k_left such that balance_left[k_left] + current_right_balance = 0
        // This means balance_left[k_left] = -current_right_balance
        int target_left_balance = -current_right_balance;

        if (map_left.count(target_left_balance)) {
            int k_left = map_left[target_left_balance];
            min_removed = std::min(min_removed, k_left + k_right);
        }
    }

    std::cout << min_removed << std::endl;
}

