int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int t;
    std::cin >> t;
    while (t--) {
        long long n, m;
        std::cin >> n >> m;

        if (m == 0) {
            std::cout << 0 << "\n";
            continue;
        }

        // Total number of substrings is n * (n + 1) / 2
        // We want to maximize f(s), which means minimizing the number of substrings
        // consisting only of '0's.
        // This is achieved by distributing the '0's as evenly as possible.
        // We have n - m zeros.
        // These zeros can be placed in m+1 potential blocks (before the first '1',
        // between any two '1's, and after the last '1').
        // To minimize the number of '0'-only substrings, we want to make these blocks
        // of '0's as short as possible.
        // This means we should place '1's to break up long sequences of '0's.
        // The optimal strategy is to place '1's such that the '0's are distributed
        // as evenly as possible.
        // This creates m+1 blocks of zeros.
        // Let k be the number of zeros. k = n - m.
        // We distribute k zeros into m+1 blocks.
        // Some blocks will have floor(k / (m+1)) zeros, and some will have ceil(k / (m+1)) zeros.
        // Number of blocks with ceil(k / (m+1)) zeros: k % (m+1)
        // Number of blocks with floor(k / (m+1)) zeros: (m+1) - (k % (m+1))

        long long total_substrings = n * (n + 1) / 2;

        long long num_zeros = n - m;
        long long num_zero_blocks = m + 1;

        long long small_block_size = num_zeros / num_zero_blocks;
        long long large_block_size = small_block_size + 1;

        long long num_large_blocks = num_zeros % num_zero_blocks;
        long long num_small_blocks = num_zero_blocks - num_large_blocks;

        long long zero_substrings_count = 0;
        zero_substrings_count += num_large_blocks * (large_block_size * (large_block_size + 1) / 2);
        zero_substrings_count += num_small_blocks * (small_block_size * (small_block_size + 1) / 2);

        std::cout << total_substrings - zero_substrings_count << "\n";
    }
    return 0;
}

