        long long current_sum = 0;
        for (int i = 0; i < n; ++i) {
            if (!active_nodes[i]) continue;
            for (int j = 0; j < n; ++j) {
                if (!active_nodes[j]) continue;
                if (i == j) continue; // Exclude paths from a vertex to itself
                current_sum += dist[i][j];
            }
        }
        results.push_back(current_sum);
    }

    // Print results in the correct order (before each removal)
    for (int i = n - 1; i >= 0; --i) {
        std::cout << results[i] << (i == 0 ? "" : " ");
    }
    std::cout << std::endl;

    return 0;
}

#include <iostream>
#include <vector>
