int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long X;
    long long d;
    std::cin >> X >> d;

    std::vector<long long> result_array;
    long long current_val = 1; // Start with 1, as elements must be positive

    while (X > 0) {
        long long k = 0;
        // Find largest k such that 2^k - 1 <= X
        // This is equivalent to 2^k <= X + 1
        // k <= log2(X + 1)
        // We need to find the largest k such that (1LL << k) - 1 <= X
        // Or, (1LL << (k+1)) - 1 > X
        // So, (1LL << k) <= X + 1

        // Iterate k from 60 down to 1 (since 2^60 is large enough for X up to 10^9)
        // We need to find the largest k such that (1LL << k) - 1 <= X
        // This is equivalent to finding the largest k such that (1LL << k) <= X + 1
        // The maximum value for X is 10^9, so X+1 is approx 10^9.
        // 2^29 is approx 5 * 10^8, 2^30 is approx 10^9.
        // So k can go up to 30.

        // A more robust way:
        // Find the highest set bit in X+1.
        // If X+1 is 0, k is 0.
        // Otherwise, k = floor(log2(X+1)).
        // For example, if X=10, X+1=11. log2(11) is 3.something. floor is 3.
        // 2^3-1 = 7 <= 10. 2^4-1 = 15 > 10. So k=3.
        // If X=7, X+1=8. log2(8)=3. floor is 3.
        // 2^3-1 = 7 <= 7. 2^4-1 = 15 > 7. So k=3.

        // Let's find k by iterating from 1 upwards.
        // This is safer than log2 for integer arithmetic and edge cases.
        long long temp_k = 1;
        while (true) {
            if ((1LL << (temp_k + 1)) - 1 > X) {
                k = temp_k;
                break;
            }
            if (temp_k >= 60) { // Prevent overflow for 1LL << (temp_k + 1)
                k = temp_k;
                break;
            }
            temp_k++;
        }

        // Add k copies of current_val to the result array
        for (int i = 0; i < k; ++i) {
            result_array.push_back(current_val);
            if (result_array.size() > 10000) {
                // This case should ideally not be reached given constraints
                // but as a safeguard.
                std::cout << -1 << std::endl;
                return 0;
            }
        }

        X -= ((1LL << k) - 1);

        // Update current_val for the next block
        // The next block's elements must be at least current_val + d
        // to ensure they don't form valid subsequences with previous blocks.
        // We choose current_val + d to be the minimum possible value.
        // If current_val + d exceeds 10^18, it's an issue.
        // The problem states a_i < 10^18.
        // Max current_val can be 1 + (30 * 10^9) which is too large.
        // The current_val must be chosen carefully.
        // The problem states a_i < 10^18.
        // The current_val should be `current_val + d` to ensure separation.
        // But if `current_val` is already large, `current_val + d` might overflow.
        // The maximum number of elements is 10000.
        // If d=1, and we add 10000 elements, current_val could be 10000.
        // If d=10^9, and we add 10000 elements, current_val could be 10000 * 10^9 = 10^13.
        // This is fine.
        // The issue is if current_val itself becomes very large.
        // The current_val is always `1 + (some_count * d)`.
        // Max count is 10000. Max d is 10^9.
        // So max current_val is 1 + 10000 * 10^9 = 1 + 10^13. This is well within 10^18.
        current_val += d;
    }

    if (result_array.size() > 10000) {
        std::cout << -1 << std::endl;
    } else {
        std::cout << result_array.size() << std::endl;
        for (size_t i = 0; i < result_array.size(); ++i) {
            std::cout << result_array[i] << (i == result_array.size() - 1 ? "" : " ");
        }
        std::cout << std::endl;
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

// Using long long for y to prevent overflow, as a_i can be up to 10^9
// and y can accumulate multiple a_x values.
// x is an index, so it fits in int.

// Structure to store memoized results
struct Result {
    long long y_val;
    int final_x;
    bool terminates;
};

// Global vector for a_values (a_1 is set dynamically)
std::vector<long long> a_values_input;
int N;

// Memoization table: memo[current_x][parity_of_step]
// parity_of_step: 0 for step 2, 1 for step 3
// We need to store results for (x, step_type) pairs.
// The maximum value of x is N.
// The maximum value of a_x is 10^9.
// The maximum value of y can be very large.
// The number of states (x, step_type) is 2 * N.
// We can use a vector of vectors or a 2D array.
// Initialize with a special value to indicate not computed.
std::vector<std::vector<Result>> memo;
const long long NOT_COMPUTED_Y = -2; // Sentinel value for y_val

// Function to solve for a given starting x and step type
Result solve(int current_x, int step_type) {
    // Check termination condition
    if (current_x <= 0 || current_x > N) {
        return {0, current_x, true}; // y_val is 0 for a terminating step
    }

    // Check memoization table
    if (memo[current_x][step_type].y_val != NOT_COMPUTED_Y) {
        return memo[current_x][step_type];
    }

    // Mark as currently computing to detect cycles
    memo[current_x][step_type] = {NOT_COMPUTED_Y - 1, 0, false}; // Use another sentinel for "in progress"

    long long val_a_x = a_values_input[current_x];
    Result next_res;

    if (step_type == 0) { // Step 2: x = x + a_x, y = y + a_x
        int next_x = current_x + val_a_x;
        next_res = solve(next_x, 1); // Next is step 3
        if (!next_res.terminates) {
            memo[current_x][step_type] = {0, 0, false}; // Cycle detected, does not terminate
        } else {
            memo[current_x][step_type] = {val_a_x + next_res.y_val, next_res.final_x, true};
        }
    } else { // Step 3: y = y + a_x, x = x - a_x
        int next_x = current_x - val_a_x;
        next_res = solve(next_x, 0); // Next is step 2
        if (!next_res.terminates) {
            memo[current_x][step_type] = {0, 0, false}; // Cycle detected, does not terminate
        } else {
            memo[current_x][step_type] = {val_a_x + next_res.y_val, next_res.final_x, true};
        }
    }
    return memo[current_x][step_type];
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N;

    // a_values_input will store a_2, ..., a_N at indices 2, ..., N.
    // Index 0 and 1 will be unused or used for a_1 dynamically.
    a_values_input.resize(N + 1);
    for (int k = 2; k <= N; ++k) {
        std::cin >> a_values_input[k];
    }

    // Initialize memoization table
    // memo[x][0] for starting with step 2 at x
    // memo[x][1] for starting with step 3 at x
    memo.resize(N + 1, std::vector<Result>(2, {NOT_COMPUTED_Y, 0, false}));

    // For each i from 1 to N-1
    for (int i = 1; i < N; ++i) {
        // Set a_1 for this run
        a_values_input[1] = i;

        // Clear memoization table for this run
        // This is crucial because a_1 changes for each i.
        // A full clear is needed.
        for (int x_idx = 0; x_idx <= N; ++x_idx) {
            memo[x_idx][0] = {NOT_COMPUTED_Y, 0, false};
            memo[x_idx][1] = {NOT_COMPUTED_Y, 0, false};
        }

        // Initial state: x=1, y=0. First operation is step 2.
        Result final_result = solve(1, 0);

        if (final_result.terminates) {
            std::cout << final_result.y_val << "\n";
        } else {
            std::cout << -1 << "\n";
        }
    }

    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
#include <limits>

struct Operation {
    int type;
    int l, r;
    long long val; // d for type 1, m for type 2
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n, m;
    std::cin >> n >> m;

    std::vector<Operation> ops(m);
    for (int i = 0; i < m; ++i) {
        std::cin >> ops[i].type >> ops[i].l >> ops[i].r >> ops[i].val;
        ops[i].l--; // 0-indexed
        ops[i].r--; // 0-indexed
    }

    // Initialize b_i to a very large positive value.
    // b_i represents the maximum possible initial value for a_i.
    // If a_i + current_delta_i <= m_k, then a_i <= m_k - current_delta_i.
    // We want to find the largest possible a_i that satisfies all constraints.
    // So, a_i must be <= min(m_k - current_delta_i) over all relevant type 2 ops.
    // Initialize b_i to a value larger than 10^9.
    std::vector<long long> b(n, 2000000000LL); // Max initial value for a_i

    // Calculate b_i values
    std::vector<long long> current_delta(n, 0);
    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                b[j] = std::min(b[j], ops[i].val - current_delta[j]);
            }
        }
    }

    // Verify the solution with the calculated b_i values
    // The initial array a_i will be b_i.
    std::vector<long long> a = b;
    std::fill(current_delta.begin(), current_delta.end(), 0); // Reset current_delta for verification

    for (int i = 0; i < m; ++i) {
        if (ops[i].type == 1) {
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                current_delta[j] += ops[i].val;
            }
        } else { // type 2
            long long max_val_in_range = std::numeric_limits<long long>::min();
            for (int j = ops[i].l; j <= ops[i].r; ++j) {
                max_val_in_range = std::max(max_val_in_range, a[j] + current_delta[j]);
            }
            if (max_val_in_range != ops[i].val) {
                std::cout << "NO\n";
                return 0;
            }
        }
    }

    std::cout << "YES\n";
    for (int i = 0; i < n; ++i) {
        std::cout << a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    long long a, b;
    std::cin >> a >> b;

    long long MOD = 1000000007;

    if (b == 1) {
        std::cout << 0 << std::endl;
        return 0;
    }

    // Sum of r from 1 to b-1: sum_r = (b-1) * b / 2
    // This is (b-1) * b * inv(2) mod MOD
    long long sum_r_term = (b - 1);
    sum_r_term = (sum_r_term * b) % MOD;

    // Modular inverse of 2 modulo 10^9 + 7 is (10^9 + 8) / 2 = 500000004
    long long inv2 = 500000004; 
    sum_r_term = (sum_r_term * inv2) % MOD;

    // Sum of (k*b + 1) from k=1 to a:
    // sum_k = sum_{k=1 to a} (k*b + 1)
    // sum_k = b * sum_{k=1 to a} k + sum_{k=1 to a} 1
    // sum_k = b * (a * (a+1) / 2) + a
    // sum_k = (b * a * (a+1) * inv(2) + a) mod MOD
    long long sum_k_term = (a * (a + 1)) % MOD;
    sum_k_term = (sum_k_term * inv2) % MOD;
    sum_k_term = (sum_k_term * b) % MOD;
    sum_k_term = (sum_k_term + a) % MOD;

    // Total sum = (sum_r_term * sum_k_term) mod MOD
    long long total_sum = (sum_r_term * sum_k_term) % MOD;

    std::cout << total_sum << std::endl;

    return 0;
}

