// Function to apply one step of median smoothing
std::vector<int> apply_median_smoothing(const std::vector<int>& a) {
    int n = a.size();
    if (n <= 2) { // Sequences of length 1 or 2 are always stable and don't change
        return a;
    }
    std::vector<int> b(n);
    b[0] = a[0];
    b[n - 1] = a[n - 1];
    for (int i = 1; i < n - 1; ++i) {
        // Median of three 0s and 1s: it's 1 if at least two are 1, else 0.
        // This is equivalent to (a[i-1] + a[i] + a[i+1] >= 2)
        // Or, using bitwise operations: (a[i-1] & a[i]) | (a[i-1] & a[i+1]) | (a[i] & a[i+1])
        // For 0/1 values, sum is simpler:
        b[i] = (a[i - 1] + a[i] + a[i + 1] >= 2) ? 1 : 0;
    }
    return b;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<int> a(n);
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i];
    }

    if (n <= 2) { // Sequences of length 1 or 2 are always stable
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Find all '01' and '10' patterns
    std::vector<int> zero_one_indices; // Indices i where a[i]=0, a[i+1]=1
    std::vector<int> one_zero_indices; // Indices i where a[i]=1, a[i+1]=0

    for (int i = 0; i < n - 1; ++i) {
        if (a[i] == 0 && a[i + 1] == 1) {
            zero_one_indices.push_back(i);
        } else if (a[i] == 1 && a[i + 1] == 0) {
            one_zero_indices.push_back(i);
        }
    }

    if (zero_one_indices.empty() && one_zero_indices.empty()) {
        // Sequence is already stable (all 0s or all 1s)
        std::cout << 0 << "\n";
        for (int i = 0; i < n; ++i) {
            std::cout << a[i] << (i == n - 1 ? "" : " ");
        }
        std::cout << "\n";
        return 0;
    }

    // Check for non-stabilizing patterns: 010101... or 101010...
    // This happens if the first '01' is followed by '10' at an odd distance,
    // and the last '10' is preceded by '01' at an odd distance.
    // More precisely, if the first 01 is at index i, and the last 10 is at index j,
    // and (j - i) is odd, then it might not stabilize.
    // The condition for non-stabilization is that the first 01 and last 10 are "intertwined"
    // such that they never meet.
    // This means the first 01 is at index `first_01_idx` and the last 10 is at index `last_10_idx`.
    // If `first_01_idx` is even and `last_10_idx` is odd, or vice versa, and they are far apart.
    // A simpler check: if the first 01 is at index `i` and the last 10 is at index `j`,
    // and `(j - i)` is odd, then the sequence will not stabilize.
    // This is because the '0' of '01' and the '1' of '10' will propagate towards each other,
    // but they will always be separated by an odd number of elements, preventing them from merging.

    int first_01_idx = zero_one_indices[0];
    int last_10_idx = one_zero_indices.back();

    if ((last_10_idx - first_01_idx) % 2 != 0) {
        std::cout << -1 << "\n";
        return 0;
    }

    // Calculate steps to stability and the final sequence
    int k = (last_10_idx - first_01_idx) / 2;

    // Apply smoothing k times
    std::vector<int> current_a = a;
    for (int step = 0; step < k; ++step) {
        current_a = apply_median_smoothing(current_a);
    }

    std::cout << k << "\n";
    for (int i = 0; i < n; ++i) {
        std::cout << current_a[i] << (i == n - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <vector>
#include <numeric>

struct Child {
    int id;
    long long v;
    long long d;
    long long p;
    bool removed;
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int n;
    std::cin >> n;

    std::vector<Child> children(n);
    for (int i = 0; i < n; ++i) {
        children[i].id = i + 1;
        std::cin >> children[i].v >> children[i].d >> children[i].p;
        children[i].removed = false;
    }

    std::vector<int> cured_children_ids;

    for (int i = 0; i < n; ++i) {
        if (children[i].removed) {
            continue;
        }

        cured_children_ids.push_back(children[i].id);
        children[i].removed = true; // Child i goes to the doctor

        long long current_office_cry_effect = children[i].v;
        long long total_hall_cry_effect = 0;

        for (int j = i + 1; j < n; ++j) {
            if (children[j].removed) {
                continue;
            }

            // Apply hall cry effect from previous children who left
            children[j].p -= total_hall_cry_effect;

            // Apply office cry effect from current child i
            if (current_office_cry_effect > 0) {
                children[j].p -= current_office_cry_effect;
                current_office_cry_effect--;
            }

            // Check if child j's confidence drops below zero
            if (children[j].p < 0) {
                children[j].removed = true;
                total_hall_cry_effect += children[j].d;
            }
        }
    }

    std::cout << cured_children_ids.size() << "\n";
    for (size_t i = 0; i < cured_children_ids.size(); ++i) {
        std::cout << cured_children_ids[i] << (i == cured_children_ids.size() - 1 ? "" : " ");
    }
    std::cout << "\n";

    return 0;
}

#include <iostream>
#include <algorithm>
#include <vector>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    int q;
    std::cin >> q;
    while (q--) {
        int n;
        std::cin >> n;
        long long min_x = -2000000000LL; // Effectively negative infinity
        long long max_x = 2000000000LL;  // Effectively positive infinity
        long long min_y = -2000000000LL; // Effectively negative infinity
        long long max_y = 2000000000LL;  // Effectively positive infinity

        for (int i = 0; i < n; ++i) {
            long long x, y;
            int f1, f2, f3, f4;
            std::cin >> x >> y >> f1 >> f2 >> f3 >> f4;

            // f1 = 0 means cannot move left (x-1). So x must be >= current x.
            // Target X must be >= x.
            if (f1 == 0) {
                min_x = std::max(min_x, x);
            }
            // f2 = 0 means cannot move up (y+1). So y must be <= current y.
            // Target Y must be <= y.
            if (f2 == 0) {
                max_y = std::min(max_y, y);
            }
            // f3 = 0 means cannot move right (x+1). So x must be <= current x.
            // Target X must be <= x.
            if (f3 == 0) {
                max_x = std::min(max_x, x);
            }
            // f4 = 0 means cannot move down (y-1). So y must be >= current y.
            // Target Y must be >= y.
            if (f4 == 0) {
                min_y = std::max(min_y, y);
            }
        }

        if (min_x <= max_x && min_y <= max_y) {
            std::cout << 1 << " " << min_x << " " << min_y << "\n";
        } else {
            std::cout << 0 << "\n";
        }
    }
    return 0;
}
